/*
   Indian Stock Analysis AI Workstation v2.0
   Unified Client-side State Machine & Dashboard Controller
   Real-time WebSocket Streaming via Angel One SmartAPI
*/

// ==================== GLOBAL INTERCEPTOR & CAPACITOR ROUTER ====================
(function() {
    const isCapacitor = window.hasOwnProperty('Capacitor') || 
                        (window.Capacitor !== undefined) || 
                        ((location.hostname === 'localhost' || location.hostname === '127.0.0.1' || location.protocol === 'capacitor:') && 
                         (location.port !== '8000' && location.port !== '8001' && location.port !== '8002' && location.port !== '5000'));
    const apiBaseUrl = isCapacitor ? 'https://my-stock-advisor.duckdns.org' : '';
    
    // Expose print fallback if running inside native Android WebView
    if (window.AndroidPrint && typeof window.AndroidPrint.print === 'function') {
        window.print = function() {
            window.AndroidPrint.print(document.title);
        };
    }

    // Android TTS Done callback
    window.onAndroidTtsDone = function() {
        if (window.SpeechPlayer && window.SpeechPlayer.isActive && window.SpeechPlayer.isPlaying) {
            window.SpeechPlayer.onAndroidTtsDone();
        }
    };

    // Android Speech callbacks
    window.onAndroidSpeechStart = function() {
        window.AndroidSpeechListening = true;
        const activeTarget = window.activeSpeechRecognizerTarget || 'chat';
        let micBtnId = 'chat-mic-btn';
        if (activeTarget === 'analyzer') micBtnId = 'analyzer-voice-search-btn';
        else if (activeTarget === 'rotation') micBtnId = 'sector-ai-voice-btn';
        else if (activeTarget === 'academy') micBtnId = 'academy-ai-mic-btn';
        else if (activeTarget === 'fs_chat') micBtnId = 'fs-chat-mic-btn';
        const micBtn = document.getElementById(micBtnId);
        if (micBtn) {
            micBtn.innerHTML = '🔴';
            micBtn.classList.add('mic-listening');
        }
    };
    window.onAndroidSpeechEnd = function() {
        window.AndroidSpeechListening = false;
        const activeTarget = window.activeSpeechRecognizerTarget || 'chat';
        let micBtnId = 'chat-mic-btn';
        if (activeTarget === 'analyzer') micBtnId = 'analyzer-voice-search-btn';
        else if (activeTarget === 'rotation') micBtnId = 'sector-ai-voice-btn';
        else if (activeTarget === 'academy') micBtnId = 'academy-ai-mic-btn';
        else if (activeTarget === 'fs_chat') micBtnId = 'fs-chat-mic-btn';
        const micBtn = document.getElementById(micBtnId);
        if (micBtn) {
            micBtn.innerHTML = '🎙️';
            micBtn.classList.remove('mic-listening');
        }
    };
    window.onAndroidSpeechError = function(errorMsg) {
        window.AndroidSpeechListening = false;
        const activeTarget = window.activeSpeechRecognizerTarget || 'chat';
        let micBtnId = 'chat-mic-btn';
        if (activeTarget === 'analyzer') micBtnId = 'analyzer-voice-search-btn';
        else if (activeTarget === 'rotation') micBtnId = 'sector-ai-voice-btn';
        else if (activeTarget === 'academy') micBtnId = 'academy-ai-mic-btn';
        else if (activeTarget === 'fs_chat') micBtnId = 'fs-chat-mic-btn';
        const micBtn = document.getElementById(micBtnId);
        if (micBtn) {
            micBtn.innerHTML = '🎙️';
            micBtn.classList.remove('mic-listening');
        }
        console.error(errorMsg);
        if (typeof showToast === 'function') {
            showToast(errorMsg, "error");
        }
    };
    window.onAndroidSpeechResult = function(transcript) {
        const activeTarget = window.activeSpeechRecognizerTarget || 'chat';
        if (activeTarget === 'analyzer') {
            const input = document.getElementById('analyzer-search-input');
            if (input) {
                input.value = transcript;
            }
            if (typeof resolveVoiceQuery === 'function') {
                resolveVoiceQuery(transcript);
            }
        } else if (activeTarget === 'rotation') {
            const input = document.getElementById('sector-ai-chat-input');
            if (input) {
                input.value = (input.value ? input.value + ' ' : '') + transcript;
            }
        } else if (activeTarget === 'academy') {
            const input = document.getElementById('academy-ai-input');
            if (input) {
                input.value = (input.value ? input.value + ' ' : '') + transcript;
            }
        } else if (activeTarget === 'fs_chat') {
            const input = document.getElementById('fs-chat-input');
            if (input) {
                input.value = (input.value ? input.value + ' ' : '') + transcript;
            }
        } else {
            const input = document.getElementById('chat-user-input');
            if (input) {
                input.value = (input.value ? input.value + ' ' : '') + transcript;
            }
        }
    };
    
    let isLoginModalOpen = false;
    function showServerLoginModal() {
        if (isLoginModalOpen) return;
        const modal = document.getElementById('mobile-server-login-modal');
        if (!modal) return;
        
        isLoginModalOpen = true;
        modal.style.display = 'flex';
        
        const userIn = document.getElementById('mobile-login-user');
        const passIn = document.getElementById('mobile-login-pass');
        const errDiv = document.getElementById('mobile-login-err');
        const btn = document.getElementById('mobile-login-btn');
        
        if (!btn) return;
        
        // Clone button to strip old event listeners
        const newBtn = btn.cloneNode(true);
        btn.parentNode.replaceChild(newBtn, btn);
        
        newBtn.addEventListener('click', async () => {
            const username = userIn ? userIn.value.trim() : '';
            const password = passIn ? passIn.value.trim() : '';
            
            if (!username || !password) {
                if (errDiv) {
                    errDiv.textContent = 'Please fill out all fields.';
                    errDiv.style.display = 'block';
                }
                return;
            }
            
            newBtn.disabled = true;
            newBtn.textContent = 'Authenticating...';
            if (errDiv) errDiv.style.display = 'none';
            
            const testToken = btoa(username + ':' + password);
            
            try {
                const testRes = await originalFetch('https://my-stock-advisor.duckdns.org/api/universe', {
                    headers: { 'Authorization': 'Basic ' + testToken }
                });
                if (testRes.status === 401) {
                    throw new Error('Invalid credentials');
                }
                
                // Save valid credentials
                localStorage.setItem('server_auth_token', testToken);
                modal.style.display = 'none';
                isLoginModalOpen = false;
                
                // Reload page dynamically to initialize all fetches with the token
                location.reload();
            } catch (err) {
                newBtn.disabled = false;
                newBtn.textContent = 'Connect Workstation';
                if (errDiv) {
                    errDiv.textContent = 'Connection failed. Check credentials.';
                    errDiv.style.display = 'block';
                }
            }
        });
    }
    
    window.showServerLoginModal = showServerLoginModal;
    
    const originalFetch = window.fetch;
    window.fetch = async function(input, init) {
        let isApi = typeof input === 'string' && input.startsWith('/api/');
        let targetUrl = isApi ? (apiBaseUrl + input) : input;
        
        const authToken = localStorage.getItem('server_auth_token');
        if (authToken && (isApi || (typeof input === 'string' && input.includes('my-stock-advisor.duckdns.org')))) {
            init = init || {};
            init.headers = init.headers || {};
            
            if (init.headers instanceof Headers) {
                init.headers.set('Authorization', 'Basic ' + authToken);
            } else {
                init.headers['Authorization'] = 'Basic ' + authToken;
            }
        }
        
        try {
            const response = await originalFetch(targetUrl, init);
            if (response.status === 401 && isCapacitor) {
                showServerLoginModal();
            }
            return response;
        } catch (error) {
            if (isCapacitor && !authToken) {
                showServerLoginModal();
            }
            throw error;
        }
    };
})();


// ==================== LIVE TICKS WEBSOCKET MANAGER ====================
let liveTicksWS = null;
let liveTicksReconnectTimer = null;
let liveTicksConnected = false;
let _wsSubscribedSymbols = new Set();
let activePortfolioLedgerItems = [];

async function fetchRealtimeIndices() {
    if (liveTicksConnected && liveTicksWS && liveTicksWS.readyState === WebSocket.OPEN) {
        return;
    }
    const indexSymbols = ["^NSEI", "^BSESN", "^NSEBANK", "^CNXIT", "^CNXINFRA", "^CNXAUTO"];
    try {
        const response = await fetch('/api/batch-quotes', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ symbols: indexSymbols })
        });
        if (!response.ok) return;
        const data = await response.json();
        const quotes = data.quotes || {};
        
        handleLiveTickMessage(quotes);
    } catch (e) {
        console.warn('Failed to fetch real-time indices:', e);
    }
}

function connectLiveTicksWS() {
    if (liveTicksWS && (liveTicksWS.readyState === WebSocket.CONNECTING || liveTicksWS.readyState === WebSocket.OPEN)) {
        return; // Already connected or connecting
    }

    const isCapacitor = window.hasOwnProperty('Capacitor') || 
                        (window.Capacitor !== undefined) || 
                        ((location.hostname === 'localhost' || location.hostname === '127.0.0.1' || location.protocol === 'capacitor:') && 
                         (location.port !== '8000' && location.port !== '8001' && location.port !== '8002' && location.port !== '5000'));
    const protocol = location.protocol === 'https:' ? 'wss:' : 'ws:';
    const authToken = localStorage.getItem('server_auth_token');
    
    let host = isCapacitor ? 'my-stock-advisor.duckdns.org' : location.host;
    if (isCapacitor && authToken) {
        try {
            const rawCreds = atob(authToken); // "username:password"
            host = `${rawCreds}@my-stock-advisor.duckdns.org`;
        } catch (e) {
            console.error('Error decoding auth token for WS:', e);
        }
    }
    
    const wsProto = isCapacitor ? 'wss:' : protocol;
    const wsUrl = `${wsProto}//${host}/ws/live-ticks`;

    try {
        liveTicksWS = new WebSocket(wsUrl);
    } catch (e) {
        console.warn('WebSocket connection failed:', e);
        updateConnectionIndicator('offline');
        scheduleWsReconnect();
        return;
    }

    liveTicksWS.onopen = () => {
        console.log('🟢 Live Ticks WebSocket connected');
        liveTicksConnected = true;
        updateConnectionIndicator('live');
        
        const indices = ["^NSEI", "^BSESN", "^NSEBANK", "^CNXIT", "^CNXINFRA", "^CNXAUTO", "MCXGOLD", "SPOTGOLD", "MCXSILVER", "SPOTSILVER", "PLATINUM"];
        indices.forEach(s => _wsSubscribedSymbols.add(s));

        // Re-subscribe to previously subscribed symbols
        if (_wsSubscribedSymbols.size > 0) {
            liveTicksWS.send(JSON.stringify({ action: 'subscribe', symbols: Array.from(_wsSubscribedSymbols) }));
        }
    };

    liveTicksWS.onmessage = (event) => {
        try {
            const msg = JSON.parse(event.data);
            if (msg.type === 'ticks') {
                handleLiveTickMessage(msg.data);
            } else if (msg.type === 'alert_triggered') {
                handleWsAlertTriggered(msg.alert);
            }
        } catch (e) {
            console.warn('Failed to parse WS message:', e);
        }
    };

    liveTicksWS.onclose = (event) => {
        console.warn('🔴 Live Ticks WebSocket closed:', event.code, event.reason);
        liveTicksConnected = false;
        updateConnectionIndicator('polling');
        scheduleWsReconnect();
    };

    liveTicksWS.onerror = (error) => {
        console.error('WebSocket error:', error);
        liveTicksConnected = false;
        updateConnectionIndicator('offline');
    };
}

function scheduleWsReconnect() {
    if (liveTicksReconnectTimer) clearTimeout(liveTicksReconnectTimer);
    liveTicksReconnectTimer = setTimeout(() => {
        console.log('Attempting WebSocket reconnection...');
        connectLiveTicksWS();
    }, 3000);
}

function wsSubscribeSymbols(symbols) {
    if (!symbols || symbols.length === 0) return;
    symbols.forEach(s => _wsSubscribedSymbols.add(s.toUpperCase()));
    if (liveTicksWS && liveTicksWS.readyState === WebSocket.OPEN) {
        liveTicksWS.send(JSON.stringify({ action: 'subscribe', symbols: symbols }));
    }
}

function wsUnsubscribeSymbols(symbols) {
    if (!symbols || symbols.length === 0) return;
    symbols.forEach(s => _wsSubscribedSymbols.delete(s.toUpperCase()));
    if (liveTicksWS && liveTicksWS.readyState === WebSocket.OPEN) {
        liveTicksWS.send(JSON.stringify({ action: 'unsubscribe', symbols: symbols }));
    }
}

function handleLiveTickMessage(ticksData) {
    // ticksData = { "TCS": { price, change, change_pct, high, low }, ... }
    if (!ticksData || typeof ticksData !== 'object') return;

    // Update marquee elements dynamically from live index ticks
    const indexMappings = {
        '^NSEI': { textElId: 'ticker-nifty', label: 'NIFTY 50' },
        '^BSESN': { textElId: 'ticker-sensex', label: 'SENSEX' },
        '^NSEBANK': { textElId: 'ticker-banknifty', label: 'BANK NIFTY' },
        '^CNXIT': { textElId: 'ticker-niftyit', label: 'NIFTY IT' },
        '^CNXINFRA': { textElId: 'ticker-niftyinfra', label: 'NIFTY INFRA' },
        '^CNXAUTO': { textElId: 'ticker-niftyauto', label: 'NIFTY AUTO' },
        'SPOTGOLD': { textElId: 'ticker-spotgold', label: 'SPOT GOLD' },
        'SPOTSILVER': { textElId: 'ticker-spotsilver', label: 'SPOT SILVER' }
    };

    for (const [sym, cfg] of Object.entries(indexMappings)) {
        const q = ticksData[sym];
        if (q && q.price > 0) {
            const els = document.querySelectorAll(`[id="${cfg.textElId}"]`);
            els.forEach(el => {
                const isPositive = q.change >= 0;
                const sign = isPositive ? '+' : '';
                const changeClass = isPositive ? 'change green-text' : 'change red-text';
                const changeArrow = isPositive ? '▲' : '▼';
                const formattedPrice = q.price.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
                const absChange = q.change !== undefined && q.change !== null ? Math.abs(q.change).toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 }) : '--';
                el.innerHTML = `${cfg.label}: <strong class="val">${formattedPrice}</strong> <span class="${changeClass}">${changeArrow} ${sign}${absChange} (${sign}${q.change_pct.toFixed(2)}%)</span>`;
            });
        }
    }

    // Update top meta banner benchmarks in the Equity Research Terminal
    const niftyTick = ticksData['^NSEI'];
    if (niftyTick && niftyTick.price > 0) {
        const el = document.getElementById('meta-nifty-bench');
        if (el) {
            const isPositive = niftyTick.change >= 0;
            const sign = isPositive ? '+' : '';
            const changeColor = isPositive ? 'var(--neon-green, #10b981)' : 'var(--neon-red, #ef4444)';
            el.innerHTML = `Nifty: <span style="font-family: 'Inter', monospace; color: var(--text-primary);">${niftyTick.price.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</span> <span style="color: ${changeColor}; font-size: 9px;">(${sign}${niftyTick.change_pct.toFixed(2)}%)</span>`;
        }
    }
    const sensexTick = ticksData['^BSESN'];
    if (sensexTick && sensexTick.price > 0) {
        const el = document.getElementById('meta-sensex-bench');
        if (el) {
            const isPositive = sensexTick.change >= 0;
            const sign = isPositive ? '+' : '';
            const changeColor = isPositive ? 'var(--neon-green, #10b981)' : 'var(--neon-red, #ef4444)';
            el.innerHTML = `Sensex: <span style="font-family: 'Inter', monospace; color: var(--text-primary);">${sensexTick.price.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</span> <span style="color: ${changeColor}; font-size: 9px;">(${sign}${sensexTick.change_pct.toFixed(2)}%)</span>`;
        }
    }

    // Update in-memory watchlist item data for sorting
    const activeWatch = (typeof watchlistsList !== 'undefined') ? watchlistsList.find(w => w.id == activeWatchlistId) : null;
    if (activeWatch && activeWatch.items) {
        activeWatch.items.forEach(item => {
            const q = ticksData[item.symbol] || ticksData[item.symbol.replace('.NS', '')];
            if (q && q.price > 0) {
                item.live_price = q.price;
                item.change = q.change;
                item.change_pct = q.change_pct;
                item.day_high = q.high;
                item.day_low = q.low;
            }
        });
    }

    // Update active stock profile in Equity Research Terminal if it's currently loaded
    if (activeStockProfile && activeStockProfile.ticker) {
        const activeTicker = activeStockProfile.ticker.toUpperCase();
        const baseTicker = activeTicker.replace('.NS', '').replace('.BO', '');
        const plainTicker = activeTicker.split('.')[0];
        
        let q = null;
        for (const [key, val] of Object.entries(ticksData)) {
            const uKey = key.toUpperCase();
            if (uKey === activeTicker || uKey === baseTicker || uKey === plainTicker) {
                q = val;
                break;
            }
        }

        if (q && q.price > 0) {
            // Update activeStockProfile fundamentals & technicals so calculations stay updated
            if (activeStockProfile.fundamentals) {
                activeStockProfile.fundamentals.current_price = q.price;
            }
            if (activeStockProfile.technicals) {
                activeStockProfile.technicals.price_change_pct = q.change_pct;
                if (q.high > 0) activeStockProfile.technicals.daily_high = q.high;
                if (q.low > 0) activeStockProfile.technicals.daily_low = q.low;
            }

            // Update top meta banner price & change in DOM
            const priceEl = document.getElementById('meta-price');
            const changeEl = document.getElementById('meta-change');
            if (priceEl) {
                const oldPriceText = priceEl.getAttribute('data-last-price');
                const priceChanged = oldPriceText && parseFloat(oldPriceText) !== q.price;
                priceEl.innerText = safeFormatRupees(q.price, 2);
                priceEl.setAttribute('data-last-price', q.price);

                // Add tick flash animation to the banner price
                if (priceChanged) {
                    const isPositive = q.change >= 0;
                    priceEl.classList.add(isPositive ? 'tick-flash-green' : 'tick-flash-red');
                    setTimeout(() => {
                        priceEl.classList.remove('tick-flash-green', 'tick-flash-red');
                    }, 600);
                }
            }

            if (changeEl) {
                const isPositive = q.change_pct >= 0;
                const sign = isPositive ? '+' : '';
                changeEl.innerHTML = `<span style="padding: 2px 6px; border-radius: 4px; background: ${isPositive ? 'rgba(16,185,129,0.12)' : 'rgba(239,68,68,0.12)'}; color: ${isPositive ? 'var(--neon-green)' : 'var(--neon-red)'}; font-weight: 700; font-size: 11px;">${sign}${q.change_pct.toFixed(2)}%</span>`;
            }

            // Update daily high/low displays on Technical tab if currently active
            const dailyHighEl = document.getElementById('tech-daily-high');
            const dailyLowEl = document.getElementById('tech-daily-low');
            if (dailyHighEl && q.high > 0) dailyHighEl.innerText = safeFormatRupees(q.high, 2);
            if (dailyLowEl && q.low > 0) dailyLowEl.innerText = safeFormatRupees(q.low, 2);

            // Update day range in meta banner
            const metaDayLowEl = document.getElementById('meta-day-low');
            const metaDayHighEl = document.getElementById('meta-day-high');
            if (metaDayLowEl && q.low > 0) metaDayLowEl.innerText = `L: ₹${q.low.toFixed(2)}`;
            if (metaDayHighEl && q.high > 0) metaDayHighEl.innerText = `H: ₹${q.high.toFixed(2)}`;

            if (q.low > 0 && q.high > 0) {
                updateMetaRangeProgress(q.price, q.low, q.high, 'meta-day-bar');
            }
            if (activeStockProfile.fundamentals) {
                updateMetaRangeProgress(q.price, activeStockProfile.fundamentals.low_52week, activeStockProfile.fundamentals.high_52week, 'meta-52w-bar');
            }

            // Dynamically update SMA alignment stack if currently rendered in DOM
            const stackContainer = document.getElementById('tech-sma-stack-container');
            if (stackContainer && activeStockProfile.technicals) {
                const sma50Val = activeStockProfile.technicals.sma_50 || 0.0;
                const sma200Val = activeStockProfile.technicals.sma_200 || 0.0;
                const stackItems = [
                    { label: 'Current Price', val: q.price, bg: 'rgba(59, 130, 246, 0.08)', border: 'var(--color-primary-glow)', textCol: 'var(--text-primary)' },
                    { label: '50-Day SMA', val: sma50Val, bg: 'rgba(16, 185, 129, 0.04)', border: 'rgba(16, 185, 129, 0.2)', textCol: 'var(--text-secondary)' },
                    { label: '200-Day SMA', val: sma200Val, bg: 'rgba(239, 68, 68, 0.04)', border: 'rgba(239, 68, 68, 0.2)', textCol: 'var(--text-secondary)' }
                ];
                stackItems.sort((a, b) => b.val - a.val);
                let stackHtml = '';
                stackItems.forEach((item, index) => {
                    stackHtml += `
                        <div style="background: ${item.bg}; border: 1px solid ${item.border}; padding: 6px 12px; border-radius: 6px; font-size: 11px; display: flex; justify-content: space-between; align-items: center; box-sizing: border-box; width: 100%;">
                            <span style="color: ${item.textCol}; font-weight: 500; font-family: 'Outfit', sans-serif;">${item.label}</span>
                            <strong style="color: var(--text-primary); font-family: 'Outfit', sans-serif;">${safeFormatRupees(item.val, 2)}</strong>
                        </div>
                    `;
                    if (index < 2) {
                        stackHtml += `<div style="text-align: center; font-size: 8px; color: var(--text-muted); margin: 1px 0;">▼</div>`;
                    }
                });
                stackContainer.innerHTML = stackHtml;
            }
        }
    }

    // Update visible DOM cells with flash animation
    const tbody = document.getElementById('watchlist-table-body');
    if (!tbody) return;

    const rows = tbody.querySelectorAll('tr[data-wl-symbol]');
    rows.forEach(row => {
        const sym = row.getAttribute('data-wl-symbol');
        const q = ticksData[sym] || ticksData[sym.replace('.NS', '')];
        if (!q || !q.price) return;

        const priceCell = row.querySelector('.wl-live-price');
        const changeCell = row.querySelector('.wl-change');
        const changePctCell = row.querySelector('.wl-change-pct');
        const highCell = row.querySelector('.wl-day-high');
        const lowCell = row.querySelector('.wl-day-low');

        const isPositive = q.change >= 0;
        const changeColor = isPositive ? 'var(--neon-green, #10b981)' : 'var(--neon-red, #ef4444)';
        const changeArrow = isPositive ? '▲' : '▼';

        const statusDot = row.querySelector('.wl-status-dot');
        if (statusDot) {
            const color = isPositive ? '#10b981' : '#ef4444';
            statusDot.style.backgroundColor = color;
            statusDot.style.boxShadow = `0 0 6px ${color}`;
            statusDot.title = isPositive ? 'Bullish daily momentum' : 'Bearish daily momentum';
        }

        // Check if price changed to trigger flash
        const oldPrice = priceCell ? priceCell.getAttribute('data-last-price') : null;
        const priceChanged = oldPrice && parseFloat(oldPrice) !== q.price;

        if (priceCell) {
            priceCell.innerHTML = `<span style="font-family: 'Inter', monospace;">₹${q.price.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</span>`;
            priceCell.setAttribute('data-last-price', q.price);
            if (priceChanged) {
                priceCell.classList.add(isPositive ? 'tick-flash-green' : 'tick-flash-red');
                setTimeout(() => {
                    priceCell.classList.remove('tick-flash-green', 'tick-flash-red');
                }, 600);
            }
        }
        if (changeCell) changeCell.innerHTML = `<span style="color: ${changeColor};">${changeArrow} ${isPositive ? '+' : ''}${q.change.toFixed(2)}</span>`;
        if (changePctCell) changePctCell.innerHTML = `<span style="color: ${changeColor}; padding: 1px 6px; border-radius: 4px; background: ${isPositive ? 'rgba(16,185,129,0.1)' : 'rgba(239,68,68,0.1)'}; font-size: 10.5px;">${isPositive ? '+' : ''}${q.change_pct.toFixed(2)}%</span>`;
        if (highCell) highCell.innerHTML = `<span style="font-family: 'Inter', monospace;">₹${q.high.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</span>`;
        if (lowCell) lowCell.innerHTML = `<span style="font-family: 'Inter', monospace;">₹${q.low.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</span>`;
    });

    // Update Today's Market Movers Dashboard
    if (window.handleMoversLiveTick) {
        for (const [sym, q] of Object.entries(ticksData)) {
            if (q && q.price > 0) {
                window.handleMoversLiveTick(sym, q.price, q.change_pct, q.change);
            }
        }
    }

    // Update Portfolio Ledger Real-time
    updatePortfolioLedgerRealtime(ticksData);
}

function handleWsAlertTriggered(alertData) {
    // alertData = { id, ticker, condition_type, operator, value, triggered_price, triggered_time }
    if (!alertData) return;

    const msg = `ALERT TRIGGERED: ${alertData.ticker} price ₹${alertData.triggered_price} (Target: ${alertData.operator} ${alertData.value})`;

    // 1. Play alert sound
    if (typeof playAlertSound === 'function') playAlertSound();

    // 2. Show Emergency HUD
    if (typeof showEmergencyHUD === 'function') showEmergencyHUD(msg);

    // 3. Toast notification
    if (typeof showToast === 'function') showToast(`🚨 REAL-TIME ALERT: ${msg}`, 'warning');

    // 4. Shake bell icon
    const bellIcon = document.querySelector('#header-bell-btn .bell-icon');
    if (bellIcon) {
        bellIcon.classList.add('bell-shake-active');
        setTimeout(() => bellIcon.classList.remove('bell-shake-active'), 800);
    }

    // 5. Add to notification list
    const notifBody = document.getElementById('notification-list-body');
    const badge = document.getElementById('bell-badge-count');
    if (notifBody) {
        if (notifBody.innerText.includes('No new system notifications')) {
            notifBody.innerHTML = '';
        }
        const now = new Date();
        const timeStr = now.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' });
        const item = document.createElement('div');
        item.className = 'notification-item';
        item.style.borderLeft = '3px solid var(--neon-red, #ef4444)';
        item.innerHTML = `
            <div class="notif-header">
                <span class="notif-badge badge-red">⚡ REAL-TIME</span>
                <span class="notif-time">Just Now (${timeStr})</span>
            </div>
            <div class="notif-text" style="color: var(--text-primary); font-weight: 500;">
                ${msg}
            </div>
        `;
        notifBody.prepend(item);
    }
    if (badge) {
        badge.textContent = parseInt(badge.textContent || '0') + 1;
        badge.style.display = 'flex';
    }

    // 6. Refresh alerts list if visible
    if (typeof fetchAlertsList === 'function') fetchAlertsList();
}

function updateMetaRangeProgress(current, low, high, barId) {
    const bar = document.getElementById(barId);
    if (!bar) return;
    if (low === null || low === undefined || high === null || high === undefined || low >= high || current === null || current === undefined) {
        bar.style.width = '0%';
        return;
    }
    const pct = Math.max(0, Math.min(100, ((current - low) / (high - low)) * 100));
    bar.style.width = `${pct}%`;
}

function updateConnectionIndicator(status) {
    let indicator = document.getElementById('ws-connection-indicator');
    if (!indicator) {
        // Create the indicator inside the header-utils section
        const headerUtils = document.querySelector('.header-utils');
        if (headerUtils) {
            indicator = document.createElement('div');
            indicator.id = 'ws-connection-indicator';
            indicator.style.cssText = 'padding:4px 10px;border-radius:12px;font-size:10px;font-weight:600;display:flex;align-items:center;gap:4px;font-family:Inter,sans-serif;cursor:default;transition:all 0.3s ease;white-space:nowrap;';
            headerUtils.insertBefore(indicator, headerUtils.firstChild);
        }
    }
    if (!indicator) return;

    if (status === 'live') {
        indicator.innerHTML = '<span style="display:inline-block;width:6px;height:6px;border-radius:50%;background:#10b981;box-shadow:0 0 6px #10b981;"></span> LIVE';
        indicator.style.background = 'rgba(16,185,129,0.15)';
        indicator.style.color = '#10b981';
        indicator.style.border = '1px solid rgba(16,185,129,0.3)';
        indicator.title = 'Angel One WebSocket: Connected — Real-time streaming active';
    } else if (status === 'polling') {
        indicator.innerHTML = '<span style="display:inline-block;width:6px;height:6px;border-radius:50%;background:#f59e0b;"></span> POLLING';
        indicator.style.background = 'rgba(245,158,11,0.15)';
        indicator.style.color = '#f59e0b';
        indicator.style.border = '1px solid rgba(245,158,11,0.3)';
        indicator.title = 'Using yfinance polling — WebSocket disconnected';
    } else {
        indicator.innerHTML = '<span style="display:inline-block;width:6px;height:6px;border-radius:50%;background:#ef4444;"></span> OFFLINE';
        indicator.style.background = 'rgba(239,68,68,0.15)';
        indicator.style.color = '#ef4444';
        indicator.style.border = '1px solid rgba(239,68,68,0.3)';
        indicator.title = 'No data connection available';
    }
}

function updatePortfolioLedgerRealtime(ticksData) {
    if (!activePortfolioLedgerItems || activePortfolioLedgerItems.length === 0) return;

    let updatedAny = false;
    activePortfolioLedgerItems.forEach(item => {
        const plainSym = item.symbol.replace('.NS', '').replace('.BO', '');
        const q = ticksData[item.symbol] || ticksData[plainSym];
        if (q && q.price > 0) {
            item.current_price = q.price;
            item.day_change_pct = q.change_pct;
            updatedAny = true;
        }
    });

    if (!updatedAny) return;

    // Recalculate totals
    let totalInvestment = 0.0;
    let totalValue = 0.0;
    let totalDayPL = 0.0;

    activePortfolioLedgerItems.forEach(item => {
        const qty = item.quantity || 0;
        const avgPrice = item.purchase_price || 0;
        const currentPrice = item.current_price || avgPrice || 0;
        const dayChangePct = item.day_change_pct || 0.0;

        const investedVal = qty * avgPrice;
        const currentVal = qty * currentPrice;
        const dayPL = qty * (currentPrice - (currentPrice / (1 + dayChangePct / 100)));

        totalInvestment += investedVal;
        totalValue += currentVal;
        totalDayPL += dayPL;
    });

    // Update DOM totals
    const totalInvEl = document.getElementById('port-total-investment');
    const totalValEl = document.getElementById('port-total-value');
    if (totalInvEl) totalInvEl.innerText = `₹${totalInvestment.toLocaleString('en-IN', {minimumFractionDigits: 2, maximumFractionDigits: 2})}`;
    if (totalValEl) totalValEl.innerText = `₹${totalValue.toLocaleString('en-IN', {minimumFractionDigits: 2, maximumFractionDigits: 2})}`;

    const netPL = totalValue - totalInvestment;
    const netPLPct = totalInvestment > 0 ? (netPL / totalInvestment) * 100 : 0.0;
    const netPLColor = netPL >= 0 ? 'var(--neon-green)' : 'var(--neon-red)';
    const netPLSign = netPL >= 0 ? '+' : '';
    const plTextEl = document.getElementById('port-total-pl');
    if (plTextEl) {
        plTextEl.innerText = `₹${netPL.toLocaleString('en-IN', {minimumFractionDigits: 2, maximumFractionDigits:2})} (${netPLSign}${netPLPct.toFixed(2)}%)`;
        plTextEl.style.color = netPLColor;
    }

    const dayPLPct = (totalValue - totalDayPL) > 0 ? (totalDayPL / (totalValue - totalDayPL)) * 100 : 0.0;
    const dayPLSign = totalDayPL >= 0 ? '+' : '';
    const dayPLColor = totalDayPL >= 0 ? 'var(--neon-green)' : 'var(--neon-red)';
    const dayPLTextEl = document.getElementById('port-day-pl');
    if (dayPLTextEl) {
        dayPLTextEl.innerText = `₹${totalDayPL.toLocaleString('en-IN', {minimumFractionDigits: 2, maximumFractionDigits:2})} (${dayPLSign}${dayPLPct.toFixed(2)}%)`;
        dayPLTextEl.style.color = dayPLColor;
    }

    // Local weighted score sum & sector calculations
    let localWeightedScoreSum = 0.0;
    let localSectorExposure = {};
    activePortfolioLedgerItems.forEach(item => {
        const qty = item.quantity || 0;
        const currentPrice = item.current_price || item.purchase_price || 0;
        const score = item.score !== undefined ? item.score : 50;
        const sector = item.sector || 'Other';
        const currentVal = qty * currentPrice;

        localWeightedScoreSum += score * currentVal;
        localSectorExposure[sector] = (localSectorExposure[sector] || 0.0) + currentVal;
    });

    let localPortfolioScore = 50;
    let localHhi = 0.0;
    if (totalValue > 0) {
        localPortfolioScore = Math.round(localWeightedScoreSum / totalValue);
        for (const sector in localSectorExposure) {
            const pct = (localSectorExposure[sector] / totalValue) * 100.0;
            localHhi += Math.pow(pct / 100.0, 2);
        }
    }

    let localDivBonus = 5;
    let localConcentrationLabel = "Well Diversified";
    if (localHhi > 0.4) {
        localConcentrationLabel = "Highly Concentrated (Undiversified)";
        localDivBonus = -15;
    } else if (localHhi > 0.25) {
        localConcentrationLabel = "Moderately Concentrated";
        localDivBonus = -5;
    }
    const localHealthScore = Math.max(10, Math.min(100, localPortfolioScore + localDivBonus));

    if (typeof animateDiagnosticsGauge === 'function') {
        animateDiagnosticsGauge(localHealthScore);
    }
    
    // Update Sector Exposure Chart
    let localSectorExposurePcts = {};
    if (totalValue > 0) {
        for (const sector in localSectorExposure) {
            localSectorExposurePcts[sector] = (localSectorExposure[sector] / totalValue) * 100.0;
        }
    }
    if (typeof renderSectorExposureChart === 'function') {
        renderSectorExposureChart(localSectorExposurePcts);
    }

    const concEl = document.getElementById('port-concentration-label');
    if (concEl) {
        concEl.innerText = localConcentrationLabel;
        if (localConcentrationLabel.toLowerCase().includes('well')) {
            concEl.style.color = 'var(--color-emerald)';
        } else if (localConcentrationLabel.toLowerCase().includes('highly') || localConcentrationLabel.toLowerCase().includes('poor')) {
            concEl.style.color = 'var(--neon-red)';
        } else {
            concEl.style.color = 'var(--color-amber)';
        }
    }

    // Update individual table rows
    const aggregatedItemsMap = {};
    activePortfolioLedgerItems.forEach(item => {
        const sym = item.symbol;
        if (!aggregatedItemsMap[sym]) {
            aggregatedItemsMap[sym] = {
                ...item,
                quantity: 0,
                total_invested_cost: 0
            };
        }
        const agg = aggregatedItemsMap[sym];
        agg.quantity += item.quantity || 0;
        agg.total_invested_cost += (item.quantity || 0) * (item.purchase_price || 0);
    });

    const aggregatedItems = Object.values(aggregatedItemsMap).map(agg => {
        if (agg.quantity > 0) {
            agg.purchase_price = agg.total_invested_cost / agg.quantity;
        } else {
            agg.purchase_price = 0;
        }
        return agg;
    });

    const ledgerBody = document.getElementById('portfolio-ledger-body');
    if (!ledgerBody) return;

    aggregatedItems.forEach(item => {
        const row = ledgerBody.querySelector(`tr[data-symbol="${item.symbol}"]`);
        if (!row) return;

        const qty = item.quantity || 0;
        const avgPrice = item.purchase_price || 0;
        const currentPrice = item.current_price || avgPrice || 0;
        const dayChangePct = item.day_change_pct || 0.0;

        const investedVal = qty * avgPrice;
        const currentVal = qty * currentPrice;
        const plVal = currentVal - investedVal;
        const plPct = investedVal > 0 ? (plVal / investedVal) * 100 : 0.0;

        const plColor = plVal >= 0 ? 'var(--neon-green)' : 'var(--neon-red)';
        const plSign = plVal >= 0 ? '+' : '';

        const netChgPct = plPct;
        const netChgColor = netChgPct >= 0 ? 'var(--neon-green)' : 'var(--neon-red)';
        const netChgSign = netChgPct >= 0 ? '+' : '';

        const dayChgColor = dayChangePct >= 0 ? 'var(--neon-green)' : 'var(--neon-red)';
        const dayChgSign = dayChangePct >= 0 ? '+' : '';

        row.setAttribute('data-qty', qty);
        row.setAttribute('data-price', avgPrice);

        // Update range bar cell
        const rangeBarCell = row.cells[3];
        if (rangeBarCell) {
            rangeBarCell.innerHTML = drawInlineRangeBar(currentPrice, item.suggested_buy_price_range, item.suggested_sell_price_range);
        }

        // Live price
        const livePriceCell = row.querySelector('.port-live-price');
        if (livePriceCell) {
            const oldPrice = livePriceCell.getAttribute('data-last-price');
            const priceChanged = oldPrice && parseFloat(oldPrice) !== currentPrice;
            livePriceCell.innerHTML = safeFormatRupees(currentPrice, 2);
            livePriceCell.setAttribute('data-last-price', currentPrice);
            if (priceChanged) {
                const isPositive = dayChangePct >= 0;
                livePriceCell.classList.add(isPositive ? 'tick-flash-green' : 'tick-flash-red');
                setTimeout(() => {
                    livePriceCell.classList.remove('tick-flash-green', 'tick-flash-red');
                }, 600);
            }
        }

        // Net change
        const netChgCell = row.querySelector('.port-net-change');
        if (netChgCell) {
            netChgCell.innerHTML = `${netChgSign}${netChgPct.toFixed(2)}%`;
            netChgCell.style.color = netChgColor;
        }

        // Day change
        const dayChgCell = row.querySelector('.port-day-change');
        if (dayChgCell) {
            dayChgCell.innerHTML = `${dayChgSign}${dayChangePct.toFixed(2)}%`;
            dayChgCell.style.color = dayChgColor;
        }

        // Current Value
        const currentValCell = row.querySelector('.port-current-value');
        if (currentValCell) {
            currentValCell.innerHTML = safeFormatRupees(currentVal, 2);
        }

        // Net PL
        const netPlCell = row.querySelector('.port-net-pl');
        if (netPlCell) {
            netPlCell.innerHTML = `${plSign}${safeFormatRupees(plVal, 2)}<br><span style="font-size: 10px; color: ${plColor};">${plSign}${plPct.toFixed(2)}%</span>`;
            netPlCell.style.color = plColor;
        }
    });

    // Responsive chart resizing
    let academyResizeTimeout;
    window.addEventListener('resize', () => {
        clearTimeout(academyResizeTimeout);
        academyResizeTimeout = setTimeout(() => {
            if (window.activeTab === 'learning' && academyActiveTopicId) {
                const module = ACADEMY_CATALOG.find(m => m.id === academyActiveTopicId);
                if (module) renderAcademyChart(module);
            }
        }, 150);
    });
}

