function setupSidebarToggle() {
    const sidebar = document.getElementById('sidebar');
    const collapseBtn = document.getElementById('sidebar-collapse-btn');
    const logoToggle = document.getElementById('logo-icon-toggle');

    if (!sidebar || !collapseBtn) return;

    // Load saved preference
    const isCollapsed = localStorage.getItem('sidebar-collapsed') === 'true';
    if (isCollapsed) {
        sidebar.classList.add('collapsed');
        collapseBtn.innerText = '▶';
        collapseBtn.title = 'Expand Sidebar';
    }

    const toggleSidebar = () => {
        sidebar.classList.toggle('collapsed');
        const currentlyCollapsed = sidebar.classList.contains('collapsed');
        localStorage.setItem('sidebar-collapsed', currentlyCollapsed);
        collapseBtn.innerText = currentlyCollapsed ? '▶' : '◀';
        collapseBtn.title = currentlyCollapsed ? 'Expand Sidebar' : 'Collapse Sidebar';

        // Trigger a window resize event to force Chart.js elements to resize perfectly
        setTimeout(() => {
            window.dispatchEvent(new Event('resize'));
        }, 300);
    };

    collapseBtn.addEventListener('click', (e) => {
        e.stopPropagation();
        toggleSidebar();
    });

    if (logoToggle) {
        logoToggle.addEventListener('click', (e) => {
            e.stopPropagation();
            toggleSidebar();
        });
    }
}

// Collapsible Sidebar Accordions (Global Investor Profile & Universe Status Drawers)
function setupSidebarAccordions() {
    const accordions = [
        {
            toggleId: 'profile-accordion-toggle',
            contentId: 'profile-accordion-content',
            arrowId: 'profile-accordion-arrow',
            cardId: 'profile-sidebar-card'
        },
        {
            toggleId: 'rebalancer-accordion-toggle',
            contentId: 'rebalancer-accordion-content',
            arrowId: 'rebalancer-accordion-arrow',
            cardId: 'rebalancer-status-card'
        }
    ];

    accordions.forEach(acc => {
        const toggle = document.getElementById(acc.toggleId);
        const content = document.getElementById(acc.contentId);
        const arrow = document.getElementById(acc.arrowId);
        const card = document.getElementById(acc.cardId);

        if (toggle && content) {
            // Load saved preference: default to open/expanded
            const isClosed = localStorage.getItem(acc.cardId + '-collapsed') === 'true';
            if (isClosed) {
                content.style.maxHeight = '0px';
                if (arrow) arrow.style.transform = 'rotate(-90deg)';
                toggle.classList.remove('open');
            } else {
                content.style.maxHeight = content.scrollHeight + 'px';
                if (arrow) arrow.style.transform = 'rotate(0deg)';
                toggle.classList.add('open');
            }

            toggle.addEventListener('click', (e) => {
                e.stopPropagation();
                const currentlyClosed = content.style.maxHeight === '0px' || content.style.maxHeight === '' || content.style.maxHeight === '0';
                if (currentlyClosed) {
                    content.style.maxHeight = content.scrollHeight + 'px';
                    if (arrow) arrow.style.transform = 'rotate(0deg)';
                    toggle.classList.add('open');
                    localStorage.setItem(acc.cardId + '-collapsed', 'false');
                } else {
                    content.style.maxHeight = '0px';
                    if (arrow) arrow.style.transform = 'rotate(-90deg)';
                    toggle.classList.remove('open');
                    localStorage.setItem(acc.cardId + '-collapsed', 'true');
                }
            });



            // Recalculate height dynamically when content inside shifts (e.g. NSE status loading)
            const observer = new MutationObserver(() => {
                if (content.style.maxHeight !== '0px' && content.style.maxHeight !== '') {
                    content.style.maxHeight = content.scrollHeight + 'px';
                }
            });
            observer.observe(content, { childList: true, subtree: true, characterData: true });
        }
    });
}

// Enterprise Header & Footer Controllers
function setupEnterpriseHeader() {
    const bellBtn = document.getElementById('header-bell-btn');
    const settingsBtn = document.getElementById('header-settings-btn');
    const linksBtn = document.getElementById('header-links-btn');
    const notifDropdown = document.getElementById('notification-dropdown-panel');
    const settingsDropdown = document.getElementById('settings-dropdown-panel');
    const linksDropdown = document.getElementById('links-dropdown-panel');

    if (!bellBtn || !settingsBtn || !notifDropdown || !settingsDropdown || !linksBtn || !linksDropdown) return;

    // Toggle Notification panel
    bellBtn.addEventListener('click', (e) => {
        e.stopPropagation();
        notifDropdown.style.display = notifDropdown.style.display === 'none' ? 'block' : 'none';
        settingsDropdown.style.display = 'none'; // Close other dropdown
        linksDropdown.style.display = 'none'; // Close other dropdown
    });

    // Toggle Settings panel
    settingsBtn.addEventListener('click', (e) => {
        e.stopPropagation();
        settingsDropdown.style.display = settingsDropdown.style.display === 'none' ? 'block' : 'none';
        notifDropdown.style.display = 'none'; // Close other dropdown
        linksDropdown.style.display = 'none'; // Close other dropdown
    });

    // Toggle Links panel
    linksBtn.addEventListener('click', (e) => {
        e.stopPropagation();
        linksDropdown.style.display = linksDropdown.style.display === 'none' ? 'block' : 'none';
        notifDropdown.style.display = 'none'; // Close other dropdown
        settingsDropdown.style.display = 'none'; // Close other dropdown
    });

    // Prevent auto-closing when clicking inside dropdowns
    notifDropdown.addEventListener('click', (e) => {
        e.stopPropagation();
    });
    settingsDropdown.addEventListener('click', (e) => {
        e.stopPropagation();
    });
    linksDropdown.addEventListener('click', (e) => {
        e.stopPropagation();
    });

    // Close on click outside
    document.addEventListener('click', (e) => {
        if (!bellBtn.contains(e.target) && !notifDropdown.contains(e.target)) {
            notifDropdown.style.display = 'none';
        }
        if (!settingsBtn.contains(e.target) && !settingsDropdown.contains(e.target)) {
            settingsDropdown.style.display = 'none';
        }
        if (!linksBtn.contains(e.target) && !linksDropdown.contains(e.target)) {
            linksDropdown.style.display = 'none';
        }
    });

    // Handle clearing notifications
    const clearBtn = document.getElementById('clear-all-alerts-btn');
    if (clearBtn) {
        clearBtn.addEventListener('click', (e) => {
            e.stopPropagation();
            
            // Save active triggered alert IDs to dismissed list in localStorage
            let dismissedIds = [];
            try {
                dismissedIds = JSON.parse(localStorage.getItem('dismissed-alert-ids') || '[]');
            } catch (err) {
                dismissedIds = [];
            }
            
            if (Array.isArray(lastAlertsList)) {
                lastAlertsList.forEach(item => {
                    if (item.triggered && !dismissedIds.includes(item.id)) {
                        dismissedIds.push(item.id);
                    }
                });
            }
            
            localStorage.setItem('dismissed-alert-ids', JSON.stringify(dismissedIds));
            
            // Re-render notification bell to reflect cleared state
            if (typeof updateNotificationBell === 'function') {
                updateNotificationBell(lastAlertsList);
            }
            showToast("System notifications cleared.", "success");
        });
    }

    // Dynamic indices update
    const marquee = document.getElementById('indices-marquee');
    if (marquee) {
        // Clone marquee content to make it a seamless, infinite loop!
        const clone = marquee.cloneNode(true);
        clone.id = 'indices-marquee-clone';
        marquee.parentElement.appendChild(clone);

        // Fetch initial indices
        fetchRealtimeIndices();

        setInterval(() => {
            if (!liveTicksConnected) {
                fetchRealtimeIndices();
            }
        }, 3000);

        // Initialize Meta Banner Dropdowns & Collapse controls
        setupMetaBannerToggles();
        setupMetaBannerCollapse();
    }

    // Setup Institutional Pitchbook trigger listeners
    const pitchbookTriggerBtn = document.getElementById('export-pitchbook-btn');
    if (pitchbookTriggerBtn) {
        pitchbookTriggerBtn.addEventListener('click', () => {
            if (activeStockProfile && activeStockProfile.ticker) {
                generatePitchbook(activeStockProfile.ticker);
            }
        });
    }

    // Wire Pitchbook Read Aloud
    const pitchbookReadAloudBtn = document.getElementById('pitchbook-read-aloud-btn');
    if (pitchbookReadAloudBtn) {
        pitchbookReadAloudBtn.addEventListener('click', () => {
            const contentPane = document.getElementById('pitchbook-content-pane');
            if (contentPane) {
                const text = contentPane.innerText;
                if (!text || text.trim() === '') {
                    showToast("No pitchbook content to read.", "warning");
                    return;
                }
                window.SpeechPlayer.startSpeakingSection("pitchbook-content-pane", "Pitchbook Summary");
            }
        });
    }

    const pitchbookPrintBtn = document.getElementById('pitchbook-print-btn');
    if (pitchbookPrintBtn) {
        pitchbookPrintBtn.addEventListener('click', () => {
            const symbol = (activeStockProfile && activeStockProfile.ticker) ? activeStockProfile.ticker.split('.')[0].toUpperCase() : 'STOCK';
            const companyName = (activeStockProfile && activeStockProfile.company_name) ? activeStockProfile.company_name : 'Pitchbook';
            
            // Format timestamp: YYYY-MM-DD_HH-MM
            const now = new Date();
            const year = now.getFullYear();
            const month = String(now.getMonth() + 1).padStart(2, '0');
            const day = String(now.getDate()).padStart(2, '0');
            const hours = String(now.getHours()).padStart(2, '0');
            const minutes = String(now.getMinutes()).padStart(2, '0');
            const timestamp = `${year}-${month}-${day}_${hours}-${minutes}`;
            
            // Clean up company name to be safe for filenames
            const cleanCompanyName = companyName.replace(/[^a-zA-Z0-9\s-_]/g, '').replace(/\s+/g, '_').trim();
            const newTitle = `${symbol}_${cleanCompanyName}_Pitchbook_${timestamp}`;
            
            // Save original title
            const originalTitle = document.title;
            
            // Set new document title
            document.title = newTitle;
            
            // Add pitchbook print class to body
            document.body.classList.add('is-printing-pitchbook');
            
            // Defer print invocation to allow style recalculations to commit before blocking thread
            setTimeout(() => {
                window.print();
                setTimeout(() => {
                    document.body.classList.remove('is-printing-pitchbook');
                    document.title = originalTitle;
                }, 1000);
            }, 150);
        });
    }

    const pitchbookCloseBtn = document.getElementById('pitchbook-close-btn');
    const pitchbookModal = document.getElementById('pitchbook-modal');
    if (pitchbookCloseBtn && pitchbookModal) {
        pitchbookCloseBtn.addEventListener('click', () => {
            pitchbookModal.style.display = 'none';
        });
        
        // Also close modal when clicking outside the modal content box
        pitchbookModal.addEventListener('click', (e) => {
            if (e.target === pitchbookModal) {
                pitchbookModal.style.display = 'none';
            }
        });
    }
}

async function generatePitchbook(symbol) {
    if (!symbol) return;
    
    // Fetch custom sandbox overrides from DCF DOM elements
    const waccEl = document.getElementById('slider-wacc-val');
    const growthEl = document.getElementById('slider-growth-val');
    const opmEl = document.getElementById('slider-opm-val');
    const termEl = document.getElementById('slider-terminal-val');
    
    // Get values or default
    const wacc = waccEl ? parseFloat(waccEl.innerText) : null;
    const growth = growthEl ? parseFloat(growthEl.innerText) : null;
    const opm = opmEl ? parseFloat(opmEl.innerText) : null;
    const term = termEl ? parseFloat(termEl.innerText) : 4.5;
    
    const horizon = document.getElementById('profile-horizon')?.value || 'Long-term (3+ years)';
    const risk = document.getElementById('profile-risk')?.value || 'Moderate';
    
    // Show global loader with custom steps for professional feedback
    showLoader(
        `Compiling Investment Memo: ${symbol.toUpperCase()}`,
        "Aggregating peer metrics, tracking sector momentum rotation, gathering governance checklists, and synthesizing institutional pitchbook report.",
        true,
        [
            { threshold: 25, msg: "[INFO] Compiling relative peer multiples & valuations...", color: '#38bdf8' },
            { threshold: 50, msg: "[INFO] Accessing Sector Momentum Radar databases...", color: '#f59e0b' },
            { threshold: 75, msg: "[INFO] Synthesizing investment committee consensus memo...", color: '#10b981' },
            { threshold: 95, msg: "[INFO] Launching Pitchbook viewer panel...", color: '#a855f7' }
        ]
    );
    
    try {
        let url = `/api/analyze/pitchbook?symbol=${encodeURIComponent(symbol)}&horizon=${encodeURIComponent(horizon)}&risk=${encodeURIComponent(risk)}&terminal_growth=${term}`;
        if (wacc !== null && !isNaN(wacc)) url += `&wacc=${wacc}`;
        if (growth !== null && !isNaN(growth)) url += `&growth=${growth}`;
        if (opm !== null && !isNaN(opm)) url += `&opm=${opm}`;
        
        const response = await fetch(url);
        if (!response.ok) throw new Error("Pitchbook compilation failed.");
        const data = await response.json();
        
        // Parse markdown text to html layout
        const formattedHtml = parseMarkdownToPitchbookHTML(data.markdown);
        
        const contentPane = document.getElementById('pitchbook-content-pane');
        if (contentPane) {
            contentPane.innerHTML = formattedHtml;
        }
        
        // Display Modal
        const modal = document.getElementById('pitchbook-modal');
        if (modal) {
            modal.style.display = 'flex';
        }
    } catch (e) {
        console.error("Pitchbook generation error:", e);
        showToast("Failed to compile pitchbook: " + e.message, "error");
    } finally {
        hideLoader();
    }
}

function parseMarkdownToPitchbookHTML(md) {
    if (!md) return "";
    
    let html = md;
    
    // Parse tables first
    if (html.includes('|')) {
        const lines = html.split('\n');
        let inTable = false;
        let tableHtml = '';
        let parsedLines = [];
        
        for (let i = 0; i < lines.length; i++) {
            const line = lines[i].trim();
            if (line.startsWith('|') && line.endsWith('|')) {
                if (!inTable) {
                    inTable = true;
                    tableHtml = '<div class="table-scroll" style="overflow-x:auto; margin: 15px 0; border: 1px solid var(--border-glass); border-radius: 6px;"><table style="width:100%; border-collapse:collapse; font-size:11px; background:rgba(255,255,255,0.01);">';
                }
                
                if (line.includes('---') || line.includes(':---')) {
                    continue;
                }
                
                const cells = line.split('|').slice(1, -1).map(c => c.trim());
                const isHeader = !tableHtml.includes('<tbody>');
                const tag = isHeader ? 'th' : 'td';
                
                let rowHtml = '<tr style="border-bottom: 1px solid var(--border-glass);">';
                for (let cell of cells) {
                    let cellStyle = 'padding:10px 12px; text-align:center; color:var(--text-primary);';
                    if (isHeader) {
                        cellStyle += 'padding:10px 12px; text-align:center; font-weight:700; color:var(--text-muted); background:rgba(255,255,255,0.03); font-family:\'Outfit\',sans-serif; text-transform:uppercase; font-size:10px;';
                    }
                    rowHtml += `<${tag} style="${cellStyle}">${cell}</${tag}>`;
                }
                rowHtml += '</tr>';
                
                if (isHeader) {
                    tableHtml += '<thead>' + rowHtml + '</thead><tbody>';
                } else {
                    tableHtml += rowHtml;
                }
            } else {
                if (inTable) {
                    inTable = false;
                    tableHtml += '</tbody></table></div>';
                    parsedLines.push(tableHtml);
                    tableHtml = '';
                }
                parsedLines.push(lines[i]);
            }
        }
        if (inTable) {
            tableHtml += '</tbody></table></div>';
            parsedLines.push(tableHtml);
        }
        html = parsedLines.join('\n');
    }
    
    // Apply header translations
    html = html
        .replace(/^# (.*?)$/gm, '<h1 style="font-family:\'Outfit\',sans-serif; font-size:18px; color:var(--color-primary-light); border-bottom:2px solid var(--color-primary); padding-bottom:8px; margin-top:25px; margin-bottom:15px; text-transform:uppercase; font-weight:800; letter-spacing:0.05em;">$1</h1>')
        .replace(/^## (.*?)$/gm, '<h2 style="font-family:\'Outfit\',sans-serif; font-size:13.5px; color:var(--text-primary); border-left:4px solid var(--color-primary); padding-left:10px; margin-top:20px; margin-bottom:12px; text-transform:uppercase; font-weight:700; letter-spacing:0.03em;">$1</h2>')
        .replace(/^### (.*?)$/gm, '<h3 style="font-family:\'Outfit\',sans-serif; font-size:11.5px; color:var(--text-secondary); margin-top:15px; margin-bottom:8px; font-weight:600;">$1</h3>')
        .replace(/\*\*(.*?)\*\*/g, '<strong style="color:var(--text-primary); font-weight:700;">$1</strong>')
        .replace(/^\* (.*?)$/gm, '<li style="margin-left:20px; margin-bottom:6px; color:var(--text-secondary); list-style-type:square;">$1</li>')
        .replace(/^- (.*?)$/gm, '<li style="margin-left:20px; margin-bottom:6px; color:var(--text-secondary); list-style-type:circle;">$1</li>');
        
    // Wrap lists nicely
    html = html.replace(/(<li.*<\/li>)/gs, '<ul style="margin: 10px 0; padding-left:0;">$1</ul>');
    
    // Split into paragraph sections
    const segments = html.split('\n\n');
    let finalHtml = '';
    for (let segment of segments) {
        segment = segment.trim();
        if (!segment) continue;
        if (segment.startsWith('<h') || segment.startsWith('<div') || segment.startsWith('<ul') || segment.startsWith('<table')) {
            finalHtml += segment + '\n';
        } else {
            finalHtml += `<p style="margin-bottom:12px; color:var(--text-secondary); line-height:1.6;">${segment}</p>\n`;
        }
    }
    
    return finalHtml;
}

function setupMetaBannerToggles() {
    const cards = document.querySelectorAll('.meta-stat-card');
    const bottomSheet = document.getElementById('mobile-meta-bottom-sheet');
    const sheetTitle = document.getElementById('mobile-bottom-sheet-title');
    const sheetBody = document.getElementById('mobile-bottom-sheet-body');
    const sheetCloseBtn = document.getElementById('mobile-bottom-sheet-close');
    const sheetOverlay = bottomSheet ? bottomSheet.querySelector('.bottom-sheet-overlay') : null;

    // Helper to close mobile bottom sheet
    function closeBottomSheet() {
        if (bottomSheet) {
            bottomSheet.classList.remove('active');
        }
    }

    if (sheetCloseBtn) {
        sheetCloseBtn.addEventListener('click', closeBottomSheet);
    }
    if (sheetOverlay) {
        sheetOverlay.addEventListener('click', closeBottomSheet);
    }

    cards.forEach(card => {
        const dropdown = card.querySelector('.meta-dropdown-panel');
        if (!dropdown) return;

        card.addEventListener('click', (e) => {
            e.stopPropagation();

            // Mobile Bottom Sheet behavior
            if (window.innerWidth <= 768) {
                // Extract card title
                const cardHeader = card.querySelector('div:first-child');
                const titleText = cardHeader ? cardHeader.textContent.trim() : 'Details';
                
                // Clone the dropdown table
                const tableClone = dropdown.querySelector('table') ? dropdown.querySelector('table').cloneNode(true) : null;
                
                if (sheetTitle) sheetTitle.textContent = titleText;
                if (sheetBody) {
                    sheetBody.innerHTML = '';
                    if (tableClone) {
                        sheetBody.appendChild(tableClone);
                    } else {
                        sheetBody.innerHTML = `<div style="text-align: center; padding: 20px; color: var(--text-muted);">No details available</div>`;
                    }
                }
                
                if (bottomSheet) {
                    bottomSheet.classList.add('active');
                }
                
                // Close any open desktop hover states
                cards.forEach(c => c.classList.remove('active'));
                return;
            }

            // Desktop click toggle behavior
            const isActive = card.classList.contains('active');
            cards.forEach(c => c.classList.remove('active'));
            if (!isActive) {
                card.classList.add('active');
            }
        });

        dropdown.addEventListener('click', (e) => {
            e.stopPropagation();
        });
    });

    // Close when clicking anywhere outside
    document.addEventListener('click', () => {
        cards.forEach(card => card.classList.remove('active'));
    });
}

function setupMetaBannerCollapse() {
    const btn = document.getElementById('meta-banner-toggle-btn');
    const header = document.querySelector('.stock-meta-banner .meta-left');
    if (!btn) return;

    // Load initial state from localStorage
    const isCollapsed = localStorage.getItem('meta-banner-collapsed') === 'true';
    if (isCollapsed) {
        setBannerState(true);
    }

    // Single unified click listener on the header container
    // Clicks on the button will naturally bubble up to the header and toggle it once
    if (header) {
        header.style.cursor = 'pointer';
        header.title = 'Click to Collapse / Expand Banner details';
        header.addEventListener('click', (e) => {
            e.stopPropagation();
            const currentlyCollapsed = localStorage.getItem('meta-banner-collapsed') === 'true';
            setBannerState(!currentlyCollapsed);
        });
    }

    function setBannerState(collapsed) {
        const banner = document.querySelector('.stock-meta-banner');
        const icon = document.getElementById('meta-banner-toggle-icon');
        const text = document.getElementById('meta-banner-toggle-text');
        
        if (!banner) return;
        
        if (collapsed) {
            banner.classList.add('collapsed');
            // Remove active dropdowns when collapsing
            document.querySelectorAll('.meta-stat-card').forEach(c => c.classList.remove('active'));
            if (icon) icon.innerText = '▼';
            if (text) text.innerText = 'Expand Banner';
            localStorage.setItem('meta-banner-collapsed', 'true');
        } else {
            banner.classList.remove('collapsed');
            if (icon) icon.innerText = '▲';
            if (text) text.innerText = 'Collapse Banner';
            localStorage.setItem('meta-banner-collapsed', 'false');
        }
    }
}

function setupEnterpriseFooter() {
    const clockEl = document.getElementById('footer-system-clock');
    const latencyEl = document.getElementById('footer-latency');

    if (!clockEl || !latencyEl) return;

    // 1. Live ticking clock
    setInterval(() => {
        const now = new Date();
        clockEl.innerText = now.toLocaleTimeString('en-IN');
    }, 1000);

    // 2. Realistic API latency fluctuations (updated dynamically on action)
    const simulateLatency = () => {
        const latency = Math.floor(25 + Math.random() * 35); // fluctuates between 25ms and 60ms
        latencyEl.innerText = `${latency}ms`;
        if (latency < 45) {
            latencyEl.className = 'green-text';
        } else {
            latencyEl.className = 'yellow-text';
        }
    };

    // Update latency periodically and on every click of navigation tabs
    setInterval(simulateLatency, 7000);
    document.querySelectorAll('.nav-btn, .strategy-btn, button').forEach(btn => {
        btn.addEventListener('click', () => {
            setTimeout(simulateLatency, 100 + Math.random() * 200);
        });
    });
}

// 1. Tab Routing Navigation
function setupTabNavigation() {
    Object.keys(tabBtns).forEach(tabKey => {
        const btn = tabBtns[tabKey] || document.getElementById('tab-' + tabKey + '-btn');
        if (btn) {
            btn.addEventListener('click', () => {
                switchTab(tabKey);
            });
        } else {
            console.warn(`Tab button not found for key: ${tabKey}`);
        }
    });

    // Listen to hash changes for browser back/forward history navigation
    window.addEventListener('hashchange', () => {
        const tabKey = location.hash.substring(1);
        if (tabKey && tabBtns[tabKey]) {
            switchTab(tabKey);
        }
    });

    // Parse and load initial tab based on location hash
    const initialTab = location.hash.substring(1);
    if (initialTab && tabBtns[initialTab]) {
        switchTab(initialTab);
    } else {
        switchTab('analyzer');
    }
}

function switchTab(tabKey) {
    if (activeTab === tabKey) return;
    activeTab = tabKey;
    localStorage.setItem('active-tab', tabKey);

    const shieldEnabled = localStorage.getItem('portfolio-security-shield-enabled') !== 'false';

    // Portfolio security interception and lock resets
    if (tabKey === 'portfolio') {
        if (shieldEnabled && !window.portfolioUnlocked) {
            const overlay = document.getElementById('portfolio-lock-overlay');
            if (overlay) overlay.classList.remove('hidden');
            if (window.triggerBiometricVerification) {
                // Introduce a small delay to avoid native lifecycle/context conflicts during Android layout transitions
                setTimeout(() => {
                    if (activeTab === 'portfolio' && !window.portfolioUnlocked) {
                        window.triggerBiometricVerification();
                    }
                }, 350);
            }
        } else {
            const overlay = document.getElementById('portfolio-lock-overlay');
            if (overlay) overlay.classList.add('hidden');
        }
    } else {
        if (shieldEnabled) {
            window.portfolioUnlocked = false;
            const overlay = document.getElementById('portfolio-lock-overlay');
            if (overlay) {
                overlay.classList.remove('hidden');
                const dots = overlay.querySelectorAll('.dot');
                dots.forEach(dot => dot.classList.remove('filled'));
            }
        } else {
            const overlay = document.getElementById('portfolio-lock-overlay');
            if (overlay) overlay.classList.add('hidden');
        }
    }

    if (location.hash !== '#' + tabKey) {
        location.hash = tabKey;
    }
    Object.keys(tabs).forEach(k => {
        const el = tabs[k] || document.getElementById('tab-' + k);
        const btn = tabBtns[k] || document.getElementById('tab-' + k + '-btn');
        if (el) {
            el.style.display = (k === tabKey) ? 'block' : 'none';
            if (k === tabKey) {
                el.classList.add('active-tab-content');
            } else {
                el.classList.remove('active-tab-content');
            }
        }
        if (btn) {
            if (k === tabKey) {
                btn.classList.add('active');
            } else {
                btn.classList.remove('active');
            }
        }
    });

    // Expose switchTab globally
    window.switchTab = switchTab;

    if (tabKey === 'sector-radar') {
        if (window.loadScreenerSectorRegime) window.loadScreenerSectorRegime();
    }

    if (tabKey === 'market-news') {
        if (window.loadGlobalMarketNews) window.loadGlobalMarketNews();
    }

    if (tabKey === 'events') {
        if (typeof loadMarketEvents === 'function') loadMarketEvents();
    }

    if (tabKey === 'trades') {
        if (typeof loadGlobalTrades === 'function') loadGlobalTrades();
    }

    if (tabKey === 'movers') {
        if (window.fetchMarketMoversData) window.fetchMarketMoversData();
        if (window.startMoversPolling) window.startMoversPolling();
    } else {
        if (window.stopMoversPolling) window.stopMoversPolling();
    }

    if (tabKey === 'alerts') {
        if (typeof fetchAlertsList === 'function') fetchAlertsList();
    }

    // Auto-resize TradingView Lightweight Charts on tab activation to prevent collapsed canvas sizing
    if (tabKey === 'swing') {
        setTimeout(() => {
            const riskContainer = document.getElementById('swing-risk-chart');
            if (activeSwingRiskChart && riskContainer) {
                activeSwingRiskChart.resize(riskContainer.clientWidth, riskContainer.clientHeight || 260);
            }
            const btContainer = document.getElementById('swing-backtest-chart');
            if (activeSwingBacktestChart && btContainer) {
                activeSwingBacktestChart.resize(btContainer.clientWidth, btContainer.clientHeight || 180);
            }
        }, 150);
    }
}

