// Particle burst for screener button
function fireScreenerParticles() {
    const container = document.getElementById('screener-btn-particles');
    if (!container) return;
    container.innerHTML = '';
    const colors = ['#6ee7b7', '#34d399', '#a7f3d0', '#fff', '#6ee7b7'];
    const count = 12;
    for (let i = 0; i < count; i++) {
        const p = document.createElement('span');
        p.className = 'particle';
        const angle = (i / count) * 360;
        const dist = 28 + Math.random() * 38;
        const rad = (angle * Math.PI) / 180;
        p.style.setProperty('--px', `${Math.cos(rad) * dist}px`);
        p.style.setProperty('--py', `${Math.sin(rad) * dist}px`);
        p.style.background = colors[i % colors.length];
        p.style.left = '50%'; p.style.top = '50%';
        p.style.marginLeft = '-2.5px'; p.style.marginTop = '-2.5px';
        p.style.animationDelay = `${i * 0.03}s`;
        container.appendChild(p);
    }
    setTimeout(() => { container.innerHTML = ''; }, 900);
}

// Stage cycling for screener button
let _screenerStageInterval = null;
const SCREENER_STAGES = [
    { icon: '🗄️', label: 'Loading universe…' },
    { icon: '🔎', label: 'Applying quality gates…' },
    { icon: '📐', label: 'Scoring constituents…' },
    { icon: '🏆', label: 'Ranking top picks…' },
    { icon: '⚡', label: 'Finalizing results…' },
];

function setScreenerBtnLoading(isLoading, resultCount) {
    const btn = document.getElementById('run-screener-btn');
    const iconEl = document.getElementById('screener-btn-icon');
    const labelEl = document.getElementById('screener-btn-label');
    if (!btn) return;
    if (isLoading) {
        btn.classList.add('loading');
        btn.classList.remove('success-flash');
        if (iconEl) iconEl.textContent = '⚙️';
        let idx = 0;
        if (labelEl) labelEl.textContent = SCREENER_STAGES[0].label;
        _screenerStageInterval = setInterval(() => {
            idx = (idx + 1) % SCREENER_STAGES.length;
            if (iconEl) iconEl.textContent = SCREENER_STAGES[idx].icon;
            if (labelEl) labelEl.textContent = SCREENER_STAGES[idx].label;
        }, 1600);
    } else {
        clearInterval(_screenerStageInterval);
        btn.classList.remove('loading');
        if (iconEl) iconEl.textContent = '✅';
        const countLabel = resultCount > 0 ? `${resultCount} stocks found!` : 'Scan Complete!';
        if (labelEl) labelEl.textContent = countLabel;
        btn.classList.add('success-flash');
        setTimeout(() => {
            btn.classList.remove('success-flash');
            if (iconEl) iconEl.textContent = '🔬';
            if (labelEl) labelEl.textContent = 'Run AI Screener Scan';
        }, 2500);
    }
}

function setupScreenerSorting() {
    const headers = document.querySelectorAll('#tab-screener th.sortable');
    headers.forEach(header => {
        header.addEventListener('click', () => {
            const field = header.getAttribute('data-sort');
            if (screenerSortCol === field) {
                screenerSortAsc = !screenerSortAsc;
            } else {
                screenerSortCol = field;
                screenerSortAsc = false; // default to descending
            }

            // Reset indicator icons and color of non-active headers
            headers.forEach(h => {
                h.style.color = 'var(--text-secondary)';
                h.innerText = h.innerText.replace(/[▲▼↕]/g, '↕');
            });

            header.style.color = 'var(--color-primary)';
            header.innerText = header.innerText.replace(/[▲▼↕]/g, screenerSortAsc ? '▲' : '▼');

            sortScreenerResults();
        });
    });
}

function setupScreenerPagination() {
    const prevBtn = document.getElementById('screener-results-prev-btn');
    const nextBtn = document.getElementById('screener-results-next-btn');
    const sizeSelect = document.getElementById('screener-results-pagesize-select');

    if (prevBtn) {
        prevBtn.addEventListener('click', () => {
            if (activeScreenerPage > 1) {
                activeScreenerPage--;
                renderScreenerResults(activeScreenerResults, true);
            }
        });
    }

    if (nextBtn) {
        nextBtn.addEventListener('click', () => {
            const totalPages = Math.ceil(activeScreenerResults.length / activeScreenerPageSize);
            if (activeScreenerPage < totalPages) {
                activeScreenerPage++;
                renderScreenerResults(activeScreenerResults, true);
            }
        });
    }

    if (sizeSelect) {
        sizeSelect.addEventListener('change', (e) => {
            activeScreenerPageSize = parseInt(e.target.value) || 10;
            activeScreenerPage = 1;
            renderScreenerResults(activeScreenerResults, true);
        });
    }
}

function sortScreenerResults() {
    if (!activeScreenerResults || activeScreenerResults.length === 0) return;

    activeScreenerResults.sort((a, b) => {
        let valA, valB;
        switch (screenerSortCol) {
            case 'rank':
                valA = a.rank || 999;
                valB = b.rank || 999;
                break;
            case 'name':
                valA = (a.name || '').toLowerCase();
                valB = (b.name || '').toLowerCase();
                break;
            case 'sector':
                valA = (a.sector || '').toLowerCase();
                valB = (b.sector || '').toLowerCase();
                break;
            case 'score':
                valA = a.score || 0;
                valB = b.score || 0;
                break;
            case 'fundamental':
                valA = a.fundamental_score || 0;
                valB = b.fundamental_score || 0;
                break;
            case 'valuation':
                valA = a.valuation_score || 0;
                valB = b.valuation_score || 0;
                break;
            case 'momentum':
                valA = a.technical_score || 0;
                valB = b.technical_score || 0;
                break;
            case 'cap_type':
                valA = (a.cap_type || '').toLowerCase();
                valB = (b.cap_type || '').toLowerCase();
                break;
            case 'action':
                valA = (a.action || '').toLowerCase();
                valB = (b.action || '').toLowerCase();
                break;
            default:
                valA = a.score || 0;
                valB = b.score || 0;
        }

        if (valA < valB) return screenerSortAsc ? -1 : 1;
        if (valA > valB) return screenerSortAsc ? 1 : -1;
        return 0;
    });

    renderScreenerResults(activeScreenerResults, true);
}
async function runAIScreener() {
    const universe = document.getElementById('screener-universe-select').value;
    const horizon = document.getElementById('profile-horizon')?.value || 'Long-term (3+ years)';
    const risk = document.getElementById('profile-risk')?.value || 'Moderate';

    setScreenerBtnLoading(true);

    // Display results box and run skeletons immediately
    const resultsBox = document.getElementById('screener-results-box');
    if (resultsBox) resultsBox.style.display = 'block';
    renderScreenerSkeletons();

    try {
        const encodedHorizon = encodeURIComponent(horizon);
        const encodedRisk = encodeURIComponent(risk);
        const sectorParam = window.screenerSectorFilter ? encodeURIComponent(window.screenerSectorFilter) : '';
        const symbolParam = window.screenerSymbolFilter ? encodeURIComponent(window.screenerSymbolFilter) : '';
        const response = await fetch(`/api/discover?strategy=${activeScreenerStrategy}&universe=${universe}&horizon=${encodedHorizon}&risk=${encodedRisk}&style=${activeScreenerStyle}&sector=${sectorParam}&symbol=${symbolParam}`);
        if (!response.ok) throw new Error("Screener scan failed.");
        let results = await response.json();

        // Assign ranks initially
        results.forEach((item, index) => {
            item.rank = index + 1;
        });

        activeScreenerResults = results;
        activeScreenerPage = 1;
        screenerSortCol = 'score';
        screenerSortAsc = false;

        // Reset header indicators
        const headers = document.querySelectorAll('#tab-screener th.sortable');
        headers.forEach(h => {
            h.style.color = 'var(--text-secondary)';
            h.innerText = h.innerText.replace(/[▲▼↕]/g, '↕');
            if (h.getAttribute('data-sort') === 'score') {
                h.style.color = 'var(--color-primary)';
                h.innerText = h.innerText.replace('↕', '▼');
            }
        });

        renderScreenerResults(results, true);
        setScreenerBtnLoading(false, results.length);
    } catch (e) {
        setScreenerBtnLoading(false, 0);
        showToast("Failed to execute screener scan: " + e.message, 'error');
    }
}
window.runAIScreener = runAIScreener;

function renderScreenerResults(results, isSorted = false) {
    const tbody = document.getElementById('screener-results-body');
    tbody.innerHTML = '';

    const renderSubscoreGauge = (score, maxVal) => {
        if (score === undefined || score === null) score = 0;

        let parsedVal = 0;
        if (typeof score === 'string' && score.includes('/')) {
            parsedVal = parseFloat(score.split('/')[0]);
        } else {
            parsedVal = parseFloat(score);
        }
        if (isNaN(parsedVal)) parsedVal = 0;

        const pct = Math.max(0, Math.min(100, (parsedVal / maxVal) * 100));

        let fillColor = 'var(--color-primary)';
        if (pct >= 75) fillColor = 'var(--neon-green)';
        else if (pct < 50) fillColor = 'var(--color-crimson)';
        else fillColor = 'var(--color-amber)';

        return `
            <div class="screener-subscore-gauge" title="${parsedVal.toFixed(0)}/${maxVal} (${pct.toFixed(0)}%)">
                <span class="screener-subscore-val">${parsedVal.toFixed(0)}</span>
                <div class="screener-subscore-bar">
                    <div class="screener-subscore-fill" style="width: ${pct}%; background: ${fillColor};"></div>
                </div>
            </div>
        `;
    };

    const pagContainer = document.getElementById('screener-results-pagination');
    const telemetryBlock = document.getElementById('screener-telemetry-block');
    const activeChipsContainer = document.getElementById('screener-active-chips');

    if (results.length === 0) {
        tbody.innerHTML = '<tr><td colspan="10" class="center-text text-muted">No matching assets found. Try adjusting selection strategy.</td></tr>';
        if (pagContainer) pagContainer.style.display = 'none';
        if (telemetryBlock) telemetryBlock.style.display = 'none';
        if (activeChipsContainer) activeChipsContainer.style.display = 'none';
        return;
    }

    if (activeChipsContainer) activeChipsContainer.style.display = 'flex';

    if (!isSorted) {
        results.forEach((item, index) => {
            item.rank = index + 1;
        });
        activeScreenerResults = results;
    }

    const totalPages = Math.ceil(results.length / activeScreenerPageSize);
    if (activeScreenerPage < 1) activeScreenerPage = 1;
    if (activeScreenerPage > totalPages) activeScreenerPage = totalPages;

    const startIndex = (activeScreenerPage - 1) * activeScreenerPageSize;
    const endIndex = Math.min(startIndex + activeScreenerPageSize, results.length);
    const pageData = results.slice(startIndex, endIndex);

    const currentActiveTicker = activeStockProfile ? activeStockProfile.ticker.replace('.NS', '').toUpperCase() : '';

    pageData.forEach((item) => {
        const tr = document.createElement('tr');
        tr.style.transition = 'all 0.2s cubic-bezier(0.4, 0, 0.2, 1)';
        tr.style.cursor = 'default';

        const itemTicker = item.symbol.replace('.NS', '').toUpperCase();
        if (currentActiveTicker && itemTicker === currentActiveTicker) {
            tr.className = 'active-peer-row';
        }

        tr.addEventListener('mouseenter', () => {
            tr.style.background = 'rgba(255, 255, 255, 0.025)';
            tr.style.transform = 'scale(1.004)';
        });
        tr.addEventListener('mouseleave', () => {
            tr.style.background = 'transparent';
            tr.style.transform = 'none';
        });

        let recClass = 'rec-hold';
        if (item.action.includes("BUY")) recClass = 'rec-buy';
        if (item.action.includes("STRONG BUY")) recClass = 'rec-strong-buy';
        if (item.action.includes("AVOID") || item.action.includes("SELL")) recClass = 'rec-sell';

        let scoreColor = 'var(--color-primary)';
        let scoreBg = 'rgba(59,130,246,0.1)';
        if (item.score >= 70) {
            scoreColor = 'var(--color-emerald)';
            scoreBg = 'rgba(16,185,129,0.1)';
        } else if (item.score >= 45) {
            scoreColor = 'var(--color-amber)';
            scoreBg = 'rgba(245,158,11,0.1)';
        } else {
            scoreColor = 'var(--color-crimson)';
            scoreBg = 'rgba(239,68,68,0.1)';
        }

        const rankMedal = item.rank === 1 ? '🥇' : item.rank === 2 ? '🥈' : item.rank === 3 ? '🥉' : `#${item.rank}`;
        const rankStyle = item.rank <= 3 ? 'font-size: 13px;' : 'font-size: 11px; color: var(--text-secondary);';

        tr.innerHTML = `
            <td><strong style="${rankStyle}">${rankMedal}</strong></td>
            <td>
                <div class="screener-symbol-link" style="cursor: pointer;" title="Click to load research workspace">
                    <strong style="color: var(--color-primary); font-family: 'Outfit', sans-serif; text-decoration: underline;">${item.name}</strong><br>
                    <span class="text-muted" style="font-size:9.5px; letter-spacing:0.02em; text-decoration: underline;">${item.symbol}</span>
                </div>
            </td>
            <td><span class="text-muted" style="font-size: 11px;">${item.sector}</span></td>
            <td><span class="text-muted" style="text-transform: uppercase; font-size: 10.5px; font-weight: 700; letter-spacing:0.02em;">${item.cap_type || 'N/A'}</span></td>
            <td><span class="badge-ticker" style="background-color:${scoreBg}; color:${scoreColor}; border: 1px solid ${scoreColor}30; font-family: 'Outfit', sans-serif; font-weight:800; font-size: 11px; padding: 3px 8px; border-radius: 6px;">${item.score}/100</span></td>
            <td>${renderSubscoreGauge(item.fundamental_score, 30)}</td>
            <td>${renderSubscoreGauge(item.valuation_score, 25)}</td>
            <td>${renderSubscoreGauge(item.technical_score, 25)}</td>
            <td><span class="badge-rec ${recClass}" style="font-size: 9.5px; padding: 3px 8px; font-weight: 700; border-radius: 5px; letter-spacing:0.04em;">${item.action}</span></td>
        `;

        tr.querySelector('.screener-symbol-link').addEventListener('click', () => {
            switchTab('analyzer');
            loadStockAnalyzer(item.symbol);
        });

        tbody.appendChild(tr);
    });

    if (pagContainer) {
        document.getElementById('screener-results-page-info').innerText = `Page ${activeScreenerPage} of ${totalPages}`;
        document.getElementById('screener-results-prev-btn').disabled = (activeScreenerPage === 1);
        document.getElementById('screener-results-next-btn').disabled = (activeScreenerPage === totalPages);
        pagContainer.style.display = 'flex';
    }

    // Dynamic AI Screener Analyst Summary Block Generator
    const summaryBox = document.getElementById('screener-summary-block');
    const summaryText = document.getElementById('screener-summary-text');

    if (summaryBox && summaryText) {
        const totalCount = results.length;
        const avgScore = results.reduce((acc, r) => acc + r.score, 0) / totalCount;
        const buyCount = results.filter(r => r.action.includes("BUY")).length;
        const avoidCount = results.filter(r => r.action.includes("AVOID") || r.action.includes("SELL")).length;

        const topPick = results[0];

        let accentColor = '#EF4444';
        let cohortTitle = '⚠️ CLEARANCE MARKET BARGAIN (Distressed Cohort)';
        let cohortMetaphor = `Think of this cohort as a clearance market bargain bin. The vast majority of assets are struggling against severe macroeconomic headwinds, high promoter pledging, or technical momentum friction. You must proceed with extreme caution, as many carry high-risk deal-breakers.`;

        if (avgScore >= 65) {
            accentColor = '#10B981';
            cohortTitle = '🏆 HIGH-PERFORMANCE SPORTS ACADEMY (Prime Cohort)';
            cohortMetaphor = `Think of this screened cohort as a world-class sports academy. The vast majority of candidates here are physically elite, highly disciplined, and operate at peak efficiency. This represents a prime asset list with outstanding structural tailwinds where capital deployment has a high probability of capturing alpha.`;
        } else if (avgScore >= 45) {
            accentColor = '#F59E0B';
            cohortTitle = '🎓 SELECTIVE UNIVERSITY CLASS (Balanced Cohort)';
            cohortMetaphor = `Think of this cohort as a selective university classroom. Most candidates are reliable, above-average performers, but they are not uniform. You need to grade them carefully using individual quality gates to separate the honors graduates from the crowd before allocating capital.`;
        }

        summaryBox.style.borderLeft = `4px solid ${accentColor}`;

        let html = '';
        html += '<div class="responsive-summary-grid">';

        html += '  <div>';
        html += `    <div style="font-size: 11px; font-weight: 700; color: ${accentColor}; margin-bottom: 5px; letter-spacing: 0.04em;">${cohortTitle}</div>`;
        html += `    <p style="font-size: 11px; color: var(--text-muted); line-height: 1.6; margin: 0; font-family: 'Inter', sans-serif;">${cohortMetaphor}</p>`;
        html += '  </div>';

        html += '  <div style="display: grid; grid-template-columns: 1fr; gap: 8px;">';
        html += '    <div style="display: flex; gap: 8px;">';
        html += '      <div style="flex: 1; background: rgba(0,0,0,0.15); border: 1px solid rgba(255,255,255,0.03); padding: 8px 10px; border-radius: 6px; display: flex; flex-direction: column; justify-content: center;">';
        html += '        <span style="font-size: 8.5px; color: var(--text-secondary); text-transform: uppercase; font-weight: 600;">Cohort Avg Score</span>';
        html += `        <strong style="font-size: 13.5px; color: ${accentColor}; margin-top: 1px; font-family: 'Outfit', sans-serif;">${avgScore.toFixed(1)}/100</strong>`;
        html += '      </div>';
        html += '      <div style="flex: 1; background: rgba(0,0,0,0.15); border: 1px solid rgba(255,255,255,0.03); padding: 8px 10px; border-radius: 6px; display: flex; flex-direction: column; justify-content: center;">';
        html += '        <span style="font-size: 8.5px; color: var(--text-secondary); text-transform: uppercase; font-weight: 600;">Buy vs Avoid Tally</span>';
        html += `        <strong style="font-size: 13.5px; color: #ffffff; margin-top: 1px; font-family: 'Outfit', sans-serif;"><span style="color:#10B981;">${buyCount}B</span> <span style="color:var(--text-muted); font-size:10px;">/</span> <span style="color:#EF4444;">${avoidCount}A</span></strong>`;
        html += '      </div>';
        html += '    </div>';

        if (topPick) {
            const cleanTopPickName = topPick.name.length > 22 ? topPick.name.substring(0, 20) + '...' : topPick.name;
            html += `    <div class="top-pick-highlight-badge" style="background: rgba(59, 130, 246, 0.05); border: 1px solid rgba(59, 130, 246, 0.25); padding: 8px 12px; border-radius: 6px; display: flex; justify-content: space-between; align-items: center; cursor: pointer; transition: all 0.2s;" onclick="loadStockAnalyzer('${topPick.symbol}')" title="Click to load workspace instantly">`;
            html += '      <div style="display: flex; flex-direction: column; gap: 1px;">';
            html += '        <span style="font-size: 8.5px; color: var(--text-secondary); text-transform: uppercase; font-weight: 600;">👑 Top Conviction Pick</span>';
            html += `        <strong style="font-size: 12px; color: #ffffff; font-family: 'Outfit', sans-serif;">${cleanTopPickName} <span style="font-size: 9.5px; color: var(--text-muted); font-weight: 500;">(${topPick.symbol})</span></strong>`;
            html += '      </div>';
            html += `      <div style="background: rgba(59, 130, 246, 0.15); border: 1px solid rgba(59, 130, 246, 0.35); border-radius: 6px; padding: 3px 8px; font-size: 11px; font-weight: 700; color: #60a5fa; font-family: 'Outfit', sans-serif;">${topPick.score}/100</div>`;
            html += '    </div>';
        }

        html += '  </div>';
        html += '</div>';

        summaryText.innerHTML = html;
        summaryBox.style.display = 'block';
    }

    // Render dynamic Sector concentration & score distribution charts
    if (telemetryBlock) {
        telemetryBlock.style.display = 'grid';

        // 1. Render Sector concentration weights list
        const sectorWeightsList = document.getElementById('screener-sector-weights-list');
        if (sectorWeightsList) {
            sectorWeightsList.innerHTML = '';

            const sectorCounts = {};
            results.forEach(r => {
                const sec = r.sector || 'Others';
                sectorCounts[sec] = (sectorCounts[sec] || 0) + 1;
            });

            const sectorArr = Object.keys(sectorCounts).map(sec => {
                return { name: sec, count: sectorCounts[sec], pct: (sectorCounts[sec] / results.length) * 100 };
            });
            sectorArr.sort((a, b) => b.count - a.count);

            const topSectors = sectorArr.slice(0, 4);
            if (sectorArr.length > 4) {
                const restCount = sectorArr.slice(4).reduce((acc, s) => acc + s.count, 0);
                topSectors.push({ name: 'Other Sectors', count: restCount, pct: (restCount / results.length) * 100 });
            }

            topSectors.forEach(sec => {
                const row = document.createElement('div');
                row.className = 'screener-sector-row';
                row.innerHTML = `
                    <div class="screener-sector-header">
                        <span style="color: var(--text-secondary);">${sec.name}</span>
                        <span style="color: var(--text-primary); font-family: 'Outfit'; font-weight: 600;">${sec.count} (${sec.pct.toFixed(0)}%)</span>
                    </div>
                    <div class="screener-sector-bar-track">
                        <div class="screener-sector-bar-fill" style="width: ${sec.pct}%;"></div>
                    </div>
                `;
                sectorWeightsList.appendChild(row);
            });
        }

        const isLightMode = document.documentElement.getAttribute('data-mode') === 'light' || document.body.getAttribute('data-mode') === 'light';
        const gridColor = isLightMode ? 'rgba(0,0,0,0.05)' : 'rgba(255,255,255,0.03)';
        const textColor = isLightMode ? '#475569' : '#9ca3af';

        // 2. Render Score Bracket Histogram using Chart.js
        const scoreBuckets = { '<60': 0, '60-70': 0, '70-80': 0, '80-90': 0, '90-100': 0 };
        results.forEach(r => {
            const score = r.score || 0;
            if (score >= 90) scoreBuckets['90-100']++;
            else if (score >= 80) scoreBuckets['80-90']++;
            else if (score >= 70) scoreBuckets['70-80']++;
            else if (score >= 60) scoreBuckets['60-70']++;
            else scoreBuckets['<60']++;
        });

        const ctxHist = document.getElementById('screener-score-histogram');
        if (ctxHist) {
            if (activeScreenerScoreChart) activeScreenerScoreChart.destroy();

            activeScreenerScoreChart = new Chart(ctxHist, {
                type: 'bar',
                data: {
                    labels: ['<60', '60-70', '70-80', '80-90', '90-100'],
                    datasets: [{
                        label: 'Stocks Count',
                        data: [scoreBuckets['<60'], scoreBuckets['60-70'], scoreBuckets['70-80'], scoreBuckets['80-90'], scoreBuckets['90-100']],
                        backgroundColor: isLightMode ? 'rgba(37, 99, 235, 0.45)' : 'rgba(59, 130, 246, 0.45)',
                        borderColor: 'var(--color-primary)',
                        borderWidth: 1.5,
                        borderRadius: 4
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    plugins: {
                        legend: { display: false },
                        tooltip: {
                            callbacks: {
                                label: function(context) { return `${context.raw} stocks`; }
                            }
                        }
                    },
                    scales: {
                        x: {
                            grid: { display: false },
                            ticks: { color: textColor, font: { size: 9, family: 'Inter' } }
                        },
                        y: {
                            grid: { color: gridColor },
                            ticks: { color: textColor, font: { size: 9, family: 'Inter' }, precision: 0 }
                        }
                    }
                }
            });
        }

        // 3. Load and render Sector Relative Strength Leaderboard
        loadScreenerSectorRegime();
    }

    const resultsBox = document.getElementById('screener-results-box');
    if (resultsBox) resultsBox.style.display = 'block';
}

function setupAnalyzerControls() {
    document.getElementById('analyzer-search-btn').addEventListener('click', (e) => {
        const q = document.getElementById('analyzer-search-input').value.trim();
        if (q) {
            fireAnalyzeParticles(e);
            loadStockAnalyzer(q);
        }
    });

    document.getElementById('analyzer-search-input').addEventListener('keypress', (e) => {
        if (e.key === 'Enter') {
            const q = document.getElementById('analyzer-search-input').value.trim();
            if (q) loadStockAnalyzer(q);
        }
    });

    // Autocomplete online suggestions for Single Stock Workspace
    const searchInput = document.getElementById('analyzer-search-input');
    const analyzerSuggestionsDiv = document.getElementById('analyzer-suggestions');
    let activeSuggestionIndex = -1;
    let suggestionsData = [];

    if (searchInput && analyzerSuggestionsDiv) {
        searchInput.addEventListener('input', async () => {
            const query = searchInput.value.trim();
            if (query.length < 2) {
                analyzerSuggestionsDiv.style.display = 'none';
                suggestionsData = [];
                activeSuggestionIndex = -1;
                return;
            }

            try {
                const res = await fetch(`/api/search/suggestions?q=${encodeURIComponent(query)}`);
                if (res.ok) {
                    const data = await res.json();
                    suggestionsData = data;
                    activeSuggestionIndex = -1;

                    if (data.length > 0) {
                        analyzerSuggestionsDiv.innerHTML = '';
                        data.forEach((item, index) => {
                            const div = document.createElement('div');
                            div.style.padding = '8px 12px';
                            div.style.cursor = 'pointer';
                            div.style.borderBottom = '1px solid var(--border-glass)';
                            div.style.transition = 'background 0.2s';
                            div.className = 'suggestion-item';
                            div.setAttribute('data-index', index);

                            // Color tag badge for cap segment (Large/Mid/Small)
                            const capText = item.cap_type ? item.cap_type.toUpperCase() : 'ALL';
                            let capColor = 'var(--text-muted)';
                            if (capText.includes('LARGE')) capColor = 'var(--neon-green)';
                            else if (capText.includes('MID')) capColor = 'var(--color-amber)';
                            else if (capText.includes('SMALL')) capColor = 'var(--color-primary)';

                            div.innerHTML = `
                                <div style="display: flex; justify-content: space-between; align-items: center; width: 100%;">
                                    <div>
                                        <span style="color:var(--text-primary); font-weight:700; font-family:'Outfit';">${item.base_symbol}</span>
                                        <span style="color:var(--text-muted); font-size: 10px;">(${item.name})</span>
                                    </div>
                                    <div style="display: flex; gap: 8px; align-items: center;">
                                        <span style="font-size:9.5px; color:var(--text-muted);">${item.sector}</span>
                                        <span style="font-size:8px; font-weight:800; border: 1px solid ${capColor}40; color:${capColor}; padding:1px 4px; border-radius:3px; background:${capColor}08;">${capText}</span>
                                    </div>
                                </div>
                            `;

                            div.addEventListener('click', () => {
                                searchInput.value = item.base_symbol;
                                analyzerSuggestionsDiv.style.display = 'none';
                                suggestionsData = [];
                                activeSuggestionIndex = -1;
                                loadStockAnalyzer(item.base_symbol);
                            });

                            analyzerSuggestionsDiv.appendChild(div);
                        });
                        analyzerSuggestionsDiv.style.display = 'block';
                    } else {
                        analyzerSuggestionsDiv.style.display = 'none';
                    }
                }
            } catch (err) {
                console.error("Analyzer suggestions error:", err);
            }
        });

        // Keydown listener for arrow keys navigation
        searchInput.addEventListener('keydown', (e) => {
            const items = analyzerSuggestionsDiv.querySelectorAll('.suggestion-item');
            if (analyzerSuggestionsDiv.style.display === 'none' || items.length === 0) {
                return;
            }

            if (e.key === 'ArrowDown') {
                e.preventDefault();
                activeSuggestionIndex = (activeSuggestionIndex + 1) % items.length;
                highlightSuggestion(items);
            } else if (e.key === 'ArrowUp') {
                e.preventDefault();
                activeSuggestionIndex = (activeSuggestionIndex - 1 + items.length) % items.length;
                highlightSuggestion(items);
            } else if (e.key === 'Enter') {
                if (activeSuggestionIndex >= 0 && activeSuggestionIndex < items.length) {
                    e.preventDefault();
                    items[activeSuggestionIndex].click();
                }
            } else if (e.key === 'Escape') {
                analyzerSuggestionsDiv.style.display = 'none';
                activeSuggestionIndex = -1;
            }
        });

        function highlightSuggestion(items) {
            items.forEach((item, index) => {
                if (index === activeSuggestionIndex) {
                    item.classList.add('active-suggestion');
                    item.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
                } else {
                    item.classList.remove('active-suggestion');
                }
            });
        }

        document.addEventListener('click', (e) => {
            if (e.target !== searchInput && e.target !== analyzerSuggestionsDiv) {
                analyzerSuggestionsDiv.style.display = 'none';
            }
        });
    }

    // Call the newly extracted card-specific controllers
    setupPeersControls();
    setupCapturePeriodControl();
}

async function resolveVoiceQuery(transcript) {
    const cleanQuery = transcript.trim();
    if (!cleanQuery) return;

    if (typeof showToast === 'function') {
        showToast(`Processing voice search: "${cleanQuery}"...`, "info");
    }

    try {
        const res = await fetch(`/api/search/suggestions?q=${encodeURIComponent(cleanQuery)}`);
        if (res.ok) {
            const suggestions = await res.json();
            if (suggestions && suggestions.length > 0) {
                const bestMatch = suggestions[0].symbol;
                if (typeof showToast === 'function') {
                    showToast(`Voice Search: Loading ${bestMatch} (${suggestions[0].name})`, "success");
                }
                const searchInput = document.getElementById('analyzer-search-input');
                if (searchInput) searchInput.value = bestMatch;
                if (typeof loadStockAnalyzer === 'function') {
                    loadStockAnalyzer(bestMatch);
                }
                return;
            }
        }
    } catch (e) {
        console.error("Voice search suggestion lookup failed:", e);
    }

    // Fallback if suggestions API does not return a direct match
    const uppercaseQuery = cleanQuery.toUpperCase();
    if (typeof showToast === 'function') {
        showToast(`Voice Search fallback: Loading "${uppercaseQuery}"`, "info");
    }
    const searchInput = document.getElementById('analyzer-search-input');
    if (searchInput) searchInput.value = uppercaseQuery;
    if (typeof loadStockAnalyzer === 'function') {
        loadStockAnalyzer(uppercaseQuery);
    }
}
window.resolveVoiceQuery = resolveVoiceQuery;

function getActiveTabNarrativeText() {
    const activeSubtabBtn = document.querySelector('.subtab-btn.active');
    if (!activeSubtabBtn) return "";
    
    const subtab = activeSubtabBtn.getAttribute('data-subtab');
    let text = "";
    
    if (subtab === 'summary') {
        const overview = document.getElementById('business-summary-text')?.innerText || "";
        text += overview + " ";
        
        const strengths = document.getElementById('swot-strengths-list')?.innerText;
        if (strengths && !strengths.includes('0 items')) {
            text += "Strengths. " + strengths + " ";
        }
        const weaknesses = document.getElementById('swot-weaknesses-list')?.innerText;
        if (weaknesses && !weaknesses.includes('0 items')) {
            text += "Weaknesses. " + weaknesses + " ";
        }
        const opps = document.getElementById('swot-opportunities-list')?.innerText;
        if (opps && !opps.includes('0 items')) {
            text += "Opportunities. " + opps + " ";
        }
        const threats = document.getElementById('swot-threats-list')?.innerText;
        if (threats && !threats.includes('0 items')) {
            text += "Threats. " + threats + " ";
        }
    } else if (subtab === 'valuation') {
        const thesis = document.getElementById('dcf-sandbox-thesis-text')?.innerText || "";
        if (thesis && !thesis.includes('Adjust sliders')) {
            text += "Valuation Sandbox AI Thesis. " + thesis;
        } else {
            text += "Interactive Cash Flow Sandbox. The DCF estimated intrinsic value is " + 
                    (document.getElementById('dcf-intrinsic-price')?.innerText || "not calculated") + 
                    " with a margin of safety of " + 
                    (document.getElementById('dcf-margin-safety')?.innerText || "not calculated") + ".";
        }
    } else if (subtab === 'audit') {
        const summaryBox = document.getElementById('audit-summary-box');
        if (summaryBox && summaryBox.style.display !== 'none') {
            const summary = document.getElementById('audit-summary-text')?.innerText || "";
            text += "AI Strategic Audit Summary. " + summary + " ";
        }
        
        const debate = document.getElementById('audit-debate-dialogue')?.innerText || "";
        if (debate && debate.trim().length > 0) {
            text += "Dialectic Consensus Audit Debate transcript: " + debate;
        }
        
        if (text.trim() === "") {
            text = "AI Strategy Audit Matrix. Please click Generate AI Matrix Summary to run subagent diagnostics.";
        }
    } else {
        const tabTitle = activeSubtabBtn.innerText.replace(/[^\w\s&]/g, '').trim();
        text = `This is the ${tabTitle} tab. It displays interactive indicators, charts, and database tables. Please switch to the Executive Summary, Valuation and D C F, or Agent Strategy Audit sub-tabs to listen to AI-generated narrative summaries.`;
    }
    
        return text.trim();
}

// Global Voice Synthesis Player Controller (Option B with Glassmorphic Floating Panel)
window.SpeechPlayer = {
    sentences: [],
    currentIndex: -1,
    isPlaying: false,
    isActive: false,
    rate: 1.0,
    targetElementId: null,
    title: "",
    isAndroid: false,
    activeUtterance: null,

    init() {
        this.isAndroid = window.AndroidTts && typeof window.AndroidTts.speak === 'function';
        this.bindEvents();
        this.initVoiceList();
    },

    bindEvents() {
        const playPauseBtn = document.getElementById('speech-control-play-pause');
        if (playPauseBtn) {
            playPauseBtn.addEventListener('click', () => this.togglePlayPause());
        }
        const stopBtn = document.getElementById('speech-control-stop');
        if (stopBtn) {
            stopBtn.addEventListener('click', () => this.stop());
        }
        const prevBtn = document.getElementById('speech-control-prev');
        if (prevBtn) {
            prevBtn.addEventListener('click', () => this.prevSentence());
        }
        const nextBtn = document.getElementById('speech-control-next');
        if (nextBtn) {
            nextBtn.addEventListener('click', () => this.nextSentence());
        }
        const closeBtn = document.getElementById('speech-panel-close-btn');
        if (closeBtn) {
            closeBtn.addEventListener('click', () => this.stop());
        }
        const rateSelect = document.getElementById('speech-control-rate');
        if (rateSelect) {
            rateSelect.addEventListener('change', (e) => {
                this.setRate(parseFloat(e.target.value));
            });
        }

        const voiceSelect = document.getElementById('speech-control-voice');
        if (voiceSelect) {
            voiceSelect.addEventListener('change', () => {
                if (this.isPlaying && this.isActive) {
                    this.speakCurrent();
                }
            });
        }

        // Delegate click for speak buttons dynamically
        document.body.addEventListener('click', (e) => {
            const btn = e.target.closest('.section-speak-btn');
            if (btn) {
                e.preventDefault();
                e.stopPropagation();
                const targetId = btn.getAttribute('data-target');
                const title = btn.getAttribute('data-title') || "Narrative Audio";
                this.startSpeakingSection(targetId, title, false);
            }
        });
    },

    initVoiceList() {
        const voiceSelect = document.getElementById('speech-control-voice');
        if (!voiceSelect) return;

        if (this.isAndroid) {
            try {
                const nativeVoicesStr = window.AndroidTts.getNativeEnglishIndiaVoices();
                const nativeVoices = JSON.parse(nativeVoicesStr || "[]");
                
                voiceSelect.innerHTML = '<option value="default">Default Indian</option>';
                
                let inMaleCount = 0, inFemaleCount = 0;
                let usMaleCount = 0, usFemaleCount = 0;
                let gbMaleCount = 0, gbFemaleCount = 0;
                let generalMaleCount = 0, generalFemaleCount = 0;
                
                nativeVoices.forEach((v) => {
                    const option = document.createElement('option');
                    option.value = v.name;
                    
                    const country = (v.country || "").toUpperCase();
                    let prefix = "🌐";
                    let label = "";
                    
                    if (country === 'IN') {
                        prefix = "🇮🇳";
                        if (v.gender === 'male') {
                            inMaleCount++;
                            label = `${prefix} Male (Voice ${inMaleCount})`;
                        } else {
                            inFemaleCount++;
                            label = `${prefix} Female (Voice ${inFemaleCount})`;
                        }
                    } else if (country === 'US') {
                        prefix = "🇺🇸";
                        if (v.gender === 'male') {
                            usMaleCount++;
                            label = `${prefix} Male (Voice ${usMaleCount})`;
                        } else {
                            usFemaleCount++;
                            label = `${prefix} Female (Voice ${usFemaleCount})`;
                        }
                    } else if (country === 'GB' || country === 'UK') {
                        prefix = "🇬🇧";
                        if (v.gender === 'male') {
                            gbMaleCount++;
                            label = `${prefix} Male (Voice ${gbMaleCount})`;
                        } else {
                            gbFemaleCount++;
                            label = `${prefix} Female (Voice ${gbFemaleCount})`;
                        }
                    } else {
                        if (v.gender === 'male') {
                            generalMaleCount++;
                            label = `${prefix} Male (Voice ${generalMaleCount})`;
                        } else {
                            generalFemaleCount++;
                            label = `${prefix} Female (Voice ${generalFemaleCount})`;
                        }
                    }
                    
                    option.textContent = label;
                    voiceSelect.appendChild(option);
                });
            } catch (err) {
                console.error("Error populating native Android voices:", err);
            }
        } else if (window.speechSynthesis) {
            const populate = () => {
                const voices = window.speechSynthesis.getVoices();
                voiceSelect.innerHTML = '<option value="default">Default Indian</option>';
                
                const indianEnglishVoices = [];
                const fallbackEnglishVoices = [];

                voices.forEach((voice) => {
                    const langLower = voice.lang.toLowerCase();
                    const nameLower = voice.name.toLowerCase();
                    
                    const isIndianEnglish = voice.lang === 'en-IN' || 
                                           (langLower.startsWith('en') && nameLower.includes('india'));
                                           
                    const maleIndicators = ["male", "rishi", "david", "ravi", "prabhat", "harman", "george", "mark", "daniel", "richard", "james", "oliver", "peter", "harry", "john", "steven", "stefan"];
                    
                    if (isIndianEnglish) {
                        let gender = "female"; // Default fallback
                        if (maleIndicators.some(indicator => nameLower.includes(indicator))) {
                            gender = "male";
                        }
                        indianEnglishVoices.push({ voice, gender });
                    } else if (langLower.startsWith('en')) {
                        let gender = "female";
                        if (maleIndicators.some(indicator => nameLower.includes(indicator))) {
                            gender = "male";
                        }
                        fallbackEnglishVoices.push({ voice, gender });
                    }
                });

                let inMaleCount = 0, inFemaleCount = 0;
                indianEnglishVoices.forEach((item) => {
                    const option = document.createElement('option');
                    option.value = item.voice.name;
                    
                    if (item.gender === 'male') {
                        inMaleCount++;
                        option.textContent = `🇮🇳 Male (Voice ${inMaleCount})`;
                    } else {
                        inFemaleCount++;
                        option.textContent = `🇮🇳 Female (Voice ${inFemaleCount})`;
                    }
                    voiceSelect.appendChild(option);
                });

                let usMaleCount = 0, usFemaleCount = 0;
                let gbMaleCount = 0, gbFemaleCount = 0;
                let generalMaleCount = 0, generalFemaleCount = 0;
                
                fallbackEnglishVoices.forEach((item) => {
                    const option = document.createElement('option');
                    option.value = item.voice.name;
                    
                    const langUpper = item.voice.lang.toUpperCase();
                    let prefix = "🌐";
                    let label = "";
                    
                    if (langUpper.includes('US')) {
                        prefix = "🇺🇸";
                        if (item.gender === 'male') {
                            usMaleCount++;
                            label = `${prefix} Male (Voice ${usMaleCount})`;
                        } else {
                            usFemaleCount++;
                            label = `${prefix} Female (Voice ${usFemaleCount})`;
                        }
                    } else if (langUpper.includes('GB') || langUpper.includes('UK')) {
                        prefix = "🇬🇧";
                        if (item.gender === 'male') {
                            gbMaleCount++;
                            label = `${prefix} Male (Voice ${gbMaleCount})`;
                        } else {
                            gbFemaleCount++;
                            label = `${prefix} Female (Voice ${gbFemaleCount})`;
                        }
                    } else {
                        if (item.gender === 'male') {
                            generalMaleCount++;
                            label = `${prefix} Male (Voice ${generalMaleCount})`;
                        } else {
                            generalFemaleCount++;
                            label = `${prefix} Female (Voice ${generalFemaleCount})`;
                        }
                    }
                    
                    option.textContent = label;
                    voiceSelect.appendChild(option);
                });
            };

            populate();
            if (typeof window.speechSynthesis.addEventListener === 'function') {
                window.speechSynthesis.addEventListener('voiceschanged', populate);
            } else {
                window.speechSynthesis.onvoiceschanged = populate;
            }
        }
    },

    startSpeakingSection(targetIdOrText, title, isDirectText = false) {
        let text = "";
        let identifier = "";

        if (isDirectText) {
            text = targetIdOrText;
            identifier = "__direct_text_" + text.length + "_" + text.slice(0, 50).replace(/[^a-zA-Z0-9]/g, "");
        } else {
            const targetEl = document.getElementById(targetIdOrText);
            if (!targetEl) {
                if (typeof showToast === 'function') {
                    showToast("Content container not found.", "warning");
                }
                return;
            }
            text = targetEl.innerText || targetEl.textContent || "";
            identifier = targetIdOrText;
        }

        text = text.trim();
        // Clean markdown indicators (but preserve hyphens for ranges and words)
        text = text.replace(/[*#`_]/g, '');
        // Remove markdown list bullets (hyphens or asterisks followed by space at start of line)
        text = text.replace(/^\s*[-*]\s+/gm, '');

        // Standardize currency for TTS
        text = text.replace(/₹\s*(\d+)/g, ' Rupees $1');
        text = text.replace(/Rs\.?\s*(\d+)/g, ' Rupees $1');
        text = text.replace(/(\d+)\s*₹/g, '$1 Rupees');
        text = text.replace(/(\d+)\s*Rs\.?/g, '$1 Rupees');
        text = text.replace(/₹/g, ' Rupees');

        // Expand Cr./Cr (Crores) and Lakhs
        text = text.replace(/([\d,]+(?:\.\d+)?)\s*cr\b\.?/gi, '$1 Crores');
        text = text.replace(/\bcr\b\.?/gi, 'Crores');
        text = text.replace(/([\d,]+(?:\.\d+)?)\s*lakhs?\b\.?/gi, '$1 Lakhs');

        // Replace number ranges like 10-15 with '10 to 15' preserving dates
        const dates = [];
        text = text.replace(/\b(\d{1,4})[-/](\d{1,2})[-/](\d{1,4})\b/g, (match) => {
            dates.push(match);
            return `__DATE_PLACEHOLDER_${dates.length - 1}__`;
        });
        text = text.replace(/(\b\d+)\s*-\s*(\d+\b)/g, '$1 to $2');
        text = text.replace(/__DATE_PLACEHOLDER_(\d+)__/g, (match, idx) => {
            return dates[parseInt(idx)].replace(/[-/]/g, ' ');
        });

        if (!text || text === "..." || text.includes("Generating") || text.includes("Analyzing") || text.includes("Select a topic") || text.includes("Run analysis to compile") || text.includes("Diagnostic text loaded here") || text.includes("Click \"Generate Report\"") || text.includes("Click 'Generate Report'") || text.includes("AI Prescription text loaded here")) {
            if (typeof showToast === 'function') {
                showToast("No analysis available to read yet. Please generate analysis first.", "warning");
            }
            return;
        }

        if (this.isActive && this.targetElementId === identifier) {
            this.togglePlayPause();
            return;
        }

        this.stopSilence();

        this.targetElementId = identifier;
        this.title = title;
        this.isActive = true;

        // Split sentences cleanly
        this.sentences = text.split(/(?<=[.!?])\s+/).map(s => s.trim()).filter(s => s.length > 0);
        
        if (this.sentences.length === 0) {
            this.sentences = [text];
        }

        this.currentIndex = 0;
        this.rate = parseFloat(document.getElementById('speech-control-rate').value || "1.0");
        
        const panel = document.getElementById('speech-controller-panel');
        if (panel) {
            panel.style.display = 'flex';
            panel.offsetHeight; // reflow
            panel.style.transform = 'translateY(0)';
            panel.style.opacity = '1';
        }

        const titleEl = document.getElementById('speech-panel-title');
        if (titleEl) {
            titleEl.innerText = this.title;
        }

        this.speakCurrent();
    },

    speakCurrent() {
        if (!this.isActive || this.currentIndex < 0 || this.currentIndex >= this.sentences.length) {
            this.stop();
            return;
        }

        this.isPlaying = true;
        this.updateUI();

        const sentenceText = this.sentences[this.currentIndex];

        const voiceSelect = document.getElementById('speech-control-voice');
        if (this.isAndroid) {
            window.AndroidSpeechSpeaking = true;
            window.AndroidTts.setSpeechRate(this.rate);
            if (voiceSelect && voiceSelect.value !== 'default') {
                window.AndroidTts.setNativeVoice(voiceSelect.value);
            }
            window.AndroidTts.speak(sentenceText, "sentence_" + this.currentIndex);
        } else {
            window.speechSynthesis.cancel();
            const utterance = new SpeechSynthesisUtterance(sentenceText);
            this.activeUtterance = utterance;
            utterance.rate = this.rate;
            if (voiceSelect && voiceSelect.value !== 'default') {
                const voices = window.speechSynthesis.getVoices();
                const matched = voices.find(v => v.name === voiceSelect.value);
                if (matched) {
                    utterance.voice = matched;
                }
            }
            utterance.onend = () => {
                if (utterance === this.activeUtterance && this.isPlaying && this.isActive) {
                    this.nextSentenceAuto();
                }
            };
            utterance.onerror = (e) => {
                if (e.error === 'interrupted' || e.error === 'cancelled') {
                    return;
                }
                console.error("Speech Synthesis error", e);
                if (utterance === this.activeUtterance && this.isPlaying && this.isActive) {
                    this.nextSentenceAuto();
                }
            };
            window.speechSynthesis.speak(utterance);
        }
    },

    onAndroidTtsDone() {
        if (this.isPlaying && this.isActive) {
            this.nextSentenceAuto();
        }
    },

    nextSentenceAuto() {
        if (this.currentIndex < this.sentences.length - 1) {
            this.currentIndex++;
            this.speakCurrent();
        } else {
            this.stop();
        }
    },

    nextSentence() {
        if (this.currentIndex < this.sentences.length - 1) {
            this.stopSilence();
            this.currentIndex++;
            this.speakCurrent();
        }
    },

    prevSentence() {
        if (this.currentIndex > 0) {
            this.stopSilence();
            this.currentIndex--;
            this.speakCurrent();
        }
    },

    togglePlayPause() {
        if (!this.isActive) return;

        if (this.isPlaying) {
            this.isPlaying = false;
            this.stopSilence();
            this.updateUI();
        } else {
            this.speakCurrent();
        }
    },

    setRate(newRate) {
        this.rate = newRate;
        if (this.isAndroid) {
            window.AndroidTts.setSpeechRate(this.rate);
        }
        if (this.isPlaying) {
            this.stopSilence();
            this.speakCurrent();
        }
    },

    stopSilence() {
        this.activeUtterance = null;
        if (this.isAndroid) {
            window.AndroidTts.stop();
            window.AndroidSpeechSpeaking = false;
        } else {
            window.speechSynthesis.cancel();
        }
    },

    stop() {
        this.stopSilence();
        this.isPlaying = false;
        this.isActive = false;
        this.currentIndex = -1;
        this.sentences = [];
        this.updateUI();
        this.hidePanel();
    },

    hidePanel() {
        const panel = document.getElementById('speech-controller-panel');
        if (panel) {
            panel.style.transform = 'translateY(50px)';
            panel.style.opacity = '0';
            setTimeout(() => {
                if (!this.isActive) {
                    panel.style.display = 'none';
                }
            }, 300);
        }
    },

    updateUI() {
        const playPauseBtn = document.getElementById('speech-control-play-pause');
        if (playPauseBtn) {
            playPauseBtn.innerHTML = this.isPlaying ? "⏸️" : "▶️";
            playPauseBtn.title = this.isPlaying ? "Pause" : "Play";
        }

        const wave = document.getElementById('speech-wave');
        if (wave) {
            const waveBars = wave.querySelectorAll('.wave-bar');
            waveBars.forEach(bar => {
                bar.style.animationPlayState = this.isPlaying ? 'running' : 'paused';
            });
        }

        const total = this.sentences.length;
        const current = total > 0 ? this.currentIndex + 1 : 0;
        const progressPct = total > 0 ? Math.round((current / total) * 100) : 0;

        const progressText = document.getElementById('speech-progress-text');
        if (progressText) {
            progressText.innerText = total > 0 ? `Sentence ${current}/${total}` : "Sentence 0/0";
        }

        const progressPctEl = document.getElementById('speech-progress-pct');
        if (progressPctEl) {
            progressPctEl.innerText = `${progressPct}%`;
        }

        const progressBar = document.getElementById('speech-progress-bar');
        if (progressBar) {
            progressBar.style.width = `${progressPct}%`;
        }
    }
};

function setupVoiceLoaderAndGlobalReader() {
    // Initialize window.SpeechPlayer if present
    if (window.SpeechPlayer) {
        window.SpeechPlayer.init();
    }

    // 1. Voice Search (Speech-to-Text Loader) setup
    const voiceSearchBtn = document.getElementById('analyzer-voice-search-btn');
    let analyzerRecognition = null;
    let isAnalyzerListening = false;

    if (voiceSearchBtn) {
        const isAndroidSpeech = window.AndroidSpeech && typeof window.AndroidSpeech.startListening === 'function';
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;

        if (isAndroidSpeech) {
            voiceSearchBtn.addEventListener('click', () => {
                if (window.AndroidSpeechListening && window.activeSpeechRecognizerTarget === 'analyzer') {
                    window.AndroidSpeech.stopListening();
                } else {
                    window.activeSpeechRecognizerTarget = 'analyzer';
                    window.AndroidSpeech.startListening();
                }
            });
        } else if (!SpeechRecognition) {
            voiceSearchBtn.style.display = 'none';
        } else {
            analyzerRecognition = new SpeechRecognition();
            analyzerRecognition.continuous = false;
            analyzerRecognition.interimResults = false;
            analyzerRecognition.lang = 'en-US';

            analyzerRecognition.onstart = () => {
                isAnalyzerListening = true;
                voiceSearchBtn.innerHTML = '🔴';
                voiceSearchBtn.classList.add('mic-listening');
            };

            analyzerRecognition.onend = () => {
                isAnalyzerListening = false;
                voiceSearchBtn.innerHTML = '🎙️';
                voiceSearchBtn.classList.remove('mic-listening');
            };

            analyzerRecognition.onresult = (event) => {
                const transcript = event.results[0][0].transcript;
                const searchInput = document.getElementById('analyzer-search-input');
                if (searchInput) {
                    searchInput.value = transcript;
                }
                resolveVoiceQuery(transcript);
            };

            analyzerRecognition.onerror = (event) => {
                console.error("Speech recognition error:", event.error);
                if (event.error === 'no-speech') {
                    return;
                }
                if (event.error === 'network') {
                    if (typeof showToast === 'function') {
                        showToast("Speech recognition network error. Please check your internet connection.", "warning");
                    }
                    return;
                }
                if (event.error === 'not-allowed') {
                    if (typeof showToast === 'function') {
                        showToast("Microphone access denied. Please enable mic permissions in browser settings.", "warning");
                    }
                    return;
                }
                if (typeof showToast === 'function') {
                    showToast(`Voice search error: ${event.error}`, "error");
                }
            };

            voiceSearchBtn.addEventListener('click', () => {
                if (isAnalyzerListening) {
                    analyzerRecognition.stop();
                } else {
                    analyzerRecognition.start();
                }
            });
        }
    }

    // 2. Global Tab-level Read Aloud setup
    const globalReadAloudBtn = document.getElementById('analyzer-global-read-aloud-btn');
    if (globalReadAloudBtn) {
        globalReadAloudBtn.addEventListener('click', () => {
            const textToSpeak = getActiveTabNarrativeText();
            if (!textToSpeak) {
                if (typeof showToast === 'function') {
                    showToast("No active content to read.", "warning");
                }
                return;
            }
            if (window.SpeechPlayer) {
                window.SpeechPlayer.startSpeakingSection(textToSpeak, "Active Tab Narrative", true);
            }
        });
    }

    // 3. Sector AI Rotation Co-Pilot Voice setup
    const sectorVoiceBtn = document.getElementById('sector-ai-voice-btn');
    let sectorRecognition = null;
    let isSectorListening = false;

    if (sectorVoiceBtn) {
        const isAndroidSpeech = window.AndroidSpeech && typeof window.AndroidSpeech.startListening === 'function';
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;

        if (isAndroidSpeech) {
            sectorVoiceBtn.addEventListener('click', () => {
                if (window.AndroidSpeechListening && window.activeSpeechRecognizerTarget === 'rotation') {
                    window.AndroidSpeech.stopListening();
                } else {
                    window.activeSpeechRecognizerTarget = 'rotation';
                    window.AndroidSpeech.startListening();
                }
            });
        } else if (!SpeechRecognition) {
            sectorVoiceBtn.style.display = 'none';
        } else {
            sectorRecognition = new SpeechRecognition();
            sectorRecognition.continuous = false;
            sectorRecognition.interimResults = false;
            sectorRecognition.lang = 'en-IN';

            sectorRecognition.onstart = () => {
                isSectorListening = true;
                sectorVoiceBtn.innerHTML = '🔴';
                sectorVoiceBtn.classList.add('mic-listening');
            };

            sectorRecognition.onend = () => {
                isSectorListening = false;
                sectorVoiceBtn.innerHTML = '🎙️';
                sectorVoiceBtn.classList.remove('mic-listening');
            };

            sectorRecognition.onresult = (event) => {
                const transcript = event.results[0][0].transcript;
                const chatInput = document.getElementById('sector-ai-chat-input');
                if (chatInput) {
                    chatInput.value = (chatInput.value ? chatInput.value + ' ' : '') + transcript;
                }
            };

            sectorRecognition.onerror = (event) => {
                console.error("Sector Co-Pilot Speech recognition error:", event.error);
                if (event.error === 'no-speech') {
                    return;
                }
                if (event.error === 'network') {
                    if (typeof showToast === 'function') {
                        showToast("Speech recognition network error. Please check your internet connection.", "warning");
                    }
                    return;
                }
                if (event.error === 'not-allowed') {
                    if (typeof showToast === 'function') {
                        showToast("Microphone access denied. Please enable mic permissions in browser settings.", "warning");
                    }
                    return;
                }
                if (typeof showToast === 'function') {
                    showToast(`Voice input error: ${event.error}`, "error");
                }
            };

            sectorVoiceBtn.addEventListener('click', () => {
                if (isSectorListening) {
                    sectorRecognition.stop();
                } else {
                    sectorRecognition.start();
                }
            });
        }
    }
}

// Extracted Peers Benchmarking Controls setup (safe for multiple invocations)
function setupPeersControls() {
    const quickCompareBtn = document.getElementById('quick-compare-peers-btn');
    if (quickCompareBtn) {
        quickCompareBtn.onclick = () => {
            if (!activeStockProfile) return;
            const targetBase = activeStockProfile.ticker.split('.')[0].toUpperCase();
            const targetName = activeStockProfile.company_name.toLowerCase();
            const cleanTargetName = targetName.replace(/limited|ltd|industries|ind|corp|co|corporation/gi, "").replace(/[^a-z0-9]/g, "");

            const tickers = [targetBase];

            // Query only checked checkboxes in the peer table
            const checkedCheckboxes = document.querySelectorAll('.peer-select-checkbox:checked');

            checkedCheckboxes.forEach(cb => {
                const name = cb.getAttribute('data-ticker');
                if (name) {
                    const cleanName = name.replace(/\(Target\)/gi, '').trim();
                    const cleanNorm = cleanName.toLowerCase();
                    const cleanStripped = cleanNorm.replace(/limited|ltd|industries|ind|corp|co|corporation/gi, "").replace(/[^a-z0-9]/g, "");

                    // Skip if it is the target company itself to avoid duplicates
                    if (cleanNorm.includes("target") ||
                        cleanStripped === cleanTargetName ||
                        cleanName.toUpperCase() === targetBase) {
                        return;
                    }

                    // Simplify the peer name to a clean search query by removing common suffixes
                    const queryName = cleanName
                        .replace(/\s+(ltd|limited|corp|co|corporation|industries|ind)\.?\s*$/gi, '')
                        .trim();

                    if (queryName && !tickers.includes(queryName)) {
                        tickers.push(queryName);
                    }
                }
            });

            // Limit to 10 total comparison items (Target + 9 selected peers)
            const finalTickers = tickers.slice(0, 10);

            switchTab('compare');

            const compareInput = document.getElementById('compare-symbols-input');
            if (compareInput) {
                compareInput.value = finalTickers.join(', ');
                document.getElementById('run-comparison-btn').click();
            }
        };
    }

    // Master peer select-all checkbox event listener
    const selectAllCheckbox = document.getElementById('peer-select-all-checkbox');
    if (selectAllCheckbox) {
        selectAllCheckbox.onchange = (e) => {
            const isChecked = e.target.checked;
            document.querySelectorAll('.peer-select-checkbox').forEach(cb => {
                cb.checked = isChecked;
            });
            // Trigger peer chart update after all boxes are selected/deselected
            setTimeout(updatePeerComparisonChart, 50);
        };
    }

    // Custom peer input and add button listeners
    const addCustomPeerBtn = document.getElementById('add-custom-peer-btn');
    const customPeerInput = document.getElementById('custom-peer-input');

    const handleAddCustomPeer = async () => {
        if (!customPeerInput) return;
        const val = customPeerInput.value.trim();
        if (!val) return;

        if (addCustomPeerBtn) addCustomPeerBtn.disabled = true;
        customPeerInput.disabled = true;

        try {
            const originalText = addCustomPeerBtn ? addCustomPeerBtn.innerText : '+ Add Stock';
            if (addCustomPeerBtn) addCustomPeerBtn.innerText = 'Adding...';

            // Resolve company ticker first via API
            const searchRes = await fetch(`/api/search?q=${encodeURIComponent(val)}`);
            if (!searchRes.ok) {
                throw new Error('Search failed');
            }
            const resolved = await searchRes.json();
            const baseSymbol = resolved.base_symbol;
            const companyName = resolved.name || baseSymbol;
            const fullTicker = resolved.yf_ticker || `${baseSymbol}.NS`;

            // Now retrieve full stock profile metrics from analyze (SQLite cache or live scraper)
            const res = await fetch(`/api/analyze?query=${encodeURIComponent(fullTicker)}`);
            if (!res.ok) {
                throw new Error('Failed to load profile');
            }
            const profile = await res.json();

            if (activeStockProfile && activeStockProfile.peers) {
                // Ensure no duplications of target or existing peers
                const alreadyExists = activeStockProfile.peers.some(p => {
                    const pName = p.Name || p.Company || "";
                    return pName.toLowerCase().includes(baseSymbol.toLowerCase()) || pName.toLowerCase().includes(companyName.toLowerCase());
                });

                if (alreadyExists) {
                    alert(`Stock "${companyName}" is already in the benchmarking list.`);
                    if (addCustomPeerBtn) {
                        addCustomPeerBtn.disabled = false;
                        addCustomPeerBtn.innerText = originalText;
                    }
                    customPeerInput.disabled = false;
                    customPeerInput.focus();
                    return;
                }

                // Format the custom peer dictionary with all 12 columns
                const newPeer = {
                    "Name": `${companyName} (Custom)`,
                    "Company": companyName,
                    "P/E": profile.fundamentals && profile.fundamentals.pe_ratio ? profile.fundamentals.pe_ratio.toFixed(1) : "N/A",
                    "Mar Cap": profile.fundamentals && profile.fundamentals.market_cap ? (profile.fundamentals.market_cap / 10000000).toFixed(0) : "N/A", // Convert Cap to Crores if not scaled
                    "P/B": profile.fundamentals && profile.fundamentals.pb_ratio ? profile.fundamentals.pb_ratio.toFixed(1) : "N/A",
                    "Debt/Equity": profile.fundamentals && profile.fundamentals.debt_equity ? profile.fundamentals.debt_equity.toFixed(2) : "N/A",
                    "Debt to Equity": profile.fundamentals && profile.fundamentals.debt_equity ? profile.fundamentals.debt_equity.toFixed(2) : "N/A",
                    "ROCE %": profile.fundamentals && profile.fundamentals.roce_pct ? profile.fundamentals.roce_pct.toFixed(1) : "N/A",
                    "ROE %": profile.fundamentals && profile.fundamentals.roe_pct ? profile.fundamentals.roe_pct.toFixed(1) : "N/A",
                    "NPM %": profile.fundamentals && profile.fundamentals.npm_pct ? profile.fundamentals.npm_pct.toFixed(1) : "N/A",
                    "Profit Qtr YoY %": profile.fundamentals && profile.fundamentals.profit_growth_qtr ? profile.fundamentals.profit_growth_qtr.toFixed(1) : "N/A",
                    "Div Yield %": profile.fundamentals && profile.fundamentals.div_yield ? profile.fundamentals.div_yield.toFixed(2) : "N/A",
                    "Sales Qtr YoY %": profile.fundamentals && profile.fundamentals.sales_growth_3y ? profile.fundamentals.sales_growth_3y.toFixed(1) : "N/A"
                };

                // Wait, if the market cap is already in Crores (like Screener peer items), we don't divide by 1e7
                if (profile.fundamentals && profile.fundamentals.market_cap) {
                    const mcRaw = profile.fundamentals.market_cap;
                    // If it is > 1000000, it's raw INR, so convert to Cr. If it is already small, keep it as is.
                    newPeer["Mar Cap"] = mcRaw > 10000000 ? (mcRaw / 10000000).toFixed(0) : mcRaw.toFixed(0);
                }

                activeStockProfile.peers.push(newPeer);
                renderPeersTable(activeStockProfile.peers);

                customPeerInput.value = '';
            }
        } catch (err) {
            console.error("Error adding custom peer stock:", err);
            alert(`Could not add "${val}" for benchmarking. Please ensure it is a valid stock name or ticker symbol.`);
        } finally {
            if (addCustomPeerBtn) {
                addCustomPeerBtn.disabled = false;
                addCustomPeerBtn.innerText = '+ Add Stock';
            }
            customPeerInput.disabled = false;
            customPeerInput.focus();
        }
    };

    if (addCustomPeerBtn) {
        addCustomPeerBtn.onclick = handleAddCustomPeer;
    }
    if (customPeerInput) {
        customPeerInput.onkeypress = (e) => {
            if (e.key === 'Enter') {
                handleAddCustomPeer();
            }
        };
    }

    // Setup event delegation for Sector Peer Benchmarking checkboxes
    const peerTableBody = document.getElementById('peer-table-body');
    if (peerTableBody) {
        peerTableBody.onchange = function(e) {
            if (e.target.classList.contains('peer-select-checkbox') || e.target.type === 'checkbox') {
                updatePeerComparisonChart();
            }
        };
    }

    // Setup peer chart period change listener
    const peerChartPeriodSelect = document.getElementById('peer-chart-period');
    if (peerChartPeriodSelect) {
        peerChartPeriodSelect.onchange = function() {
            updatePeerComparisonChart();
        };
    }

    // Setup peer spectrum metric select change listener
    const peerSpectrumSelect = document.getElementById('peer-spectrum-metric-select');
    if (peerSpectrumSelect) {
        peerSpectrumSelect.onchange = function() {
            if (activeStockProfile && activeStockProfile.peers) {
                updatePeerSpectrumSlider(this.value, activeStockProfile.peers);
            }
        };
    }
}

