async function runComparisonAnalysis() {
    const input = document.getElementById('compare-symbols-input').value;
    if (!input) return;

    showLoader(
        "Benchmarking Rivals...",
        "Orchestrating simultaneous scraper runs and consulting senior sector strategists to produce a competitive Sector Battleground analysis.",
        true,
        [
            { threshold: 15, msg: "[INFO] Fetching daily historical series for peer group...", color: '#38bdf8' },
            { threshold: 30, msg: "[INFO] Aggregating operational margins, debt load, and interest cover...", color: '#f59e0b' },
            { threshold: 45, msg: "[INFO] Generating multi-dimensional operational radar matrix...", color: '#10b981' },
            { threshold: 60, msg: "[INFO] Initiating AI sector strategist peer comparison engine...", color: '#a855f7' },
            { threshold: 75, msg: "[INFO] Evaluating historical performance and crowning sector champion...", color: '#34d399' },
            { threshold: 90, msg: "[INFO] Compiling final battleground thesis report...", color: '#38bdf8' }
        ]
    );

    try {
        const response = await fetch(`/api/compare?tickers=${encodeURIComponent(input)}`);
        if (!response.ok) throw new Error("Comparison scan failed.");
        const data = await response.json();

        // Complete the loader animation and console text
        const progressBar = document.getElementById('global-loader-progress-bar');
        const progressConsole = document.getElementById('global-loader-progress-console');
        if (progressBar) progressBar.style.width = '100%';
        if (progressConsole) {
            const line = document.createElement('div');
            line.style.color = 'var(--color-emerald)';
            line.style.fontWeight = 'bold';
            line.innerText = `[SUCCESS] Sector battleground diagnostics completed successfully!`;
            progressConsole.appendChild(line);
            progressConsole.scrollTop = progressConsole.scrollHeight;
        }

        setTimeout(() => {
            hideLoader();
            renderComparisonArena(data);
        }, 650);

    } catch (e) {
        hideLoader();
        showToast("Comparison Arena error: " + e.message, 'error');
    }
}

function renderComparisonArena(data) {
    const headerRow = document.getElementById('compare-table-header');
    const tbody = document.getElementById('compare-table-body');

    headerRow.innerHTML = '<th>Financial Metric</th>';
    tbody.innerHTML = '';

    if (data.error) {
        tbody.innerHTML = `<tr><td colspan="5" class="center-text text-muted">${data.error}</td></tr>`;
        return;
    }

    const matrix = data.matrix;
    window.activeCompareMatrix = matrix;

    const radarSelect = document.getElementById('radar-metric-select');
    if (radarSelect) {
        radarSelect.value = 'all';
    }

    // Highlight sector champion column (with the highest score)
    let bestScore = -1;
    let bestIndex = -1;
    matrix.forEach((item, index) => {
        if (item.score > bestScore) {
            bestScore = item.score;
            bestIndex = index;
        }
    });

    matrix.forEach((item, index) => {
        const isChamp = index === bestIndex;
        if (isChamp) {
            headerRow.innerHTML += `<th class="champion-column-header">${item.company_name} <span class="champion-trophy-badge">🏆 CHAMPION</span></th>`;
        } else {
            headerRow.innerHTML += `<th>${item.company_name}</th>`;
        }
    });

    // Render the radar chart
    drawCompareRadarChart(matrix);

    // Render the playoff champion showcase
    renderCompareChampionShowcase(matrix, bestIndex);

    const metrics = [
        { label: 'AI Advisory Score', key: 'score', icon: '📊', format: v => {
            if (v === null || v === undefined) return 'N/A';
            const percent = Math.max(0, Math.min(100, v));
            let color = 'var(--color-emerald)';
            if (v < 45) color = 'var(--color-crimson)';
            else if (v < 70) color = 'var(--color-amber)';
            return `
                <div style="display: flex; flex-direction: column; gap: 4px;">
                    <div style="display: flex; justify-content: space-between; align-items: center; font-size: 11px;">
                        <strong>${v}/100</strong>
                    </div>
                    <div style="width: 100%; height: 5px; background: var(--bg-track); border-radius: 3px; overflow: hidden; position: relative;">
                        <div style="width: ${percent}%; height: 100%; background: ${color}; border-radius: 3px; box-shadow: 0 0 4px ${color};"></div>
                    </div>
                </div>
            `;
        }},
        { label: 'AI Analyst Action', key: 'action', icon: '💎', format: v => {
            if (!v) return 'N/A';
            let cls = 'badge-hold';
            if (v.toUpperCase().includes('BUY')) cls = 'badge-buy';
            if (v.toUpperCase().includes('SELL') || v.toUpperCase().includes('UNDERPERFORM')) cls = 'badge-sell';
            return `<span class="rec-glowing-badge ${cls}">${v}</span>`;
        }},
        { label: 'Current Price', key: 'price', icon: '💰', format: v => v !== null && v !== undefined ? `Rs. ${v.toLocaleString('en-IN')}` : 'N/A' },
        { label: 'Stock Trailing P/E', key: 'pe', icon: '⚙️', format: v => v !== null && v !== undefined ? (typeof v === 'number' ? v.toFixed(1) : v) : 'N/A' },
        { label: 'Return on Equity (ROE)', key: 'roe', icon: '📈', format: v => {
            if (v === null || v === undefined) return 'N/A';
            const val = typeof v === 'number' ? v : parseFloat(v);
            const percent = Math.max(0, Math.min(100, (val / 40) * 100));
            return `
                <div style="display: flex; flex-direction: column; gap: 4px;">
                    <div>${val.toFixed(1)}%</div>
                    <div style="width: 100%; height: 4px; background: var(--bg-track); border-radius: 2px; overflow: hidden;">
                        <div style="width: ${percent}%; height: 100%; background: var(--color-emerald); border-radius: 2px;"></div>
                    </div>
                </div>
            `;
        }},
        { label: 'Return on Capital (ROCE)', key: 'roce', icon: '📈', format: v => {
            if (v === null || v === undefined) return 'N/A';
            const val = typeof v === 'number' ? v : parseFloat(v);
            const percent = Math.max(0, Math.min(100, (val / 40) * 100));
            return `
                <div style="display: flex; flex-direction: column; gap: 4px;">
                    <div>${val.toFixed(1)}%</div>
                    <div style="width: 100%; height: 4px; background: var(--bg-track); border-radius: 2px; overflow: hidden;">
                        <div style="width: ${percent}%; height: 100%; background: var(--color-emerald); border-radius: 2px;"></div>
                    </div>
                </div>
            `;
        }},
        { label: 'Debt to Equity', key: 'debt_eq', icon: '🛡️', format: v => {
            if (v === null || v === undefined) return 'N/A';
            const val = typeof v === 'number' ? v : parseFloat(v);
            let color = 'var(--color-emerald)';
            if (val > 1.5) color = 'var(--color-crimson)';
            else if (val > 1.0) color = 'var(--color-amber)';
            const percent = Math.max(0, Math.min(100, (val / 2) * 100));
            return `
                <div style="display: flex; flex-direction: column; gap: 4px;">
                    <div>${val.toFixed(2)}</div>
                    <div style="width: 100%; height: 4px; background: var(--bg-track); border-radius: 2px; overflow: hidden;">
                        <div style="width: ${percent}%; height: 100%; background: ${color}; border-radius: 2px;"></div>
                    </div>
                </div>
            `;
        }},
        { label: 'DCF Margin of Safety', key: 'margin_of_safety', icon: '🛡️', format: v => {
            if (v === null || v === undefined) return 'N/A';
            const val = typeof v === 'number' ? v : parseFloat(v);
            let color = 'var(--color-emerald)';
            if (val < 0) color = 'var(--color-crimson)';
            const clampedVal = Math.max(-50, Math.min(50, val));
            const width = Math.abs(clampedVal) * 2;
            const left = clampedVal < 0 ? (50 - width) : 50;
            return `
                <div style="display: flex; flex-direction: column; gap: 4px;">
                    <span class="${val >= 0 ? 'green-text' : 'red-text'}">${val > 0 ? '+' : ''}${val.toFixed(1)}%</span>
                    <div style="width: 100%; height: 4px; background: var(--bg-track); border-radius: 2px; position: relative; overflow: hidden;">
                        <div style="position: absolute; left: ${left}%; width: ${width}%; height: 100%; background: ${color}; border-radius: 2px;"></div>
                    </div>
                </div>
            `;
        }},
        { label: 'RSI-14 Momentum', key: 'rsi', icon: '⚡', format: v => v !== null && v !== undefined ? (typeof v === 'number' ? v.toFixed(1) : v) : 'N/A' },
        { label: 'Moving Average Trend', key: 'trend', icon: '⚡', format: v => v || 'N/A' }
    ];

    metrics.forEach(m => {
        const tr = document.createElement('tr');
        tr.innerHTML = `<td><span class="metric-lead-icon">${m.icon}</span><strong>${m.label}</strong></td>`;

        matrix.forEach((item, index) => {
            const val = item[m.key];
            const formatted = m.format(val);
            const isChamp = index === bestIndex;

            let tdClass = isChamp ? "champion-cell" : "";
            if (m.key === 'roe' && val > 15) tdClass += " green-text";
            if (m.key === 'margin_of_safety' && val > 10) tdClass += " green-text";
            if (m.key === 'margin_of_safety' && val < -10) tdClass += " red-text";
            if (m.key === 'debt_eq' && val > 1.5) tdClass += " red-text";
            if (m.key === 'trend' && val === 'Bullish') tdClass += " green-text";

            let style = "";
            if (isChamp && m.key === 'score') style += ' font-size: 14px;';

            tr.innerHTML += `<td class="${tdClass.trim()}" style="${style}">${formatted}</td>`;
        });

        tbody.appendChild(tr);
    });

    const compareThesisEl = document.getElementById('compare-ai-thesis');
    if (compareThesisEl) {
        const champCompany = bestIndex !== -1 ? matrix[bestIndex].company_name : "N/A";
        const champScore = bestIndex !== -1 ? matrix[bestIndex].score : 0;

        let thesisHTML = `
        <div class="battleground-playoff-card">
            <div class="playoff-header">
                <div class="playoff-title">⚔️ AI Competitive Arena Audits</div>
                <div class="playoff-badge">Playoff Playbook</div>
            </div>
            <p class="playoff-analogy-text">
                Think of benchmarking rival equities like analyzing a high-stakes sports championship playoff bracket. Every company enters the arena with distinct strengths—some have dominant offensive statistics (high ROE & momentum) while others boast fortress-like defensive lines (undervalued PE & large DCF Margin of Safety). Sector champion status is awarded not merely to the largest player, but to the competitor that displays the most balanced combination of capital efficiency, margin protection, and technical momentum to dominate the tournament.
            </p>
            <div class="playoff-champion-box">
                <span class="playoff-champ-label">Current Sector Playoff Leader:</span>
                <span class="playoff-champ-value">
                    🏆 <strong>${champCompany}</strong>
                    <span class="badge-rec rec-buy" style="font-size: 11px; padding: 2px 8px; border-radius: 4px; font-weight:700;">${champScore}/100</span>
                </span>
            </div>
        </div>
        `;

        if (data.thesis) {
            thesisHTML += data.thesis.replace(/<h4>Rival Quality & Solvency Standings<\/h4>/gi,
                `<h4>Rival Quality & Solvency Standings <button class="section-speak-btn no-print" data-target="compare-ai-thesis" data-title="Rival Quality & Solvency" style="background: none; border: none; cursor: pointer; padding: 0; outline: none; font-size: 13px; display: inline-flex; align-items: center; justify-content: center; vertical-align: middle;">🔊</button></h4>`
            ).replace(/<h4>AI Comparative Analysis \(Local Fallback Workstation\)<\/h4>/gi,
                `<h4>AI Comparative Analysis (Local Fallback Workstation) <button class="section-speak-btn no-print" data-target="compare-ai-thesis" data-title="AI Comparative Analysis" style="background: none; border: none; cursor: pointer; padding: 0; outline: none; font-size: 13px; display: inline-flex; align-items: center; justify-content: center; vertical-align: middle;">🔊</button></h4>`
            );
            compareThesisEl.innerHTML = thesisHTML;
        } else {
            thesisHTML += `
            <div id="generate-battleground-thesis-container" style="text-align: center; padding: 20px 10px; border: 1px dashed var(--border-glass); border-radius: 8px; margin-top: 20px; background: rgba(255,255,255,0.01);">
                <p style="margin-bottom: 15px; color: var(--text-secondary); font-size: 12.5px;">AI Sector Battleground Thesis analysis is ready to benchmark these assets.</p>
                <button id="generate-battleground-thesis-btn" class="btn-primary" style="padding: 8px 16px; font-size: 12px; font-weight: 600; border-radius: 6px;">
                    ⚔️ Generate AI Sector Battleground Thesis & Tactical Analysis
                </button>
            </div>
            `;
            compareThesisEl.innerHTML = thesisHTML;

            document.getElementById('generate-battleground-thesis-btn').addEventListener('click', async () => {
                const btnContainer = document.getElementById('generate-battleground-thesis-container');
                btnContainer.innerHTML = `
                    <div style="display: flex; flex-direction: column; align-items: center; justify-content: center; gap: 8px;">
                        <span class="spinner" style="display: inline-block; width: 20px; height: 20px; border: 2px solid rgba(255,255,255,0.1); border-top-color: var(--neon-green); border-radius: 50%; animation: spin 1s linear infinite;"></span>
                        <p style="color: var(--neon-green); font-weight: 600; font-size: 12px; margin: 0;">Generating Battleground Thesis (calling LLM)...</p>
                    </div>
                `;

                try {
                    const symbolsInput = document.getElementById('compare-symbols-input').value;
                    const res = await fetch(`/api/compare?tickers=${encodeURIComponent(symbolsInput)}&generate_thesis=true`);
                    if (!res.ok) throw new Error("Failed to generate AI battleground thesis");
                    const responseData = await res.json();

                    if (responseData.thesis) {
                        btnContainer.outerHTML = responseData.thesis.replace(/<h4>Rival Quality & Solvency Standings<\/h4>/gi,
                            `<h4>Rival Quality & Solvency Standings <button class="section-speak-btn no-print" data-target="compare-ai-thesis" data-title="Rival Quality & Solvency" style="background: none; border: none; cursor: pointer; padding: 0; outline: none; font-size: 13px; display: inline-flex; align-items: center; justify-content: center; vertical-align: middle;">🔊</button></h4>`
                        ).replace(/<h4>AI Comparative Analysis \(Local Fallback Workstation\)<\/h4>/gi,
                            `<h4>AI Comparative Analysis (Local Fallback Workstation) <button class="section-speak-btn no-print" data-target="compare-ai-thesis" data-title="AI Comparative Analysis" style="background: none; border: none; cursor: pointer; padding: 0; outline: none; font-size: 13px; display: inline-flex; align-items: center; justify-content: center; vertical-align: middle;">🔊</button></h4>`
                        );
                    } else {
                        btnContainer.innerHTML = `<p style="color: var(--neon-red); font-size: 12px;">Failed to load thesis content.</p>`;
                    }
                } catch (err) {
                    btnContainer.innerHTML = `<p style="color: var(--neon-red); font-size: 12px;">Error: ${err.message}</p>`;
                }
            });
        }
    }

    const compareBox = document.getElementById('comparison-results-box');
    if (compareBox) compareBox.style.display = 'block';
}

function drawCompareRadarChart(matrix, selectedMetric = 'all') {
    const canvas = document.getElementById('compare-radar-chart');
    if (!canvas) return;

    if (activeCompareRadarChart) {
        activeCompareRadarChart.destroy();
        activeCompareRadarChart = null;
    }

    const isLightMode = document.documentElement.getAttribute('data-theme') === 'light' || document.documentElement.getAttribute('data-mode') === 'light';
    const gridColor = isLightMode ? 'rgba(0, 0, 0, 0.08)' : 'rgba(255, 255, 255, 0.08)';
    const textColor = isLightMode ? '#374151' : '#d1d5db';
    const ctx = canvas.getContext('2d');

    // Define color palette for companies
    const colors = [
        { border: '#3b82f6', bg: 'rgba(59, 130, 246, 0.08)' },
        { border: '#10b981', bg: 'rgba(16, 185, 129, 0.08)' },
        { border: '#f59e0b', bg: 'rgba(245, 158, 11, 0.08)' },
        { border: '#8b5cf6', bg: 'rgba(139, 92, 246, 0.08)' },
        { border: '#ec4899', bg: 'rgba(236, 72, 153, 0.08)' }
    ];

    // Helper to convert hex to rgb
    function hexToRgb(hex) {
        const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
        return result ? `${parseInt(result[1], 16)}, ${parseInt(result[2], 16)}, ${parseInt(result[3], 16)}` : null;
    }

    // Helper to create radial gradient for fill
    function createDatasetGradient(borderColor, opacity1 = 0.15, opacity2 = 0.02) {
        const width = canvas.width || 300;
        const height = canvas.height || 300;
        const centerX = width / 2;
        const centerY = height / 2;
        const radius = Math.min(width, height) / 2;

        try {
            const grad = ctx.createRadialGradient(centerX, centerY, 10, centerX, centerY, radius || 150);
            const rgb = hexToRgb(borderColor) || '59, 130, 246';
            grad.addColorStop(0, `rgba(${rgb}, ${opacity1})`);
            grad.addColorStop(1, `rgba(${rgb}, ${opacity2})`);
            return grad;
        } catch (e) {
            return borderColor + '10'; // Safe fallback string
        }
    }

    let chartLabels = [];
    if (selectedMetric === 'all') {
        chartLabels = ['Valuation', 'Quality', 'Growth', 'Momentum', 'Financial Health'];
    } else if (selectedMetric === 'valuation') {
        chartLabels = ['P/E Multiple Score', 'Intrinsic Discount', 'Valuation Rating', 'AI Advisory Score'];
    } else if (selectedMetric === 'quality') {
        chartLabels = ['ROCE Strength', 'ROE Strength', 'Capital Efficiency', 'AI Advisory Score'];
    } else if (selectedMetric === 'solvency') {
        chartLabels = ['Solvency (D/E)', 'Margin of Safety', 'Financial Cushion', 'AI Advisory Score'];
    } else if (selectedMetric === 'momentum') {
        chartLabels = ['RSI-14 Momentum', 'Trend Alignment', 'Momentum Strength', 'AI Advisory Score'];
    } else {
        chartLabels = ['Valuation', 'Quality', 'Growth', 'Momentum', 'Financial Health'];
    }

    // Pre-calculate company scores
    const companyScores = matrix.map(item => {
        const peVal = typeof item.pe === 'number' ? item.pe : 30;
        const peScore = Math.max(0, Math.min(100, (100 - peVal * 1.5)));

        const roceVal = typeof item.roce === 'number' ? item.roce : 0;
        const roceScore = Math.max(0, Math.min(100, roceVal * 2.5));

        const roeVal = typeof item.roe === 'number' ? item.roe : 0;
        const roeScore = Math.max(0, Math.min(100, roeVal * 2.5));

        const mosVal = typeof item.margin_of_safety === 'number' ? item.margin_of_safety : 0;
        const mosScore = Math.max(0, Math.min(100, mosVal + 50));

        const deVal = typeof item.debt_eq === 'number' ? item.debt_eq : 0;
        const deScore = Math.max(0, Math.min(100, (2 - deVal) * 50));

        const scoreVal = typeof item.score === 'number' ? item.score : 50;
        const rsiVal = typeof item.rsi === 'number' ? item.rsi : 50;

        let trendVal = 50;
        const trendStr = (item.trend || '').toLowerCase();
        if (trendStr.includes('bullish') || trendStr.includes('bull')) trendVal = 90;
        else if (trendStr.includes('bearish') || trendStr.includes('bear')) trendVal = 20;

        let valRatingScore = 60;
        const valRatingStr = (item.valuation_rating || '').toLowerCase();
        if (valRatingStr.includes('under')) valRatingScore = 100;
        else if (valRatingStr.includes('over')) valRatingScore = 20;

        const peRaw = typeof item.pe === 'number' ? item.pe.toFixed(1) : 'N/A';
        const roeRaw = typeof item.roe === 'number' ? item.roe.toFixed(1) + '%' : 'N/A';
        const roceRaw = typeof item.roce === 'number' ? item.roce.toFixed(1) + '%' : 'N/A';
        const deRaw = typeof item.debt_eq === 'number' ? item.debt_eq.toFixed(2) : 'N/A';
        const mosRaw = typeof item.margin_of_safety === 'number' ? item.margin_of_safety.toFixed(1) + '%' : 'N/A';
        const rsiRaw = typeof item.rsi === 'number' ? item.rsi.toFixed(1) : 'N/A';

        // Pack values into mapped dictionary matching label index keys
        let dataValues = [];
        if (selectedMetric === 'all') {
            dataValues = [
                Math.round(peScore * 0.5 + mosScore * 0.5), // Valuation
                Math.round(roceScore * 0.5 + roeScore * 0.5), // Quality
                Math.round(scoreVal * 0.85 + roeScore * 0.15), // Growth
                Math.round(rsiVal * 0.4 + trendVal * 0.6), // Momentum
                Math.round(deScore * 0.6 + mosScore * 0.4) // Financial Health
            ];
        } else if (selectedMetric === 'valuation') {
            dataValues = [peScore, mosScore, valRatingScore, scoreVal];
        } else if (selectedMetric === 'quality') {
            dataValues = [roceScore, roeScore, Math.round((roceScore + roeScore) / 2), scoreVal];
        } else if (selectedMetric === 'solvency') {
            dataValues = [deScore, mosScore, Math.round((deScore + mosScore) / 2), scoreVal];
        } else if (selectedMetric === 'momentum') {
            dataValues = [rsiVal, trendVal, trendVal, scoreVal];
        } else {
            dataValues = [peScore, roceScore, roeScore, deScore, mosScore];
        }

        return {
            companyName: item.company_name,
            ticker: item.ticker.replace('.NS', '').replace('.BO', ''),
            scores: dataValues,
            raw: { pe: peRaw, roe: roeRaw, roce: roceRaw, de: deRaw, mos: mosRaw, rsi: rsiRaw, trend: item.trend, valRating: item.valuation_rating }
        };
    });

    // Compute Sector Average
    const numAxes = chartLabels.length;
    const sectorAverages = [];
    for (let i = 0; i < numAxes; i++) {
        let sum = 0;
        companyScores.forEach(c => {
            sum += c.scores[i] || 0;
        });
        sectorAverages.push(Math.round(sum / companyScores.length));
    }

    // Build the chart datasets
    const chartDatasets = companyScores.map((c, idx) => {
        const color = colors[idx % colors.length];
        return {
            label: c.ticker,
            data: c.scores,
            borderColor: color.border,
            backgroundColor: createDatasetGradient(color.border, 0.15, 0.02),
            borderWidth: 2.5,
            pointRadius: 4,
            pointBackgroundColor: color.border,
            pointBorderColor: '#fff',
            pointHoverRadius: 6,
            pointHoverBackgroundColor: color.border,
            pointHoverBorderColor: '#fff',
            tension: 0.35, // Smooth organic loops!
            companyName: c.companyName,
            rawMetrics: c.raw
        };
    });

    // Add Sector Average as a dashed reference line
    chartDatasets.push({
        label: 'Sector Average',
        data: sectorAverages,
        borderColor: '#9ca3af',
        backgroundColor: 'rgba(156, 163, 175, 0.02)',
        borderWidth: 1.5,
        borderDash: [5, 5], // Dashed reference line
        pointRadius: 3,
        pointBackgroundColor: '#9ca3af',
        pointBorderColor: '#fff',
        pointHoverRadius: 5,
        tension: 0.35,
        companyName: 'Sector Average',
        rawMetrics: null
    });

    const chartScales = {
        r: {
            grid: {
                circular: true, // Enterprise-standard circular radar grids!
                color: gridColor,
                lineWidth: 1
            },
            angleLines: {
                display: true,
                color: gridColor
            },
            pointLabels: {
                color: textColor,
                font: { family: "'Outfit', sans-serif", size: 10, weight: '700' }
            },
            ticks: {
                display: true,
                color: textColor,
                backdropColor: 'transparent',
                font: { family: "'Outfit', sans-serif", size: 8 },
                stepSize: 20
            },
            min: 0,
            max: 100
        }
    };

    activeCompareRadarChart = new Chart(canvas, {
        type: 'radar',
        data: {
            labels: chartLabels,
            datasets: chartDatasets
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            animation: {
                duration: 1500,
                easing: 'easeOutElastic' // Organic bounce animation on load
            },
            // Interactive legend highlights
            plugins: {
                legend: {
                    display: true,
                    position: 'bottom',
                    labels: {
                        color: textColor,
                        font: {
                            family: "'Outfit', sans-serif",
                            size: 10,
                            weight: '600'
                        },
                        boxWidth: 12,
                        padding: 15
                    }
                },
                tooltip: {
                    callbacks: {
                        title: function(context) {
                            const dataset = context[0].dataset;
                            return dataset.label; // Company Ticker
                        },
                        label: function(context) {
                            const dataset = context.dataset;
                            const score = context.raw;
                            const label = context.label; // Axis label

                            if (dataset.label === 'Sector Average') {
                                return `Sector Avg - ${label}: ${score.toFixed(0)}/100`;
                            }

                            const raw = dataset.rawMetrics;
                            if (!raw) return `${label}: ${score.toFixed(0)}/100`;

                            if (label === 'Valuation' || label === 'P/E Multiple Score') {
                                return `${label}: ${score.toFixed(0)}/100 (P/E: ${raw.pe}, MoS: ${raw.mos})`;
                            }
                            if (label === 'Quality' || label === 'ROCE Strength' || label === 'ROE Strength' || label === 'Capital Efficiency') {
                                return `${label}: ${score.toFixed(0)}/100 (ROE: ${raw.roe}, ROCE: ${raw.roce})`;
                            }
                            if (label === 'Momentum' || label === 'RSI-14 Momentum' || label === 'Trend Alignment') {
                                return `${label}: ${score.toFixed(0)}/100 (RSI: ${raw.rsi}, Trend: ${raw.trend || 'N/A'})`;
                            }
                            if (label === 'Financial Health' || label === 'Solvency (D/E)' || label === 'Financial Cushion') {
                                return `${label}: ${score.toFixed(0)}/100 (D/E: ${raw.de}, MoS: ${raw.mos})`;
                            }
                            if (label === 'AI Advisory Score') {
                                return `AI Score: ${score.toFixed(0)}/100`;
                            }

                            return `${label}: ${score.toFixed(0)}/100`;
                        }
                    }
                }
            },
            // Interactive hover highlight effect
            onHover: (event, chartElements) => {
                if (!activeCompareRadarChart) return;
                const activeIndex = chartElements.length > 0 ? chartElements[0].datasetIndex : -1;

                let changed = false;
                activeCompareRadarChart.data.datasets.forEach((dataset, idx) => {
                    // Skip sector average modification to keep it clean as a reference
                    if (dataset.label === 'Sector Average') return;

                    const originalColor = colors[idx % colors.length];
                    const targetBorderColor = activeIndex === -1 || idx === activeIndex
                        ? originalColor.border
                        : `${originalColor.border}22`; // Dim non-hovered borders
                    const targetBgColor = activeIndex === -1 || idx === activeIndex
                        ? createDatasetGradient(originalColor.border, 0.15, 0.02)
                        : 'rgba(0, 0, 0, 0)'; // Dim non-hovered fills

                    if (dataset.borderColor !== targetBorderColor) {
                        dataset.borderColor = targetBorderColor;
                        dataset.backgroundColor = targetBgColor;
                        changed = true;
                    }
                });

                if (changed) {
                    activeCompareRadarChart.update('none'); // Update responsively without animation lag
                }
            },
            scales: chartScales
        }
    });
}

function renderCompareChampionShowcase(matrix, bestIndex) {
    const showcaseBox = document.getElementById('compare-champion-showcase-box');
    if (!showcaseBox) return;

    if (bestIndex === -1 || !matrix[bestIndex]) {
        showcaseBox.innerHTML = `<div style="color: var(--text-muted); font-size: 12px; text-align: center; width: 100%;">No champion crowned yet. Run benchmarking comparison first.</div>`;
        return;
    }

    const champ = matrix[bestIndex];
    const finalScore = champ.score || 0;
    const recAction = champ.action || 'HOLD';
    let recClass = 'rec-hold';
    let recEmoji = '🟡';
    if (recAction.toUpperCase().includes('BUY')) {
        recClass = 'rec-buy';
        recEmoji = '🟢';
    } else if (recAction.toUpperCase().includes('SELL') || recAction.toUpperCase().includes('AVOID')) {
        recClass = 'rec-sell';
        recEmoji = '🔴';
    }

    let gaugeColor = 'var(--color-emerald)';
    if (finalScore < 45) gaugeColor = 'var(--color-crimson)';
    else if (finalScore < 70) gaugeColor = 'var(--color-amber)';

    showcaseBox.innerHTML = `
        <div class="synthesis-score-gauge-wrap no-print" style="flex: 0 0 130px; display: flex; flex-direction: column; align-items: center; justify-content: center; background: rgba(30, 41, 59, 0.25); border: 1px solid var(--border-glass); border-radius: 10px; padding: 15px; box-shadow: inset 0 1px 1px rgba(255,255,255,0.05); height: 100%; box-sizing: border-box;">
            <div class="synthesis-gauge-container" style="width: 76px; height: 76px; position: relative;">
                <svg viewBox="0 0 36 36" class="synthesis-gauge-svg" style="width: 100%; height: 100%; transform: rotate(-90deg);">
                    <path class="synthesis-gauge-bg" d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" style="fill: none; stroke: rgba(255, 255, 255, 0.04); stroke-width: 3.2;" />
                    <path id="compare-gauge-fill" class="synthesis-gauge-fill" stroke-dasharray="${finalScore}, 100" d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" style="fill: none; stroke: ${gaugeColor}; stroke-width: 3.2; stroke-linecap: round; filter: drop-shadow(0 0 3px ${gaugeColor}); transition: stroke-dasharray 1s ease-out;" />
                </svg>
                <div class="synthesis-gauge-text" style="position: absolute; top: 0; left: 0; width: 100%; height: 100%; display: flex; flex-direction: column; align-items: center; justify-content: center;">
                    <span style="font-family: 'Outfit', sans-serif; font-size: 18px; font-weight: 800; color: var(--text-primary);">${finalScore}</span>
                    <span style="font-size: 7px; color: var(--text-muted); text-transform: uppercase; letter-spacing: 0.05em; margin-top: -3px;">Score</span>
                </div>
            </div>
            <div style="margin-top: 10px; text-align: center; width: 100%;">
                <span style="font-size: 7px; color: var(--text-secondary); text-transform: uppercase; letter-spacing: 0.05em; display: block; margin-bottom: 2px;">CROWNED CHAMP</span>
                <span class="badge-rec ${recClass}" style="font-size: 9px; font-weight: 700; padding: 2px 6px; border-radius: 4px; display: inline-block;">${recAction} ${recEmoji}</span>
            </div>
        </div>
        <div style="flex-grow: 1; display: flex; flex-direction: column; gap: 8px; justify-content: center; height: 100%; box-sizing: border-box;">
            <h4 style="font-family: 'Outfit', sans-serif; font-size: 11px; font-weight: 700; text-transform: uppercase; margin: 0 0 2px 0; color: var(--text-primary); display: flex; align-items: center; gap: 6px;">
                🏆 CROWNED SECTOR CHAMPION
            </h4>
            <div style="font-size: 16px; font-weight: 800; font-family: 'Outfit', sans-serif; color: var(--color-primary-light);">
                ${champ.company_name}
            </div>
            <div class="playoff-bracket-bracket" style="border-left: 2px solid var(--border-glass); padding-left: 10px; display: flex; flex-direction: column; gap: 4px; margin-top: 2px;">
                <div style="font-size: 10.5px; display: flex; align-items: center; justify-content: space-between;">
                    <span style="color: var(--text-muted);">Offensive Strength (ROE / ROCE)</span>
                    <strong style="color: var(--neon-green);">${typeof champ.roce === 'number' ? champ.roce.toFixed(1) : 'N/A'}%</strong>
                </div>
                <div style="font-size: 10.5px; display: flex; align-items: center; justify-content: space-between;">
                    <span style="color: var(--text-muted);">Defensive Line (D/E Ratio)</span>
                    <strong style="color: ${champ.debt_eq > 1.0 ? 'var(--neon-red)' : 'var(--neon-green)'};">${typeof champ.debt_eq === 'number' ? champ.debt_eq.toFixed(2) : 'N/A'}</strong>
                </div>
                <div style="font-size: 10.5px; display: flex; align-items: center; justify-content: space-between;">
                    <span style="color: var(--text-muted);">Valuation Margin (MOS %)</span>
                    <strong style="color: ${champ.margin_of_safety > 0 ? 'var(--neon-green)' : 'var(--neon-red)'};">${typeof champ.margin_of_safety === 'number' ? (champ.margin_of_safety > 0 ? '+' : '') + champ.margin_of_safety.toFixed(1) : 'N/A'}%</strong>
                </div>
            </div>
        </div>
    `;
}

// 8. Automated Alert Center
function setupAlertCenter() {
    document.getElementById('save-alert-btn').addEventListener('click', setAlertRule);
    document.getElementById('scan-alerts-btn').addEventListener('click', checkAlertRules);

    // Natural Language Builder submit listener
    const nlSubmitBtn = document.getElementById('alert-nl-submit');
    if (nlSubmitBtn) {
        nlSubmitBtn.addEventListener('click', generateNLAlertRule);
    }

    // Hook Suggested Prompt Pills
    document.querySelectorAll('.nl-template-pill').forEach(pill => {
        pill.addEventListener('click', (e) => {
            const templateText = e.currentTarget.getAttribute('data-template');

            // Resolve stock name dynamically:
            // 1. Manual search input in Alert form
            // 2. Active profile symbol in Workspace
            // 3. Fallback to default
            let targetStock = 'RELIANCE';
            const alertInputVal = document.getElementById('alert-symbol')?.value.trim();
            if (alertInputVal) {
                targetStock = alertInputVal.toUpperCase();
            } else if (typeof activeStockProfile !== 'undefined' && activeStockProfile && activeStockProfile.ticker) {
                targetStock = activeStockProfile.ticker.split('.')[0].toUpperCase();
            }

            const promptText = templateText.replace(/{STOCK}/g, targetStock);
            const txt = document.getElementById('alert-nl-prompt');
            if (txt) {
                txt.value = promptText;
                txt.focus();
            }
        });
    });


    // Autocomplete on stock input
    setupAlertSymbolAutocomplete();

    // Dynamic cheatsheet guide
    const conditionSelect = document.getElementById('alert-condition');
    if (conditionSelect) {
        conditionSelect.addEventListener('change', updateAlertCheatsheet);
        // Trigger once to set defaults
        updateAlertCheatsheet();
    }

    // Acknowledge warning HUD button listener
    const ackBtn = document.getElementById('hud-ack-btn');
    if (ackBtn) {
        ackBtn.addEventListener('click', dismissEmergencyHUD);
    }

    // Play Warning Tone preview
    const playToneBtn = document.getElementById('cockpit-play-tone-btn');
    if (playToneBtn) {
        playToneBtn.addEventListener('click', () => {
            const select = document.getElementById('cockpit-audio-select');
            if (select) playAlertSound(select.value);
        });
    }

    // Simulate Emergency Warning HUD
    const simAlarmBtn = document.getElementById('cockpit-simulate-alarm-btn');
    if (simAlarmBtn) {
        simAlarmBtn.addEventListener('click', () => {
            const select = document.getElementById('cockpit-audio-select');
            const toneStyle = select ? select.value : 'sonar_ping';

            const warningHud = document.getElementById('emergency-warning-hud');
            const warningMsg = document.getElementById('hud-warning-message');

            if (warningHud) {
                warningHud.style.display = 'block';
                if (warningMsg) {
                    warningMsg.textContent = "SENTINEL COCKPIT DIAGNOSTIC ALARM: Active warning state simulation triggered.";
                }
                playAlertSound(toneStyle);
                showToast("System warning alarm simulation active.", "warning");
            }
        });
    }

    setupAlertsTableSorting();
    fetchWhatsAppSettings();
    fetchDailyWrapupSettings();
    setupDailyWrapupListeners();
    fetchScreenerCookieSettings();
    setupScreenerCookieListeners();
    fetchAlertsList();
    startRealTimeAlertScanner();

    // Sentinel Diagnostics HUD Button Listeners
    const forceCheckBtn = document.getElementById('sentinel-force-evaluate-btn');
    if (forceCheckBtn) {
        forceCheckBtn.addEventListener('click', async () => {
            const ticker = document.getElementById('sentinel-ticker')?.textContent;
            if (ticker && ticker !== 'N/A') {
                showToast(`Force evaluating rule metrics for ${ticker}...`, "info");
                await checkAlertRules();
                // Find and re-deploy telemetry for updated status
                const updatedItem = lastAlertsList.find(x => x.ticker === ticker);
                if (updatedItem) deploySentinelTelemetry(updatedItem);
            }
        });
    }

    const chartViewBtn = document.getElementById('sentinel-chart-view-btn');
    if (chartViewBtn) {
        chartViewBtn.addEventListener('click', () => {
            const symbol = document.getElementById('sentinel-ticker')?.textContent;
            if (symbol && symbol !== 'N/A') {
                window.loadStockAnalyzer(symbol);
            }
        });
    }
}

async function generateNLAlertRule() {
    const promptInput = document.getElementById('alert-nl-prompt');
    const submitBtn = document.getElementById('alert-nl-submit');
    const loader = document.getElementById('alert-nl-loader');

    if (!promptInput || !promptInput.value.trim()) {
        showToast("Please enter an alert description prompt.", "error");
        return;
    }

    const promptText = promptInput.value.trim();
    submitBtn.disabled = true;
    loader.style.display = 'flex';

    try {
        const activeTicker = activeStockProfile ? activeStockProfile.ticker : "";
        const response = await fetch('/api/alerts/parse-nl', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                prompt: promptText,
                active_ticker: activeTicker
            })
        });

        if (!response.ok) {
            const errData = await response.json();
            throw new Error(errData.detail || "Failed to parse rule.");
        }

        const data = await response.json();
        showToast(`AI Alert successfully created: ${data.ticker} on ${data.condition_type}`, "success");
        promptInput.value = '';
        fetchAlertsList();
    } catch (e) {
        showToast("Failed to parse alert prompt: " + e.message, "error");
    } finally {
        submitBtn.disabled = false;
        loader.style.display = 'none';
    }
}

// Start Real-Time Alert Engine background scanner
function startRealTimeAlertScanner() {
    const getInterval = () => 10000; // Poll every 10 seconds for quick automatic updates

    const runScan = async () => {
        const alertsEnabled = localStorage.getItem('setting-alerts-enabled') !== 'false';
        if (!alertsEnabled) {
            setTimeout(runScan, getInterval());
            return;
        }

        try {
            const response = await fetch('/api/alerts/check');
            if (!response.ok) return;
            const data = await response.json();

            // Always update notification bell to keep it in sync with database status!
            if (typeof updateNotificationBell === 'function') {
                updateNotificationBell(data.alerts);
            }

            // Check if there are any new triggers in this sweep
            if (data.triggers && data.triggers.length > 0) {
                // 1. Play premium institutional alert sound
                playAlertSound();

                // 2. Display Emergency HUD
                const hudMsg = data.triggers.join("<br>");
                showEmergencyHUD(hudMsg);

                // 3. Display a toast notification for each trigger
                data.triggers.forEach(msg => {
                    showToast(`🚨 SYSTEM ALERT: ${msg}`, 'warning');
                });

                // Shake the bell icon dynamically
                const bellIcon = document.querySelector('#header-bell-btn .bell-icon');
                if (bellIcon) {
                    bellIcon.classList.add('bell-shake-active');
                    setTimeout(() => {
                        bellIcon.classList.remove('bell-shake-active');
                    }, 800);
                }

                // 6. If user is currently looking at the alert center tab, update the list automatically!
                const alertsTab = document.getElementById('tab-alerts');
                if (alertsTab && alertsTab.style.display !== 'none') {
                    renderAlertsList(data.alerts);
                }
            }
        } catch (e) {
            console.warn("Silent alert background scanner failed:", e);
        }
        // Schedule next scan with dynamic interval
        setTimeout(runScan, getInterval());
    };

    // Start first scan after initial interval
    setTimeout(runScan, getInterval());
}

let tvAudioCtx = null;

function playAlertSound(style = null) {
    const audioSelect = document.getElementById('hud-audio-select');
    const activeStyle = style || (audioSelect ? audioSelect.value : 'sonar_ping');
    if (activeStyle === 'mute') return;

    try {
        if (!tvAudioCtx) {
            tvAudioCtx = new (window.AudioContext || window.webkitAudioContext)();
        }
        if (tvAudioCtx.state === 'suspended') {
            tvAudioCtx.resume();
        }
        const audioCtx = tvAudioCtx;

        if (activeStyle === 'sonar_ping') {
            const osc = audioCtx.createOscillator();
            const gainNode = audioCtx.createGain();
            osc.connect(gainNode);
            gainNode.connect(audioCtx.destination);
            osc.type = 'sine';
            osc.frequency.setValueAtTime(1400, audioCtx.currentTime);
            osc.frequency.exponentialRampToValueAtTime(700, audioCtx.currentTime + 0.6);
            gainNode.gain.setValueAtTime(0.12, audioCtx.currentTime);
            gainNode.gain.exponentialRampToValueAtTime(0.001, audioCtx.currentTime + 0.8);
            osc.start(audioCtx.currentTime);
            osc.stop(audioCtx.currentTime + 0.8);
        } else if (activeStyle === 'chimes') {
            const now = audioCtx.currentTime;
            const frequencies = [880, 1100, 1320, 1650];
            frequencies.forEach((freq, idx) => {
                const osc = audioCtx.createOscillator();
                const gain = audioCtx.createGain();
                osc.connect(gain);
                gain.connect(audioCtx.destination);
                osc.type = 'triangle';
                osc.frequency.value = freq;
                const delay = idx * 0.08;
                gain.gain.setValueAtTime(0, now);
                gain.gain.linearRampToValueAtTime(0.06, now + delay + 0.03);
                gain.gain.exponentialRampToValueAtTime(0.001, now + delay + 0.35);
                osc.start(now + delay);
                osc.stop(now + delay + 0.4);
            });
        } else {
            const osc1 = audioCtx.createOscillator();
            const gain1 = audioCtx.createGain();
            osc1.connect(gain1);
            gain1.connect(audioCtx.destination);
            osc1.type = 'sine';
            osc1.frequency.value = 880;
            gain1.gain.setValueAtTime(0.08, audioCtx.currentTime);
            gain1.gain.exponentialRampToValueAtTime(0.001, audioCtx.currentTime + 0.15);
            osc1.start(audioCtx.currentTime);
            osc1.stop(audioCtx.currentTime + 0.15);

            const osc2 = audioCtx.createOscillator();
            const gain2 = audioCtx.createGain();
            osc2.connect(gain2);
            gain2.connect(audioCtx.destination);
            osc2.type = 'sine';
            osc2.frequency.value = 1200;
            gain2.gain.setValueAtTime(0.08, audioCtx.currentTime + 0.15);
            gain2.gain.exponentialRampToValueAtTime(0.001, audioCtx.currentTime + 0.35);
            osc2.start(audioCtx.currentTime + 0.15);
            osc2.stop(audioCtx.currentTime + 0.35);
        }
    } catch (e) {
        console.warn("AudioContext tone synthesis failed: ", e);
    }
}

function updateNotificationBell(list) {
    const notifBody = document.getElementById('notification-list-body');
    const badge = document.getElementById('bell-badge-count');
    const sidebarBadge = document.getElementById('sidebar-alerts-badge');
    if (!notifBody) return;

    let dismissedIds = [];
    try {
        dismissedIds = JSON.parse(localStorage.getItem('dismissed-alert-ids') || '[]');
    } catch (e) {
        dismissedIds = [];
    }

    const activeTriggers = list.filter(item => item.triggered && !dismissedIds.includes(item.id));
    
    // Sort by trigger date descending
    activeTriggers.sort((a, b) => new Date(b.trigger_date || 0) - new Date(a.trigger_date || 0));

    if (activeTriggers.length === 0) {
        notifBody.innerHTML = '<div style="font-size:10px; color:var(--text-muted); padding:20px; text-align:center;">No new system notifications.</div>';
        if (badge) {
            badge.style.display = 'none';
            badge.innerText = '0';
        }
        if (sidebarBadge) {
            sidebarBadge.style.display = 'none';
            sidebarBadge.innerText = '0';
        }
        return;
    }

    notifBody.innerHTML = '';
    activeTriggers.forEach(item => {
        const msg = `ALERT TRIGGERED: ${item.ticker} met condition (${item.condition_type} ${item.operator} ${item.value})`;
        const notifEl = document.createElement('div');
        notifEl.className = 'notification-item';
        notifEl.style.borderLeft = '3px solid var(--color-crimson, #ef4444)';
        notifEl.innerHTML = `
            <div class="notif-header">
                <span class="notif-badge badge-red" style="background: rgba(239, 68, 68, 0.15); color: #f87171; border: 1px solid rgba(239,68,68,0.3); font-size: 8px; padding: 2px 4px; border-radius: 3px; font-weight: 700;">TRIGGERED</span>
                <span class="notif-time" style="font-size: 9.5px; color: var(--text-secondary);">${item.trigger_date || 'Just Now'}</span>
            </div>
            <div class="notif-text" style="color: var(--text-primary); font-weight: 500; font-size: 11px; margin-top: 4px;">
                ${msg}
            </div>
            ${item.ai_context ? `<div class="notif-subtext" style="font-size: 10px; color: var(--text-secondary); margin-top: 4px; font-style: italic; line-height: 1.3;">🤖 ${item.ai_context}</div>` : ''}
        `;
        notifBody.appendChild(notifEl);
    });

    if (badge) {
        badge.innerText = activeTriggers.length;
        badge.style.display = 'flex';
    }
    if (sidebarBadge) {
        sidebarBadge.innerText = activeTriggers.length;
        sidebarBadge.style.display = 'flex';
    }
}

async function fetchAlertsList() {
    try {
        const response = await fetch('/api/alerts/list');
        const list = await response.json();
        renderAlertsList(list);
    } catch (e) {
        console.error("Failed to load alerts list: ", e);
    }
}

async function setAlertRule() {
    const symbol = document.getElementById('alert-symbol').value;
    const cond = document.getElementById('alert-condition').value;
    const op = document.getElementById('alert-operator').value;
    const val = document.getElementById('alert-value').value;

    if (!symbol || !val) return;

    const payload = {
        ticker: symbol,
        condition_type: cond,
        operator: op,
        value: val
    };

    try {
        const response = await fetch('/api/alerts/set', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload)
        });

        if (!response.ok) throw new Error("Failed to set alert.");

        showToast("Alert rule successfully registered in the Center.", 'success');
        fetchAlertsList();
    } catch (e) {
        showToast("Alert save error: " + e.message, 'error');
    }
}

function renderAlertsList(list) {
    lastAlertsList = list;

    // Update notification bell dropdown dynamically
    if (typeof updateNotificationBell === 'function') {
        updateNotificationBell(list);
    }

    // Also update cockpit radar scanner target plots!
    renderRadarTargets(list);

    // Update visual analytics distribution metrics chart
    updateAlertsAnalyticsChart(list);

    // Sort and render the page (keeping current sorting but resetting page if bounds exceeded)
    sortAlerts(alertsSortCol, false);
}

function renderAlertsPage(page) {
    const tbody = document.getElementById('alerts-table-body');
    const pagContainer = document.getElementById('alerts-log-pagination');
    if (!tbody) return;

    tbody.innerHTML = '';

    let filteredList = lastAlertsList;
    if (alertsLogSearchQuery) {
        const query = alertsLogSearchQuery.toLowerCase().trim();
        filteredList = lastAlertsList.filter(item => {
            return (item.ticker || '').toLowerCase().includes(query) ||
                   (item.condition_type || '').toLowerCase().includes(query) ||
                   (item.operator || '').toLowerCase().includes(query) ||
                   (item.value || '').toLowerCase().includes(query) ||
                   (item.status || '').toLowerCase().includes(query);
        });
    }

    alertsLogFilteredCount = filteredList.length;

    // Telemetry matches count update
    const telBadge = document.getElementById('alerts-search-telemetry');
    const telCount = document.getElementById('alerts-search-match-count');
    if (telBadge && telCount) {
        if (alertsLogSearchQuery) {
            telCount.textContent = `${filteredList.length} of ${lastAlertsList.length}`;
            telBadge.style.display = 'inline-flex';
        } else {
            telBadge.style.display = 'none';
        }
    }

    if (lastAlertsList.length === 0) {
        tbody.innerHTML = '<tr><td colspan="6" class="center-text text-muted">No alert rules configured. Create one on the left.</td></tr>';
        if (pagContainer) pagContainer.style.display = 'none';
        return;
    }

    if (filteredList.length === 0) {
        tbody.innerHTML = '<tr><td colspan="6" class="center-text text-muted">No matching alert rules found. Try adjusting your query.</td></tr>';
        if (pagContainer) pagContainer.style.display = 'none';
        return;
    }

    const totalPages = Math.ceil(filteredList.length / alertsPageSize) || 1;
    if (page < 1) page = 1;
    if (page > totalPages) page = totalPages;
    activeAlertsPage = page;

    const startIndex = (page - 1) * alertsPageSize;
    const endIndex = Math.min(startIndex + alertsPageSize, filteredList.length);
    const pageSlice = filteredList.slice(startIndex, endIndex);

    pageSlice.forEach(item => {
        const tr = document.createElement('tr');

        let statusBadge = '';
        if (item.status === 'Triggered') {
            statusBadge = `<span class="alert-status-badge triggered">🚨 Triggered</span>`;
        } else {
            statusBadge = `<span class="alert-status-badge scanning">🟢 Scanning</span>`;
        }

        let operatorCellContent = '';
        let condBadgeStyle = '';
        if (item.condition_type === 'COMPOUND') {
            condBadgeStyle = 'background: rgba(168, 85, 247, 0.2); color: #c084fc; border: 1px solid rgba(168, 85, 247, 0.4); font-size:10px; cursor: default; position: relative;';
            try {
                const condList = JSON.parse(item.value);
                const parts = condList.map(c => {
                    if (c.operator && !c.indicator) {
                        return ` <span class="logical-op" style="color: #c084fc; font-weight: bold;">${c.operator}</span> `;
                    }
                    return `${c.indicator} ${c.operator} ${c.value}`;
                });
                operatorCellContent = parts.join('');
            } catch (err) {
                operatorCellContent = item.value;
            }
        } else {
            condBadgeStyle = 'font-size:10px; cursor: default; position: relative;';
            operatorCellContent = `${item.operator} ${item.value}`;
        }

        tr.innerHTML = `
            <td><a href="#" class="alert-stock-link" data-ticker="${item.ticker}" title="Open in Equity Research Terminal" style="color: var(--color-primary-light); text-decoration: none; font-weight: 700; cursor: pointer; border-bottom: 1px dashed rgba(59,130,246,0.3); transition: all 0.2s ease;">${item.ticker}</a></td>
            <td><span class="badge-ticker alert-condition-badge" style="${condBadgeStyle}" title="${item.condition_type}">${item.condition_type}</span></td>
            <td style="font-family: monospace; font-size:12px; font-weight:600;">${operatorCellContent}</td>
            <td>${statusBadge}</td>
            <td class="rs-hide-mobile"><span class="text-muted" style="font-size:11px;">${item.trigger_date || 'Active scan...'}</span></td>
            <td>
                <button class="btn-translucent-delete" data-id="${item.id}">Delete 🗑️</button>
            </td>
        `;

        // Make stock ticker clickable → navigate to Equity Research Terminal
        const stockLink = tr.querySelector('.alert-stock-link');
        if (stockLink) {
            stockLink.addEventListener('click', (e) => {
                e.preventDefault();
                const ticker = stockLink.getAttribute('data-ticker');
                loadStockAnalyzer(ticker);
            });
            stockLink.addEventListener('mouseenter', () => {
                stockLink.style.color = '#60a5fa';
                stockLink.style.borderBottomColor = 'rgba(96,165,250,0.6)';
            });
            stockLink.addEventListener('mouseleave', () => {
                stockLink.style.color = 'var(--color-primary-light)';
                stockLink.style.borderBottomColor = 'rgba(59,130,246,0.3)';
            });
        }

        tr.querySelector('.btn-translucent-delete').addEventListener('click', async () => {
            if (confirm(`Are you sure you want to delete alert #${item.id}?`)) {
                try {
                    const response = await fetch(`/api/alerts/${item.id}`, { method: 'DELETE' });
                    if (!response.ok) throw new Error("Failed to delete alert.");
                    showToast("Alert successfully deleted.", "success");
                    fetchAlertsList();
                } catch (e) {
                    showToast("Failed to delete alert: " + e.message, "error");
                }
            }
        });

        tbody.appendChild(tr);

        if (item.ai_context) {
            const trWarning = document.createElement('tr');
            trWarning.className = 'ai-warning-row';
            trWarning.innerHTML = `
                <td colspan="6" style="padding: 6px 12px; background: rgba(239, 68, 68, 0.04); border-top: none;">
                    <div style="display: flex; align-items: flex-start; gap: 8px; font-size: 11px; line-height: 1.45; color: var(--text-primary);">
                        <span style="color: #ef4444; font-size: 12px; margin-top: 1px;">🤖</span>
                        <div>
                            <strong style="color: #ef4444; text-transform: uppercase; font-size: 9px; letter-spacing: 0.05em; display: block; margin-bottom: 2px;">AI Copilot Analysis</strong>
                            ${item.ai_context}
                        </div>
                    </div>
                </td>
            `;
            tbody.appendChild(trWarning);
        }
    });

    if (pagContainer) {
        document.getElementById('alerts-log-page-info').innerText = `Page ${page} of ${totalPages}`;
        document.getElementById('alerts-log-prev-btn').disabled = (page === 1);
        document.getElementById('alerts-log-next-btn').disabled = (page === totalPages);
        pagContainer.style.display = 'flex';
    }
}

function sortAlerts(col, toggle = true) {
    if (toggle) {
        if (alertsSortCol === col) {
            alertsSortAsc = !alertsSortAsc;
        } else {
            alertsSortCol = col;
            alertsSortAsc = true;
        }
    }

    lastAlertsList.sort((a, b) => {
        let valA = a[col];
        let valB = b[col];

        if (col === 'id') {
            valA = parseInt(valA) || 0;
            valB = parseInt(valB) || 0;
        } else if (col === 'value') {
            valA = parseFloat(valA) || 0;
            valB = parseFloat(valB) || 0;
        } else {
            valA = (valA || '').toString().toLowerCase();
            valB = (valB || '').toString().toLowerCase();
        }

        if (valA < valB) return alertsSortAsc ? -1 : 1;
        if (valA > valB) return alertsSortAsc ? 1 : -1;
        return 0;
    });

    updateAlertsHeaderIndicators();

    const totalPages = Math.ceil(lastAlertsList.length / alertsPageSize) || 1;
    if (activeAlertsPage > totalPages) {
        activeAlertsPage = totalPages;
    }
    renderAlertsPage(activeAlertsPage);
}

function updateAlertsHeaderIndicators() {
    const sortMappings = {
        'alerts-th-symbol': 'ticker',
        'alerts-th-condition': 'condition_type',
        'alerts-th-value': 'value',
        'alerts-th-status': 'status',
        'alerts-th-triggered': 'trigger_date'
    };

    Object.keys(sortMappings).forEach(thId => {
        const th = document.getElementById(thId);
        if (th) {
            const indicator = th.querySelector('.sort-indicator');
            if (indicator) {
                if (sortMappings[thId] === alertsSortCol) {
                    indicator.innerText = alertsSortAsc ? ' ▲' : ' ▼';
                    indicator.style.opacity = '1';
                } else {
                    indicator.innerText = '';
                    indicator.style.opacity = '0.3';
                }
            }
        }
    });
}

function setupAlertsTableSorting() {
    const sortMappings = {
        'alerts-th-id': 'id',
        'alerts-th-symbol': 'ticker',
        'alerts-th-condition': 'condition_type',
        'alerts-th-value': 'value',
        'alerts-th-status': 'status',
        'alerts-th-triggered': 'trigger_date'
    };

    Object.keys(sortMappings).forEach(thId => {
        const th = document.getElementById(thId);
        if (th) {
            th.addEventListener('click', () => {
                sortAlerts(sortMappings[thId]);
            });
        }
    });

    const prevBtn = document.getElementById('alerts-log-prev-btn');
    const nextBtn = document.getElementById('alerts-log-next-btn');
    if (prevBtn && nextBtn) {
        prevBtn.addEventListener('click', () => {
            if (activeAlertsPage > 1) {
                renderAlertsPage(activeAlertsPage - 1);
            }
        });
        nextBtn.addEventListener('click', () => {
            const totalPages = Math.ceil(alertsLogFilteredCount / alertsPageSize) || 1;
            if (activeAlertsPage < totalPages) {
                renderAlertsPage(activeAlertsPage + 1);
            }
        });
    }

    const pageSizeSelect = document.getElementById('alerts-log-pagesize-select');
    if (pageSizeSelect) {
        pageSizeSelect.addEventListener('change', (e) => {
            alertsPageSize = parseInt(e.target.value) || 10;
            activeAlertsPage = 1;
            renderAlertsPage(1);
        });
    }

    // Set up search and clear actions
    const searchInput = document.getElementById('alerts-log-search');
    const searchClear = document.getElementById('alerts-search-clear');
    if (searchInput) {
        searchInput.addEventListener('input', (e) => {
            alertsLogSearchQuery = e.target.value;
            if (searchClear) {
                searchClear.style.display = alertsLogSearchQuery ? 'block' : 'none';
            }
            activeAlertsPage = 1;
            renderAlertsPage(1);
        });
    }

    if (searchClear && searchInput) {
        searchClear.addEventListener('click', () => {
            searchInput.value = '';
            alertsLogSearchQuery = '';
            searchClear.style.display = 'none';
            activeAlertsPage = 1;
            renderAlertsPage(1);
            searchInput.focus();
        });
    }
}

async function checkAlertRules() {
    showLoader(
        "Scanning Alert Rules...",
        "Executing alert criteria scans against real-time financial metrics, historical PE floors, and RSI bands."
    );

    try {
        const response = await fetch('/api/alerts/check');
        const data = await response.json();

        renderAlertsList(data.alerts);

        if (data.triggers.length > 0) {
            // Play sound and show Emergency HUD
            playAlertSound();
            const hudMsg = data.triggers.join("<br>");
            showEmergencyHUD(hudMsg);

            showToast("ALERTS TRIGGERED: " + data.triggers.join(", "), "warning");
        } else {
            showToast("Alert scanning sweep complete. All asset conditions are currently holding within boundaries.", "success");
        }
    } catch (e) {
        showToast("Alert scanning failed: " + e.message, "error");
    } finally {
        hideLoader();
    }
}

