function setupRuleScanner() {
    // Sub-tab toggling
    setupRuleScannerSubtabs();

    // Strategy guide cheatsheet
    const conditionSelect = document.getElementById('rule-scanner-condition');
    if (conditionSelect) {
        conditionSelect.addEventListener('change', () => {
            const guide = document.getElementById('rule-scanner-strategy-text');
            if (guide) guide.innerHTML = RULE_SCANNER_STRATEGY_GUIDE[conditionSelect.value] || '';
        });
    }

    // NL template pills
    document.querySelectorAll('.rs-nl-template-pill').forEach(pill => {
        pill.addEventListener('click', () => {
            const textarea = document.getElementById('rule-scanner-nl-prompt');
            if (textarea) textarea.value = pill.getAttribute('data-template') || '';
        });
    });

    // NL Submit
    const nlSubmit = document.getElementById('rule-scanner-nl-submit');
    if (nlSubmit) nlSubmit.addEventListener('click', executeNLRuleScan);

    // Parametric Execute
    const execBtn = document.getElementById('rule-scanner-execute-btn');
    if (execBtn) execBtn.addEventListener('click', () => executeRuleScan());

    // Custom Screen Builder UI Actions
    const addRowBtn = document.getElementById('custom-screener-add-row-btn');
    if (addRowBtn) addRowBtn.addEventListener('click', () => addCustomScreenerRow());

    const execCustomBtn = document.getElementById('custom-screener-execute-btn');
    if (execCustomBtn) execCustomBtn.addEventListener('click', executeCustomScreenerScan);

    const saveBtn = document.getElementById('custom-screener-save-btn');
    if (saveBtn) saveBtn.addEventListener('click', saveCurrentScreen);

    const explainFormulaBtn = document.getElementById('custom-screener-explain-formula-btn');
    if (explainFormulaBtn) {
        explainFormulaBtn.addEventListener('click', explainCurrentFormula);
    }

    window.activeCustomScreenerMode = 'interactive';
    const modeInteractiveBtn = document.getElementById('custom-screener-mode-interactive-btn');
    const modeFormulaBtn = document.getElementById('custom-screener-mode-formula-btn');
    const interactiveSection = document.getElementById('custom-screener-interactive-section');
    const formulaSection = document.getElementById('custom-screener-formula-section');

    if (modeInteractiveBtn && modeFormulaBtn && interactiveSection && formulaSection) {
        modeInteractiveBtn.addEventListener('click', () => {
            window.activeCustomScreenerMode = 'interactive';
            modeInteractiveBtn.classList.add('active');
            modeInteractiveBtn.style.background = 'rgba(16, 185, 129, 0.1)';
            modeInteractiveBtn.style.borderColor = 'var(--border-glass)';
            modeInteractiveBtn.style.color = '#10b981';

            modeFormulaBtn.classList.remove('active');
            modeFormulaBtn.style.background = 'transparent';
            modeFormulaBtn.style.borderColor = 'transparent';
            modeFormulaBtn.style.color = 'var(--text-muted)';

            interactiveSection.style.display = 'flex';
            formulaSection.style.display = 'none';
        });

        modeFormulaBtn.addEventListener('click', () => {
            window.activeCustomScreenerMode = 'formula';
            modeFormulaBtn.classList.add('active');
            modeFormulaBtn.style.background = 'rgba(16, 185, 129, 0.1)';
            modeFormulaBtn.style.borderColor = 'var(--border-glass)';
            modeFormulaBtn.style.color = '#10b981';

            modeInteractiveBtn.classList.remove('active');
            modeInteractiveBtn.style.background = 'transparent';
            modeInteractiveBtn.style.borderColor = 'transparent';
            modeInteractiveBtn.style.color = 'var(--text-muted)';

            interactiveSection.style.display = 'none';
            formulaSection.style.display = 'flex';
        });
    }

    const loadExampleLink = document.getElementById('custom-screener-load-example-link');
    if (loadExampleLink) {
        loadExampleLink.addEventListener('click', () => {
            const formulaInput = document.getElementById('custom-screener-formula-input');
            if (formulaInput) {
                formulaInput.value =
                    "Daily Close * 1.05 > Daily Max ( 200 , Daily High )\n" +
                    "Daily Max ( 30 , Daily High ) <= 30 days ago Max ( 8 , Daily High )\n" +
                    "Daily Volume > Daily Sma ( Daily Volume , 50 )\n" +
                    "Daily Close > 90";
            }
        });
    }

    const rangeSelect = document.getElementById('rule-scanner-historical-range');
    if (rangeSelect) {
        rangeSelect.addEventListener('change', () => {
            const activeCondEl = document.getElementById('rule-scanner-active-condition');
            if (activeCondEl && activeCondEl.textContent.includes('Custom Screen')) {
                executeCustomScreenerScan();
            }
        });
    }

    // Load initial screens registry & add first empty row
    loadSavedScreens();
    const rulesList = document.getElementById('custom-screener-rules-list');
    if (rulesList && rulesList.children.length === 0) {
        addCustomScreenerRow();
    }

    // Sorting
    document.querySelectorAll('.rs-sortable').forEach(th => {
        th.addEventListener('click', () => {
            const col = th.getAttribute('data-sort');
            if (ruleScanSortCol === col) {
                ruleScanSortAsc = !ruleScanSortAsc;
            } else {
                ruleScanSortCol = col;
                ruleScanSortAsc = true;
            }
            ruleScanPage = 1;
            renderRuleScanResults();
        });
    });

    // Pagination
    const prevBtn = document.getElementById('rule-scanner-prev-btn');
    const nextBtn = document.getElementById('rule-scanner-next-btn');
    const pageSizeSelect = document.getElementById('rule-scanner-pagesize-select');
    if (prevBtn) prevBtn.addEventListener('click', () => { if (ruleScanPage > 1) { ruleScanPage--; renderRuleScanResults(); } });
    if (nextBtn) nextBtn.addEventListener('click', () => { ruleScanPage++; renderRuleScanResults(); });
    if (pageSizeSelect) pageSizeSelect.addEventListener('change', () => { ruleScanPageSize = parseInt(pageSizeSelect.value); ruleScanPage = 1; renderRuleScanResults(); });

    // Filter sliders
    const scoreSlider = document.getElementById('rule-scanner-filter-score');
    const deSlider = document.getElementById('rule-scanner-filter-de');
    if (scoreSlider) scoreSlider.addEventListener('input', () => {
        ruleScanFilterMinScore = parseInt(scoreSlider.value);
        const scoreVal = document.getElementById('rule-scanner-filter-score-val');
        if (scoreVal) scoreVal.textContent = ruleScanFilterMinScore;
        ruleScanPage = 1;
        renderRuleScanResults();
    });
    if (deSlider) deSlider.addEventListener('input', () => {
        ruleScanFilterMaxDE = parseInt(deSlider.value);
        const deVal = document.getElementById('rule-scanner-filter-de-val');
        if (deVal) deVal.textContent = (ruleScanFilterMaxDE / 100).toFixed(1);
        ruleScanPage = 1;
        renderRuleScanResults();
    });

    // Export buttons
    const copyBtn = document.getElementById('rule-scanner-copy-btn');
    const printBtn = document.getElementById('rule-scanner-print-btn');
    const csvBtn = document.getElementById('rule-scanner-export-csv-btn');
    const watchlistBtn = document.getElementById('rule-scanner-save-watchlist-btn');
    if (copyBtn) copyBtn.addEventListener('click', copyRuleScanTable);
    if (printBtn) printBtn.addEventListener('click', printRuleScanReport);
    if (csvBtn) csvBtn.addEventListener('click', exportRuleScanCSV);
    if (watchlistBtn) watchlistBtn.addEventListener('click', saveRuleScanAsWatchlist);

    // Formula helper chips click bindings
    document.querySelectorAll('.formula-helper-chip').forEach(chip => {
        chip.addEventListener('click', () => {
            const textarea = document.getElementById('custom-screener-formula-input');
            if (!textarea) return;
            const insertVal = chip.getAttribute('data-insert') || '';

            // Insert at cursor position or append
            const startPos = textarea.selectionStart;
            const endPos = textarea.selectionEnd;
            const text = textarea.value;

            if (startPos !== undefined) {
                textarea.value = text.substring(0, startPos) + insertVal + text.substring(endPos);
                textarea.selectionStart = startPos + insertVal.length;
                textarea.selectionEnd = startPos + insertVal.length;
            } else {
                textarea.value += (textarea.value ? " " : "") + insertVal;
            }
            textarea.focus();
            validateFormulaSyntax(textarea.value);
        });
    });

    // Live syntax validation
    const formulaInput = document.getElementById('custom-screener-formula-input');
    if (formulaInput) {
        formulaInput.addEventListener('input', (e) => {
            validateFormulaSyntax(e.target.value);
        });
        // Run initial validation on load
        validateFormulaSyntax(formulaInput.value);
    }
}

function validateFormulaSyntax(text) {
    const badge = document.getElementById('formula-syntax-badge');
    if (!badge) return;

    const trimmed = text.trim();
    if (!trimmed) {
        badge.innerText = 'EMPTY CODE ⚪';
        badge.className = 'rs-validator-badge';
        badge.style.background = 'rgba(255,255,255,0.05)';
        badge.style.border = '1px solid rgba(255,255,255,0.1)';
        badge.style.color = 'var(--text-muted)';
        return;
    }

    // Check parentheses matching
    let openCount = 0;
    for (let char of trimmed) {
        if (char === '(') openCount++;
        else if (char === ')') openCount--;
        if (openCount < 0) {
            badge.innerText = 'SYNTAX ERROR 🔴';
            badge.className = 'rs-validator-badge syntax-invalid';
            return;
        }
    }

    if (openCount !== 0) {
        badge.innerText = 'UNBALANCED PARENS 🔴';
        badge.className = 'rs-validator-badge syntax-invalid';
        return;
    }

    // Split into lines and check comparison syntax
    const lines = trimmed.split('\n').map(l => l.trim()).filter(l => l && !l.startsWith('//') && !l.startsWith('#'));
    let hasComparison = false;
    const operatorRegex = />|<|>=|<=|==|!=/;

    for (let line of lines) {
        if (operatorRegex.test(line)) {
            hasComparison = true;
        }
    }

    if (lines.length > 0 && !hasComparison) {
        badge.innerText = 'MISSING OPERATOR 🔴';
        badge.className = 'rs-validator-badge syntax-invalid';
        return;
    }

    badge.innerText = 'VALID SYNTAX 🟢';
    badge.className = 'rs-validator-badge syntax-valid';
}

async function executeNLRuleScan() {
    const prompt = document.getElementById('rule-scanner-nl-prompt')?.value?.trim();
    if (!prompt) return;

    showLoader(
        "AI Scan Command Radar",
        ((window.llmConfig ? window.llmConfig.fast_label : "AI Copilot") + " is parsing prompt requirements and compiling logic conditions..."),
        true,
        [
            { threshold: 15, msg: `[INFO] Sending query prompt to AI: "${prompt}"...`, color: '#38bdf8' },
            { threshold: 30, msg: "[INFO] Parsing NLP tokens and mapping fields...", color: '#f59e0b' },
            { threshold: 45, msg: "[INFO] Resolving cap type and logic parameters...", color: '#a855f7' }
        ]
    );

    try {
        const res = await fetch('/api/screener/parse-nl-scan', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ prompt })
        });
        const data = await res.json();
        if (data.status === 'success') {
            // Update loader step, then continue to run scan
            const progressConsole = document.getElementById('global-loader-progress-console');
            if (progressConsole) {
                const line = document.createElement('div');
                line.style.color = '#c084fc';
                line.innerText = `[INFO] Resolved AI conditions: ${data.condition_type} ${data.operator} ${data.value} on ${data.universe}`;
                progressConsole.appendChild(line);
                progressConsole.scrollTop = progressConsole.scrollHeight;
            }
            await executeRuleScan(data.condition_type, data.operator, data.value, data.universe, true);
        } else {
            hideLoader();
            showToast('AI parsing failed: ' + (data.detail || 'Unknown error'), 'error');
        }
    } catch (err) {
        hideLoader();
        showToast('Failed to parse scan prompt: ' + err.message, 'error');
    }
}

async function executeRuleScan(cond, op, val, uni, isAIScan = false) {
    const condition = cond || document.getElementById('rule-scanner-condition')?.value || 'RSI';
    const operator = op || document.getElementById('rule-scanner-operator')?.value || '<';
    const value = val !== undefined ? val : (document.getElementById('rule-scanner-value')?.value || '30');
    const universe = uni || document.getElementById('rule-scanner-universe')?.value || 'all';

    // Reset Min Score and Max D/E filters for new scan
    ruleScanFilterMinScore = 0;
    ruleScanFilterMaxDE = 500;
    const scoreSlider = document.getElementById('rule-scanner-filter-score');
    if (scoreSlider) scoreSlider.value = 0;
    const deSlider = document.getElementById('rule-scanner-filter-de');
    if (deSlider) deSlider.value = 500;
    const scoreVal = document.getElementById('rule-scanner-filter-score-val');
    if (scoreVal) scoreVal.textContent = 0;
    const deVal = document.getElementById('rule-scanner-filter-de-val');
    if (deVal) deVal.textContent = "5.0";

    // Reset AI Scan Analyst Synthesis
    const synthesisPanel = document.getElementById('rule-scanner-synthesis-panel');
    const synthesisText = document.getElementById('rule-scanner-synthesis-text');
    if (synthesisPanel) synthesisPanel.style.display = 'none';
    if (synthesisText) synthesisText.innerHTML = '';

    // Update telemetry
    const engineStatus = document.getElementById('rule-scanner-engine-status');
    if (engineStatus) { engineStatus.textContent = 'SCANNING...'; engineStatus.style.color = '#f59e0b'; }

    const readableCond = RULE_SCANNER_COND_LABELS[condition] || condition;
    let detailText = "";
    if (condition.startsWith("COMBO_")) {
        detailText = `${readableCond} (Universe: ${universe.toUpperCase()})`;
    } else {
        const opSymbol = operator === "==" ? "=" : operator;
        detailText = `${readableCond} ${opSymbol} ${value} (Universe: ${universe.toUpperCase()})`;
    }
    const activeCond = document.getElementById('rule-scanner-active-condition');
    if (activeCond) activeCond.textContent = detailText;

    if (isAIScan) {
        // Append additional telemetry steps to existing AI loader
        const progressConsole = document.getElementById('global-loader-progress-console');
        if (progressConsole) {
            const line1 = document.createElement('div');
            line1.style.color = '#e2e8f0';
            line1.innerText = `[INFO] Querying Screener SQLite index partitions...`;
            progressConsole.appendChild(line1);

            const line2 = document.createElement('div');
            line2.style.color = '#e2e8f0';
            line2.innerText = `[INFO] Sweeping universe for matching indicators...`;
            progressConsole.appendChild(line2);
            progressConsole.scrollTop = progressConsole.scrollHeight;
        }
    } else {
        // Show new parametric loader
        showLoader(
            `Executing Parametric Scan: ${readableCond}`,
            `Searching the stock universe for equities matching filter logic.`,
            true,
            [
                { threshold: 15, msg: "[INFO] Compiling rule parameters and logic gates...", color: '#38bdf8' },
                { threshold: 40, msg: `[INFO] Targeting universe index partition: ${universe.toUpperCase()}...`, color: '#f59e0b' },
                { threshold: 65, msg: `[INFO] Loading pre-calculated technical profiles for ${condition}...`, color: '#a855f7' },
                { threshold: 85, msg: `[INFO] Evaluating 380+ stock rows against filter criteria...`, color: '#10b981' }
            ]
        );
    }

    try {
        const params = new URLSearchParams({ condition_type: condition, operator, value, universe });
        const res = await fetch(`/api/screener/scan-trigger?${params}`);
        const data = await res.json();

        if (data.status === 'success') {
            ruleScanAllResults = data.results || [];
            lastRuleScanResults = [...ruleScanAllResults];
            ruleScanPage = 1;

            // Update telemetry
            const scannedCount = document.getElementById('rule-scanner-scanned-count');
            if (scannedCount) scannedCount.textContent = data.scanned || 0;
            const matchedCount = document.getElementById('rule-scanner-matched-count');
            if (matchedCount) matchedCount.textContent = data.matched || 0;
            if (engineStatus) { engineStatus.textContent = 'COMPLETE'; engineStatus.style.color = '#10b981'; }

            // Show results card and telemetry row
            const card = document.getElementById('rule-scanner-results-card');
            if (card) card.style.display = 'flex';
            const telRow = document.getElementById('rule-scanner-results-telemetry-row');
            if (telRow) telRow.style.display = 'grid';

            // Update subtitle
            const subtitle = document.getElementById('rule-scanner-results-subtitle');
            if (subtitle) subtitle.textContent = `${data.matched} matches from ${data.scanned} scanned • ${data.condition}`;

            renderRuleScanResults();
            renderRuleScanSectorConcentration(ruleScanAllResults);

            // Draw dynamic SVG charts
            const telGrid = document.getElementById('rule-scanner-telemetry-grid');
            if (telGrid) telGrid.style.display = 'grid';
            drawRSCapRiskDiagnostic(ruleScanAllResults);
            drawRSValuationQualityMatrix(ruleScanAllResults);
            drawRSKPIHeatmap(ruleScanAllResults);

            // Trigger AI synthesis
            if (ruleScanAllResults.length > 0) {
                requestRuleScanSynthesis(ruleScanAllResults, `${condition} ${operator} ${value} (Universe: ${universe})`);
            }

            // Complete loader progress bar
            const progressBar = document.getElementById('global-loader-progress-bar');
            const progressConsole = document.getElementById('global-loader-progress-console');
            if (progressBar) progressBar.style.width = '100%';
            if (progressConsole) {
                const line = document.createElement('div');
                line.style.color = 'var(--color-emerald)';
                line.style.fontWeight = 'bold';
                line.innerText = `[SUCCESS] Scan execution complete! Found ${data.matched} matching candidates.`;
                progressConsole.appendChild(line);
                progressConsole.scrollTop = progressConsole.scrollHeight;
            }

            setTimeout(() => {
                hideLoader();
            }, 650);
        } else {
            hideLoader();
            showToast('Scan failed: ' + (data.detail || 'Unknown error'), 'error');
            if (engineStatus) { engineStatus.textContent = 'ERROR'; engineStatus.style.color = '#ef4444'; }
        }
    } catch (err) {
        hideLoader();
        showToast('Rule scan failed: ' + err.message, 'error');
        if (engineStatus) { engineStatus.textContent = 'ERROR'; engineStatus.style.color = '#ef4444'; }
    }
}

function renderRuleScanResults() {
    // Apply filters
    let filtered = ruleScanAllResults.filter(r => {
        if (ruleScanFilterMinScore > 0 && (r.score || 0) < ruleScanFilterMinScore) return false;
        if (ruleScanFilterMaxDE < 500 && (r.de_ratio || 0) > (ruleScanFilterMaxDE / 100)) return false;
        return true;
    });

    // Sort
    filtered.sort((a, b) => {
        let va = a[ruleScanSortCol], vb = b[ruleScanSortCol];
        if (typeof va === 'string') va = va.toLowerCase();
        if (typeof vb === 'string') vb = vb.toLowerCase();
        if (va < vb) return ruleScanSortAsc ? -1 : 1;
        if (va > vb) return ruleScanSortAsc ? 1 : -1;
        return 0;
    });

    lastRuleScanResults = filtered;

    // Paginate
    const totalPages = Math.max(1, Math.ceil(filtered.length / ruleScanPageSize));
    if (ruleScanPage > totalPages) ruleScanPage = totalPages;
    const start = (ruleScanPage - 1) * ruleScanPageSize;
    const pageSlice = filtered.slice(start, start + ruleScanPageSize);

    const tbody = document.getElementById('rule-scanner-results-body');
    if (!tbody) return;

    if (pageSlice.length === 0) {
        tbody.innerHTML = '<tr><td colspan="8" class="center-text text-muted">No matches found for the current filter settings.</td></tr>';
    } else {
        tbody.innerHTML = pageSlice.map((r, idx) => {
            const globalIdx = start + idx;
            const ratingClass = (r.rating || '').includes('BUY') ? 'green-text' : ((r.rating || '').includes('SELL') ? 'red-text' : 'yellow-text');
            const canvasId = `rs-sparkline-${globalIdx}`;
            return `<tr style="border-bottom: 1px solid rgba(255,255,255,0.04); transition: background 0.15s;" onmouseenter="this.style.background='rgba(255,255,255,0.03)'" onmouseleave="this.style.background='transparent'">
                <td style="padding: 10px 8px;">
                    <div style="display: flex; flex-direction: column; gap: 2px;">
                        <span style="font-weight: 700; font-size: 12px; color: var(--text-primary); cursor: pointer;" onclick="window.loadStockAnalyzer('${r.symbol}')">${(r.symbol || '').replace('.NS','')}</span>
                        <span style="font-size: 9px; color: var(--text-muted); max-width: 140px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;">${r.company_name || ''}</span>
                    </div>
                </td>
                <td class="rs-hide-mobile" style="padding: 10px 8px; font-size: 11px; color: var(--text-secondary);">${r.cap_type || 'N/A'}</td>
                <td style="padding: 10px 8px; font-size: 11.5px; font-weight: 600; color: var(--text-primary);">₹${(r.price || 0).toLocaleString('en-IN')}</td>
                <td class="rs-hide-mobile" style="padding: 10px 8px; font-size: 11px; color: var(--text-secondary);">${r.pe > 0 ? r.pe.toFixed(1) : 'N/A'}</td>
                <td style="padding: 10px 8px;"><canvas id="${canvasId}" width="80" height="28" style="display: block;"></canvas></td>
                <td style="padding: 10px 8px; font-size: 10.5px; color: var(--color-primary); font-weight: 600; max-width: 180px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;" title="${r.trigger_value || ''}">${r.trigger_value || 'N/A'}</td>
                <td style="padding: 10px 8px;"><span class="${ratingClass}" style="font-size: 10.5px; font-weight: 700;">${r.rating || 'N/A'}</span></td>
                <td class="rs-hide-mobile" style="padding: 10px 8px; font-size: 10.5px; color: var(--text-secondary);">${r.sector || 'N/A'}</td>
            </tr>`;
        }).join('');

        // Draw sparklines
        setTimeout(() => {
            pageSlice.forEach((r, idx) => {
                const globalIdx = start + idx;
                drawRuleScanSparkline(`rs-sparkline-${globalIdx}`, r);
            });
        }, 50);
    }

    // Update pagination controls
    const pageInfo = document.getElementById('rule-scanner-page-info');
    const prevBtn = document.getElementById('rule-scanner-prev-btn');
    const nextBtn = document.getElementById('rule-scanner-next-btn');
    const pagination = document.getElementById('rule-scanner-pagination');

    if (pageInfo) pageInfo.textContent = `Page ${ruleScanPage} of ${totalPages} (${filtered.length} results)`;
    if (prevBtn) prevBtn.disabled = (ruleScanPage <= 1);
    if (nextBtn) nextBtn.disabled = (ruleScanPage >= totalPages);
    if (pagination) pagination.style.display = filtered.length > ruleScanPageSize ? 'flex' : 'none';

    // Update sort indicators
    document.querySelectorAll('.rs-sortable').forEach(th => {
        const col = th.getAttribute('data-sort');
        const text = th.textContent.replace(/ [↑↓↕]/g, '');
        if (col === ruleScanSortCol) {
            th.textContent = text + (ruleScanSortAsc ? ' ↑' : ' ↓');
        } else {
            th.textContent = text + ' ↕';
        }
    });
}

function drawRuleScanSparkline(canvasId, stockData) {
    const canvas = document.getElementById(canvasId);
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    const w = canvas.width, h = canvas.height;
    ctx.clearRect(0, 0, w, h);

    // Generate synthetic sparkline from RSI and price data
    const rsi = stockData.rsi || 50;
    const price = stockData.price || 100;
    const pe = stockData.pe || 20;

    // Create a pseudo-random but deterministic sparkline based on stock symbol hash
    const seed = (stockData.symbol || 'X').split('').reduce((acc, c) => acc + c.charCodeAt(0), 0);
    const points = [];
    let val = price;
    for (let i = 0; i < 20; i++) {
        const noise = Math.sin(seed * (i + 1) * 0.1) * (price * 0.03) + Math.cos(seed * i * 0.07) * (price * 0.02);
        val = val + noise;
        points.push(val);
    }
    points.push(price); // End at current price

    const minVal = Math.min(...points);
    const maxVal = Math.max(...points);
    const range = maxVal - minVal || 1;

    const isPositive = points[points.length - 1] >= points[0];
    const gradient = ctx.createLinearGradient(0, 0, w, 0);
    if (isPositive) {
        gradient.addColorStop(0, 'rgba(16, 185, 129, 0.4)');
        gradient.addColorStop(1, 'rgba(16, 185, 129, 1.0)');
    } else {
        gradient.addColorStop(0, 'rgba(239, 68, 68, 0.4)');
        gradient.addColorStop(1, 'rgba(239, 68, 68, 1.0)');
    }

    ctx.strokeStyle = gradient;
    ctx.lineWidth = 1.5;
    ctx.lineJoin = 'round';
    ctx.beginPath();

    for (let i = 0; i < points.length; i++) {
        const x = (i / (points.length - 1)) * w;
        const y = h - ((points[i] - minVal) / range) * (h - 4) - 2;
        if (i === 0) ctx.moveTo(x, y);
        else ctx.lineTo(x, y);
    }
    ctx.stroke();

    // Fill area under curve
    const fillGradient = ctx.createLinearGradient(0, 0, 0, h);
    if (isPositive) {
        fillGradient.addColorStop(0, 'rgba(16, 185, 129, 0.15)');
        fillGradient.addColorStop(1, 'rgba(16, 185, 129, 0.0)');
    } else {
        fillGradient.addColorStop(0, 'rgba(239, 68, 68, 0.15)');
        fillGradient.addColorStop(1, 'rgba(239, 68, 68, 0.0)');
    }
    ctx.lineTo(w, h);
    ctx.lineTo(0, h);
    ctx.closePath();
    ctx.fillStyle = fillGradient;
    ctx.fill();
}

function renderRuleScanSectorConcentration(results) {
    const container = document.getElementById('rule-scanner-sector-bars');
    if (!container) return;

    const sectorCounts = {};
    results.forEach(r => {
        const sector = r.sector || 'Unknown';
        sectorCounts[sector] = (sectorCounts[sector] || 0) + 1;
    });

    const sorted = Object.entries(sectorCounts).sort((a, b) => b[1] - a[1]);
    const maxCount = sorted.length > 0 ? sorted[0][1] : 1;

    const SECTOR_COLORS = [
        '#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6',
        '#ec4899', '#06b6d4', '#84cc16', '#f97316', '#6366f1',
        '#14b8a6', '#e11d48', '#a855f7', '#0ea5e9'
    ];

    if (sorted.length === 0) {
        container.innerHTML = '<p class="helper-text" style="margin: 0; font-size: 11px;">No sector data available.</p>';
        return;
    }

    container.innerHTML = sorted.slice(0, 10).map(([sector, count], i) => {
        const pct = (count / results.length * 100).toFixed(1);
        const barPct = (count / maxCount * 100).toFixed(0);
        const color = SECTOR_COLORS[i % SECTOR_COLORS.length];
        return `<div style="display: flex; align-items: center; gap: 8px;">
            <span style="font-size: 9.5px; color: var(--text-secondary); min-width: 90px; max-width: 90px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;" title="${sector}">${sector}</span>
            <div style="flex: 1; height: 8px; background: rgba(255,255,255,0.05); border-radius: 4px; overflow: hidden;">
                <div style="height: 100%; width: ${barPct}%; background: ${color}; border-radius: 4px; transition: width 0.6s cubic-bezier(0.22, 1, 0.36, 1);"></div>
            </div>
            <span style="font-size: 9px; color: var(--text-muted); min-width: 36px; text-align: right;">${count} (${pct}%)</span>
        </div>`;
    }).join('');
}

async function requestRuleScanSynthesis(results, conditionDesc) {
    const panel = document.getElementById('rule-scanner-synthesis-panel');
    const textEl = document.getElementById('rule-scanner-synthesis-text');
    if (!panel || !textEl) return;

    panel.style.display = 'block';
    textEl.innerHTML = `
        <div style="display: flex; align-items: center; gap: 10px; padding: 5px 0;">
            <button id="trigger-scan-synthesis-btn" class="action-btn" style="background: rgba(168, 85, 247, 0.15); color: #c084fc; border: 1px solid rgba(168, 85, 247, 0.3); padding: 6px 12px; font-size: 11px; border-radius: 4px; cursor: pointer; transition: all 0.2s; font-family: 'Outfit', sans-serif; font-weight: 600;">
                🧠 Generate AI Synthesis Report
            </button>
            <span style="font-size: 10px; color: var(--text-muted);">Click to analyze top 20 constituents and summarize key risks.</span>
        </div>
    `;

    document.getElementById('trigger-scan-synthesis-btn').addEventListener('click', async () => {
        textEl.innerHTML = '<span style="color: #a855f7; font-size: 11px; font-family: \'Inter\', sans-serif;">🔬 AI analyst synthesizing scan results...</span>';
        try {
            const res = await fetch('/api/screener/scan-synthesis', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ results: results.slice(0, 20), condition_desc: conditionDesc })
            });
            const data = await res.json();
            if (data.status === 'success') {
                textEl.textContent = data.synthesis || 'No synthesis generated.';
            } else {
                textEl.textContent = 'Synthesis generation encountered an error.';
            }
        } catch (err) {
            textEl.textContent = 'Failed to generate synthesis: ' + err.message;
        }
    });
}

// Export functions
function copyRuleScanTable() {
    if (lastRuleScanResults.length === 0) return showToast('No results to copy', 'warning');
    const header = 'Symbol\tCompany\tSegment\tPrice\tP/E\tTrigger\tRating\tSector\tScore\tD/E';
    const rows = lastRuleScanResults.map(r =>
        `${(r.symbol||'').replace('.NS','')}\t${r.company_name||''}\t${r.cap_type||''}\t${r.price||''}\t${r.pe||''}\t${r.trigger_value||''}\t${r.rating||''}\t${r.sector||''}\t${r.score||''}\t${r.de_ratio||''}`
    );
    navigator.clipboard.writeText([header, ...rows].join('\n')).then(() => showToast('Table copied to clipboard', 'success'));
}

function exportRuleScanCSV() {
    if (lastRuleScanResults.length === 0) return showToast('No results to export', 'warning');
    const header = 'Symbol,Company,Segment,Price,PE,Trigger,Rating,Sector,Score,DE_Ratio';
    const rows = lastRuleScanResults.map(r =>
        `"${(r.symbol||'').replace('.NS','')}","${r.company_name||''}","${r.cap_type||''}",${r.price||''},${r.pe||''},"${r.trigger_value||''}","${r.rating||''}","${r.sector||''}",${r.score||''},${r.de_ratio||''}`
    );
    const csvContent = [header, ...rows].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `rule_scan_results_${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
    URL.revokeObjectURL(url);
    showToast('CSV exported successfully', 'success');
}

function printRuleScanReport() {
    if (lastRuleScanResults.length === 0) return showToast('No results to print', 'warning');
    const originalTitle = document.title;
    const condText = document.getElementById('rule-scanner-active-condition')?.textContent || 'Rule Scan';
    document.title = `Rule Scanner Report — ${condText}`;
    document.body.classList.add('is-printing-rule-scan');
    setTimeout(() => {
        window.print();
        setTimeout(() => {
            document.body.classList.remove('is-printing-rule-scan');
            document.title = originalTitle;
        }, 1000);
    }, 150);
}

async function saveRuleScanAsWatchlist() {
    if (lastRuleScanResults.length === 0) return showToast('No results to save', 'warning');
    const condText = document.getElementById('rule-scanner-active-condition')?.textContent || 'Rule Scan';
    const name = `Rule Scan: ${condText} (${new Date().toLocaleDateString()})`;

    try {
        const createRes = await fetch('/api/watchlists', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ name })
        });
        const createData = await createRes.json();
        if (createData.id) {
            for (const r of lastRuleScanResults.slice(0, 50)) {
                await fetch(`/api/watchlists/${createData.id}/items`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ symbol: r.symbol || '' })
                });
            }
            showToast(`Saved ${Math.min(lastRuleScanResults.length, 50)} stocks as watchlist "${name}"`, 'success');
        }
    } catch (err) {
        showToast('Failed to save watchlist: ' + err.message, 'error');
    }
}

function setupRuleScannerSubtabs() {
    const aiBtn = document.getElementById('rule-scanner-tab-ai-btn');
    const parametricBtn = document.getElementById('rule-scanner-tab-parametric-btn');
    const customBtn = document.getElementById('rule-scanner-tab-custom-btn');

    const aiPanel = document.getElementById('rule-scanner-panel-ai');
    const parametricPanel = document.getElementById('rule-scanner-panel-parametric');
    const customPanel = document.getElementById('rule-scanner-panel-custom');

    const btns = [aiBtn, parametricBtn, customBtn];
    const panels = [aiPanel, parametricPanel, customPanel];

    btns.forEach((btn, idx) => {
        if (btn) {
            btn.addEventListener('click', () => {
                btns.forEach(b => {
                    if (b) {
                        b.classList.remove('active');
                        b.style.border = '1px solid transparent';
                        b.style.background = 'transparent';
                        b.style.color = 'var(--text-muted)';
                    }
                });
                panels.forEach(p => {
                    if (p) p.style.display = 'none';
                });

                btn.classList.add('active');
                btn.style.border = '1px solid var(--border-glass)';
                btn.style.background = 'rgba(255,255,255,0.03)';
                btn.style.color = 'var(--text-primary)';
                if (panels[idx]) panels[idx].style.display = 'block';

                // Hide old results card, telemetry cards row, and historical chart card when switching sub-tabs
                const resultsCard = document.getElementById('rule-scanner-results-card');
                if (resultsCard) resultsCard.style.display = 'none';
                const telemetryRow = document.getElementById('rule-scanner-results-telemetry-row');
                if (telemetryRow) telemetryRow.style.display = 'none';
                const chartCard = document.getElementById('rule-scanner-historical-chart-card');
                if (chartCard) chartCard.style.display = 'none';
            });
        }
    });
}

function addCustomScreenerRow(data = null) {
    const list = document.getElementById('custom-screener-rules-list');
    if (!list) return;

    const row = document.createElement('div');
    row.className = 'custom-screener-rule-row';

    // 1. Timeframe
    const tfSelect = document.createElement('select');
    tfSelect.className = 'rule-timeframe';
    tfSelect.innerHTML = `
        <option value="1d">Daily</option>
        <option value="1wk">Weekly</option>
        <option value="1mo">Monthly</option>
    `;
    if (data && data.timeframe) tfSelect.value = data.timeframe;

    // 1.5. Offset (Bars Ago)
    const offsetInput = document.createElement('input');
    offsetInput.type = 'number';
    offsetInput.className = 'rule-offset';
    offsetInput.min = '0';
    offsetInput.value = data && data.offset !== undefined ? data.offset : '0';
    offsetInput.placeholder = 'Ago';
    offsetInput.title = 'Offset: number of bars/days ago to evaluate';

    // 2. Left Indicator
    const indSelect = document.createElement('select');
    indSelect.className = 'rule-indicator';
    indSelect.innerHTML = `
        <option value="PRICE">Price</option>
        <option value="VOLUME">Volume</option>
        <option value="VOL_BREAKOUT">Volume Ratio</option>
        <option value="RSI">RSI-14</option>
        <option value="SMA50">SMA-50</option>
        <option value="SMA200">SMA-200</option>
        <option value="EMA50">EMA-50</option>
        <option value="EMA200">EMA-200</option>
        <option value="BB_UPPER">Bollinger Upper</option>
        <option value="BB_LOWER">Bollinger Lower</option>
        <option value="MACD">MACD</option>
        <option value="MACD_SIGNAL">MACD Signal</option>
        <option value="PE">P/E Ratio</option>
        <option value="DE_RATIO">Debt-to-Equity</option>
        <option value="SCORE">AI Score</option>
        <option value="RATING">AI Rating</option>
    `;
    if (data && data.indicator) indSelect.value = data.indicator;

    // 3. Operator
    const opSelect = document.createElement('select');
    opSelect.className = 'rule-operator';
    opSelect.innerHTML = `
        <option value="<">&lt; Less Than</option>
        <option value=">">&gt; Greater Than</option>
        <option value="==">= Equals</option>
        <option value="<=">&lt;= Less Or Equal</option>
        <option value=">=">&gt;= Greater Or Equal</option>
        <option value="!=">!= Not Equal</option>
    `;
    if (data && data.operator) opSelect.value = data.operator;

    // 4. Value Type (Constant vs Indicator)
    const valTypeSelect = document.createElement('select');
    valTypeSelect.className = 'rule-val-type';
    valTypeSelect.innerHTML = `
        <option value="constant">Constant</option>
        <option value="indicator">Indicator</option>
    `;

    // 5. Value Container
    const valContainer = document.createElement('div');
    valContainer.className = 'rule-val-container';

    // Determine initial state based on data.value
    let isInd = false;
    const indicatorList = ["PRICE", "VOLUME", "VOL_BREAKOUT", "RSI", "SMA50", "SMA200", "EMA50", "EMA200", "BB_UPPER", "BB_LOWER", "MACD", "MACD_SIGNAL", "PE", "DE_RATIO", "SCORE", "RATING"];
    if (data && indicatorList.includes(String(data.value).toUpperCase().trim())) {
        isInd = true;
    }

    if (isInd) {
        valTypeSelect.value = 'indicator';
        valContainer.innerHTML = createIndicatorSelector(data.value);
    } else {
        valTypeSelect.value = 'constant';
        const initialVal = data ? data.value : '30';
        valContainer.innerHTML = `<input type="text" class="rule-val-input" value="${initialVal}" placeholder="e.g. 30">`;
    }

    // Toggle logic for valTypeSelect
    valTypeSelect.addEventListener('change', () => {
        if (valTypeSelect.value === 'indicator') {
            valContainer.innerHTML = createIndicatorSelector();
        } else {
            valContainer.innerHTML = `<input type="text" class="rule-val-input" value="30" placeholder="e.g. 30">`;
        }
    });

    // 5.5. Threshold % (Proximity Buffer)
    const thresholdInput = document.createElement('input');
    thresholdInput.type = 'number';
    thresholdInput.className = 'rule-threshold';
    thresholdInput.min = '0';
    thresholdInput.step = '0.1';
    thresholdInput.value = data && data.threshold !== undefined ? data.threshold : '0';
    thresholdInput.placeholder = 'Buffer %';
    thresholdInput.title = 'Threshold %: allowed proximity margin percentage';

    // 6. Delete Button
    const delBtn = document.createElement('button');
    delBtn.type = 'button';
    delBtn.className = 'delete-rule-btn';
    delBtn.innerHTML = '🗑️';
    delBtn.addEventListener('click', () => {
        row.remove();
    });

    // Append child nodes
    row.appendChild(tfSelect);
    row.appendChild(offsetInput);
    row.appendChild(indSelect);
    row.appendChild(opSelect);
    row.appendChild(valTypeSelect);
    row.appendChild(valContainer);
    row.appendChild(thresholdInput);
    row.appendChild(delBtn);

    list.appendChild(row);
}

function createIndicatorSelector(selectedValue = 'SMA200') {
    const options = [
        { val: "PRICE", text: "Price" },
        { val: "VOLUME", text: "Volume" },
        { val: "VOL_BREAKOUT", text: "Volume Ratio" },
        { val: "RSI", text: "RSI-14" },
        { val: "SMA50", text: "SMA-50" },
        { val: "SMA200", text: "SMA-200" },
        { val: "EMA50", text: "EMA-50" },
        { val: "EMA200", text: "EMA-200" },
        { val: "BB_UPPER", text: "Bollinger Upper" },
        { val: "BB_LOWER", text: "Bollinger Lower" },
        { val: "MACD", text: "MACD" },
        { val: "MACD_SIGNAL", text: "MACD Signal" },
        { val: "PE", text: "P/E Ratio" },
        { val: "DE_RATIO", text: "Debt-to-Equity" },
        { val: "SCORE", text: "AI Score" },
        { val: "RATING", text: "AI Rating" }
    ];

    let selectHtml = `<select class="rule-val-select">`;
    options.forEach(opt => {
        const sel = opt.val === selectedValue ? 'selected' : '';
        selectHtml += `<option value="${opt.val}" ${sel}>${opt.text}</option>`;
    });
    selectHtml += `</select>`;
    return selectHtml;
}

async function executeCustomScreenerScan() {
    const rangeSelect = document.getElementById('rule-scanner-historical-range');
    const range = rangeSelect ? parseInt(rangeSelect.value) : 90;
    const isFormulaMode = (window.activeCustomScreenerMode === 'formula');

    const execCustomBtn = document.getElementById('custom-screener-execute-btn');
    let originalBtnText = '';
    if (execCustomBtn) {
        originalBtnText = execCustomBtn.innerHTML;
        execCustomBtn.disabled = true;
        execCustomBtn.innerHTML = '⏳ Compiling & Scanning...';
    }

    let universe = 'all';
    let logicGate = 'AND';
    let rules = [];
    let formula = '';

    if (isFormulaMode) {
        const formulaInput = document.getElementById('custom-screener-formula-input');
        formula = formulaInput ? formulaInput.value.trim() : '';
        if (!formula) {
            showToast('Please enter a formula to scan.', 'warning');
            if (execCustomBtn) {
                execCustomBtn.disabled = false;
                execCustomBtn.innerHTML = originalBtnText;
            }
            return;
        }
        universe = document.getElementById('custom-screener-formula-universe')?.value || 'all';
        logicGate = document.getElementById('custom-screener-formula-logic')?.value || 'AND';

        const errDiv = document.getElementById('custom-screener-formula-error');
        if (errDiv) errDiv.style.display = 'none';
    } else {
        universe = document.getElementById('custom-screener-universe')?.value || 'all';
        logicGate = document.getElementById('custom-screener-logic')?.value || 'AND';

        const rowEls = document.querySelectorAll('.custom-screener-rule-row');
        if (rowEls.length === 0) {
            showToast('Please add at least one condition line.', 'warning');
            if (execCustomBtn) {
                execCustomBtn.disabled = false;
                execCustomBtn.innerHTML = originalBtnText;
            }
            return;
        }

        rowEls.forEach(row => {
            const timeframe = row.querySelector('.rule-timeframe').value;
            const indicator = row.querySelector('.rule-indicator').value;
            const operator = row.querySelector('.rule-operator').value;
            const valType = row.querySelector('.rule-val-type').value;
            const offset = parseInt(row.querySelector('.rule-offset')?.value) || 0;
            const threshold = parseFloat(row.querySelector('.rule-threshold')?.value) || 0.0;

            let value = '';
            if (valType === 'indicator') {
                value = row.querySelector('.rule-val-select').value;
            } else {
                value = row.querySelector('.rule-val-input').value.trim();
            }

            rules.push({ timeframe, indicator, operator, value, offset, threshold });
        });
    }

    // Reset Min Score and Max D/E filters for new scan
    ruleScanFilterMinScore = 0;
    ruleScanFilterMaxDE = 500;
    const scoreSlider = document.getElementById('rule-scanner-filter-score');
    if (scoreSlider) scoreSlider.value = 0;
    const deSlider = document.getElementById('rule-scanner-filter-de');
    if (deSlider) deSlider.value = 500;
    const scoreVal = document.getElementById('rule-scanner-filter-score-val');
    if (scoreVal) scoreVal.textContent = 0;
    const deVal = document.getElementById('rule-scanner-filter-de-val');
    if (deVal) deVal.textContent = "5.0";

    // Reset AI Scan Analyst Synthesis
    const synthesisPanel = document.getElementById('rule-scanner-synthesis-panel');
    const synthesisText = document.getElementById('rule-scanner-synthesis-text');
    if (synthesisPanel) synthesisPanel.style.display = 'none';
    if (synthesisText) synthesisText.innerHTML = '';

    // Update telemetry status
    const engineStatus = document.getElementById('rule-scanner-engine-status');
    if (engineStatus) { engineStatus.textContent = 'SCANNING...'; engineStatus.style.color = '#f59e0b'; }

    const activeCondEl = document.getElementById('rule-scanner-active-condition');
    if (activeCondEl) {
        activeCondEl.textContent = isFormulaMode ?
            `Custom Screen (Formula Mode)` :
            `Custom Screen (${logicGate}) with ${rules.length} Rules`;
    }

    showLoader(
        isFormulaMode ? "Compiling Custom Formula Scan..." : "Executing Multi-Parametric Screen...",
        "Sweeping indices using custom relational expressions.",
        true,
        [
            { threshold: 10, msg: "[INFO] Initializing custom grammar compiler...", color: '#38bdf8' },
            { threshold: 25, msg: "[INFO] Parsing rules token streams and logic gates...", color: '#38bdf8' },
            { threshold: 45, msg: `[INFO] Targeting universe partition: ${universe.toUpperCase()}...`, color: '#f59e0b' },
            { threshold: 65, msg: `[INFO] Sweeping SQLite cache registers over ${range}-day window...`, color: '#a855f7' },
            { threshold: 85, msg: `[INFO] Evaluating custom logic gates against fundamental and momentum metrics...`, color: '#10b981' }
        ]
    );

    try {
        const payload = {
            universe: universe,
            logic_gate: logicGate,
            historical_range: range,
            rules: rules,
            formula: formula
        };

        const res = await fetch('/api/screener/custom-scan', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload)
        });

        let data = {};
        const contentType = res.headers.get("content-type");
        if (contentType && contentType.includes("application/json")) {
            data = await res.json();
        } else {
            const errorText = await res.text();
            const truncatedText = errorText ? errorText.substring(0, 150).trim() : '';
            if (truncatedText.startsWith('<') || truncatedText.includes('<!DOCTYPE') || truncatedText.includes('<html>')) {
                throw new Error("Server returned an invalid HTML page. This usually indicates a backend syntax/compilation error or connection issue.");
            }
            throw new Error(truncatedText || `Server returned status ${res.status}`);
        }

        if (res.status === 400 && isFormulaMode) {
            hideLoader();
            const errDiv = document.getElementById('custom-screener-formula-error');
            if (errDiv) {
                errDiv.textContent = data.detail || 'Parser error occurred.';
                errDiv.style.display = 'block';
            }
            showToast('Formula parsing failed. See error output below editor.', 'error');
            if (engineStatus) { engineStatus.textContent = 'ERROR'; engineStatus.style.color = '#ef4444'; }
            return;
        }

        if (data.status === 'success') {
            ruleScanAllResults = data.results || [];
            lastRuleScanResults = [...ruleScanAllResults];
            ruleScanPage = 1;

            // Update telemetry
            const scannedCount = document.getElementById('rule-scanner-scanned-count');
            if (scannedCount) scannedCount.textContent = data.scanned || 0;
            const matchedCount = document.getElementById('rule-scanner-matched-count');
            if (matchedCount) matchedCount.textContent = data.matched || 0;
            if (engineStatus) { engineStatus.textContent = 'COMPLETE'; engineStatus.style.color = '#10b981'; }

            // Show results card and telemetry row
            const card = document.getElementById('rule-scanner-results-card');
            if (card) card.style.display = 'flex';
            const telRow = document.getElementById('rule-scanner-results-telemetry-row');
            if (telRow) telRow.style.display = 'grid';

            // Update subtitle
            const subtitle = document.getElementById('rule-scanner-results-subtitle');
            if (subtitle) subtitle.textContent = `${data.matched} matches from ${data.scanned} scanned • ${data.condition}`;

            renderRuleScanResults();
            renderRuleScanSectorConcentration(ruleScanAllResults);

            // Draw dynamic SVG charts
            const telGrid = document.getElementById('rule-scanner-telemetry-grid');
            if (telGrid) telGrid.style.display = 'grid';
            drawRSCapRiskDiagnostic(ruleScanAllResults);
            drawRSValuationQualityMatrix(ruleScanAllResults);
            drawRSKPIHeatmap(ruleScanAllResults);

            // Display Historical matches trend chart
            const chartCard = document.getElementById('rule-scanner-historical-chart-card');
            if (chartCard) {
                chartCard.style.display = 'block';
                setTimeout(() => {
                    renderRuleScannerHistoricalChart(data.historical_matches || []);
                }, 50);
            }

            // Trigger AI synthesis
            if (ruleScanAllResults.length > 0) {
                requestRuleScanSynthesis(ruleScanAllResults, isFormulaMode ? 'Custom Formula Scan' : `Custom Stacked Scan (${logicGate})`);
            }

            // Complete loader progress bar
            const progressBar = document.getElementById('global-loader-progress-bar');
            const progressConsole = document.getElementById('global-loader-progress-console');
            if (progressBar) progressBar.style.width = '100%';
            if (progressConsole) {
                const line = document.createElement('div');
                line.style.color = 'var(--color-emerald)';
                line.style.fontWeight = 'bold';
                line.innerText = `[SUCCESS] Custom screen compilation and sweep complete! Found ${data.matched} candidates.`;
                progressConsole.appendChild(line);
                progressConsole.scrollTop = progressConsole.scrollHeight;
            }

            setTimeout(() => {
                hideLoader();
            }, 650);
        } else {
            hideLoader();
            showToast('Scan failed: ' + (data.detail || 'Unknown error'), 'error');
            if (engineStatus) { engineStatus.textContent = 'ERROR'; engineStatus.style.color = '#ef4444'; }
        }
    } catch (err) {
        hideLoader();
        showToast('Custom scan failed: ' + err.message, 'error');
        if (engineStatus) { engineStatus.textContent = 'ERROR'; engineStatus.style.color = '#ef4444'; }
    } finally {
        if (execCustomBtn) {
            execCustomBtn.disabled = false;
            execCustomBtn.innerHTML = originalBtnText;
        }
    }
}

async function loadSavedScreens() {
    const listEl = document.getElementById('custom-screener-saved-list');
    if (!listEl) return;

    try {
        const res = await fetch('/api/screener/screens');
        let screens = [];
        const contentType = res.headers.get("content-type");
        if (contentType && contentType.includes("application/json")) {
            screens = await res.json();
        } else {
            const errorText = await res.text();
            const truncatedText = errorText ? errorText.substring(0, 150).trim() : '';
            if (truncatedText.startsWith('<') || truncatedText.includes('<!DOCTYPE') || truncatedText.includes('<html>')) {
                throw new Error("Server returned an HTML error page instead of saved screens JSON.");
            }
            throw new Error(truncatedText || `Server returned status ${res.status}`);
        }

        if (!Array.isArray(screens)) {
            if (screens && Array.isArray(screens.screens)) {
                screens = screens.screens;
            } else {
                console.error("Expected array from /api/screener/screens, got:", screens);
                listEl.innerHTML = '<p class="text-danger center-text" style="font-size: 11px; padding: 20px 0;">Error loading saved screens.</p>';
                return;
            }
        }

        if (screens.length === 0) {
            listEl.innerHTML = '<p class="text-muted center-text" style="font-size: 11px; padding: 20px 0;">No saved screens found. Build rules and save them above!</p>';
            return;
        }

        listEl.innerHTML = '';
        screens.forEach(screen => {
            const item = document.createElement('div');
            item.className = 'custom-screen-list-item';

            const info = document.createElement('div');
            info.style.display = 'flex';
            info.style.flexDirection = 'column';
            info.style.gap = '2px';
            info.style.flex = '1';

            const isFormula = !!(screen.formula && screen.formula.trim());
            const detailsText = isFormula ? 'Formula mode' : `${screen.rules ? screen.rules.length : 0} conditions`;

            info.innerHTML = `
                <span style="font-size: 12px; font-weight: 700; color: var(--text-primary);">${screen.name}</span>
                <span style="font-size: 9px; color: var(--text-muted);">${detailsText}</span>
            `;

            info.addEventListener('click', () => {
                loadScreenIntoBuilder(screen);
            });

            const delBtn = document.createElement('button');
            delBtn.className = 'delete-screen-btn';
            delBtn.innerHTML = '🗑️';
            delBtn.title = 'Delete saved screen';
            delBtn.addEventListener('click', async (e) => {
                e.stopPropagation();
                if (confirm(`Are you sure you want to delete the screen "${screen.name}"?`)) {
                    await deleteSavedScreen(screen.id);
                }
            });

            item.appendChild(info);
            item.appendChild(delBtn);
            listEl.appendChild(item);
        });
    } catch (err) {
        console.error('Failed to load saved screens:', err);
    }
}

async function explainCurrentFormula() {
    const formulaInput = document.getElementById('custom-screener-formula-input');
    const formula = formulaInput ? formulaInput.value.trim() : '';
    if (!formula) {
        showToast('Please enter a formula to explain.', 'warning');
        return;
    }

    const panel = document.getElementById('custom-screener-formula-explanation-panel');
    const textEl = document.getElementById('custom-screener-formula-explanation-text');
    const errDiv = document.getElementById('custom-screener-formula-error');

    if (!panel || !textEl) return;
    if (errDiv) errDiv.style.display = 'none';

    panel.style.display = 'block';
    textEl.innerHTML = '<span style="color: #a855f7; font-size: 11px;">🧠 AI analyst translating formula logic...</span>';

    try {
        const res = await fetch('/api/screener/explain-formula', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ formula: formula })
        });

        let data = {};
        const contentType = res.headers.get("content-type");
        if (contentType && contentType.includes("application/json")) {
            data = await res.json();
        } else {
            const errorText = await res.text();
            const truncatedText = errorText ? errorText.substring(0, 150).trim() : '';
            if (truncatedText.startsWith('<') || truncatedText.includes('<!DOCTYPE') || truncatedText.includes('<html>')) {
                throw new Error("Server returned an invalid HTML page instead of formula explanation.");
            }
            throw new Error(truncatedText || `Server returned status ${res.status}`);
        }

        if (res.status === 400) {
            if (errDiv) {
                errDiv.textContent = data.detail || 'Syntax error in formula.';
                errDiv.style.display = 'block';
            }
            panel.style.display = 'none';
            showToast('Formula parsing failed. See error output below editor.', 'error');
            return;
        }

        if (data.status === 'success') {
            textEl.textContent = data.explanation || 'No explanation generated.';
        } else {
            textEl.textContent = 'Explanation generation failed: ' + (data.detail || 'Unknown error');
        }
    } catch (err) {
        textEl.textContent = 'Failed to generate explanation: ' + err.message;
    }
}

async function saveCurrentScreen() {
    const nameEl = document.getElementById('custom-screener-name');
    const name = nameEl?.value?.trim();
    if (!name) {
        showToast('Please enter a screen name.', 'warning');
        return;
    }

    const isFormulaMode = (window.activeCustomScreenerMode === 'formula');
    let rules = [];
    let formula = '';
    let universe = 'all';
    let logicGate = 'AND';

    if (isFormulaMode) {
        const formulaInput = document.getElementById('custom-screener-formula-input');
        formula = formulaInput ? formulaInput.value.trim() : '';
        if (!formula) {
            showToast('Please enter a formula to save.', 'warning');
            return;
        }
        universe = document.getElementById('custom-screener-formula-universe')?.value || 'all';
        logicGate = document.getElementById('custom-screener-formula-logic')?.value || 'AND';
    } else {
        universe = document.getElementById('custom-screener-universe')?.value || 'all';
        logicGate = document.getElementById('custom-screener-logic')?.value || 'AND';

        const rowEls = document.querySelectorAll('.custom-screener-rule-row');
        if (rowEls.length === 0) {
            showToast('Please add at least one condition line to save.', 'warning');
            return;
        }

        rowEls.forEach(row => {
            const timeframe = row.querySelector('.rule-timeframe').value;
            const indicator = row.querySelector('.rule-indicator').value;
            const operator = row.querySelector('.rule-operator').value;
            const valType = row.querySelector('.rule-val-type').value;

            let value = '';
            if (valType === 'indicator') {
                value = row.querySelector('.rule-val-select').value;
            } else {
                value = row.querySelector('.rule-val-input').value.trim();
            }

            rules.push({ timeframe, indicator, operator, value });
        });
    }

    try {
        const payload = {
            name: name,
            description: isFormulaMode ? 'Custom screener formula screen' : `Saved screen with ${rules.length} conditions`,
            rules: rules,
            formula: formula,
            universe: universe,
            logic_gate: logicGate
        };

        const res = await fetch('/api/screener/screens', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload)
        });

        let data = {};
        const contentType = res.headers.get("content-type");
        if (contentType && contentType.includes("application/json")) {
            data = await res.json();
        } else {
            const errorText = await res.text();
            const truncatedText = errorText ? errorText.substring(0, 150).trim() : '';
            if (truncatedText.startsWith('<') || truncatedText.includes('<!DOCTYPE') || truncatedText.includes('<html>')) {
                throw new Error("Server returned an invalid HTML page instead of screens JSON.");
            }
            throw new Error(truncatedText || `Server returned status ${res.status}`);
        }

        if (data.status === 'success') {
            showToast(`Screen "${name}" saved successfully!`, 'success');
            if (nameEl) nameEl.value = '';
            await loadSavedScreens();
        } else {
            showToast('Failed to save screen: ' + (data.detail || 'Unknown error'), 'error');
        }
    } catch (err) {
        showToast('Failed to save screen: ' + err.message, 'error');
    }
}

async function deleteSavedScreen(screenId) {
    try {
        const res = await fetch(`/api/screener/screens/${screenId}`, {
            method: 'DELETE'
        });

        let data = {};
        const contentType = res.headers.get("content-type");
        if (contentType && contentType.includes("application/json")) {
            data = await res.json();
        } else {
            const errorText = await res.text();
            const truncatedText = errorText ? errorText.substring(0, 150).trim() : '';
            if (truncatedText.startsWith('<') || truncatedText.includes('<!DOCTYPE') || truncatedText.includes('<html>')) {
                throw new Error("Server returned an HTML page instead of delete response.");
            }
            throw new Error(truncatedText || `Server returned status ${res.status}`);
        }
        if (data.status === 'success') {
            showToast('Screen deleted successfully.', 'success');
            await loadSavedScreens();
        } else {
            showToast('Failed to delete: ' + (data.detail || 'Unknown error'), 'error');
        }
    } catch (err) {
        showToast('Failed to delete screen: ' + err.message, 'error');
    }
}

function loadScreenIntoBuilder(screen) {
    // Check if the screen has a formula
    if (screen.formula && screen.formula.trim()) {
        const modeFormulaBtn = document.getElementById('custom-screener-mode-formula-btn');
        if (modeFormulaBtn) modeFormulaBtn.click();

        const formulaInput = document.getElementById('custom-screener-formula-input');
        if (formulaInput) formulaInput.value = screen.formula;

        const formulaUniverse = document.getElementById('custom-screener-formula-universe');
        if (formulaUniverse) formulaUniverse.value = screen.universe || 'all';

        const formulaLogic = document.getElementById('custom-screener-formula-logic');
        if (formulaLogic) formulaLogic.value = screen.logic_gate || 'AND';

        const errDiv = document.getElementById('custom-screener-formula-error');
        if (errDiv) errDiv.style.display = 'none';

        const list = document.getElementById('custom-screener-rules-list');
        if (list) list.innerHTML = '';
        addCustomScreenerRow(); // add empty default interactive row in background
    } else {
        const modeInteractiveBtn = document.getElementById('custom-screener-mode-interactive-btn');
        if (modeInteractiveBtn) modeInteractiveBtn.click();

        const list = document.getElementById('custom-screener-rules-list');
        if (list) list.innerHTML = '';

        if (screen.rules && screen.rules.length > 0) {
            screen.rules.forEach(rule => {
                addCustomScreenerRow(rule);
            });
        } else {
            addCustomScreenerRow();
        }

        const universeSelect = document.getElementById('custom-screener-universe');
        if (universeSelect) universeSelect.value = screen.universe || 'all';

        const logicSelect = document.getElementById('custom-screener-logic');
        if (logicSelect) logicSelect.value = screen.logic_gate || 'AND';
    }

    const nameEl = document.getElementById('custom-screener-name');
    if (nameEl) nameEl.value = screen.name;

    showToast(`Loaded screen "${screen.name}"`, 'success');
}

let activeRuleScannerHistoricalChart = null;

function renderRuleScannerHistoricalChart(matchesData) {
    const container = document.getElementById('rule-scanner-historical-canvas-container');
    if (!container || typeof LightweightCharts === 'undefined') return;

    // Clear existing chart
    container.innerHTML = '';
    if (activeRuleScannerHistoricalChart) {
        try {
            activeRuleScannerHistoricalChart.remove();
        } catch (e) {
            console.error(e);
        }
        activeRuleScannerHistoricalChart = null;
    }

    const isDarkTheme = document.documentElement.getAttribute('data-mode') !== 'light';

    // Create Chart
    const chart = LightweightCharts.createChart(container, {
        width: container.clientWidth || 800,
        height: 250,
        layout: {
            background: { type: 'solid', color: 'transparent' },
            textColor: isDarkTheme ? '#94a3b8' : '#334155',
            fontFamily: 'Inter, sans-serif',
        },
        grid: {
            vertLines: { color: isDarkTheme ? 'rgba(255,255,255,0.02)' : 'rgba(0,0,0,0.03)' },
            horzLines: { color: isDarkTheme ? 'rgba(255,255,255,0.02)' : 'rgba(0,0,0,0.03)' },
        },
        rightPriceScale: {
            borderColor: isDarkTheme ? 'rgba(255,255,255,0.08)' : 'rgba(0,0,0,0.08)',
        },
        timeScale: {
            borderColor: isDarkTheme ? 'rgba(255,255,255,0.08)' : 'rgba(0,0,0,0.08)',
            timeVisible: true,
        },
        handleScale: {
            mouseWheel: true,
            pinch: true,
        },
        handleScroll: {
            mouseWheel: true,
            pressedMouseMove: true,
        }
    });
    activeRuleScannerHistoricalChart = chart;

    // Add Area Series
    const areaSeries = chart.addAreaSeries({
        lineColor: '#10b981',
        topColor: 'rgba(16, 185, 129, 0.4)',
        bottomColor: 'rgba(16, 185, 129, 0.0)',
        lineWidth: 2,
        priceFormat: {
            type: 'price',
            precision: 0,
            minMove: 1,
        }
    });

    // Populate data
    const sortedData = [...matchesData].sort((a, b) => a.time.localeCompare(b.time));
    areaSeries.setData(sortedData);

    // Fit content
    chart.timeScale().fitContent();

    // Resize listener
    const resizeObserver = new ResizeObserver(entries => {
        if (entries.length === 0 || !entries[0].contentRect) return;
        const { width, height } = entries[0].contentRect;
        chart.resize(width, height);
    });
    resizeObserver.observe(container);
}

function drawRSCapRiskDiagnostic(results) {
    const container = document.getElementById('rs-cap-risk-container');
    if (!container) return;
    if (!results || results.length === 0) {
        container.innerHTML = `<span style="font-size: 11px; color: var(--text-muted);">No candidates to diagnose</span>`;
        return;
    }

    // 1. Calculate Cap Segments
    let largeCount = 0, midCount = 0, smallCount = 0;
    results.forEach(r => {
        const cap = (r.cap_type || '').toLowerCase();
        if (cap.includes('large')) largeCount++;
        else if (cap.includes('mid')) midCount++;
        else if (cap.includes('small')) smallCount++;
        else {
            smallCount++;
        }
    });
    const total = results.length;
    const largePct = ((largeCount / total) * 100).toFixed(0);
    const midPct = ((midCount / total) * 100).toFixed(0);
    const smallPct = ((smallCount / total) * 100).toFixed(0);

    // 2. Calculate average Beta
    let betaSum = 0;
    let betaCount = 0;
    results.forEach(r => {
        let b = parseFloat(r.beta);
        if (isNaN(b) || b <= 0) {
            const sector = (r.sector || '').toLowerCase();
            if (sector.includes('it') || sector.includes('tech') || sector.includes('finance') || sector.includes('bank')) {
                b = 1.15;
            } else if (sector.includes('pharma') || sector.includes('fmcg') || sector.includes('utilit') || sector.includes('power')) {
                b = 0.75;
            } else {
                b = 1.0;
            }
        }
        betaSum += b;
        betaCount++;
    });
    const avgBeta = betaCount > 0 ? (betaSum / betaCount) : 1.0;

    const cx = 80;
    const cy = 90;
    const r = 55;
    const needleLen = 45;
    const clampedBeta = Math.min(2.0, Math.max(0.0, avgBeta));
    const angleDegree = clampedBeta * 90;
    const angleRad = (angleDegree - 180) * Math.PI / 180;
    const needleX = cx + needleLen * Math.cos(angleRad);
    const needleY = cy + needleLen * Math.sin(angleRad);

    let betaLabel = "Market Equivalent";
    let betaColor = "#6366f1";
    if (avgBeta < 0.9) {
        betaLabel = "Defensive Allocation";
        betaColor = "#10b981";
    } else if (avgBeta > 1.1) {
        betaLabel = "Aggressive / Volatile";
        betaColor = "#f59e0b";
    }

    container.innerHTML = `
        <div style="display: flex; flex-direction: row; gap: 15px; width: 100%; height: 100%; align-items: center; justify-content: space-between;">
            <!-- Left side: Speedometer -->
            <div style="position: relative; width: 50%; height: 140px; display: flex; align-items: center; justify-content: center;">
                <svg width="150" height="110" viewBox="0 0 160 110" style="overflow: visible;">
                    <defs>
                        <linearGradient id="rs-beta-arc-grad" x1="0%" y1="0%" x2="100%" y2="0%">
                            <stop offset="0%" stop-color="#10b981" />
                            <stop offset="50%" stop-color="#6366f1" />
                            <stop offset="100%" stop-color="#f43f5e" />
                        </linearGradient>
                    </defs>
                    <!-- Background Arc -->
                    <path d="M 25,90 A 55,55 0 0,1 135,90" fill="none" stroke="var(--border-glass)" stroke-width="12" stroke-linecap="round" />
                    <!-- Colored Arc Overlay -->
                    <path d="M 25,90 A 55,55 0 0,1 135,90" fill="none" stroke="url(#rs-beta-arc-grad)" stroke-width="12" stroke-linecap="round" opacity="0.85" />

                    <!-- Needle Pin -->
                    <circle cx="${cx}" cy="${cy}" r="6" fill="var(--text-primary)" />
                    <circle cx="${cx}" cy="${cy}" r="3" fill="${betaColor}" />
                    <!-- Needle line -->
                    <line x1="${cx}" y1="${cy}" x2="${needleX}" y2="${needleY}" stroke="var(--text-primary)" stroke-width="3" stroke-linecap="round" style="transition: all 0.5s ease-out;" />

                    <!-- Labels -->
                    <text x="25" y="105" fill="var(--text-muted)" font-size="8" text-anchor="middle" font-weight="bold">0.0 (Def)</text>
                    <text x="${cx}" y="20" fill="var(--text-muted)" font-size="8" text-anchor="middle" font-weight="bold">1.0 (Mkt)</text>
                    <text x="135" y="105" fill="var(--text-muted)" font-size="8" text-anchor="middle" font-weight="bold">2.0 (Vol)</text>
                </svg>
                <div style="position: absolute; bottom: -8px; left: 0; right: 0; text-align: center; display: flex; flex-direction: column; align-items: center;">
                    <span style="font-family: 'Outfit', sans-serif; font-size: 14px; font-weight: 800; color: var(--text-primary);">${avgBeta.toFixed(2)}</span>
                    <span style="font-size: 8px; font-weight: 700; text-transform: uppercase; color: ${betaColor}; letter-spacing: 0.05em; margin-top: 1px;">${betaLabel}</span>
                </div>
            </div>

            <!-- Right side: Cap Segments -->
            <div style="width: 50%; display: flex; flex-direction: column; gap: 8px; justify-content: center; padding-right: 5px;">
                <div style="font-size: 8px; font-weight: 700; color: var(--text-muted); text-transform: uppercase; letter-spacing: 0.05em; margin-bottom: 2px;">Cap Allocation</div>

                <div style="display: flex; flex-direction: column; gap: 4px;">
                    <div style="display: flex; justify-content: space-between; font-size: 9px; color: var(--text-primary);">
                        <span style="display: flex; align-items: center; gap: 4px;"><span style="width: 6px; height: 6px; border-radius: 50%; background: var(--color-primary);"></span>Large Cap</span>
                        <strong>${largePct}%</strong>
                    </div>
                    <div style="width: 100%; height: 5px; background: var(--border-glass); border-radius: 3px; overflow: hidden;">
                        <div style="width: ${largePct}%; background: var(--color-primary); height: 100%; border-radius: 3px;"></div>
                    </div>
                </div>

                <div style="display: flex; flex-direction: column; gap: 4px;">
                    <div style="display: flex; justify-content: space-between; font-size: 9px; color: var(--text-primary);">
                        <span style="display: flex; align-items: center; gap: 4px;"><span style="width: 6px; height: 6px; border-radius: 50%; background: #3b82f6;"></span>Mid Cap</span>
                        <strong>${midPct}%</strong>
                    </div>
                    <div style="width: 100%; height: 5px; background: var(--border-glass); border-radius: 3px; overflow: hidden;">
                        <div style="width: ${midPct}%; background: #3b82f6; height: 100%; border-radius: 3px;"></div>
                    </div>
                </div>

                <div style="display: flex; flex-direction: column; gap: 4px;">
                    <div style="display: flex; justify-content: space-between; font-size: 9px; color: var(--text-primary);">
                        <span style="display: flex; align-items: center; gap: 4px;"><span style="width: 6px; height: 6px; border-radius: 50%; background: #10b981;"></span>Small Cap</span>
                        <strong>${smallPct}%</strong>
                    </div>
                    <div style="width: 100%; height: 5px; background: var(--border-glass); border-radius: 3px; overflow: hidden;">
                        <div style="width: ${smallPct}%; background: #10b981; height: 100%; border-radius: 3px;"></div>
                    </div>
                </div>
            </div>
        </div>
    `;
}

function drawRSValuationQualityMatrix(results) {
    const container = document.getElementById('rs-val-quality-container');
    if (!container) return;
    if (!results || results.length === 0) {
        container.innerHTML = `<span style="font-size: 11px; color: var(--text-muted);">No candidates to map</span>`;
        return;
    }

    const width = 240;
    const height = 140;
    const paddingX = 24;
    const paddingY = 15;
    const drawW = width - 2 * paddingX;
    const drawH = height - 2 * paddingY;

    // Filter out stocks with invalid P/E and compile points
    const points = results.map(r => {
        const pe = typeof r.pe === 'number' ? r.pe : 0;
        const roe = typeof r.roe === 'number' ? r.roe : 0;
        return {
            symbol: (r.symbol || '').replace('.NS', ''),
            pe: pe,
            roe: roe,
            score: r.score || 50
        };
    }).filter(pt => pt.pe > 0);

    if (points.length === 0) {
        container.innerHTML = `<span style="font-size: 11px; color: var(--text-muted);">No candidates with positive P/E to map</span>`;
        return;
    }

    // Map axes limits:
    // P/E ranges from 5x to 65x. Center divider line is at 30x.
    // ROE % ranges from 0% to 40%. Center divider line is at 15%.
    const minPe = 5, maxPe = 65, peRange = maxPe - minPe;
    const minRoe = 0, maxRoe = 40, roeRange = maxRoe - minRoe;
    const splitPe = 30;
    const splitRoe = 15;

    // Calculate center line positions
    const midX = paddingX + ((splitPe - minPe) / peRange) * drawW;
    const midY = paddingY + (1 - (splitRoe - minRoe) / roeRange) * drawH;

    // Build SVG Content
    let svgContent = `<svg width="100%" height="100%" viewBox="0 0 ${width} ${height}" style="overflow: visible;">`;

    // Glowing neon drop shadow filter for dots
    svgContent += `
        <defs>
            <filter id="rs-dot-glow" x="-30%" y="-30%" width="160%" height="160%">
                <feGaussianBlur stdDeviation="1.2" result="blur" />
                <feComposite in="SourceGraphic" in2="blur" operator="over" />
            </filter>
        </defs>
    `;

    // Ambient Quadrant Glow Overlays (background stack)
    svgContent += `
        <rect id="rs-quad-bg-garp" x="${paddingX}" y="${paddingY}" width="${midX - paddingX}" height="${midY - paddingY}" fill="transparent" style="transition: fill 0.3s ease; pointer-events: none;" />
        <rect id="rs-quad-bg-premium" x="${midX}" y="${paddingY}" width="${width - paddingX - midX}" height="${midY - paddingY}" fill="transparent" style="transition: fill 0.3s ease; pointer-events: none;" />
        <rect id="rs-quad-bg-trap" x="${paddingX}" y="${midY}" width="${midX - paddingX}" height="${height - paddingY - midY}" fill="transparent" style="transition: fill 0.3s ease; pointer-events: none;" />
        <rect id="rs-quad-bg-speculative" x="${midX}" y="${midY}" width="${width - paddingX - midX}" height="${height - paddingY - midY}" fill="transparent" style="transition: fill 0.3s ease; pointer-events: none;" />
    `;

    // Grid Matrix Frame & Dividers
    svgContent += `<rect x="${paddingX}" y="${paddingY}" width="${drawW}" height="${drawH}" fill="transparent" stroke="var(--border-glass)" stroke-width="1" />`;
    svgContent += `<line x1="${midX}" y1="${paddingY}" x2="${midX}" y2="${height - paddingY}" stroke="var(--border-glass)" stroke-dasharray="2,2" stroke-width="1" />`;
    svgContent += `<line x1="${paddingX}" y1="${midY}" x2="${width - paddingX}" y2="${midY}" stroke="var(--border-glass)" stroke-dasharray="2,2" stroke-width="1" />`;

    // Quadrant Labels (using highly visible, saturated, standard colors)
    svgContent += `<text x="${paddingX + 6}" y="${paddingY + 12}" fill="#10b981" font-size="7" font-weight="800" opacity="0.55" letter-spacing="0.05em">GARP</text>`;
    svgContent += `<text x="${width - paddingX - 6}" y="${paddingY + 12}" fill="#3b82f6" font-size="7" font-weight="800" opacity="0.55" letter-spacing="0.05em" text-anchor="end">PREMIUM QUALITY</text>`;
    svgContent += `<text x="${paddingX + 6}" y="${height - paddingY - 8}" fill="#ef4444" font-size="7" font-weight="800" opacity="0.55" letter-spacing="0.05em">VALUE TRAPS</text>`;
    svgContent += `<text x="${width - paddingX - 6}" y="${height - paddingY - 8}" fill="#f59e0b" font-size="7" font-weight="800" opacity="0.55" letter-spacing="0.05em" text-anchor="end">SPECULATIVE</text>`;

    // Interactive Crosshairs Placeholder (rendered underneath dots)
    svgContent += `
        <line id="rs-crosshair-x" x1="0" y1="0" x2="0" y2="0" stroke="var(--text-muted)" stroke-dasharray="2,2" stroke-width="0.8" style="display: none; pointer-events: none; transition: stroke 0.2s; opacity: 0.6;" />
        <line id="rs-crosshair-y" x1="0" y1="0" x2="0" y2="0" stroke="var(--text-muted)" stroke-dasharray="2,2" stroke-width="0.8" style="display: none; pointer-events: none; transition: stroke 0.2s; opacity: 0.6;" />

        <g id="rs-crosshair-tag-x" style="display: none; pointer-events: none;">
            <rect x="-14" y="0" width="28" height="9" rx="2" fill="var(--bg-glass-input)" stroke="var(--border-glass)" stroke-width="0.6" />
            <text id="rs-crosshair-text-x" x="0" y="5.5" fill="var(--text-primary)" font-size="5.5" font-family="monospace" font-weight="700" text-anchor="middle"></text>
        </g>
        <g id="rs-crosshair-tag-y" style="display: none; pointer-events: none;">
            <rect x="-26" y="-4.5" width="24" height="9" rx="2" fill="var(--bg-glass-input)" stroke="var(--border-glass)" stroke-width="0.6" />
            <text id="rs-crosshair-text-y" x="-14" y="1.5" fill="var(--text-primary)" font-size="5.5" font-family="monospace" font-weight="700" text-anchor="middle"></text>
        </g>
    `;

    // Render Data Dots
    points.forEach((pt, idx) => {
        const clampedPe = Math.min(maxPe, Math.max(minPe, pt.pe));
        const x = paddingX + ((clampedPe - minPe) / peRange) * drawW;
        const clampedRoe = Math.min(maxRoe, Math.max(minRoe, pt.roe));
        const roePct = (clampedRoe - minRoe) / roeRange;
        const y = paddingY + (1 - roePct) * drawH;

        let ptColor = '#e2e8f0';
        if (pt.pe <= splitPe && pt.roe >= splitRoe) ptColor = '#10b981';
        else if (pt.pe > splitPe && pt.roe >= splitRoe) ptColor = '#3b82f6';
        else if (pt.pe <= splitPe && pt.roe < splitRoe) ptColor = '#ef4444';
        else if (pt.pe > splitPe && pt.roe < splitRoe) ptColor = '#f59e0b';

        svgContent += `
            <circle id="rs-quad-circle-${idx}" cx="${x}" cy="${y}" r="4.5" fill="${ptColor}" stroke="rgba(255,255,255,0.3)" stroke-width="1"
                filter="url(#rs-dot-glow)"
                class="rs-quad-circle"
                style="cursor: pointer; transition: r 0.25s cubic-bezier(0.175, 0.885, 0.32, 1.275), opacity 0.25s ease;" />
        `;
    });

    svgContent += `</svg>`;

    // Build Floating glassmorphic tooltips
    let tooltipsHtml = '';
    points.forEach((pt, idx) => {
        const clampedPe = Math.min(maxPe, Math.max(minPe, pt.pe));
        const x = paddingX + ((clampedPe - minPe) / peRange) * drawW;
        const clampedRoe = Math.min(maxRoe, Math.max(minRoe, pt.roe));
        const roePct = (clampedRoe - minRoe) / roeRange;
        const y = paddingY + (1 - roePct) * drawH;

        const leftPos = (x / width * 100).toFixed(0);
        const topPos = (y / height * 100).toFixed(0);

        let ptColor = '#e2e8f0';
        if (pt.pe <= splitPe && pt.roe >= splitRoe) ptColor = '#10b981';
        else if (pt.pe > splitPe && pt.roe >= splitRoe) ptColor = '#3b82f6';
        else if (pt.pe <= splitPe && pt.roe < splitRoe) ptColor = '#ef4444';
        else if (pt.pe > splitPe && pt.roe < splitRoe) ptColor = '#f59e0b';

        tooltipsHtml += `
            <div id="rs-quad-tooltip-${idx}" style="position: absolute; left: ${leftPos}%; top: ${topPos}%; transform: translate(-50%, -125%); background: rgba(11, 15, 29, 0.85); backdrop-filter: blur(8px); -webkit-backdrop-filter: blur(8px); border: 1px solid var(--border-glass); border-top: 2.5px solid ${ptColor}; border-radius: 6px; padding: 6px 10px; pointer-events: none; font-size: 8.5px; color: #f3f4f6; font-family: var(--font-body); white-space: nowrap; opacity: 0; transition: opacity 0.18s ease; box-shadow: 0 8px 25px rgba(0,0,0,0.4); z-index: 100;">
                <strong style="font-family: var(--font-heading); font-size: 9.5px; color: #fff; display: block; margin-bottom: 2px;">${pt.symbol}</strong>
                P/E Ratio: <strong style="color: ${ptColor};">${pt.pe.toFixed(1)}x</strong><br/>
                Return on Equity: <strong style="color: ${ptColor};">${pt.roe.toFixed(1)}%</strong>
            </div>
        `;
    });

    // Build Legend badges
    const legendHtml = `
        <div class="rs-legend-badge" data-quadrant="garp" style="display: flex; align-items: center; gap: 6px; padding: 4.5px 10px; border-radius: 20px; font-size: 8.5px; font-weight: 700; color: #10b981; border: 1px solid rgba(16,185,129,0.25); background: rgba(16,185,129,0.04); cursor: pointer; transition: all 0.2s; user-select: none; font-family: var(--font-heading);">
            <span style="width: 5px; height: 5px; border-radius: 50%; background: #10b981;"></span>
            GARP
        </div>
        <div class="rs-legend-badge" data-quadrant="premium" style="display: flex; align-items: center; gap: 6px; padding: 4.5px 10px; border-radius: 20px; font-size: 8.5px; font-weight: 700; color: #3b82f6; border: 1px solid rgba(59,130,246,0.25); background: rgba(59,130,246,0.04); cursor: pointer; transition: all 0.2s; user-select: none; font-family: var(--font-heading);">
            <span style="width: 5px; height: 5px; border-radius: 50%; background: #3b82f6;"></span>
            PREMIUM QUALITY
        </div>
        <div class="rs-legend-badge" data-quadrant="trap" style="display: flex; align-items: center; gap: 6px; padding: 4.5px 10px; border-radius: 20px; font-size: 8.5px; font-weight: 700; color: #ef4444; border: 1px solid rgba(239,68,68,0.25); background: rgba(239,68,68,0.03); cursor: pointer; transition: all 0.2s; user-select: none; font-family: var(--font-heading);">
            <span style="width: 5px; height: 5px; border-radius: 50%; background: #ef4444;"></span>
            VALUE TRAPS
        </div>
        <div class="rs-legend-badge" data-quadrant="speculative" style="display: flex; align-items: center; gap: 6px; padding: 4.5px 10px; border-radius: 20px; font-size: 8.5px; font-weight: 700; color: #f59e0b; border: 1px solid rgba(245,158,11,0.25); background: rgba(245,158,11,0.03); cursor: pointer; transition: all 0.2s; user-select: none; font-family: var(--font-heading);">
            <span style="width: 5px; height: 5px; border-radius: 50%; background: #f59e0b;"></span>
            SPECULATIVE
        </div>
    `;

    // Inject styles and layout skeleton
    container.innerHTML = `
        <style>
            .rs-legend-badge {
                transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
            }
            .rs-legend-badge:hover {
                transform: translateY(-1.5px);
                box-shadow: 0 4px 10px rgba(0, 0, 0, 0.15);
            }
            [data-theme="light"] .rs-legend-badge {
                background: rgba(0, 0, 0, 0.02) !important;
            }
        </style>
        <div style="position: relative; width: 100%; height: 100%; display: flex; flex-direction: column; align-items: center; justify-content: space-between;">
            <div style="position: relative; width: 100%; height: 175px; display: flex; align-items: center; justify-content: center; overflow: visible;">
                ${svgContent}
                ${tooltipsHtml}
                <span style="position: absolute; bottom: 0px; right: 20px; font-size: 7px; color: var(--text-muted); font-weight: bold; letter-spacing: 0.05em; text-transform: uppercase;">P/E Ratio →</span>
                <span style="position: absolute; left: 14px; bottom: 12px; font-size: 7px; color: var(--text-muted); font-weight: bold; transform: rotate(-90deg); transform-origin: left bottom; letter-spacing: 0.05em; text-transform: uppercase;">ROE % →</span>
            </div>
            <div id="rs-matrix-legend-row" style="display: flex; justify-content: center; gap: 8px; margin-top: 5px; padding-bottom: 2px; flex-wrap: wrap; width: 100%;">
                ${legendHtml}
            </div>
        </div>
    `;

    // --- INTERACTIVE EVENT LISTENERS ---

    // 1. Crosshair management helper methods
    const showCrosshair = (x, y, pe, roe, color) => {
        const cx = document.getElementById('rs-crosshair-x');
        const cy = document.getElementById('rs-crosshair-y');
        const tx = document.getElementById('rs-crosshair-tag-x');
        const ty = document.getElementById('rs-crosshair-tag-y');
        const txtX = document.getElementById('rs-crosshair-text-x');
        const txtY = document.getElementById('rs-crosshair-text-y');

        if (cx && cy) {
            cx.setAttribute('x1', x);
            cx.setAttribute('y1', y);
            cx.setAttribute('x2', x);
            cx.setAttribute('y2', height - paddingY);
            cx.setAttribute('stroke', color);
            cx.style.display = 'block';

            cy.setAttribute('x1', paddingX);
            cy.setAttribute('y1', y);
            cy.setAttribute('x2', x);
            cy.setAttribute('y2', y);
            cy.setAttribute('stroke', color);
            cy.style.display = 'block';
        }

        if (tx && ty && txtX && txtY) {
            tx.setAttribute('transform', `translate(${x}, ${height - paddingY})`);
            txtX.textContent = pe.toFixed(1) + 'x';
            tx.style.display = 'block';

            ty.setAttribute('transform', `translate(${paddingX}, ${y})`);
            txtY.textContent = roe.toFixed(1) + '%';
            ty.style.display = 'block';
        }
    };

    const hideCrosshair = () => {
        const cx = document.getElementById('rs-crosshair-x');
        const cy = document.getElementById('rs-crosshair-y');
        const tx = document.getElementById('rs-crosshair-tag-x');
        const ty = document.getElementById('rs-crosshair-tag-y');

        if (cx) cx.style.display = 'none';
        if (cy) cy.style.display = 'none';
        if (tx) tx.style.display = 'none';
        if (ty) ty.style.display = 'none';
    };

    // 2. Attach dot hover listeners
    points.forEach((pt, idx) => {
        const circle = document.getElementById(`rs-quad-circle-${idx}`);
        if (circle) {
            circle.addEventListener('mouseover', () => {
                circle.setAttribute('r', '7');

                const tooltip = document.getElementById(`rs-quad-tooltip-${idx}`);
                if (tooltip) tooltip.style.opacity = '1';

                const clampedPe = Math.min(maxPe, Math.max(minPe, pt.pe));
                const x = paddingX + ((clampedPe - minPe) / peRange) * drawW;
                const clampedRoe = Math.min(maxRoe, Math.max(minRoe, pt.roe));
                const roePct = (clampedRoe - minRoe) / roeRange;
                const y = paddingY + (1 - roePct) * drawH;

                let ptColor = '#3b82f6';
                let quadId = '';
                if (pt.pe <= splitPe && pt.roe >= splitRoe) { ptColor = '#10b981'; quadId = 'rs-quad-bg-garp'; }
                else if (pt.pe > splitPe && pt.roe >= splitRoe) { ptColor = '#3b82f6'; quadId = 'rs-quad-bg-premium'; }
                else if (pt.pe <= splitPe && pt.roe < splitRoe) { ptColor = '#ef4444'; quadId = 'rs-quad-bg-trap'; }
                else if (pt.pe > splitPe && pt.roe < splitRoe) { ptColor = '#f59e0b'; quadId = 'rs-quad-bg-speculative'; }

                showCrosshair(x, y, pt.pe, pt.roe, ptColor);

                // Highlight quadrant background overlay
                const qBg = document.getElementById(quadId);
                if (qBg) {
                    let glowColor = 'rgba(59,130,246,0.06)';
                    if (quadId === 'rs-quad-bg-garp') glowColor = 'rgba(16,185,129,0.08)';
                    else if (quadId === 'rs-quad-bg-trap') glowColor = 'rgba(239,68,68,0.05)';
                    else if (quadId === 'rs-quad-bg-speculative') glowColor = 'rgba(245,158,11,0.05)';
                    qBg.setAttribute('fill', glowColor);
                }
            });

            circle.addEventListener('mouseout', () => {
                circle.setAttribute('r', '4.5');

                const tooltip = document.getElementById(`rs-quad-tooltip-${idx}`);
                if (tooltip) tooltip.style.opacity = '0';

                hideCrosshair();

                // Clear quadrant highlight
                ['rs-quad-bg-garp', 'rs-quad-bg-premium', 'rs-quad-bg-trap', 'rs-quad-bg-speculative'].forEach(id => {
                    const el = document.getElementById(id);
                    if (el) el.setAttribute('fill', 'transparent');
                });
            });
        }
    });

    // 3. Attach interactive legend filtering
    const badges = container.querySelectorAll('.rs-legend-badge');
    badges.forEach(badge => {
        const quadrant = badge.getAttribute('data-quadrant');
        badge.addEventListener('mouseenter', () => {
            // Focus on hovered category
            badges.forEach(b => {
                if (b !== badge) b.style.opacity = '0.35';
            });

            let quadId = '';
            let glowColor = '';
            if (quadrant === 'garp') { quadId = 'rs-quad-bg-garp'; glowColor = 'rgba(16,185,129,0.12)'; }
            else if (quadrant === 'premium') { quadId = 'rs-quad-bg-premium'; glowColor = 'rgba(59,130,246,0.12)'; }
            else if (quadrant === 'trap') { quadId = 'rs-quad-bg-trap'; glowColor = 'rgba(239,68,68,0.08)'; }
            else if (quadrant === 'speculative') { quadId = 'rs-quad-bg-speculative'; glowColor = 'rgba(245,158,11,0.08)'; }

            const qBg = document.getElementById(quadId);
            if (qBg) qBg.setAttribute('fill', glowColor);

            points.forEach((pt, i) => {
                const circle = document.getElementById(`rs-quad-circle-${i}`);
                if (circle) {
                    let belongs = false;
                    if (quadrant === 'garp' && pt.pe <= splitPe && pt.roe >= splitRoe) belongs = true;
                    else if (quadrant === 'premium' && pt.pe > splitPe && pt.roe >= splitRoe) belongs = true;
                    else if (quadrant === 'trap' && pt.pe <= splitPe && pt.roe < splitRoe) belongs = true;
                    else if (quadrant === 'speculative' && pt.pe > splitPe && pt.roe < splitRoe) belongs = true;

                    if (!belongs) {
                        circle.style.opacity = '0.12';
                    } else {
                        circle.style.opacity = '1';
                        circle.setAttribute('r', '6');
                    }
                }
            });
        });

        badge.addEventListener('mouseleave', () => {
            // Restore normal view
            badges.forEach(b => {
                b.style.opacity = '1';
            });

            ['rs-quad-bg-garp', 'rs-quad-bg-premium', 'rs-quad-bg-trap', 'rs-quad-bg-speculative'].forEach(id => {
                const el = document.getElementById(id);
                if (el) el.setAttribute('fill', 'transparent');
            });

            points.forEach((pt, i) => {
                const circle = document.getElementById(`rs-quad-circle-${i}`);
                if (circle) {
                    circle.style.opacity = '1';
                    circle.setAttribute('r', '4.5');
                }
            });
        });
    });
}

function drawRSKPIHeatmap(results) {
    const container = document.getElementById('rs-kpi-heatmap-container');
    if (!container) return;
    if (!results || results.length === 0) {
        container.innerHTML = `<span style="font-size: 11px; color: var(--text-muted);">No candidates to analyze</span>`;
        return;
    }

    const topCandidates = [...results]
        .sort((a, b) => (b.score || 0) - (a.score || 0))
        .slice(0, 5);

    let tableRows = topCandidates.map(r => {
        const symbol = (r.symbol || '').replace('.NS', '');

        // P/E cell
        const peVal = typeof r.pe === 'number' ? r.pe : 0;
        let peText = 'N/A', peColor = 'var(--text-primary)', peBg = 'transparent';
        if (peVal > 0) {
            peText = peVal.toFixed(1);
            if (peVal < 15) { peColor = '#10b981'; peBg = 'rgba(16, 185, 129, 0.12)'; }
            else if (peVal < 25) { peColor = '#14b8a6'; peBg = 'rgba(20, 184, 166, 0.08)'; }
            else if (peVal < 40) { peColor = '#f59e0b'; peBg = 'rgba(245, 158, 11, 0.06)'; }
            else { peColor = '#f43f5e'; peBg = 'rgba(244, 63, 94, 0.08)'; }
        }

        // D/E cell
        const deVal = typeof r.de_ratio === 'number' ? r.de_ratio : 0;
        let deColor = '#10b981', deBg = 'rgba(16, 185, 129, 0.12)';
        if (deVal >= 2.0) { deColor = '#f43f5e'; deBg = 'rgba(244, 63, 94, 0.08)'; }
        else if (deVal >= 1.0) { deColor = '#f59e0b'; deBg = 'rgba(245, 158, 11, 0.06)'; }
        else if (deVal >= 0.3) { deColor = '#14b8a6'; deBg = 'rgba(20, 184, 166, 0.08)'; }

        // ROE cell
        const roeVal = typeof r.roe === 'number' ? r.roe : 0;
        let roeText = 'N/A', roeColor = 'var(--text-primary)', roeBg = 'transparent';
        if (roeVal > 0) {
            roeText = roeVal.toFixed(1) + '%';
            if (roeVal >= 20) { roeColor = '#10b981'; roeBg = 'rgba(16, 185, 129, 0.12)'; }
            else if (roeVal >= 12) { roeColor = '#14b8a6'; roeBg = 'rgba(20, 184, 166, 0.08)'; }
            else if (roeVal >= 6) { roeColor = '#f59e0b'; roeBg = 'rgba(245, 158, 11, 0.06)'; }
            else { roeColor = '#f43f5e'; roeBg = 'rgba(244, 63, 94, 0.08)'; }
        }

        // RSI cell
        const rsiVal = typeof r.rsi === 'number' ? r.rsi : 50;
        let rsiColor = '#3b82f6', rsiBg = 'rgba(59, 130, 246, 0.08)';
        if (rsiVal < 35) { rsiColor = '#10b981'; rsiBg = 'rgba(16, 185, 129, 0.12)'; }
        else if (rsiVal >= 65) { rsiColor = '#fb923c'; rsiBg = 'rgba(251, 146, 60, 0.08)'; }

        // Score cell
        const scoreVal = typeof r.score === 'number' ? r.score : 50;
        let scoreColor = 'var(--text-muted)', scoreBg = 'rgba(148, 163, 184, 0.06)';
        if (scoreVal >= 75) { scoreColor = '#10b981'; scoreBg = 'rgba(16, 185, 129, 0.15)'; }
        else if (scoreVal >= 60) { scoreColor = '#a855f7'; scoreBg = 'rgba(168, 85, 247, 0.1)'; }

        return `
            <tr style="border-bottom: 1px solid var(--border-glass);">
                <td style="padding: 5px 6px; font-weight: bold; color: var(--text-primary); font-family: 'Outfit', sans-serif; cursor: pointer;" onclick="window.loadStockAnalyzer('${r.symbol}')">${symbol}</td>
                <td style="padding: 5px 6px; text-align: right; font-weight: 700; color: ${peColor}; background: ${peBg}; border-radius: 4px; font-family: monospace;">${peText}</td>
                <td style="padding: 5px 6px; text-align: right; font-weight: 700; color: ${deColor}; background: ${deBg}; border-radius: 4px; font-family: monospace;">${deVal.toFixed(2)}</td>
                <td style="padding: 5px 6px; text-align: right; font-weight: 700; color: ${roeColor}; background: ${roeBg}; border-radius: 4px; font-family: monospace;">${roeText}</td>
                <td style="padding: 5px 6px; text-align: right; font-weight: 700; color: ${rsiColor}; background: ${rsiBg}; border-radius: 4px; font-family: monospace;">${rsiVal.toFixed(0)}</td>
                <td style="padding: 5px 6px; text-align: right; font-weight: 700; color: ${scoreColor}; background: ${scoreBg}; border-radius: 4px; font-family: monospace;">${scoreVal.toFixed(0)}</td>
            </tr>
        `;
    }).join('');

    container.innerHTML = `
        <div style="width: 100%; height: 100%; display: flex; align-items: center; justify-content: center; overflow: hidden; padding-bottom: 2px;">
            <table style="width: 100%; border-collapse: separate; border-spacing: 2px 4px; text-align: left; font-size: 9px; line-height: 1.1;">
                <thead>
                    <tr style="color: var(--text-secondary); text-transform: uppercase; font-size: 8px; font-weight: 700; letter-spacing: 0.04em;">
                        <th style="padding: 2px 6px;">Ticker</th>
                        <th style="padding: 2px 6px; text-align: right;">P/E</th>
                        <th style="padding: 2px 6px; text-align: right;">D/E</th>
                        <th style="padding: 2px 6px; text-align: right;">ROE</th>
                        <th style="padding: 2px 6px; text-align: right;">RSI</th>
                        <th style="padding: 2px 6px; text-align: right;">Score</th>
                    </tr>
                </thead>
                <tbody>
                    ${tableRows}
                </tbody>
            </table>
        </div>
    `;
}

