function setupTVWorkstationChartControls() {
    const activeInd = document.getElementById('tv-active-indicator');
    const lengthSelect = document.getElementById('tv-length');
    const multSelect = document.getElementById('tv-mult');
    const showVolume = document.getElementById('tv-show-volume');
    const showLines = document.getElementById('tv-show-lines');
    const showBreaks = document.getElementById('tv-show-breaks');

    const showFibs = document.getElementById('tv-show-fibs');
    const showOBs = document.getElementById('tv-show-obs');
    const showFVGs = document.getElementById('tv-show-fvgs');
    const showStructs = document.getElementById('tv-show-structs');
    const showInternalStructs = document.getElementById('tv-show-internal-structs');

    // LuxAlgo SMC Controls
    const smcSwing = document.getElementById('tv-smc-swing');
    const smcInternal = document.getElementById('tv-smc-internal');
    const smcOBs = document.getElementById('tv-smc-obs');
    const smcFVGs = document.getElementById('tv-smc-fvgs');
    const smcEqhl = document.getElementById('tv-smc-eqhl');
    const smcMtf = document.getElementById('tv-smc-mtf');
    const smcZones = document.getElementById('tv-smc-zones');

    // LRTC Controls
    const showLrtcChannel = document.getElementById('tv-lrtc-show-channel');
    const showLrtcHistorical = document.getElementById('tv-lrtc-show-historical');
    const showLrtcAlerts = document.getElementById('tv-lrtc-show-alerts');

    // Pitchfork Controls
    const pfTypeSelect = document.getElementById('tv-pitchfork-type');
    const pfZigzag = document.getElementById('tv-pitchfork-show-zigzag');
    const pfFibs = document.getElementById('tv-pitchfork-show-fibs');

    // Indicators checkboxes
    const indicatorLuxAlgo = document.getElementById('tv-indicator-lux-algo');
    const indicatorMxwll = document.getElementById('tv-indicator-mxwll');
    const indicatorLuxSMC = document.getElementById('tv-indicator-lux-smc');
    const indicatorLRTC = document.getElementById('tv-indicator-lrtc');
    const indicatorPitchfork = document.getElementById('tv-indicator-pitchfork');

    // EMA checkboxes
    const tvEma20 = document.getElementById('tv-ema-20');
    const tvEma50 = document.getElementById('tv-ema-50');
    const tvEma100 = document.getElementById('tv-ema-100');
    const tvEma200 = document.getElementById('tv-ema-200');
    const tvEmaCustom = document.getElementById('tv-ema-custom');

    // Initialize pill styles
    updateIndicatorPillStyles();
    updateEmaPillStyles();

    // Bind checkboxes and handle defaults
    const indCheckboxes = [
        { cb: indicatorLuxAlgo, length: '14' },
        { cb: indicatorMxwll, length: '14' },
        { cb: indicatorLuxSMC, length: '50' },
        { cb: indicatorLRTC, length: '40', mult: '2.0' },
        { cb: indicatorPitchfork, length: '100' }
    ];
    indCheckboxes.forEach(item => {
        if (item.cb) {
            item.cb.addEventListener('change', () => {
                updateIndicatorPillStyles();
                if (item.cb.checked) {
                    if (item.length && lengthSelect) {
                        lengthSelect.value = item.length;
                    }
                    if (item.mult && multSelect) {
                        multSelect.value = item.mult;
                    }
                }
                // Sync the tv-active-indicator hidden input
                if (activeInd) {
                    const activeList = [];
                    if (indicatorLuxAlgo?.checked) activeList.push('lux-algo');
                    if (indicatorMxwll?.checked) activeList.push('mxwll');
                    if (indicatorLuxSMC?.checked) activeList.push('lux-smc');
                    if (indicatorLRTC?.checked) activeList.push('lrtc');
                    if (indicatorPitchfork?.checked) activeList.push('pitchfork');
                    activeInd.value = activeList.length > 0 ? activeList.join(',') : 'none';
                }
                if (activeStockProfile && activeStockProfile.ticker) {
                    renderTVWorkstationChart(activeStockProfile.ticker);
                }
                renderTvChartTemplates();
                updateTvChartConsensusRating();
            });
        }
    });

    const emaCheckboxes = [tvEma20, tvEma50, tvEma100, tvEma200, tvEmaCustom];
    emaCheckboxes.forEach(cb => {
        if (cb) {
            cb.addEventListener('change', () => {
                updateEmaPillStyles();
                if (activeStockProfile && activeStockProfile.ticker) {
                    renderTVWorkstationChart(activeStockProfile.ticker);
                }
            });
        }
    });

    const elements = [
        activeInd, lengthSelect, multSelect, showVolume, showLines, showBreaks,
        showFibs, showOBs, showFVGs, showStructs, showInternalStructs,
        smcSwing, smcInternal, smcOBs, smcFVGs, smcEqhl, smcMtf, smcZones,
        showLrtcChannel, showLrtcHistorical, showLrtcAlerts,
        pfTypeSelect, pfZigzag, pfFibs
    ];
    elements.forEach(el => {
        if (el) {
            el.addEventListener('change', () => {
                if (activeStockProfile && activeStockProfile.ticker) {
                    renderTVWorkstationChart(activeStockProfile.ticker);
                }
                renderTvChartTemplates();
                updateTvChartConsensusRating();
            });
        }
    });

    const generateBtn = document.getElementById('tv-btn-generate-synthesis');
    if (generateBtn) {
        generateBtn.addEventListener('click', (e) => {
            e.stopPropagation();
            triggerTVIndicatorSynthesis();
        });
    }

    const header = document.getElementById('tv-ai-insights-header');
    const wrapper = document.getElementById('tv-ai-synthesis-content-wrapper');
    const icon = document.getElementById('tv-ai-insights-toggle-icon');
    if (header && wrapper && icon) {
        header.addEventListener('click', () => {
            const isCollapsed = wrapper.style.display === 'none';
            if (isCollapsed) {
                wrapper.style.display = 'block';
                icon.style.transform = 'rotate(0deg)';
            } else {
                wrapper.style.display = 'none';
                icon.style.transform = 'rotate(-90deg)';
            }
        });
    }

    // Conversational Chatbot Bindings
    const tvChatSendBtn = document.getElementById('tv-chart-chat-send-btn');
    if (tvChatSendBtn) {
        tvChatSendBtn.addEventListener('click', triggerTvChatQuery);
    }
    const tvChatInput = document.getElementById('tv-chart-chat-input');
    if (tvChatInput) {
        tvChatInput.addEventListener('keydown', (e) => {
            if (e.key === 'Enter') {
                triggerTvChatQuery();
            }
        });
    }
    const tvChatClearBtn = document.getElementById('tv-chart-clear-chat-btn');
    if (tvChatClearBtn) {
        tvChatClearBtn.addEventListener('click', () => {
            const history = document.getElementById('tv-chart-chat-history');
            if (history) {
                history.innerHTML = '<div class="bot-message" style="align-self: flex-start; background: rgba(255,255,255,0.05); color: var(--text-secondary); padding: 8px 12px; border-radius: 12px 12px 12px 0px; max-width: 85%; line-height: 1.4;">Hello! I am your Technical Analyst chatbot. Select indicators on the chart to dynamically update the templates below, or ask any question about key reversal patterns, order blocks, volume spikes, and catalyst confluences.</div>';
            }
            tvChatHistoryList = [];
            clearTvTemporaryPriceLines();
        });
    }
    const tvChatExportBtn = document.getElementById('tv-chart-export-chat-btn');
    if (tvChatExportBtn) {
        tvChatExportBtn.addEventListener('click', () => {
            if (tvChatHistoryList.length === 0) {
                showToast("No chat history to export.", "warning");
                return;
            }
            let text = "Interactive Chart AI Chatbot History:\n\n";
            tvChatHistoryList.forEach(m => {
                const role = m.role === 'user' ? 'User' : 'AI Analyst';
                text += `[${role}]: ${m.content}\n\n`;
            });
            navigator.clipboard.writeText(text).then(() => {
                showToast("Chat history copied to clipboard!", "success");
            }).catch(err => {
                console.error("Failed to copy text:", err);
            });
        });
    }
    const tvChatStopTtsBtn = document.getElementById('tv-chart-stop-tts-btn');
    if (tvChatStopTtsBtn) {
        tvChatStopTtsBtn.addEventListener('click', () => {
            if (window.speechSynthesis) window.speechSynthesis.cancel();
            tvChatStopTtsBtn.style.display = 'none';
            document.querySelectorAll('.tv-chat-speak-btn').forEach(btn => {
                btn.innerHTML = '🔊 Speak';
                btn.classList.remove('speaking');
            });
        });
    }
    
    // Bind templates renderer and voice integrations
    renderTvChartTemplates();
    setupTvChatSTT();
    updateTvChartConsensusRating();
    initSmcGlossaryModal();
    initConfluenceModal();
}

