function renderTvChartTemplates() {
    const container = document.getElementById('tv-chart-templates-container');
    if (!container) return;
    container.innerHTML = '';
    
    let pills = [...tvChatTemplatesMap.general];
    
    const indicatorLuxAlgo = document.getElementById('tv-indicator-lux-algo');
    const indicatorMxwll = document.getElementById('tv-indicator-mxwll');
    const indicatorLuxSMC = document.getElementById('tv-indicator-lux-smc');
    const indicatorLRTC = document.getElementById('tv-indicator-lrtc');
    const indicatorPitchfork = document.getElementById('tv-indicator-pitchfork');
    
    if (indicatorLuxAlgo && indicatorLuxAlgo.checked) pills = pills.concat(tvChatTemplatesMap['lux-algo']);
    if (indicatorMxwll && indicatorMxwll.checked) pills = pills.concat(tvChatTemplatesMap['mxwll']);
    if (indicatorLuxSMC && indicatorLuxSMC.checked) pills = pills.concat(tvChatTemplatesMap['lux-smc']);
    if (indicatorLRTC && indicatorLRTC.checked) pills = pills.concat(tvChatTemplatesMap['lrtc']);
    if (indicatorPitchfork && indicatorPitchfork.checked) pills = pills.concat(tvChatTemplatesMap['pitchfork']);
    
    pills.forEach(tpl => {
        const btn = document.createElement('button');
        btn.className = 'tv-template-pill';
        btn.style.cssText = `
            background: rgba(16, 185, 129, 0.1);
            border: 1px solid rgba(16, 185, 129, 0.25);
            color: var(--text-primary);
            font-size: 10px;
            padding: 4px 10px;
            border-radius: 12px;
            cursor: pointer;
            transition: all 0.2s;
            flex-shrink: 0;
            font-weight: 500;
        `;
        btn.innerText = tpl.label;
        btn.addEventListener('mouseenter', () => {
            btn.style.background = 'rgba(16, 185, 129, 0.2)';
            btn.style.borderColor = 'rgba(16, 185, 129, 0.4)';
        });
        btn.addEventListener('mouseleave', () => {
            btn.style.background = 'rgba(16, 185, 129, 0.1)';
            btn.style.borderColor = 'rgba(16, 185, 129, 0.25)';
        });
        btn.addEventListener('click', () => {
            const input = document.getElementById('tv-chart-chat-input');
            if (input) {
                input.value = tpl.text;
                triggerTvChatQuery();
            }
        });
        container.appendChild(btn);
    });
}

async function triggerTvChatQuery() {
    const input = document.getElementById('tv-chart-chat-input');
    if (!input) return;
    const promptText = input.value.trim();
    if (!promptText) return;
    
    const sendBtn = document.getElementById('tv-chart-chat-send-btn');
    const spinner = document.getElementById('tv-chart-send-spinner');
    const history = document.getElementById('tv-chart-chat-history');
    if (!history) return;
    
    appendTvChatMessage('user', promptText);
    input.value = '';
    
    if (sendBtn) sendBtn.disabled = true;
    if (spinner) spinner.style.display = 'inline-block';
    
    const botMsgId = 'tv-bot-' + Date.now();
    appendTvChatLoading(botMsgId);
    
    try {
        const activeInd = document.getElementById('tv-active-indicator')?.value || 'general';
        const length = parseInt(document.getElementById('tv-length')?.value || '14', 10);
        const mult = parseFloat(document.getElementById('tv-mult')?.value || '1.0');
        
        const payload = {
            symbol: activeStockProfile ? activeStockProfile.ticker : 'STOCK',
            indicator: activeInd,
            length: length,
            mult: mult,
            custom_prompt: promptText,
            chat_history: tvChatHistoryList
        };
        
        const res = await fetch('/api/chart/chat-analyst', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload)
        });
        
        if (!res.ok) throw new Error("Failed to compile AI chart query");
        const data = await res.json();
        
        removeTvChatLoading(botMsgId);
        appendTvChatMessage('bot', data.analysis || "No response received.");
        tvChatHistoryList.push({ role: 'user', content: promptText });
        tvChatHistoryList.push({ role: 'assistant', content: data.analysis || "" });
        
        updateTvChartConsensusRating();
    } catch (err) {
        console.error("AI Chart Chat error:", err);
        removeTvChatLoading(botMsgId);
        appendTvChatMessage('bot', "❌ Error: Failed to generate response from AI model.");
    } finally {
        if (sendBtn) sendBtn.disabled = false;
        if (spinner) spinner.style.display = 'none';
    }
}

function clearTvTemporaryPriceLines() {
    if (activeTVCandleSeries) {
        tvTemporaryPriceLines.forEach(line => {
            try {
                activeTVCandleSeries.removePriceLine(line);
            } catch (err) {}
        });
    }
    tvTemporaryPriceLines = [];
}

function addTvTemporaryPriceLine(price, label) {
    if (!activeTVCandleSeries) return;
    clearTvTemporaryPriceLines();
    
    try {
        const line = activeTVCandleSeries.createPriceLine({
            price: parseFloat(price),
            color: '#fbbf24',
            lineWidth: 2,
            lineStyle: LightweightCharts.LineStyle.Solid,
            axisLabelVisible: true,
            title: label || 'Target Level'
        });
        tvTemporaryPriceLines.push(line);
        
        setTimeout(() => {
            try {
                if (activeTVCandleSeries) {
                    activeTVCandleSeries.removePriceLine(line);
                }
            } catch (e) {}
        }, 8000);
    } catch (err) {
        console.error("Error adding temporary price line:", err);
    }
}
window.addTvTemporaryPriceLine = addTvTemporaryPriceLine;

function makePricesClickable(htmlText) {
    const regex = /(?:Rs\.|₹)\s*([\d,]+(?:\.\d{1,2})?)/g;
    return htmlText.replace(regex, (match, val) => {
        const numericVal = val.replace(/,/g, '');
        return `<span class="clickable-price-level" data-price="${numericVal}" onclick="window.addTvTemporaryPriceLine(${numericVal}, 'Target Level: ₹${numericVal}')">${match}</span>`;
    });
}

function appendTvChatMessage(role, content) {
    const history = document.getElementById('tv-chart-chat-history');
    if (!history) return;
    
    const div = document.createElement('div');
    div.style.cssText = `
        display: flex;
        flex-direction: column;
        gap: 4px;
        max-width: 85%;
        padding: 8px 12px;
        border-radius: 12px;
        line-height: 1.4;
    `;
    
    if (role === 'user') {
        div.style.alignSelf = 'flex-end';
        div.style.background = 'var(--color-primary-glow)';
        div.style.color = 'var(--text-primary)';
        div.style.borderRadius = '12px 12px 0px 12px';
        div.innerText = content;
    } else {
        div.style.alignSelf = 'flex-start';
        div.style.background = 'rgba(255,255,255,0.05)';
        div.style.color = 'var(--text-secondary)';
        div.style.borderRadius = '12px 12px 12px 0px';
        
        let html = formatMarkdownToHTML(content);
        html = makePricesClickable(html);
        
        const speechContainer = document.createElement('div');
        speechContainer.style.cssText = 'display: flex; gap: 8px; margin-top: 6px; font-size: 10px;';
        
        const speakBtn = document.createElement('button');
        speakBtn.className = 'tv-chat-speak-btn';
        speakBtn.style.cssText = 'background: transparent; border: none; padding: 2px 4px; cursor: pointer; font-size: 14px; opacity: 0.7;';
        speakBtn.innerHTML = '🔊';
        
        speakBtn.addEventListener('click', () => {
            const rawText = content;
            const plainText = rawText.replace(/[#*`_-]/g, '').trim();
            const cleanForSpeech = plainText
                .replace(/\+/g, ' plus ')
                .replace(/\b-\b/g, ' minus ')
                .replace(/^-/mg, ' minus ')
                .replace(/\s+-\s*/g, ' minus ');
            if (window.SpeechPlayer) {
                window.SpeechPlayer.startSpeakingSection(cleanForSpeech, "AI Technical Analyst", true);
            }
        });
        
        speechContainer.appendChild(speakBtn);
        
        const contentDiv = document.createElement('div');
        contentDiv.innerHTML = html;
        div.appendChild(contentDiv);
        div.appendChild(speechContainer);
    }
    
    history.appendChild(div);
    history.scrollTop = history.scrollHeight;
}

function appendTvChatLoading(id) {
    const history = document.getElementById('tv-chart-chat-history');
    if (!history) return;
    
    const div = document.createElement('div');
    div.id = id;
    div.style.cssText = `
        align-self: flex-start;
        background: rgba(255,255,255,0.05);
        color: var(--text-muted);
        padding: 8px 12px;
        border-radius: 12px 12px 12px 0px;
        max-width: 85%;
        font-style: italic;
    `;
    div.innerText = "Thinking...";
    
    history.appendChild(div);
    history.scrollTop = history.scrollHeight;
}

function removeTvChatLoading(id) {
    const el = document.getElementById(id);
    if (el) el.remove();
}


function setupTvChatSTT() {
    const micBtn = document.getElementById('tv-chart-chat-mic-btn');
    const inputEl = document.getElementById('tv-chart-chat-input');
    if (!micBtn || !inputEl) return;
    
    const isAndroidSpeech = window.AndroidSpeech && typeof window.AndroidSpeech.startListening === 'function';
    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    
    if (isAndroidSpeech) {
        micBtn.addEventListener('click', () => {
            if (window.AndroidSpeechListening && window.activeSpeechRecognizerTarget === 'tv_chart_chat') {
                window.AndroidSpeech.stopListening();
            } else {
                window.activeSpeechRecognizerTarget = 'tv_chart_chat';
                window.AndroidSpeech.startListening();
            }
        });
    } else if (!SpeechRecognition) {
        micBtn.style.display = 'none';
    } else {
        let recognition = new SpeechRecognition();
        recognition.continuous = false;
        recognition.interimResults = false;
        recognition.lang = 'en-US';
        let isListening = false;
        
        recognition.onstart = () => {
            isListening = true;
            micBtn.innerHTML = '🔴';
            micBtn.classList.add('mic-listening');
        };
        
        recognition.onend = () => {
            isListening = false;
            micBtn.innerHTML = '🎙️';
            micBtn.classList.remove('mic-listening');
        };
        
        recognition.onresult = (event) => {
            const transcript = event.results[0][0].transcript;
            if (inputEl) {
                inputEl.value = (inputEl.value ? inputEl.value + ' ' : '') + transcript;
            }
        };
        
        recognition.onerror = (event) => {
            console.error("Speech recognition error:", event.error);
        };
        
        micBtn.addEventListener('click', () => {
            if (isListening) {
                recognition.stop();
            } else {
                recognition.start();
            }
        });
    }
}

function updateTvChartConsensusRating() {
    const ratingBadge = document.getElementById('tv-chart-rating-badge');
    if (!ratingBadge) return;
    
    let score = 0;
    
    // Check which indicators are selected/checked
    const showSmc = document.getElementById('tv-indicator-lux-smc')?.checked;
    const showLrtc = document.getElementById('tv-indicator-lrtc')?.checked;
    const showPf = document.getElementById('tv-indicator-pitchfork')?.checked;
    
    if (showSmc) {
        const smcBiasEl = document.getElementById('smc-hud-bias');
        if (smcBiasEl) {
            const text = smcBiasEl.innerText.toUpperCase();
            if (text.includes('BULLISH')) score += 1;
            else if (text.includes('BEARISH')) score -= 1;
        }
    }
    
    if (showLrtc) {
        const lrtcDirectionEl = document.getElementById('lrtc-hud-slope');
        if (lrtcDirectionEl) {
            const text = lrtcDirectionEl.innerText.toUpperCase();
            if (text.includes('RISING') || text.includes('BULLISH')) score += 1;
            else if (text.includes('FALLING') || text.includes('BEARISH')) score -= 1;
        }
    }
    
    if (showPf) {
        const pfBiasEl = document.getElementById('pf-hud-bias');
        if (pfBiasEl) {
            const text = pfBiasEl.innerText.toUpperCase();
            if (text.includes('ABOVE MEDIAN') || text.includes('BULLISH')) score += 1;
            else if (text.includes('BELOW MEDIAN') || text.includes('BEARISH')) score -= 1;
        }
    }
    
    let ratingStr = "NEUTRAL";
    let color = "#fbbf24";
    let bg = "rgba(245, 158, 11, 0.2)";
    let border = "rgba(245, 158, 11, 0.3)";
    
    if (score >= 2) {
        ratingStr = "STRONG BUY";
        color = "#10b981";
        bg = "rgba(16, 185, 129, 0.2)";
        border = "rgba(16, 185, 129, 0.3)";
    } else if (score === 1) {
        ratingStr = "BUY";
        color = "#34d399";
        bg = "rgba(52, 211, 153, 0.15)";
        border = "rgba(52, 211, 153, 0.25)";
    } else if (score === -1) {
        ratingStr = "SELL";
        color = "#f87171";
        bg = "rgba(239, 68, 68, 0.15)";
        border = "rgba(239, 68, 68, 0.25)";
    } else if (score <= -2) {
        ratingStr = "STRONG SELL";
        color = "#ef4444";
        bg = "rgba(239, 68, 68, 0.25)";
        border = "rgba(239, 68, 68, 0.35)";
    }
    
    ratingBadge.innerText = ratingStr;
    ratingBadge.style.color = color;
    ratingBadge.style.background = bg;
    ratingBadge.style.borderColor = border;
    
    const confluenceWarning = document.getElementById('tv-chart-confluence-warning');
    if (confluenceWarning) {
        let isConfluence = false;
        
        const extractPrices = (txt) => {
            if (!txt || txt.toUpperCase().includes("NONE") || txt.toUpperCase().includes("N/A")) return [];
            const matches = txt.match(/\d+(?:\.\d+)?/g);
            return matches ? matches.map(Number) : [];
        };

        const activeLevels = [];
        const showBreaks = document.getElementById('tv-indicator-lux-algo')?.checked;
        const showMxwll = document.getElementById('tv-indicator-mxwll')?.checked;
        
        // 1. Breaks
        if (showBreaks) {
            const txt = document.getElementById('breaks-hud-levels')?.innerText || '';
            if (txt.includes("Bullish")) {
                const parts = txt.split("Bearish");
                const prices = extractPrices(parts[0]);
                prices.forEach(p => activeLevels.push({ name: "LuxAlgo Bullish Break", value: p, type: "bullish", indicator: "LuxAlgo" }));
                if (parts.length > 1) {
                    extractPrices(parts[1]).forEach(p => activeLevels.push({ name: "LuxAlgo Bearish Break", value: p, type: "bearish", indicator: "LuxAlgo" }));
                }
            } else if (txt.includes("Bearish")) {
                extractPrices(txt).forEach(p => activeLevels.push({ name: "LuxAlgo Bearish Break", value: p, type: "bearish", indicator: "LuxAlgo" }));
            } else {
                extractPrices(txt).forEach(p => activeLevels.push({ name: "LuxAlgo Break", value: p, type: "neutral", indicator: "LuxAlgo" }));
            }
        }
        
        // 2. SMC
        if (showSmc) {
            const supTxt = document.getElementById('smc-hud-supply')?.innerText || '';
            extractPrices(supTxt).forEach(p => activeLevels.push({ name: "SMC Supply OB", value: p, type: "bearish", indicator: "SMC" }));
            const demTxt = document.getElementById('smc-hud-demand')?.innerText || '';
            extractPrices(demTxt).forEach(p => activeLevels.push({ name: "SMC Demand OB", value: p, type: "bullish", indicator: "SMC" }));
        }

        // 3. Maxwell FVG
        if (showMxwll) {
            const supTxt = document.getElementById('mxwll-hud-supply')?.innerText || '';
            extractPrices(supTxt).forEach(p => activeLevels.push({ name: "Maxwell Supply FVG", value: p, type: "bearish", indicator: "Maxwell" }));
            const demTxt = document.getElementById('mxwll-hud-demand')?.innerText || '';
            extractPrices(demTxt).forEach(p => activeLevels.push({ name: "Maxwell Demand FVG", value: p, type: "bullish", indicator: "Maxwell" }));
        }

        // 4. LRTC
        if (showLrtc && window.latestTvChartData?.lrtc_latest) {
            const latest = window.latestTvChartData.lrtc_latest;
            if (latest.upper_end) {
                activeLevels.push({ name: "LRTC Upper Boundary", value: Number(latest.upper_end), type: "bearish", indicator: "LRTC" });
            }
            if (latest.lower_end) {
                activeLevels.push({ name: "LRTC Lower Boundary", value: Number(latest.lower_end), type: "bullish", indicator: "LRTC" });
            }
            if (latest.median_end) {
                activeLevels.push({ name: "LRTC Median Line", value: Number(latest.median_end), type: "neutral", indicator: "LRTC" });
            }
        }

        // 5. Pitchfork
        if (showPf && window.latestTvChartData?.pitchfork) {
            const pf = window.latestTvChartData.pitchfork;
            if (pf.upper_line && pf.upper_line.length > 0) {
                const val = pf.upper_line[pf.upper_line.length - 1].value;
                activeLevels.push({ name: "Pitchfork Upper Line", value: Number(val), type: "bearish", indicator: "Pitchfork" });
            }
            if (pf.lower_line && pf.lower_line.length > 0) {
                const val = pf.lower_line[pf.lower_line.length - 1].value;
                activeLevels.push({ name: "Pitchfork Lower Line", value: Number(val), type: "bullish", indicator: "Pitchfork" });
            }
            if (pf.median_line && pf.median_line.length > 0) {
                const val = pf.median_line[pf.median_line.length - 1].value;
                activeLevels.push({ name: "Pitchfork Median Line", value: Number(val), type: "neutral", indicator: "Pitchfork" });
            }
        }

        let clusterLevels = [];
        let minSpread = 9999;
        
        for (let i = 0; i < activeLevels.length; i++) {
            for (let j = i + 1; j < activeLevels.length; j++) {
                const lv1 = activeLevels[i];
                const lv2 = activeLevels[j];
                if (lv1.indicator === lv2.indicator) continue;
                
                const diffPct = Math.abs(lv1.value - lv2.value) / Math.min(lv1.value, lv2.value);
                if (diffPct <= 0.015) {
                    isConfluence = true;
                    if (diffPct < minSpread) {
                        minSpread = diffPct;
                    }
                    if (!clusterLevels.includes(lv1)) clusterLevels.push(lv1);
                    if (!clusterLevels.includes(lv2)) clusterLevels.push(lv2);
                }
            }
        }

        if (isConfluence && clusterLevels.length > 0) {
            const prices = clusterLevels.map(l => l.value);
            const minPrice = Math.min(...prices);
            const maxPrice = Math.max(...prices);
            const avgPrice = prices.reduce((a, b) => a + b, 0) / prices.length;
            const spread = ((maxPrice - minPrice) / avgPrice) * 100;
            
            const bullCount = clusterLevels.filter(l => l.type === "bullish").length;
            const bearCount = clusterLevels.filter(l => l.type === "bearish").length;
            
            let signal = "NEUTRAL / CONGESTION";
            let signalColor = "#fbbf24";
            if (bullCount > bearCount) {
                signal = "🟢 BUY / LONG (Support Confluence)";
                signalColor = "#34d399";
            } else if (bearCount > bullCount) {
                signal = "🔴 SELL / SHORT (Resistance Confluence)";
                signalColor = "#f87171";
            }

            const sl = bullCount > bearCount ? minPrice * 0.985 : maxPrice * 1.015;
            const t1 = bullCount > bearCount ? avgPrice * 1.03 : avgPrice * 0.97;
            const t2 = bullCount > bearCount ? avgPrice * 1.06 : avgPrice * 0.94;

            window.currentConfluenceDetails = {
                signal: signal,
                signalColor: signalColor,
                spread: spread.toFixed(2) + "%",
                levels: clusterLevels,
                entryMin: minPrice.toFixed(2),
                entryMax: maxPrice.toFixed(2),
                sl: sl.toFixed(2),
                t1: t1.toFixed(2),
                t2: t2.toFixed(2),
                avgPrice: avgPrice.toFixed(2)
            };
        } else {
            window.currentConfluenceDetails = null;
        }
        
        confluenceWarning.style.display = isConfluence ? 'flex' : 'none';
    }
}

