function renderSmcGlossary(filter = 'all') {
    const listContainer = document.getElementById('smc-glossary-list');
    if (!listContainer) return;
    listContainer.innerHTML = '';
    
    const filtered = filter === 'all' 
        ? smcGlossaryTerms 
        : smcGlossaryTerms.filter(t => t.category === filter);
        
    filtered.forEach(term => {
        const card = document.createElement('div');
        card.style.cssText = `
            background: rgba(255, 255, 255, 0.03);
            border: 1px solid var(--border-glass);
            border-radius: 8px;
            padding: 12px;
            display: flex;
            flex-direction: column;
            gap: 6px;
            transition: all 0.2s ease;
        `;
        
        let catColor = '#a855f7';
        let catLabel = 'SMC Core';
        if (term.category === 'mxwll') {
            catColor = '#3b82f6';
            catLabel = 'Mxwll FVG';
        } else if (term.category === 'liquidity') {
            catColor = '#fbbf24';
            catLabel = 'Liquidity';
        }
        
        card.innerHTML = `
            <div style="display:flex; justify-content:space-between; align-items:center; flex-wrap:wrap; gap:4px;">
                <strong style="color:var(--text-primary); font-size:12.5px;">${term.name}</strong>
                <span style="font-size:8px; font-weight:700; background:rgba(255,255,255,0.05); color:${catColor}; padding:2px 6px; border-radius:4px; text-transform:uppercase; letter-spacing: 0.05em;">${catLabel}</span>
            </div>
            <div style="color:var(--text-secondary); line-height:1.4; font-size:11px;">${term.desc}</div>
            <div style="font-size:10px; font-weight:600; color:var(--text-muted); display:flex; align-items:center; gap:4px; margin-top:2px;">
                <span>Trading Interpretation:</span>
                <span style="color:var(--text-primary); font-style:italic;">${term.signal}</span>
            </div>
        `;
        listContainer.appendChild(card);
    });
}

function initSmcGlossaryModal() {
    const btn = document.getElementById('tv-chart-smc-glossary-btn');
    const modal = document.getElementById('smc-glossary-modal');
    const closeBtn = document.getElementById('smc-glossary-close-btn');
    
    if (btn && modal) {
        btn.addEventListener('click', () => {
            modal.style.display = 'flex';
            renderSmcGlossary('all');
            
            // Reset filter button styles
            document.querySelectorAll('.smc-filter-btn').forEach(fb => {
                fb.classList.remove('active');
                fb.style.borderColor = 'var(--border-glass)';
                fb.style.background = 'transparent';
                fb.style.color = 'var(--text-secondary)';
            });
            const allBtn = document.querySelector('.smc-filter-btn[data-filter="all"]');
            if (allBtn) {
                allBtn.classList.add('active');
                allBtn.style.borderColor = 'var(--color-primary)';
                allBtn.style.background = 'rgba(124, 58, 237, 0.15)';
                allBtn.style.color = '#a78bfa';
            }
        });
    }
    
    if (closeBtn && modal) {
        closeBtn.addEventListener('click', () => {
            modal.style.display = 'none';
        });
        modal.addEventListener('click', (e) => {
            if (e.target === modal) {
                modal.style.display = 'none';
            }
        });
    }
    
    // Bind filter buttons
    document.querySelectorAll('.smc-filter-btn').forEach(btnEl => {
        btnEl.addEventListener('click', () => {
            document.querySelectorAll('.smc-filter-btn').forEach(fb => {
                fb.classList.remove('active');
                fb.style.borderColor = 'var(--border-glass)';
                fb.style.background = 'transparent';
                fb.style.color = 'var(--text-secondary)';
            });
            btnEl.classList.add('active');
            btnEl.style.borderColor = 'var(--color-primary)';
            btnEl.style.background = 'rgba(124, 58, 237, 0.15)';
            btnEl.style.color = '#a78bfa';
            
            const filter = btnEl.getAttribute('data-filter');
            renderSmcGlossary(filter);
        });
    });
}

function initConfluenceModal() {
    const warningBadge = document.getElementById('tv-chart-confluence-warning');
    const modal = document.getElementById('tv-confluence-modal');
    const closeBtn = document.getElementById('tv-confluence-close-btn');
    const aiActionBtn = document.getElementById('tv-confluence-ai-action-btn');
    
    // Define globally to allow robust fallback inline onclick triggering
    window.showConfluenceBreakdownModal = function() {
        console.log("showConfluenceBreakdownModal called. currentConfluenceDetails:", window.currentConfluenceDetails);
        const tvModal = document.getElementById('tv-confluence-modal');
        if (!tvModal) {
            console.error("tv-confluence-modal not found in DOM");
            return;
        }
        if (!window.currentConfluenceDetails) {
            console.warn("No current confluence details available");
            return;
        }
        
        const details = window.currentConfluenceDetails;
        
        // Populate dialog elements
        const signalVal = document.getElementById('tv-confluence-signal-val');
        if (signalVal) {
            signalVal.innerText = details.signal.replace(/🟢 |🔴 /g, '');
            signalVal.style.color = details.signalColor;
        }
        
        const spreadVal = document.getElementById('tv-confluence-spread-val');
        if (spreadVal) {
            spreadVal.innerText = details.spread;
        }
        
        const entryZone = document.getElementById('tv-confluence-entry-zone');
        if (entryZone) {
            entryZone.innerText = `₹${details.entryMin} - ₹${details.entryMax}`;
        }
        
        const slVal = document.getElementById('tv-confluence-sl');
        if (slVal) {
            slVal.innerText = `₹${details.sl}`;
        }
        
        const t1Val = document.getElementById('tv-confluence-t1');
        if (t1Val) {
            t1Val.innerText = `₹${details.t1}`;
        }
        
        const t2Val = document.getElementById('tv-confluence-t2');
        if (t2Val) {
            t2Val.innerText = `₹${details.t2}`;
        }
        
        const list = document.getElementById('tv-confluence-levels-list');
        if (list) {
            list.innerHTML = '';
            details.levels.forEach(lv => {
                const div = document.createElement('div');
                div.style.display = 'flex';
                div.style.justifyContent = 'space-between';
                div.style.background = 'rgba(255,255,255,0.02)';
                div.style.border = '1px solid var(--border-glass)';
                div.style.padding = '8px 10px';
                div.style.borderRadius = '4px';
                
                const badgeColor = lv.type === 'bullish' ? '#34d399' : (lv.type === 'bearish' ? '#f87171' : '#9ca3af');
                const badgeBg = lv.type === 'bullish' ? 'rgba(52, 211, 153, 0.1)' : (lv.type === 'bearish' ? 'rgba(248, 113, 113, 0.1)' : 'rgba(156, 163, 175, 0.1)');
                
                div.innerHTML = `
                    <div style="display: flex; align-items: center; gap: 6px;">
                        <span style="font-size: 8px; padding: 2px 6px; border-radius: 4px; color: ${badgeColor}; background: ${badgeBg}; font-weight: 700; text-transform: uppercase; border: 1px solid ${badgeColor}40;">${lv.type}</span>
                        <span style="font-weight: 600; color: var(--text-primary); font-size: 11px;">${lv.name}</span>
                    </div>
                    <div style="font-weight: 700; color: var(--text-primary); font-size: 11px;">₹${Number(lv.value).toFixed(2)}</div>
                `;
                list.appendChild(div);
            });
        }
        
        tvModal.style.display = 'flex';
    };
    
    if (warningBadge) {
        warningBadge.addEventListener('click', (e) => {
            e.stopPropagation();
            window.showConfluenceBreakdownModal();
        });
    }
    
    if (closeBtn && modal) {
        closeBtn.addEventListener('click', () => {
            modal.style.display = 'none';
        });
        modal.addEventListener('click', (e) => {
            if (e.target === modal) {
                modal.style.display = 'none';
            }
        });
    }
    
    if (aiActionBtn && modal) {
        aiActionBtn.addEventListener('click', () => {
            if (!window.currentConfluenceDetails) return;
            modal.style.display = 'none';
            
            const details = window.currentConfluenceDetails;
            const input = document.getElementById('tv-chart-chat-input');
            if (input) {
                const levelsStr = details.levels.map(l => `${l.name} (₹${Number(l.value).toFixed(2)})`).join(', ');
                input.value = `Explain the trade setup for the Confluence Cluster detected near ₹${details.avgPrice} (overlapping indicators: ${levelsStr}). Recommend a step-by-step entry strategy, invalidation stop-loss, and target profit levels.`;
                triggerTvChatQuery();
            }
        });
    }
}


async function triggerTVIndicatorSynthesis() {
    const btn = document.getElementById('tv-btn-generate-synthesis');
    const content = document.getElementById('tv-ai-synthesis-content');
    if (!btn || !content) return;

    if (!activeStockProfile || !activeStockProfile.ticker) {
        content.innerHTML = `<span style="color: var(--text-muted);">Please load a stock ticker profile first.</span>`;
        return;
    }

    const ticker = activeStockProfile.ticker;
    const indicator = document.getElementById('tv-active-indicator')?.value || 'lux-algo';
    const length = parseInt(document.getElementById('tv-length')?.value || '14', 10);
    const mult = parseFloat(document.getElementById('tv-mult')?.value || '1.0');

    // Set loading state
    btn.disabled = true;
    btn.innerHTML = `<span>⏳ Analyzing...</span>`;
    content.innerHTML = `
        <div style="display: flex; flex-direction: column; gap: 8px; padding: 10px 0;">
            <div class="skeleton-pulse" style="height: 14px; width: 60%; background: rgba(255,255,255,0.05); border-radius: 4px;"></div>
            <div class="skeleton-pulse" style="height: 14px; width: 85%; background: rgba(255,255,255,0.05); border-radius: 4px;"></div>
            <div class="skeleton-pulse" style="height: 14px; width: 75%; background: rgba(255,255,255,0.05); border-radius: 4px;"></div>
            <div class="skeleton-pulse" style="height: 14px; width: 40%; background: rgba(255,255,255,0.05); border-radius: 4px;"></div>
        </div>
    `;

    try {
        const url = `/api/chart/indicator-synthesis?ticker=${encodeURIComponent(ticker)}&indicator=${indicator}&length=${length}&mult=${mult}`;
        const res = await fetch(url);
        if (!res.ok) throw new Error("Server returned error status.");
        const data = await res.json();

        content.innerHTML = formatMarkdownToHTML(data.synthesis);
    } catch (e) {
        console.error("AI indicator synthesis error: ", e);
        content.innerHTML = `<span style="color: #ef4444;">Failed to compile AI insights: ${e.message}. Please verify the backend LLM configurations.</span>`;
    } finally {
        btn.disabled = false;
        btn.innerHTML = `<span>⚡ Generate AI Analysis</span>`;
    }
}

function formatMarkdownToHTML(text) {
    if (!text) return "";
    let formatted = text;
    // Replace headers
    formatted = formatted.replace(/^### (.*$)/gim, '<h4 style="margin: 12px 0 6px 0; color: var(--text-primary); font-weight: 600; font-size: 13px;">$1</h4>');
    formatted = formatted.replace(/^## (.*$)/gim, '<h3 style="margin: 15px 0 8px 0; color: var(--text-primary); font-weight: 600; font-size: 14px;">$1</h3>');
    formatted = formatted.replace(/^# (.*$)/gim, '<h2 style="margin: 18px 0 10px 0; color: var(--text-primary); font-weight: 700; font-size: 15px;">$1</h2>');

    // Replace bold text
    formatted = formatted.replace(/\*\*(.*?)\*\*/g, '<strong style="color: var(--text-primary); font-weight: 700;">$1</strong>');

    // Replace bullet points
    formatted = formatted.replace(/^\s*-\s+(.*$)/gim, '<li style="margin-left: 15px; margin-bottom: 4px; list-style-type: disc;">$1</li>');

    // Convert line breaks to clean HTML paragraphs
    formatted = formatted.split('\n\n').map(p => {
        const trimmed = p.trim();
        if (trimmed.startsWith('<li') || trimmed.startsWith('<h')) return trimmed;
        return `<p style="margin-bottom: 8px;">${trimmed.replace(/\n/g, '<br>')}</p>`;
    }).join('');

    // Layman tooltips for identified chart patterns
    const patternGlossary = {
        "Double Bottom": "Layman: A 'W' shape on the chart where the price hit a floor twice and bounced back. Signals that sellers have given up and a rise is starting.",
        "Double Top": "Layman: An 'M' shape on the chart where the price hit a ceiling twice and fell back. Signals that buyers have given up and a fall is starting.",
        "Head and Shoulders": "Layman: A peak (head) surrounded by two lower peaks (shoulders). Signals that the uptrend has run out of gas and a downtrend is coming.",
        "Inverse Head and Shoulders": "Layman: A trough (head) surrounded by two higher troughs (shoulders). Signals that the downtrend has hit bottom and an uptrend is starting.",
        "Ascending Triangle": "Layman: A flat ceiling resistance line and a rising support line. Shows buyers are buying at higher lows, preparing for an upward breakout.",
        "Descending Triangle": "Layman: A flat floor support line and a falling resistance line. Shows sellers are pushing lower highs, preparing for a downward breakdown.",
        "Symmetrical Triangle": "Layman: Price squeezing between a falling ceiling and a rising floor. Represents a tight coil before an explosive breakout in either direction.",
        "Bull Flag": "Layman: A brief downward pause/channel after a sharp rally. Signals the stock is catching its breath before continuing the upward run.",
        "Bear Flag": "Layman: A brief upward pause/channel after a sharp drop. Signals the stock is pausing before continuing the downward slide.",
        "Pennant": "Layman: A tiny triangle consolidation that forms after a major move, signaling trend continuation.",
        "Wedge Breakout": "Layman: A price squeeze within sloping trendlines, leading to an explosive breakout in the opposite direction of the wedge."
    };

    for (const [pattern, definition] of Object.entries(patternGlossary)) {
        const regex = new RegExp(`\\b(${pattern})\\b`, "gi");
        formatted = formatted.replace(regex, `<span class="pattern-tooltip-highlight" style="color: var(--color-primary-light); border-bottom: 1.5px dashed var(--color-primary-light); cursor: help; font-weight: 600;" title="${definition}">$1</span>`);
    }

    return formatted;
}

window.renderTVWorkstationChart = renderTVWorkstationChart;

async function renderTVAdvancedChart(symbol) {
    if (!symbol || symbol === 'STOCK') {
        symbol = "RELIANCE.NS";
    }
    const container = document.getElementById('tv-advanced-container');
    if (!container) return;

    let cleanTicker = symbol.replace('^', '').split('.')[0].toUpperCase();
    let tvSymbol = "";
    
    if (symbol.includes('.NS') || symbol.includes('.BO')) {
        tvSymbol = "BSE:" + cleanTicker;
    } else if (symbol === '^NSEI' || cleanTicker === 'NSEI') {
        tvSymbol = "NSE:NIFTY";
    } else if (symbol === '^BSESN' || cleanTicker === 'BSESN') {
        tvSymbol = "BSE:SENSEX";
    } else if (symbol === '^NSEBANK' || cleanTicker === 'NSEBANK') {
        tvSymbol = "NSE:BANKNIFTY";
    } else if (symbol === '^CNXIT' || cleanTicker === 'CNXIT') {
        tvSymbol = "NSE:NIFTYIT";
    } else if (symbol === '^CNXINFRA' || cleanTicker === 'CNXINFRA') {
        tvSymbol = "NSE:NIFTYINFRA";
    } else if (symbol === '^CNXAUTO' || cleanTicker === 'CNXAUTO') {
        tvSymbol = "NSE:NIFTYAUTO";
    } else {
        tvSymbol = cleanTicker;
    }
    
    // Update external button href
    const externalBtn = document.getElementById('tv-advanced-external-btn');
    if (externalBtn) {
        externalBtn.href = `https://in.tradingview.com/chart/?symbol=${encodeURIComponent(tvSymbol)}`;
    }

    // Detect theme (dark or light)
    const isDark = document.documentElement.getAttribute('data-mode') === 'light' ? 'light' : 'dark';
    
    container.innerHTML = `<div id="tradingview_advanced_widget" style="width: 100%; height: 100%; min-height: 520px;"></div>`;
    
    if (typeof TradingView === 'undefined') {
        container.innerHTML = `<div style="padding: 20px; text-align: center; color: var(--text-muted);">TradingView API is offline. Please check your network connection.</div>`;
        return;
    }

    new TradingView.widget({
        "autosize": true,
        "symbol": tvSymbol,
        "interval": "D",
        "timezone": "Asia/Kolkata",
        "theme": isDark,
        "style": "1",
        "locale": "en",
        "enable_publishing": false,
        "hide_side_toolbar": false,
        "allow_symbol_change": true,
        "container_id": "tradingview_advanced_widget"
    });
}
window.renderTVAdvancedChart = renderTVAdvancedChart;

// ==================== FULLSCREEN WORKSTATION CHART OVERLAYS ====================
(function() {
    const style = document.createElement('style');
    style.innerHTML = `
        .fullscreen-card-active {
            position: fixed !important;
            top: 0 !important;
            left: 0 !important;
            width: 100vw !important;
            height: 100vh !important;
            z-index: 999999 !important;
            background: var(--bg-card, #0f172a) !important;
            padding: 20px !important;
            box-sizing: border-box !important;
            display: flex !important;
            flex-direction: column !important;
            gap: 15px !important;
        }
        /* Stretch nested wrapper div of TV chart to remove empty bottom spacing */
        #tv-chart-card.fullscreen-card-active > div:nth-child(2) {
            flex: 1 !important;
            display: flex !important;
            flex-direction: column !important;
            min-height: 0 !important;
        }
        .fullscreen-card-active #tv-chart-container {
            flex: 1 !important;
            height: auto !important;
            min-height: 0 !important;
        }
        .fullscreen-card-active #fibonacci-chart-container {
            flex: 1 !important;
            height: auto !important;
            min-height: 0 !important;
        }
        .fullscreen-card-active .price-chart-container {
            flex: 1 !important;
            height: auto !important;
            min-height: 0 !important;
        }
        .fullscreen-card-active .card-header {
            margin-bottom: 0 !important;
            border-bottom: 1px solid var(--border-glass) !important;
            padding-bottom: 10px !important;
        }
        @keyframes skeletonPulse {
            0% { opacity: 0.5; }
            50% { opacity: 1.0; }
            100% { opacity: 0.5; }
        }
        .skeleton-pulse {
            animation: skeletonPulse 1.5s infinite ease-in-out;
        }
    `;
    document.head.appendChild(style);

    document.addEventListener('DOMContentLoaded', () => {
        // Helper to setup card-level fullscreen toggle in capture phase
        function setupFullscreenToggle(cardId, containerSelector, minHeight, resizeCallback) {
            const card = document.getElementById(cardId);
            if (!card) return;
            const container = card.querySelector(containerSelector);
            if (!container) return;

            container.style.cursor = 'zoom-in';

            // Listen on the card itself using capture phase (true)
            card.addEventListener('dblclick', (e) => {
                // Ignore if clicked on input/select/button controls, labels, legends, summary blocks, or headers
                if (e.target.closest('input, select, option, button, label, a, .chart-controls, .card-header, #fibonacci-chart-hud, #tv-chart-legend-panel, .fib-summary-block, #price-trend-summary-block')) {
                    return;
                }

                const isFullscreen = card.classList.contains('fullscreen-card-active');
                if (isFullscreen) {
                    card.classList.remove('fullscreen-card-active');
                    container.style.cursor = 'zoom-in';
                    setTimeout(() => {
                        const targetWidth = container.clientWidth || 300;
                        resizeCallback(targetWidth, minHeight);
                    }, 50);
                } else {
                    card.classList.add('fullscreen-card-active');
                    container.style.cursor = 'zoom-out';
                    setTimeout(() => {
                        const targetHeight = Math.max(container.clientHeight || 0, window.innerHeight - 320);
                        const targetWidth = container.clientWidth || (window.innerWidth - 40);
                        if (targetWidth > 50 && targetHeight > 50) {
                            resizeCallback(targetWidth, targetHeight);
                        }
                    }, 50);
                }
            }, true);
        }

        // 1. TradingView Workstation Chart
        setupFullscreenToggle('tv-chart-card', '#tv-chart-container', 420, (width, height) => {
            if (activeTVWorkstationChart && width > 50 && height > 50) {
                activeTVWorkstationChart.resize(width, height);
            }
        });

        // 2. Fibonacci Retracements Chart
        setupFullscreenToggle('tech-fib-card', '#fibonacci-chart-container', 250, (width, height) => {
            if (window.activeFibLightweightChart && width > 50 && height > 50) {
                window.activeFibLightweightChart.resize(width, height);
            }
            if (activeFibChartInstance) {
                activeFibChartInstance.resize();
            }
        });

        // 3. Historical Price & Trend Analysis Chart
        setupFullscreenToggle('price-trend-chart-card', '.price-chart-container', 350, (width, height) => {
            if (activeChartInstance) {
                activeChartInstance.resize();
            }
        });

        // Escape key to exit fullscreen (for any active fullscreen card)
        document.addEventListener('keydown', (e) => {
            if (e.key === 'Escape') {
                const activeFullscreenCard = document.querySelector('.fullscreen-card-active');
                if (activeFullscreenCard) {
                    activeFullscreenCard.classList.remove('fullscreen-card-active');

                    const tvContainer = document.getElementById('tv-chart-container');
                    const fibContainer = document.getElementById('fibonacci-chart-container');
                    const priceCard = document.getElementById('price-trend-chart-card');
                    const priceContainer = priceCard ? priceCard.querySelector('.price-chart-container') : null;

                    // Restore cursors
                    if (tvContainer) tvContainer.style.cursor = 'zoom-in';
                    if (fibContainer) fibContainer.style.cursor = 'zoom-in';
                    if (priceContainer) priceContainer.style.cursor = 'zoom-in';

                    // Resize matching charts
                    setTimeout(() => {
                        if (activeFullscreenCard.id === 'tv-chart-card' && activeTVWorkstationChart && tvContainer) {
                            const targetWidth = tvContainer.clientWidth || 300;
                            activeTVWorkstationChart.resize(targetWidth, 420);
                        } else if (activeFullscreenCard.id === 'tech-fib-card') {
                            if (window.activeFibLightweightChart && fibContainer) {
                                const targetWidth = fibContainer.clientWidth || 300;
                                window.activeFibLightweightChart.resize(targetWidth, 250);
                            }
                            if (activeFibChartInstance) {
                                activeFibChartInstance.resize();
                            }
                        } else if (activeFullscreenCard.id === 'price-trend-chart-card' && activeChartInstance) {
                            activeChartInstance.resize();
                        }
                    }, 50);
                }
            }
        });
    });

    window.activeSectorRegimeData = null;
    window.sectorRadarView = 'sectors';

    async function loadScreenerSectorRegime(forceRefresh = false) {
        const listEl = document.getElementById('sector-radar-list');
        const refreshBtn = document.getElementById('sector-radar-refresh-btn');
        const spinner = document.getElementById('sector-radar-refresh-spinner');
        const icon = document.getElementById('sector-radar-refresh-icon');

        if (!listEl) return;

        if (forceRefresh) {
            if (spinner) spinner.style.display = 'inline-block';
            if (icon) icon.style.display = 'none';
            if (refreshBtn) refreshBtn.setAttribute('disabled', 'true');
        }

        try {
            const url = forceRefresh ? '/api/screener/sector-regime/refresh' : '/api/screener/sector-regime';
            const method = forceRefresh ? 'POST' : 'GET';
            const response = await fetch(url, { method: method });
            if (!response.ok) throw new Error("Fetch failed.");
            const data = await response.json();
            
            // If it was a manual refresh, data is returned under a "data" wrapper key
            window.activeSectorRegimeData = forceRefresh && data.data ? data.data : data;

            window.renderSectorRegimeList();
        } catch (e) {
            console.error("Failed to load sector regime stats:", e);
            listEl.innerHTML = '<div style="font-size:10px; color:var(--neon-red); text-align:center; padding:15px;">Failed to load sector standings.</div>';
        } finally {
            if (spinner) spinner.style.display = 'none';
            if (icon) icon.style.display = 'inline-block';
            if (refreshBtn) refreshBtn.removeAttribute('disabled');
        }
    }

    window.screenerSectorFilter = null;
    window.screenerSymbolFilter = null;
    window.activeSectorSentiments = {};
    window.renderSectorRegimeList = function() {
        const listEl = document.getElementById('sector-radar-list');
        const lookbackSelect = document.getElementById('sector-radar-lookback');
        const capSelect = document.getElementById('sector-radar-cap');
        if (!listEl || !window.activeSectorRegimeData) return;

        const period = lookbackSelect ? lookbackSelect.value : '1m';
        const colName = `return_${period}`; // return_1m, return_3m, return_6m, return_1y, return_ytd
        const selectedCap = capSelect ? capSelect.value.toLowerCase() : 'all';

        // 1. Process sectors and calculate stats dynamically on the client-side
        const processedSectors = [];
        let totalAdvances = 0;
        let totalDeclines = 0;

        window.activeSectorRegimeData.forEach(s => {
            // Filter stocks by cap type
            const filteredStocks = [];
            (s.stocks || []).forEach(stk => {
                if (selectedCap === 'all' || (stk.cap_type && stk.cap_type.toLowerCase() === selectedCap)) {
                    filteredStocks.push(stk);
                    const retVal = stk[colName] || 0.0;
                    if (retVal >= 0) {
                        totalAdvances++;
                    } else {
                        totalDeclines++;
                    }
                }
            });

            if (filteredStocks.length === 0) return;

            // Re-average returns based on filtered stocks
            const sumRet = filteredStocks.reduce((acc, curr) => acc + (curr[colName] || 0.0), 0.0);
            const avgRet = sumRet / filteredStocks.length;

            // Find leader and laggard inside the filtered list
            let leader = filteredStocks[0];
            let laggard = filteredStocks[0];
            filteredStocks.forEach(stk => {
                if ((stk[colName] || 0.0) > (leader[colName] || 0.0)) leader = stk;
                if ((stk[colName] || 0.0) < (laggard[colName] || 0.0)) laggard = stk;
            });

            let leader_sym = "N/A";
            let leader_ret = 0.0;
            let laggard_sym = "N/A";
            let laggard_ret = 0.0;

            if (filteredStocks.length === 1) {
                const singleStock = filteredStocks[0];
                const singleRet = singleStock[colName] || 0.0;
                if (singleRet >= 0) {
                    leader_sym = singleStock.symbol.replace(".NS", "");
                    leader_ret = singleRet;
                    laggard_sym = "N/A";
                    laggard_ret = 0.0;
                } else {
                    leader_sym = "N/A";
                    leader_ret = 0.0;
                    laggard_sym = singleStock.symbol.replace(".NS", "");
                    laggard_ret = singleRet;
                }
            } else {
                leader_sym = leader.symbol.replace(".NS", "");
                leader_ret = leader[colName] || 0.0;
                laggard_sym = laggard.symbol.replace(".NS", "");
                laggard_ret = laggard[colName] || 0.0;
            }

            processedSectors.push({
                sector: s.sector,
                updated_at: s.updated_at,
                avg_return: avgRet,
                stocks_count: filteredStocks.length,
                leader_symbol: leader_sym,
                leader_return: leader_ret,
                laggard_symbol: laggard_sym,
                laggard_return: laggard_ret,
                stocks: filteredStocks
            });
        });

        // Sort sectors descending by average return
        processedSectors.sort((a, b) => b.avg_return - a.avg_return);

        // 2. Render color-coded Advance/Decline HUD
        const ratio = totalDeclines > 0 ? (totalAdvances / totalDeclines) : 1.0;
        const totalCount = totalAdvances + totalDeclines;
        const advPct = totalCount > 0 ? (totalAdvances / totalCount * 100) : 50;
        const decPct = 100 - advPct;

        const ratioEl = document.getElementById('market-breadth-ratio-lbl');
        const advEl = document.getElementById('market-advances-count');
        const decEl = document.getElementById('market-declines-count');
        const advBar = document.getElementById('market-breadth-adv-bar');
        const decBar = document.getElementById('market-breadth-dec-bar');

        if (ratioEl) {
            ratioEl.innerText = `${ratio.toFixed(2)}x ${ratio >= 1.0 ? 'Advances' : 'Declines'}`;
            ratioEl.style.color = ratio >= 1.0 ? 'var(--neon-green)' : 'var(--neon-red)';
        }
        if (advEl) advEl.innerHTML = `▲ ${totalAdvances} Advances`;
        if (decEl) decEl.innerHTML = `▼ ${totalDeclines} Declines`;
        if (advBar) advBar.style.width = `${advPct}%`;
        if (decBar) decBar.style.width = `${decPct}%`;

        // 3. Render color-coded Heatmap Matrix tiles
        listEl.innerHTML = '';
        if (processedSectors.length === 0) {
            listEl.innerHTML = '<div style="font-size:10px; color:var(--text-muted); text-align:center; padding:15px; grid-column: 1/-1;">No sectors match the selected capitalization filter.</div>';
            return;
        }

        const activeView = window.sectorRadarView || 'sectors';
        if (activeView === 'stocks') {
            listEl.style.display = 'grid';
            listEl.style.gridTemplateColumns = 'repeat(auto-fill, minmax(280px, 1fr))';
            
            processedSectors.forEach(s => {
                const groupEl = document.createElement('div');
                groupEl.className = 'stock-heatmap-sector-group';
                
                const secRet = s.avg_return || 0.0;
                const secSign = secRet >= 0 ? '+' : '';
                const secColor = secRet >= 0 ? 'var(--neon-green)' : 'var(--neon-red)';
                
                groupEl.innerHTML = `
                    <div class="stock-heatmap-sector-header">
                        <span>${s.sector}</span>
                        <span style="color: ${secColor}; font-weight:800;">${secSign}${secRet.toFixed(2)}%</span>
                    </div>
                    <div class="stock-heatmap-grid" id="stock-grid-${s.sector.replace(/\s+/g, '-')}"></div>
                `;
                
                const gridEl = groupEl.querySelector('.stock-heatmap-grid');
                
                // Sort stocks in sector descending by performance in active period
                const sortedStocks = [...(s.stocks || [])].sort((a, b) => {
                    const valA = a[colName] || 0.0;
                    const valB = b[colName] || 0.0;
                    return valB - valA;
                });

                sortedStocks.forEach(stk => {
                    const ret = stk[colName] || 0.0;
                    const sign = ret >= 0 ? '+' : '';
                    
                    let tileBg = 'rgba(255, 255, 255, 0.015)';
                    let tileBorder = '1px solid var(--border-glass)';
                    let valueColor = 'var(--text-primary)';
                    
                    if (ret >= 5.0) {
                        tileBg = 'rgba(16, 185, 129, 0.22)';
                        tileBorder = '1px solid rgba(16, 185, 129, 0.5)';
                        valueColor = 'var(--neon-green)';
                    } else if (ret > 0.0) {
                        tileBg = 'rgba(16, 185, 129, 0.08)';
                        tileBorder = '1px solid rgba(16, 185, 129, 0.25)';
                        valueColor = '#a7f3d0';
                    } else if (ret <= -5.0) {
                        tileBg = 'rgba(239, 68, 68, 0.22)';
                        tileBorder = '1px solid rgba(239, 68, 68, 0.5)';
                        valueColor = 'var(--neon-red)';
                    } else if (ret < 0.0) {
                        tileBg = 'rgba(239, 68, 68, 0.08)';
                        tileBorder = '1px solid rgba(239, 68, 68, 0.25)';
                        valueColor = '#fca5a5';
                    }
                    
                    const tile = document.createElement('div');
                    tile.className = 'stock-heatmap-tile';
                    tile.style.background = tileBg;
                    tile.style.borderColor = tileBorder.replace('1px solid ', '');
                    
                    tile.title = `${stk.company_name}\nCap: ${stk.cap_type.toUpperCase()}\nReturn: ${sign}${ret.toFixed(2)}%\nClick to analyze stock details!`;
                    
                    tile.innerHTML = `
                        <span class="stock-heatmap-tile-sym">${stk.symbol.replace('.NS', '')}</span>
                        <span class="stock-heatmap-tile-pct" style="color: ${valueColor};">${sign}${ret.toFixed(1)}%</span>
                    `;
                    
                    tile.addEventListener('click', () => {
                        if (window.switchTab) window.switchTab('analyzer');
                        if (window.loadStockAnalyzer) {
                            window.loadStockAnalyzer(stk.symbol);
                        }
                    });
                    
                    gridEl.appendChild(tile);
                });
                
                listEl.appendChild(groupEl);
            });
            return;
        }

        // Restore sector grid template columns
        listEl.style.gridTemplateColumns = 'repeat(auto-fill, minmax(240px, 1fr))';

        // Find max return value for scaling
        const maxVal = Math.max(...processedSectors.map(s => Math.abs(s.avg_return || 0.1)));

        processedSectors.forEach(s => {
            const ret = s.avg_return || 0.0;
            const absPct = maxVal > 0 ? (Math.abs(ret) / maxVal) * 100 : 0;
            const sign = ret >= 0 ? '+' : '';
            
            // Heatmap color logic
            let tileBg = 'rgba(255, 255, 255, 0.015)';
            let tileBorder = '1px solid var(--border-glass)';
            let valueColor = 'var(--text-primary)';
            let barColor = 'rgba(255, 255, 255, 0.1)';

            if (ret >= 5.0) {
                tileBg = 'rgba(16, 185, 129, 0.15)';
                tileBorder = '1px solid rgba(16, 185, 129, 0.4)';
                valueColor = 'var(--neon-green)';
                barColor = 'var(--neon-green)';
            } else if (ret > 0.0) {
                tileBg = 'rgba(16, 185, 129, 0.05)';
                tileBorder = '1px solid rgba(16, 185, 129, 0.18)';
                valueColor = '#a7f3d0';
                barColor = 'rgba(16, 185, 129, 0.6)';
            } else if (ret <= -5.0) {
                tileBg = 'rgba(239, 68, 68, 0.15)';
                tileBorder = '1px solid rgba(239, 68, 68, 0.4)';
                valueColor = 'var(--neon-red)';
                barColor = 'var(--neon-red)';
            } else if (ret < 0.0) {
                tileBg = 'rgba(239, 68, 68, 0.05)';
                tileBorder = '1px solid rgba(239, 68, 68, 0.18)';
                valueColor = '#fca5a5';
                barColor = 'rgba(239, 68, 68, 0.6)';
            }

            // Sentiment Overlay
            const sentimentScore = window.activeSectorSentiments[s.sector];
            let sentimentHtml = '';
            if (sentimentScore !== undefined) {
                const icon = sentimentScore >= 60 ? '🐂' : (sentimentScore <= 40 ? '🐻' : '⚖️');
                const col = sentimentScore >= 60 ? 'var(--neon-green)' : (sentimentScore <= 40 ? 'var(--neon-red)' : '#f59e0b');
                sentimentHtml = `<span style="font-size: 9.5px; background: var(--bg-glass-input); padding: 2px 6px; border-radius: 4px; border: 1px solid var(--border-glass); font-weight: 700; color: ${col}; display: inline-flex; align-items: center; gap: 3px;">
                                    🌡️ ${icon} ${sentimentScore}% Sent.
                                 </span>`;
            } else {
                sentimentHtml = `<span style="font-size: 9.5px; background: var(--bg-glass-input); padding: 2px 6px; border-radius: 4px; border: 1px solid var(--border-glass); font-weight: 500; color: var(--text-muted); display: inline-flex; align-items: center; gap: 3px;" title="Click 'Analyze Rotation' button below to calculate live news-driven sentiment ratings">
                                    🌡️ AI Sent: --%
                                 </span>`;
            }

            const tile = document.createElement('div');
            tile.className = 'sector-heatmap-tile';
            tile.style.background = tileBg;
            tile.style.border = tileBorder;
            tile.title = `Last calculated: ${s.updated_at}\nClick to view constituent stocks!`;

            tile.innerHTML = `
                <div class="sector-heatmap-tile-header">
                    <div style="display: flex; flex-direction: column; gap: 4px;">
                        <span class="sector-heatmap-tile-title">${s.sector}</span>
                        <div style="margin-top: 2px;">${sentimentHtml}</div>
                    </div>
                    <span class="sector-heatmap-tile-pct" style="color: ${valueColor};">${sign}${ret.toFixed(2)}%</span>
                </div>
                <div class="sector-heatmap-tile-drivers" style="margin-top: 10px; font-size: 10.5px; line-height: 1.35; display: flex; flex-direction: column; gap: 2px; width: 100%; box-sizing: border-box;">
                    <span style="color: var(--text-secondary); text-overflow: ellipsis; overflow: hidden; white-space: nowrap; display: block; width: 100%;">
                        🟢 <strong style="color: var(--neon-green);">Leader:</strong> ${s.leader_symbol !== 'N/A' ? `${s.leader_symbol} (${s.leader_return >= 0 ? '+' : ''}${s.leader_return.toFixed(1)}%)` : 'N/A'}
                    </span>
                    <span style="color: var(--text-secondary); text-overflow: ellipsis; overflow: hidden; white-space: nowrap; display: block; width: 100%;">
                        🔴 <strong style="color: var(--neon-red);">Laggard:</strong> ${s.laggard_symbol !== 'N/A' ? `${s.laggard_symbol} (${s.laggard_return >= 0 ? '+' : ''}${s.laggard_return.toFixed(1)}%)` : 'N/A'}
                    </span>
                </div>
                <div class="sector-heatmap-tile-bar-bg">
                    <div class="sector-heatmap-tile-bar-fill" style="width: ${absPct}%; background: ${barColor};"></div>
                </div>
                <div class="sector-heatmap-tile-footer" style="display: flex; justify-content: space-between; align-items: center; margin-top: 15px; font-size: 11px; width: 100%; border-top: 1px solid rgba(255, 255, 255, 0.04); padding-top: 8px;">
                    <span class="view-stocks-btn" style="color: var(--color-primary); font-weight: 700; display: flex; align-items: center; gap: 4px; cursor: pointer;">
                        🔍 View ${s.stocks_count} Stocks
                    </span>
                    <span class="screen-sector-btn" style="color: var(--text-muted); text-decoration: underline; cursor: pointer;">
                        Screener ↗
                    </span>
                </div>
            `;
            
            // Clicking the main tile area opens the stock modal
            tile.addEventListener('click', (e) => {
                if (e.target.closest('.screen-sector-btn') || e.target.closest('.view-stocks-btn')) {
                    return;
                }
                window.openSectorStocksModal(s.sector, s.stocks, period);
            });
            
            // View stocks button triggers modal
            const viewBtn = tile.querySelector('.view-stocks-btn');
            if (viewBtn) {
                viewBtn.addEventListener('click', (e) => {
                    e.stopPropagation();
                    window.openSectorStocksModal(s.sector, s.stocks, period);
                });
            }
            
            // Screener link triggers scan redirection
            const screenBtn = tile.querySelector('.screen-sector-btn');
            if (screenBtn) {
                screenBtn.addEventListener('click', (e) => {
                    e.stopPropagation();
                    window.screenerSectorFilter = s.sector;
                    window.screenerSymbolFilter = null;

                    const styleSelect = document.getElementById('screener-style-select');
                    const universeSelect = document.getElementById('screener-universe-select');
                    if (styleSelect) styleSelect.value = 'all';
                    if (universeSelect) universeSelect.value = 'all';

                    if (window.switchTab) {
                        window.switchTab('screener');
                        
                        // Set the global variables in our script scope
                        activeScreenerStrategy = 'hybrid';
                        activeScreenerStyle = 'all';

                        const strategyBtns = document.querySelectorAll('#tab-screener .strategy-btn');
                        strategyBtns.forEach(btn => {
                            btn.classList.remove('active');
                            if (btn.getAttribute('data-strategy') === 'hybrid') btn.classList.add('active');
                        });

                        if (window.renderActiveScreenerChips) {
                            window.renderActiveScreenerChips();
                        }
                        if (window.runAIScreener) {
                            window.runAIScreener();
                        }
                    }
                });
            }

            listEl.appendChild(tile);
        });
    };

    window.openSectorStocksModal = function(sectorName, stocksList, period) {
        const modal = document.getElementById('sector-stocks-modal');
        const titleEl = document.getElementById('sector-stocks-modal-title');
        const badgeEl = document.getElementById('sector-stocks-horizon-badge');
        const searchInput = document.getElementById('sector-stocks-search');
        const tableBody = document.getElementById('sector-stocks-table-body');
        const closeBtn = document.getElementById('sector-stocks-modal-close-btn');

        if (!modal || !tableBody) return;

        // Reset search input
        if (searchInput) searchInput.value = '';

        // Map period labels
        const horizonLabels = {
            '1d': '1 Day',
            '5d': '5 Days',
            '1m': '1 Month (20D)',
            '3m': '3 Months',
            '6m': '6 Months',
            '1y': '1 Year',
            '5y': '5 Years',
            'ytd': 'Year-To-Date (YTD)'
        };
        if (badgeEl) badgeEl.innerText = horizonLabels[period] || period;
        if (titleEl) titleEl.innerText = `🔥 ${sectorName} Sector Constituents`;

        const activeCol = `return_${period}`;

        // Keep local copy sorted descending by return in the active period
        let stocks = [...stocksList].sort((a, b) => {
            const valA = a[activeCol] || 0.0;
            const valB = b[activeCol] || 0.0;
            return valB - valA;
        });

        function renderRows(filteredStocks) {
            tableBody.innerHTML = '';
            if (filteredStocks.length === 0) {
                tableBody.innerHTML = `<tr><td colspan="11" style="text-align: center; padding: 15px; color: var(--text-muted);">No stocks matching filter.</td></tr>`;
                return;
            }

            filteredStocks.forEach(stk => {
                const ret1d = stk.return_1d || 0.0;
                const ret5d = stk.return_5d || 0.0;
                const ret1m = stk.return_1m || 0.0;
                const ret3m = stk.return_3m || 0.0;
                const ret6m = stk.return_6m || 0.0;
                const ret1y = stk.return_1y || 0.0;
                const ret5y = stk.return_5y || 0.0;

                // Color-coded pill builder
                function getPillHtml(val) {
                    const sign = val >= 0 ? '+' : '';
                    const col = val >= 5.0 ? 'var(--neon-green)' : (val >= 0.0 ? '#a7f3d0' : (val <= -5.0 ? 'var(--neon-red)' : '#fca5a5'));
                    const bg = val >= 5.0 ? 'rgba(16, 185, 129, 0.15)' : (val >= 0.0 ? 'rgba(16, 185, 129, 0.05)' : (val <= -5.0 ? 'rgba(239, 68, 68, 0.15)' : 'rgba(239, 68, 68, 0.05)'));
                    return `<span style="display: inline-block; padding: 2px 6px; border-radius: 4px; font-weight: 700; color: ${col}; background: ${bg}; border: 1px solid rgba(255,255,255,0.03); font-family: 'Outfit'; min-width: 50px; text-align: right;">${sign}${val.toFixed(1)}%</span>`;
                }

                // Cap badge
                let capBadgeHtml = '';
                const cap = (stk.cap_type || 'small').toLowerCase();
                if (cap === 'large') {
                    capBadgeHtml = `<span style="background: rgba(59, 130, 246, 0.15); border: 1px solid rgba(59, 130, 246, 0.3); color: #60a5fa; padding: 1px 4px; border-radius: 4px; font-size: 9.5px; font-weight: 700;">L</span>`;
                } else if (cap === 'mid') {
                    capBadgeHtml = `<span style="background: rgba(16, 185, 129, 0.15); border: 1px solid rgba(16, 185, 129, 0.3); color: #34d399; padding: 1px 4px; border-radius: 4px; font-size: 9.5px; font-weight: 700;">M</span>`;
                } else {
                    capBadgeHtml = `<span style="background: rgba(245, 158, 11, 0.15); border: 1px solid rgba(245, 158, 11, 0.3); color: #fbbf24; padding: 1px 4px; border-radius: 4px; font-size: 9.5px; font-weight: 700;">S</span>`;
                }

                const tr = document.createElement('tr');
                tr.style.borderBottom = '1px solid var(--border-glass)';

                tr.innerHTML = `
                    <td style="padding: 10px 12px; font-weight: 700; color: var(--color-primary);">${stk.symbol.replace(".NS", "")}</td>
                    <td style="padding: 10px 12px; color: var(--text-secondary); max-width: 250px; text-overflow: ellipsis; overflow: hidden; white-space: nowrap;">${stk.company_name}</td>
                    <td style="padding: 10px 12px; text-align: center;">${capBadgeHtml}</td>
                    <td style="padding: 10px 12px; text-align: center;">${getPillHtml(ret1d)}</td>
                    <td style="padding: 10px 12px; text-align: center;">${getPillHtml(ret5d)}</td>
                    <td style="padding: 10px 12px; text-align: center;">${getPillHtml(ret1m)}</td>
                    <td style="padding: 10px 12px; text-align: center;">${getPillHtml(ret3m)}</td>
                    <td style="padding: 10px 12px; text-align: center;">${getPillHtml(ret6m)}</td>
                    <td style="padding: 10px 12px; text-align: center;">${getPillHtml(ret1y)}</td>
                    <td style="padding: 10px 12px; text-align: center;">${getPillHtml(ret5y)}</td>
                    <td style="padding: 10px 12px; text-align: center; display: flex; gap: 6px; justify-content: center; align-items: center;">
                        <button class="btn-primary modal-analyze-btn" style="height: 24px; padding: 0 8px; border-radius: 4px; font-size: 9.5px; font-weight: 700; background: var(--color-primary); color: #000; border: none; cursor: pointer; font-family: 'Outfit';">Analyze 📈</button>
                        <button class="btn-secondary modal-screen-btn" style="height: 24px; padding: 0 8px; border-radius: 4px; font-size: 9.5px; font-weight: 700; cursor: pointer; font-family: 'Outfit';">Screen 🔍</button>
                    </td>
                `;

                // Bind Analyze button click
                tr.querySelector('.modal-analyze-btn').addEventListener('click', () => {
                    modal.style.display = 'none';
                    if (window.switchTab) window.switchTab('analyzer');
                    if (window.loadStockAnalyzer) {
                        window.loadStockAnalyzer(stk.symbol);
                    }
                });

                // Bind Screen button click
                tr.querySelector('.modal-screen-btn').addEventListener('click', () => {
                    modal.style.display = 'none';
                    window.screenerSectorFilter = null;
                    window.screenerSymbolFilter = stk.symbol.replace(".NS", "");

                    const styleSelect = document.getElementById('screener-style-select');
                    const universeSelect = document.getElementById('screener-universe-select');
                    if (styleSelect) styleSelect.value = 'all';
                    if (universeSelect) universeSelect.value = 'all';

                    if (window.switchTab) {
                        window.switchTab('screener');
                        
                        activeScreenerStrategy = 'hybrid';
                        activeScreenerStyle = 'all';

                        const strategyBtns = document.querySelectorAll('#tab-screener .strategy-btn');
                        strategyBtns.forEach(btn => {
                            btn.classList.remove('active');
                            if (btn.getAttribute('data-strategy') === 'hybrid') btn.classList.add('active');
                        });

                        if (window.renderActiveScreenerChips) {
                            window.renderActiveScreenerChips();
                        }
                        if (window.runAIScreener) {
                            window.runAIScreener();
                        }
                    }
                });
                
                tableBody.appendChild(tr);
            });
        }

        // Render all stocks initially
        renderRows(stocks);

        // Search filtering keyup handler
        if (searchInput) {
            const onSearch = () => {
                const query = searchInput.value.toLowerCase().trim();
                const filtered = stocks.filter(stk => 
                    stk.symbol.toLowerCase().includes(query) || 
                    stk.company_name.toLowerCase().includes(query)
                );
                renderRows(filtered);
            };
            searchInput.removeEventListener('input', searchInput._onInput);
            searchInput._onInput = onSearch;
            searchInput.addEventListener('input', onSearch);
        }

        // Show modal wrapper
        modal.style.display = 'flex';

        // Close bindings
        const onClose = () => {
            modal.style.display = 'none';
        };
        if (closeBtn) {
            closeBtn.onclick = onClose;
        }
        modal.onclick = (e) => {
            if (e.target === modal) onClose();
        };
    };

    window.setupSectorRadarControls = function() {
        const lookbackSelect = document.getElementById('sector-radar-lookback');
        if (lookbackSelect) {
            lookbackSelect.addEventListener('change', () => {
                if (window.renderSectorRegimeList && window.activeSectorRegimeData) {
                    window.renderSectorRegimeList();
                }
            });
        }
        const capSelect = document.getElementById('sector-radar-cap');
        if (capSelect) {
            capSelect.addEventListener('change', () => {
                if (window.renderSectorRegimeList && window.activeSectorRegimeData) {
                    window.renderSectorRegimeList();
                }
            });
        }
        const viewControl = document.getElementById('sector-radar-view-control');
        if (viewControl) {
            viewControl.querySelectorAll('.segmented-btn').forEach(btn => {
                btn.addEventListener('click', () => {
                    viewControl.querySelectorAll('.segmented-btn').forEach(b => b.classList.remove('active'));
                    btn.classList.add('active');
                    window.sectorRadarView = btn.getAttribute('data-view');
                    if (window.renderSectorRegimeList && window.activeSectorRegimeData) {
                        window.renderSectorRegimeList();
                    }
                });
            });
        }
        const refreshBtn = document.getElementById('sector-radar-refresh-btn');
        if (refreshBtn) {
            refreshBtn.addEventListener('click', () => {
                if (window.loadScreenerSectorRegime) {
                    window.loadScreenerSectorRegime(true);
                }
            });
        }

        // 4. Wire up On-Demand AI Rotation Insights
        const aiBtn = document.getElementById('sector-ai-btn');
        const aiSpinner = document.getElementById('sector-ai-spinner');
        const aiContent = document.getElementById('sector-ai-content');
        const chatArea = document.getElementById('sector-ai-chat-area');
        const chatStream = document.getElementById('sector-ai-chat-stream');
        const chatInput = document.getElementById('sector-ai-chat-input');
        const chatSend = document.getElementById('sector-ai-chat-send');

        let chatHistory = [];

        if (aiBtn) {
            aiBtn.onclick = async () => {
                try {
                    if (aiSpinner) aiSpinner.style.display = 'inline-block';
                    aiBtn.setAttribute('disabled', 'true');
                    aiContent.innerHTML = 'Consulting AI rotation strategist and pulling live yfinance driver catalysts... Please wait.';

                    const period = lookbackSelect ? lookbackSelect.value : '1m';
                    const capType = capSelect ? capSelect.value : 'all';

                    const response = await fetch('/api/screener/sector-regime/ai-analysis', {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({ cap_type: capType, period: period })
                    });
                    
                    if (!response.ok) {
                        throw new Error(`Server returned status code ${response.status}`);
                    }
                    
                    const data = await response.json();
                    
                    // Store sector sentiments and redraw matrix with thermometers!
                    if (data.sector_sentiments) {
                        window.activeSectorSentiments = data.sector_sentiments;
                        window.renderSectorRegimeList();
                    }

                    // Render insights HTML
                    let alphaHtml = '';
                    if (data.alpha_ideas && data.alpha_ideas.length > 0) {
                        alphaHtml = `<div style="margin-top: 10px;">
                                        <strong style="color: var(--color-primary);">🧬 AI Alpha Breakout Ideas:</strong>
                                        <div style="display: flex; flex-direction: column; gap: 8px; margin-top: 6px;">
                                            ${data.alpha_ideas.map(item => `
                                                <div style="background: rgba(255,255,255,0.02); border: 1px solid rgba(255,255,255,0.04); border-radius: 6px; padding: 10px; display: flex; flex-direction: column; gap: 4px;">
                                                    <div style="display: flex; justify-content: space-between; align-items: center;">
                                                        <span class="chat-ticker-btn" data-ticker="${item.symbol}" style="font-weight: 700; color: var(--color-primary); cursor: pointer; text-decoration: underline;">
                                                            ${item.symbol.replace(".NS", "")} (${item.sector})
                                                        </span>
                                                        <span style="font-size: 10px; color: var(--text-muted);">${item.company_name}</span>
                                                    </div>
                                                    <div style="color: var(--text-secondary); font-size: 11px;">${item.reasoning}</div>
                                                </div>
                                            `).join('')}
                                        </div>
                                     </div>`;
                    }

                    let riskHtml = '';
                    if (data.risk_flags && data.risk_flags.length > 0) {
                        riskHtml = `<div style="margin-top: 10px;">
                                        <strong style="color: var(--neon-red);">⚠️ Rotational Risk Warnings:</strong>
                                        <ul style="margin: 6px 0 0 0; padding-left: 20px; color: var(--text-secondary);">
                                            ${data.risk_flags.map(item => `<li><strong style="color: var(--text-primary);">${item.sector}:</strong> ${item.flag_reason}</li>`).join('')}
                                        </ul>
                                     </div>`;
                    }

                    aiContent.innerHTML = `
                        <div style="display: flex; flex-direction: column; gap: 10px;">
                            <div>
                                <strong style="color: #a5b4fc;">💡 Rotation Commentary:</strong> ${data.commentary}
                            </div>
                            <div style="border-top: 1px solid rgba(255,255,255,0.04); padding-top: 8px;">
                                <strong style="color: #a5b4fc;">📊 Top-Down Macro Allocator Analysis:</strong> ${data.macro_allocator}
                            </div>
                            ${alphaHtml}
                            ${riskHtml}
                        </div>
                    `;

                    // Bind chat ticker clicks
                    aiContent.querySelectorAll('.chat-ticker-btn').forEach(btn => {
                        btn.onclick = () => {
                            const ticker = btn.getAttribute('data-ticker');
                            if (window.switchTab) window.switchTab('analyzer');
                            if (window.loadStockAnalyzer) window.loadStockAnalyzer(ticker);
                        };
                    });

                    // Reveal Chat Co-Pilot Interface
                    if (chatArea) {
                        chatArea.style.display = 'flex';
                        if (chatStream) {
                            const welcomeMsg = `Hello! I am your Rotation Co-Pilot, operating context-aware of the current standings (${capType} cap segment over ${period} horizon). Ask me any follow-up question!`;
                            const welcomeId = `rotation-msg-welcome`;
                            chatStream.innerHTML = `
                                <div style="margin-bottom: 4px;">
                                    <span style="color: var(--color-primary); font-weight: 700;">[Co-Pilot]</span>
                                    <button class="section-speak-btn" data-target="${welcomeId}" data-title="Rotation Co-Pilot" style="margin-left: 2px;">🔊</button>
                                    <span id="${welcomeId}">${welcomeMsg}</span>
                                </div>
                            `;
                            chatHistory = [
                                { role: "assistant", content: welcomeMsg }
                            ];
                        }
                    }

                } catch (e) {
                    console.error("AI Rotation analysis query failed:", e);
                    aiContent.innerHTML = `<span style="color: var(--neon-red);">Failed to query AI Rotational intelligence. Please verify your API key: ${e.message}</span>`;
                } finally {
                    if (aiSpinner) aiSpinner.style.display = 'none';
                    aiBtn.removeAttribute('disabled');
                }
            };
        }

        // Setup Chat sending logic
        if (chatSend && chatInput && chatStream) {
            const handleChatSend = async () => {
                const query = chatInput.value.trim();
                if (!query) return;

                chatInput.value = '';
                
                // Append user bubble
                chatStream.innerHTML += `
                    <div style="margin-top: 6px;">
                        <span style="color: #a5b4fc; font-weight: 700;">[User]</span> ${query}
                    </div>
                `;
                chatHistory.push({ role: "user", content: query });
                chatStream.scrollTop = chatStream.scrollHeight;

                // Append loading bubble
                const loadId = `copilot-load-${Date.now()}`;
                chatStream.innerHTML += `
                    <div id="${loadId}" style="margin-top: 6px; color: var(--text-muted);">
                        <span style="color: var(--color-primary); font-weight: 700;">[Co-Pilot]</span> thinking...
                    </div>
                `;
                chatStream.scrollTop = chatStream.scrollHeight;

                try {
                    const period = lookbackSelect ? lookbackSelect.value : '1m';
                    const capType = capSelect ? capSelect.value : 'all';

                    // Gather active standings summary to feed chatbot context
                    const response = await fetch('/api/screener/sector-regime/ai-chat', {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({
                            question: query,
                            history: chatHistory,
                            sector_data: window.activeSectorRegimeData
                        })
                    });

                    if (!response.ok) {
                        throw new Error(`Server returned ${response.status}`);
                    }

                    const reply = await response.json();
                    
                    // Remove loading bubble
                    const loadEl = document.getElementById(loadId);
                    if (loadEl) loadEl.remove();

                    // Parse any markdown ticker formats like [TCS.NS] into clickable tags
                    let formattedReply = reply.replace(/\[([A-Z0-9_\-\.]+)(?:\.NS)?\]/g, (match, ticker) => {
                        const cleanTicker = ticker.includes(".NS") ? ticker : `${ticker}.NS`;
                        return `<span class="chat-inline-ticker" data-ticker="${cleanTicker}" style="font-weight: 700; color: var(--color-primary); cursor: pointer; text-decoration: underline;">${ticker}</span>`;
                    });

                    const replyId = `rotation-msg-${Date.now()}`;
                    chatStream.innerHTML += `
                        <div style="margin-top: 6px;">
                            <span style="color: var(--color-primary); font-weight: 700;">[Co-Pilot]</span>
                            <button class="section-speak-btn" data-target="${replyId}" data-title="Rotation Co-Pilot" style="margin-left: 2px;">🔊</button>
                            <span id="${replyId}">${formattedReply}</span>
                        </div>
                    `;
                    chatHistory.push({ role: "assistant", content: reply });
                    chatStream.scrollTop = chatStream.scrollHeight;

                    // Bind inline ticker clicks
                    chatStream.querySelectorAll('.chat-inline-ticker').forEach(btn => {
                        btn.onclick = () => {
                            const ticker = btn.getAttribute('data-ticker');
                            if (window.switchTab) window.switchTab('analyzer');
                            if (window.loadStockAnalyzer) window.loadStockAnalyzer(ticker);
                        };
                    });

                } catch (err) {
                    console.error("Co-Pilot Chat response failed:", err);
                    const loadEl = document.getElementById(loadId);
                    if (loadEl) loadEl.remove();
                    chatStream.innerHTML += `
                        <div style="margin-top: 6px; color: var(--neon-red);">
                            <span style="color: var(--color-primary); font-weight: 700;">[Co-Pilot]</span> Connection error. Failed to query AI assistant.
                        </div>
                    `;
                    chatStream.scrollTop = chatStream.scrollHeight;
                }
            };

            chatSend.onclick = handleChatSend;
            chatInput.onkeydown = (e) => {
                if (e.key === 'Enter') handleChatSend();
            };
        }
    };

    // --- TODAY'S MARKET MOVERS WORKSPACE LOGIC ---
    let activeMoversFilter = 'all';
    let moversDataCache = null;
    let moversIntervalId = null;
    let tooltipEl = null;

    function setupMarketMovers() {
        const moversTabBtn = document.getElementById('tab-movers-btn');
        if (!moversTabBtn) return;

        // Create quick-look tooltip in DOM if not present
        if (!document.getElementById('movers-quick-tooltip')) {
            tooltipEl = document.createElement('div');
            tooltipEl.id = 'movers-quick-tooltip';
            tooltipEl.className = 'movers-tooltip';
            document.body.appendChild(tooltipEl);
        } else {
            tooltipEl = document.getElementById('movers-quick-tooltip');
        }

        // Setup filter buttons
        const segmentedControl = document.getElementById('movers-segmented-control');
        if (segmentedControl) {
            segmentedControl.querySelectorAll('.segmented-btn').forEach(btn => {
                btn.addEventListener('click', (e) => {
                    segmentedControl.querySelectorAll('.segmented-btn').forEach(b => b.classList.remove('active'));
                    btn.classList.add('active');
                    activeMoversFilter = btn.getAttribute('data-filter');
                    if (moversDataCache) {
                        renderMoversTables(moversDataCache);
                    }
                });
            });
        }

        // Listen for tab click to trigger initial fetch
        moversTabBtn.addEventListener('click', () => {
            fetchMarketMoversData();
            // Start interval polling when active
            if (moversIntervalId) clearInterval(moversIntervalId);
            moversIntervalId = setInterval(fetchMarketMoversData, 60000); // refresh frontend UI from backend cache every 60s
        });

        // Clear interval when switching away from Movers tab
        document.querySelectorAll('.nav-btn').forEach(btn => {
            if (btn !== moversTabBtn) {
                btn.addEventListener('click', () => {
                    if (moversIntervalId) {
                        clearInterval(moversIntervalId);
                        moversIntervalId = null;
                    }
                });
            }
        });

        // Expose helpers globally so they work via switchTab hooks
        window.fetchMarketMoversData = fetchMarketMoversData;
        window.startMoversPolling = function() {
            if (moversIntervalId) clearInterval(moversIntervalId);
            moversIntervalId = setInterval(fetchMarketMoversData, 60000);
        };
        window.stopMoversPolling = function() {
            if (moversIntervalId) {
                clearInterval(moversIntervalId);
                moversIntervalId = null;
            }
        };

        // If this tab is already active (loaded via URL hash), trigger initial fetch
        if (activeTab === 'movers' || location.hash === '#movers') {
            fetchMarketMoversData();
            window.startMoversPolling();
        }

        // Setup Web Socket updates
        setupMoversWebSocketUpdates();
    }

    async function fetchMarketMoversData() {
        try {
            const res = await fetch('/api/market-movers');
            if (res.ok) {
                const data = await res.json();
                moversDataCache = data;
                renderMarketMovers(data);
            } else {
                console.error("Failed to fetch market movers data:", res.statusText);
            }
        } catch (err) {
            console.error("Error fetching market movers:", err);
        }
    }

    function renderMarketMovers(data) {
        if (!data || data.status === 'initializing') {
            showMoversLoadingSkeleton();
            return;
        }

        // 1. Render Breadth Gauge
        const advances = data.advances || 0;
        const declines = data.declines || 0;
        const total = advances + declines || 1;
        const advancesPct = (advances / total) * 100;
        const declinesPct = (declines / total) * 100;

        const advBar = document.getElementById('breadth-advances-bar');
        const decBar = document.getElementById('breadth-declines-bar');
        const ratioText = document.getElementById('breadth-ratio-text');
        const advLbl = document.getElementById('breadth-advances-lbl');
        const decLbl = document.getElementById('breadth-declines-lbl');

        if (advBar) advBar.style.width = advancesPct + '%';
        if (decBar) decBar.style.width = declinesPct + '%';
        if (ratioText) ratioText.innerText = `${Math.round(advancesPct)}% Bullish | ${Math.round(declinesPct)}% Bearish`;
        if (advLbl) advLbl.innerText = `Advances: ${advances}`;
        if (decLbl) decLbl.innerText = `Declines: ${declines}`;

        // 2. Render Cap Temperatures
        const largeTemp = document.getElementById('large-cap-temp-val');
        const midTemp = document.getElementById('mid-cap-temp-val');
        const smallTemp = document.getElementById('small-cap-temp-val');

        if (largeTemp) {
            largeTemp.innerText = (data.large_cap_temp >= 0 ? '+' : '') + data.large_cap_temp.toFixed(2) + '%';
            largeTemp.className = data.large_cap_temp >= 0 ? 'change-pct positive' : 'change-pct negative';
        }
        if (midTemp) {
            midTemp.innerText = (data.mid_cap_temp >= 0 ? '+' : '') + data.mid_cap_temp.toFixed(2) + '%';
            midTemp.className = data.mid_cap_temp >= 0 ? 'change-pct positive' : 'change-pct negative';
        }
        if (smallTemp) {
            smallTemp.innerText = (data.small_cap_temp >= 0 ? '+' : '') + data.small_cap_temp.toFixed(2) + '%';
            smallTemp.className = data.small_cap_temp >= 0 ? 'change-pct positive' : 'change-pct negative';
        }

        // 3. Render Indices Grid
        const indexGrid = document.getElementById('index-performance-grid');
        if (indexGrid) {
            indexGrid.innerHTML = '';
            const indices = data.indices || [];
            indices.forEach(idx => {
                const card = document.createElement('div');
                card.className = 'index-card';
                card.id = `index-card-${idx.symbol.replace('^', '')}`;
                
                const isPos = idx.change_pct >= 0;
                const changeClass = isPos ? 'index-change positive' : 'index-change negative';
                const prefix = isPos ? '+' : '';
                const changeVal = idx.change !== undefined && idx.change !== null ? idx.change : 0;
                const absChange = Math.abs(changeVal).toLocaleString('en-IN', {minimumFractionDigits: 2, maximumFractionDigits: 2});

                card.innerHTML = `
                    <span class="index-name">${idx.name}</span>
                    <div class="index-val-row">
                        <span class="index-price" id="index-price-${idx.symbol.replace('^', '').replace('.NS','')/*.NS fallback*/}">₹${idx.price.toLocaleString('en-IN', {minimumFractionDigits:2})}</span>
                        <span class="${changeClass}" id="index-change-${idx.symbol.replace('^', '').replace('.NS','')}">${prefix}${absChange} (${prefix}${idx.change_pct.toFixed(2)}%)</span>
                    </div>
                `;
                const isCommodity = ['MCXGOLD', 'MCXSILVER', 'SPOTGOLD', 'SPOTSILVER', 'PLATINUM'].includes(idx.symbol);
                if (!isCommodity) {
                    card.style.cursor = 'pointer';
                    card.addEventListener('click', () => {
                        if (window.switchTab) window.switchTab('analyzer');
                        if (window.loadStockAnalyzer) window.loadStockAnalyzer(idx.symbol);
                    });
                } else {
                    card.classList.add('non-clickable');
                }

                indexGrid.appendChild(card);
            });
        }

        // 4. Render Movers Tables
        renderMoversTables(data);
    }

    function renderMoversTables(data) {
        const gainersList = data.gainers[activeMoversFilter] || [];
        const losersList = data.losers[activeMoversFilter] || [];

        const gainersTbody = document.getElementById('top-gainers-tbody');
        const losersTbody = document.getElementById('top-losers-tbody');

        if (gainersTbody) {
            gainersTbody.innerHTML = '';
            if (gainersList.length === 0) {
                gainersTbody.innerHTML = `<tr><td colspan="5" class="text-center text-muted" style="padding: 20px;">No gainers matching filters</td></tr>`;
            } else {
                gainersList.forEach(stock => {
                    const tr = document.createElement('tr');
                    tr.className = 'clickable-row';
                    tr.setAttribute('data-symbol', stock.symbol);
                    tr.innerHTML = `
                        <td style="padding: 12px; font-weight: 700; color: var(--neon-blue);">${stock.symbol.replace('.NS', '')}</td>
                        <td style="padding: 12px; color: var(--text-primary); max-width: 180px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;">${stock.company_name}</td>
                        <td style="padding: 12px; text-align: right; font-family: 'Outfit', sans-serif; font-weight: 600;" id="movers-price-${stock.symbol.replace('.NS', '')}">${stock.price.toFixed(2)}</td>
                        <td style="padding: 12px; text-align: right; font-family: 'Outfit', sans-serif; font-weight: 700; color: var(--neon-green);" id="movers-change-abs-${stock.symbol.replace('.NS', '')}">${(stock.change || 0).toFixed(2)}</td>
                        <td style="padding: 12px; text-align: right; font-family: 'Outfit', sans-serif; font-weight: 700; color: var(--neon-green);" id="movers-change-pct-${stock.symbol.replace('.NS', '')}">+${stock.change_pct.toFixed(2)}%</td>
                    `;
                    bindMoversRowEvents(tr, stock);
                    gainersTbody.appendChild(tr);
                });
            }
        }

        if (losersTbody) {
            losersTbody.innerHTML = '';
            if (losersList.length === 0) {
                losersTbody.innerHTML = `<tr><td colspan="5" class="text-center text-muted" style="padding: 20px;">No losers matching filters</td></tr>`;
            } else {
                losersList.forEach(stock => {
                    const tr = document.createElement('tr');
                    tr.className = 'clickable-row';
                    tr.setAttribute('data-symbol', stock.symbol);
                    tr.innerHTML = `
                        <td style="padding: 12px; font-weight: 700; color: var(--neon-blue);">${stock.symbol.replace('.NS', '')}</td>
                        <td style="padding: 12px; color: var(--text-primary); max-width: 180px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;">${stock.company_name}</td>
                        <td style="padding: 12px; text-align: right; font-family: 'Outfit', sans-serif; font-weight: 600;" id="movers-price-${stock.symbol.replace('.NS', '')}">${stock.price.toFixed(2)}</td>
                        <td style="padding: 12px; text-align: right; font-family: 'Outfit', sans-serif; font-weight: 700; color: #ef4444;" id="movers-change-abs-${stock.symbol.replace('.NS', '')}">${Math.abs(stock.change || 0).toFixed(2)}</td>
                        <td style="padding: 12px; text-align: right; font-family: 'Outfit', sans-serif; font-weight: 700; color: #ef4444;" id="movers-change-pct-${stock.symbol.replace('.NS', '')}">${stock.change_pct.toFixed(2)}%</td>
                    `;
                    bindMoversRowEvents(tr, stock);
                    losersTbody.appendChild(tr);
                });
            }
        }
    }

    function bindMoversRowEvents(tr, stock) {
        tr.addEventListener('click', () => {
            if (window.switchTab) window.switchTab('analyzer');
            if (window.loadStockAnalyzer) window.loadStockAnalyzer(stock.symbol);
        });

        tr.addEventListener('mouseenter', (e) => {
            const rect = tr.getBoundingClientRect();
            tooltipEl.innerHTML = `
                <div class="movers-tooltip-header">
                    <span>${stock.symbol.replace('.NS', '')}</span>
                    <span style="font-size: 9px; padding: 2px 6px; border-radius: 4px; background: rgba(59,130,246,0.15); color: var(--neon-blue); text-transform: uppercase;">${stock.cap_type} Cap</span>
                </div>
                <div class="movers-tooltip-item">
                    <span class="movers-tooltip-label">Company:</span>
                    <span class="movers-tooltip-value" style="max-width: 135px; text-overflow: ellipsis; white-space: nowrap; overflow: hidden;">${stock.company_name}</span>
                </div>
                <div class="movers-tooltip-item">
                    <span class="movers-tooltip-label">LTP Price:</span>
                    <span class="movers-tooltip-value">₹${stock.price.toFixed(2)}</span>
                </div>
                <div class="movers-tooltip-item">
                    <span class="movers-tooltip-label">Day Change:</span>
                    <span class="movers-tooltip-value" style="color: ${stock.change_pct >= 0 ? 'var(--neon-green)' : '#ef4444'};">${stock.change_pct >= 0 ? '+' : ''}${stock.change_pct.toFixed(2)}%</span>
                </div>
                <div class="movers-tooltip-item">
                    <span class="movers-tooltip-label">Segment:</span>
                    <span class="movers-tooltip-value">${stock.cap_type.toUpperCase()} CAP EQ</span>
                </div>
            `;
            tooltipEl.style.display = 'block';
            tooltipEl.style.left = (window.scrollX + rect.left + 50) + 'px';
            tooltipEl.style.top = (window.scrollY + rect.top - 80) + 'px';
        });

        tr.addEventListener('mousemove', (e) => {
            const rect = tr.getBoundingClientRect();
            tooltipEl.style.left = (window.scrollX + rect.left + 50) + 'px';
            tooltipEl.style.top = (window.scrollY + rect.top - 80) + 'px';
        });

        tr.addEventListener('mouseleave', () => {
            tooltipEl.style.display = 'none';
        });
    }

    function showMoversLoadingSkeleton() {
        const indexGrid = document.getElementById('index-performance-grid');
        if (indexGrid) {
            indexGrid.innerHTML = `
                <div class="skeleton-card" style="height: 70px; border-radius: 8px; background: var(--border-glass);"></div>
                <div class="skeleton-card" style="height: 70px; border-radius: 8px; background: var(--border-glass);"></div>
                <div class="skeleton-card" style="height: 70px; border-radius: 8px; background: var(--border-glass);"></div>
                <div class="skeleton-card" style="height: 70px; border-radius: 8px; background: var(--border-glass);"></div>
            `;
        }
        const gainersTbody = document.getElementById('top-gainers-tbody');
        const losersTbody = document.getElementById('top-losers-tbody');
        if (gainersTbody) gainersTbody.innerHTML = `<tr><td colspan="5" class="text-center text-muted" style="padding: 20px;">Fetching initial database sweep (approx 20s)...</td></tr>`;
        if (losersTbody) losersTbody.innerHTML = `<tr><td colspan="5" class="text-center text-muted" style="padding: 20px;">Fetching initial database sweep (approx 20s)...</td></tr>`;
    }

    function setupMoversWebSocketUpdates() {
        window.handleMoversLiveTick = function(symbol, price, changePct, changeVal) {
            const cleanSym = symbol.replace('.NS', '').replace('.BO', '').replace('^', '');
            
            // 1. Update Movers tables rows if visible
            const priceEl = document.getElementById(`movers-price-${cleanSym}`);
            const changeAbsEl = document.getElementById(`movers-change-abs-${cleanSym}`);
            const changePctEl = document.getElementById(`movers-change-pct-${cleanSym}`);
            if (priceEl) {
                const oldPrice = parseFloat(priceEl.innerText.replace(/,/g, ''));
                priceEl.innerText = `${price.toFixed(2)}`;
                
                // Trigger radial blink animations
                const parentRow = priceEl.closest('tr');
                if (parentRow) {
                    parentRow.classList.remove('tick-blink-positive', 'tick-blink-negative');
                    void parentRow.offsetWidth; // trigger reflow
                    if (price > oldPrice) {
                        parentRow.classList.add('tick-blink-positive');
                    } else if (price < oldPrice) {
                        parentRow.classList.add('tick-blink-negative');
                    }
                }
            }

            const colorStyle = changePct >= 0 ? 'var(--neon-green)' : '#ef4444';

            if (changeAbsEl) {
                const displayChange = changeVal !== undefined && changeVal !== null ? changeVal : (price - (price / (1 + changePct / 100)));
                const absChange = Math.abs(displayChange).toFixed(2);
                changeAbsEl.innerText = `${absChange}`;
                changeAbsEl.style.color = colorStyle;
            }

            if (changePctEl) {
                const sign = changePct >= 0 ? '+' : '';
                changePctEl.innerText = `${sign}${changePct.toFixed(2)}%`;
                changePctEl.style.color = colorStyle;
            }

            // 2. Update Index cards if visible
            const idxPriceEl = document.getElementById(`index-price-${cleanSym}`);
            const idxChangeEl = document.getElementById(`index-change-${cleanSym}`);
            if (idxPriceEl && idxChangeEl) {
                const oldPrice = parseFloat(idxPriceEl.innerText.replace('₹', '').replace(/,/g, ''));
                idxPriceEl.innerText = `₹${price.toLocaleString('en-IN', {minimumFractionDigits:2})}`;
                
                const displayChange = changeVal !== undefined && changeVal !== null ? changeVal : 0;
                const sign = changePct >= 0 ? '+' : '-';
                const absChange = Math.abs(displayChange).toLocaleString('en-IN', {minimumFractionDigits:2, maximumFractionDigits:2});
                idxChangeEl.innerText = `${sign}${absChange} (${changePct >= 0 ? '+' : ''}${changePct.toFixed(2)}%)`;
                idxChangeEl.className = changePct >= 0 ? 'index-change positive' : 'index-change negative';

                const cardEl = idxPriceEl.closest('.index-card');
                if (cardEl) {
                    cardEl.classList.remove('tick-blink-positive', 'tick-blink-negative');
                    void cardEl.offsetWidth; // trigger reflow
                    if (price > oldPrice) {
                        cardEl.classList.add('tick-blink-positive');
                    } else if (price < oldPrice) {
                        cardEl.classList.add('tick-blink-negative');
                    }
                }
            }
        };
    }

    // Expose to window for tab switching triggers
    window.setupMarketMovers = setupMarketMovers;
    window.loadScreenerSectorRegime = loadScreenerSectorRegime;
    window.setupPortfolioSecurity = setupPortfolioSecurity;

    // Portfolio Biometric & PIN Security
    function setupPortfolioSecurity() {
        console.log("[Portfolio Lock] setupPortfolioSecurity initializing...");
        window.portfolioUnlocked = false;
        
        const shieldEnabled = localStorage.getItem('portfolio-security-shield-enabled') !== 'false';
        if (!shieldEnabled) {
            const overlay = document.getElementById('portfolio-lock-overlay');
            if (overlay) overlay.classList.add('hidden');
        }
        
        const biometricBtn = document.getElementById('portfolio-biometric-btn');
        const keyButtons = document.querySelectorAll('.lock-keypad-grid .key-btn[data-key]');
        const dots = document.querySelectorAll('#lock-pin-dots .dot');
        const clearBtn = document.getElementById('lock-pin-clear-btn');
        const changePinBtn = document.getElementById('lock-pin-change-btn');
        const cardEl = document.querySelector('.lock-shield-card');
        
        console.log(`[Portfolio Lock] Found ${keyButtons.length} keypad buttons and ${dots.length} dots.`);
        
        let currentPinEntry = "";
        
        // Hide biometric button if not on native mobile platform
        const isNative = typeof window.Capacitor !== 'undefined' && 
                         typeof window.Capacitor.isNativePlatform === 'function' && 
                         window.Capacitor.isNativePlatform();
        console.log("[Portfolio Lock] isNativePlatform is:", isNative);
        if (!isNative && biometricBtn) {
            console.log("[Portfolio Lock] Hiding biometric button (desktop/web environment).");
            biometricBtn.style.display = 'none';
        }
        
        function updatePinDots() {
            console.log("[Portfolio Lock] Updating dots. Current length:", currentPinEntry.length);
            dots.forEach((dot, index) => {
                if (index < currentPinEntry.length) {
                    dot.classList.add('filled');
                } else {
                    dot.classList.remove('filled');
                }
            });
        }
        
        function unlockPortfolio() {
            window.portfolioUnlocked = true;
            const overlay = document.getElementById('portfolio-lock-overlay');
            if (overlay) {
                overlay.classList.add('hidden');
            }
            currentPinEntry = "";
            updatePinDots();
        }
        
        function validatePinEntry() {
            const savedPin = localStorage.getItem('portfolio-pin') || '1234';
            if (currentPinEntry === savedPin) {
                unlockPortfolio();
                showToast("Access granted.", "success");
            } else {
                if (cardEl) {
                    cardEl.classList.add('error');
                    setTimeout(() => {
                        cardEl.classList.remove('error');
                    }, 500);
                }
                showToast("Incorrect passcode PIN.", "error");
                currentPinEntry = "";
                updatePinDots();
            }
        }
        
        let isBiometricPromptActive = false;
        async function triggerBiometricVerification() {
            if (isBiometricPromptActive) {
                console.log("[Portfolio Lock] Biometric prompt is already active. Ignoring call.");
                return;
            }
            isBiometricPromptActive = true;
            if (!isNative) {
                console.log("Not running in native Capacitor environment. Skipping native biometrics.");
                isBiometricPromptActive = false;
                return;
            }
            const NativeBiometric = window.Capacitor && window.Capacitor.Plugins && window.Capacitor.Plugins.NativeBiometric;
            if (!NativeBiometric) {
                console.warn("Capacitor NativeBiometric plugin not available.");
                isBiometricPromptActive = false;
                return;
            }
            try {
                const result = await NativeBiometric.isAvailable();
                if (result.isAvailable) {
                    await NativeBiometric.verifyIdentity({
                        reason: 'Authenticate to view secure Portfolio metrics',
                        title: 'Portfolio Access Shield',
                        subtitle: 'Verify Biometrics',
                        description: 'Scan your fingerprint or face to unlock portfolio doctor.',
                        maxAttempts: 3
                    });
                    unlockPortfolio();
                    showToast("Portfolio security shield unlocked via biometrics.", "success");
                }
            } catch (err) {
                console.error("Biometric authentication error/failed:", err);
                showToast("Biometric verification canceled or failed.", "info");
            } finally {
                isBiometricPromptActive = false;
            }
        }
        
        // Expose biometric prompt globally so switchTab can invoke it
        window.triggerBiometricVerification = triggerBiometricVerification;
        
        // Wire up events
        if (biometricBtn) {
            biometricBtn.addEventListener('click', () => {
                triggerBiometricVerification();
            });
        }
        
        console.log("[Portfolio Lock] Binding keypad listeners...");
        keyButtons.forEach(btn => {
            btn.addEventListener('click', () => {
                const val = btn.getAttribute('data-key');
                console.log("[Portfolio Lock] Button clicked. Key:", val);
                if (currentPinEntry.length < 4) {
                    currentPinEntry += val;
                    updatePinDots();
                    if (currentPinEntry.length === 4) {
                        console.log("[Portfolio Lock] 4 digits entered, validating PIN...");
                        setTimeout(validatePinEntry, 200);
                    }
                }
            });
        });
        console.log("[Portfolio Lock] Keypad listeners bound.");
        
        if (clearBtn) {
            clearBtn.addEventListener('click', () => {
                currentPinEntry = "";
                updatePinDots();
            });
        }
        
        if (changePinBtn) {
            changePinBtn.addEventListener('click', () => {
                const savedPin = localStorage.getItem('portfolio-pin') || '1234';
                const currentPinPrompt = prompt("Enter current 4-digit PIN passcode:");
                if (currentPinPrompt === null) return;
                
                if (currentPinPrompt !== savedPin) {
                    showToast("Incorrect current PIN passcode.", "error");
                    return;
                }
                
                const newPinPrompt = prompt("Enter new 4-digit PIN passcode:");
                if (newPinPrompt === null) return;
                
                if (!/^\d{4}$/.test(newPinPrompt)) {
                    showToast("Invalid PIN. Must be exactly 4 digits.", "error");
                    return;
                }
                
                const confirmPinPrompt = prompt("Confirm new 4-digit PIN passcode:");
                if (confirmPinPrompt === null) return;
                
                if (newPinPrompt !== confirmPinPrompt) {
                    showToast("PIN confirmation did not match.", "error");
                    return;
                }
                
                localStorage.setItem('portfolio-pin', newPinPrompt);
                showToast("Passcode PIN successfully updated.", "success");
            });
        }
        
        // Auto-lock when tab or app backgrounded
        document.addEventListener('visibilitychange', () => {
            const shieldEnabled = localStorage.getItem('portfolio-security-shield-enabled') !== 'false';
            if (!shieldEnabled) return;

            if (document.hidden) {
                window.portfolioUnlocked = false;
                const overlay = document.getElementById('portfolio-lock-overlay');
                if (overlay) {
                    overlay.classList.remove('hidden');
                    currentPinEntry = "";
                    updatePinDots();
                }
            }
        });
        
        const CapacitorApp = window.Capacitor && window.Capacitor.Plugins && window.Capacitor.Plugins.App;
        if (CapacitorApp) {
            CapacitorApp.addListener('appStateChange', ({ isActive }) => {
                const shieldEnabled = localStorage.getItem('portfolio-security-shield-enabled') !== 'false';
                if (!shieldEnabled) return;

                if (!isActive) {
                    window.portfolioUnlocked = false;
                    const overlay = document.getElementById('portfolio-lock-overlay');
                    if (overlay) {
                        overlay.classList.remove('hidden');
                        currentPinEntry = "";
                        updatePinDots();
                    }
                }
            });
        }
    }
})();

(function() {
    // TradingView Advanced Fullscreen Controller
    const advancedCard = document.getElementById('tv-advanced-card');
    const fullscreenBtn = document.getElementById('tv-advanced-fullscreen-btn');
    const container = document.getElementById('tv-advanced-container');

    function toggleAdvancedFullscreen() {
        if (!advancedCard) return;
        const isFull = advancedCard.classList.toggle('chart-full-window');
        if (fullscreenBtn) {
            fullscreenBtn.innerHTML = isFull ? '🗗 Exit Fullscreen' : '🗖 Fullscreen';
        }
        if (container) {
            if (isFull) {
                container.style.height = 'calc(100vh - 80px)';
            } else {
                container.style.height = '520px';
            }
        }
    }

    if (advancedCard) {
        advancedCard.addEventListener('dblclick', (e) => {
            // Prevent toggling if clicked on input/button/a tags
            if (e.target.closest('button') || e.target.closest('a') || e.target.closest('select')) return;
            toggleAdvancedFullscreen();
        });
    }

    if (fullscreenBtn) {
        fullscreenBtn.addEventListener('click', (e) => {
            e.stopPropagation();
            toggleAdvancedFullscreen();
        });
    }

    document.addEventListener('keydown', (e) => {
        if (e.key === 'Escape') {
            if (advancedCard && advancedCard.classList.contains('chart-full-window')) {
                advancedCard.classList.remove('chart-full-window');
                if (fullscreenBtn) {
                    fullscreenBtn.innerHTML = '🗖 Fullscreen';
                }
                if (container) {
                    container.style.height = '520px';
                }
            }
        }
    });
})();

(function() {
    let cachedOptimizationResult = null;
    let activeOptimizationTarget = 'sharpe'; // 'sharpe' or 'vol'
    let optimizerChartInstance = null;

    // Cache element lookups
    const emptyState = document.getElementById('portfolio-optimizer-empty-state');
    const workspace = document.getElementById('portfolio-optimizer-workspace');
    const assetsListContainer = document.getElementById('portfolio-optimizer-assets-list');
    const runBtn = document.getElementById('run-portfolio-optimizer-btn');
    const cashRange = document.getElementById('portfolio-optimizer-cash-range');
    const cashVal = document.getElementById('portfolio-optimizer-cash-val');
    
    const tableWrap = document.getElementById('portfolio-optimizer-table-wrap');
    const tableBody = document.getElementById('portfolio-optimizer-table-body');
    const targetHeader = document.getElementById('port-opt-table-target-header');
    
    const kpiGrid = document.getElementById('portfolio-optimizer-kpi-grid');
    const kpiReturnVal = document.getElementById('port-opt-kpi-return-val');
    const kpiReturnDiff = document.getElementById('port-opt-kpi-return-diff');
    const kpiSharpeVal = document.getElementById('port-opt-kpi-sharpe-val');
    const kpiSharpeDiff = document.getElementById('port-opt-kpi-sharpe-diff');
    
    const ticketsWrap = document.getElementById('portfolio-optimizer-tickets-wrap');
    const ticketsList = document.getElementById('portfolio-optimizer-tickets-list');

    const aiWrap = document.getElementById('portfolio-optimizer-ai-wrap');
    const aiResult = document.getElementById('portfolio-optimizer-ai-result');
    const runAiBtn = document.getElementById('run-optimizer-ai-btn');

    const targetSharpeBtn = document.getElementById('port-opt-target-sharpe');
    const targetVolBtn = document.getElementById('port-opt-target-vol');

    // Slide/Input config
    if (cashRange && cashVal) {
        cashRange.addEventListener('input', () => {
            cashVal.innerText = cashRange.value + '%';
        });
    }

    // Toggle triggers
    if (targetSharpeBtn && targetVolBtn) {
        targetSharpeBtn.addEventListener('click', () => {
            activeOptimizationTarget = 'sharpe';
            targetSharpeBtn.classList.add('active');
            targetSharpeBtn.style.color = 'var(--text-primary)';
            targetVolBtn.classList.remove('active');
            targetVolBtn.style.color = 'var(--text-muted)';
            if (targetHeader) targetHeader.innerText = '🏆 Max Sharpe Weight';
            renderOptimizationOutputs();
        });
        targetVolBtn.addEventListener('click', () => {
            activeOptimizationTarget = 'vol';
            targetVolBtn.classList.add('active');
            targetVolBtn.style.color = 'var(--text-primary)';
            targetSharpeBtn.classList.remove('active');
            targetSharpeBtn.style.color = 'var(--text-muted)';
            if (targetHeader) targetHeader.innerText = '🛡️ Min Risk Weight';
            renderOptimizationOutputs();
        });
    }

    async function loadPortfolioOptimizerPanel() {
        if (!emptyState || !workspace || !assetsListContainer) return;

        let items = (typeof activePortfolioLedgerItems !== 'undefined' && activePortfolioLedgerItems) ? activePortfolioLedgerItems : [];
        if (items.length === 0) {
            try {
                const response = await fetch('/api/portfolio');
                if (response.ok) {
                    const fetchedItems = await response.json();
                    if (typeof activePortfolioLedgerItems !== 'undefined') {
                        activePortfolioLedgerItems = fetchedItems;
                    }
                    items = fetchedItems;
                }
            } catch (err) {
                console.error("Failed to sync ledger items: ", err);
            }
        }

        if (items.length === 0) {
            emptyState.style.display = 'block';
            workspace.style.display = 'none';
            return;
        }

        // Group transactions by symbol to avoid tranche duplicates
        const grouped = {};
        items.forEach(item => {
            const sym = item.symbol;
            if (!grouped[sym]) {
                grouped[sym] = {
                    symbol: sym,
                    quantity: 0,
                    totalCost: 0,
                    current_price: parseFloat(item.current_price || 0)
                };
            }
            const qty = parseFloat(item.quantity || 0);
            const price = parseFloat(item.purchase_price || 0);
            grouped[sym].quantity += qty;
            grouped[sym].totalCost += qty * price;
        });

        window.uniqueOptimizerAssets = Object.values(grouped).map(item => {
            return {
                symbol: item.symbol,
                quantity: item.quantity,
                avg_buy_price: item.quantity > 0 ? (item.totalCost / item.quantity) : 0,
                current_price: item.current_price,
                current_value: item.quantity * item.current_price
            };
        });

        emptyState.style.display = 'none';
        workspace.style.display = 'grid'; // Split columns

        // Populate assets checkable list with aggregated holdings
        assetsListContainer.innerHTML = window.uniqueOptimizerAssets.map(item => `
            <div class="optimizer-asset-item" style="margin-bottom: 8px;">
                <div style="display: flex; align-items: center; gap: 8px;">
                    <input type="checkbox" class="optimizer-asset-checkbox" checked data-symbol="${item.symbol}" style="cursor: pointer; transform: scale(1.15);">
                    <strong style="color: var(--text-primary); font-family: 'Outfit', sans-serif;">${item.symbol}</strong>
                </div>
                <span style="font-size: 11px; color: var(--text-secondary);">Qty: ${item.quantity} | Avg: ₹${parseFloat(item.avg_buy_price || 0).toLocaleString(undefined, {minimumFractionDigits: 1, maximumFractionDigits: 1})}</span>
            </div>
        `).join('');
    }

    async function runPortfolioOptimization() {
        if (!runBtn) return;
        const checkboxes = document.querySelectorAll('.optimizer-asset-checkbox');
        const checkedTickers = [];
        checkboxes.forEach(cb => {
            if (cb.checked) {
                checkedTickers.push(cb.getAttribute('data-symbol'));
            }
        });

        if (checkedTickers.length < 2) {
            showToast("Please select at least 2 stock holdings to run covariance optimization.", "warning");
            return;
        }

        runBtn.disabled = true;
        const originalText = runBtn.innerHTML;
        runBtn.innerHTML = `<span>⏳ Simulating Frontier Portfolios...</span>`;

        const cashPct = parseFloat(cashRange ? cashRange.value : 0) || 0;

        // Calculate current weights for baseline comparison
        const items = window.uniqueOptimizerAssets || [];
        const selectedHoldings = items.filter(item => checkedTickers.includes(item.symbol));
        const totalValue = selectedHoldings.reduce((sum, item) => sum + (parseFloat(item.current_value) || 0), 0);

        const currentWeights = {};
        selectedHoldings.forEach(item => {
            const val = parseFloat(item.current_value) || 0;
            currentWeights[item.symbol] = totalValue > 0 ? (val / totalValue) * 100.0 : 0.0;
        });

        try {
            const response = await fetch('/api/portfolio/optimize-sharpe', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    tickers: checkedTickers,
                    cash_pct: cashPct,
                    current_weights: currentWeights
                })
            });

            if (!response.ok) throw new Error("Optimization query returned error status.");
            const data = await response.json();

            if (data.status === 'success') {
                cachedOptimizationResult = data;
                
                // Draw efficient frontier chart
                renderOptimizerChart(data.simulations, data.max_sharpe, data.min_vol);
                
                // Render outputs
                renderOptimizationOutputs();
                
                showToast("Portfolio frontier analysis and Sharpe optimization completed.", "success");
            } else {
                throw new Error("Optimization failed.");
            }
        } catch (err) {
            console.error("Optimization failed: ", err);
            showToast("Optimization failed. Verify connection status or ticker history.", "error");
        } finally {
            runBtn.disabled = false;
            runBtn.innerHTML = originalText;
        }
    }

    function renderOptimizationOutputs() {
        if (!cachedOptimizationResult || !tableBody || !tableWrap || !kpiGrid || !ticketsList || !ticketsWrap) return;

        const targetData = activeOptimizationTarget === 'sharpe' ? cachedOptimizationResult.max_sharpe : cachedOptimizationResult.min_vol;
        const items = window.uniqueOptimizerAssets || [];
        
        // Calculate total invested capital in active items
        const selectedHoldings = items.filter(item => {
            const cb = document.querySelector(`.optimizer-asset-checkbox[data-symbol="${item.symbol}"]`);
            return cb && cb.checked;
        });

        const totalValue = selectedHoldings.reduce((sum, item) => sum + (parseFloat(item.current_value) || 0), 0);

        // Calculate current weights
        const currentWeights = {};
        selectedHoldings.forEach(item => {
            const val = parseFloat(item.current_value) || 0;
            currentWeights[item.symbol] = totalValue > 0 ? (val / totalValue) * 100.0 : 0.0;
        });

        // 1. Populate weights comparison table
        tableWrap.style.display = 'block';
        tableBody.innerHTML = '';

        // Union of optimal target weight keys and current selected holdings
        const allKeysSet = new Set([
            ...Object.keys(targetData.weights),
            ...Object.keys(currentWeights)
        ]);
        const allKeys = Array.from(allKeysSet);
        allKeys.forEach(key => {
            const curW = currentWeights[key] || 0.0;
            const tarW = targetData.weights[key] || 0.0;
            const diff = tarW - curW;
            const diffSign = diff >= 0 ? `+${diff.toFixed(1)}%` : `${diff.toFixed(1)}%`;
            const diffColor = diff >= 0 ? '#10b981' : '#ef4444';

            tableBody.innerHTML += `
                <tr style="border-bottom: 1px solid rgba(255,255,255,0.02);">
                    <td style="padding: 8px; font-weight: 700; color: var(--text-primary); text-align: left;">${key}</td>
                    <td style="padding: 8px; text-align: right; color: var(--text-secondary);">${curW.toFixed(1)}%</td>
                    <td style="padding: 8px; text-align: right; font-weight: 700; color: var(--text-primary);">${tarW.toFixed(1)}%</td>
                    <td style="padding: 8px; text-align: right; font-weight: 700; color: ${diffColor};">${diffSign}</td>
                </tr>
            `;
        });

        // 2. Populate KPI cards
        kpiGrid.style.display = 'grid';
        if (kpiReturnVal && kpiReturnDiff) {
            kpiReturnVal.innerText = targetData.return.toFixed(2) + '%';
            
            const currReturn = (cachedOptimizationResult.current_portfolio && typeof cachedOptimizationResult.current_portfolio.return !== 'undefined') ? cachedOptimizationResult.current_portfolio.return : 11.5;
            const retDiff = targetData.return - currReturn;
            kpiReturnDiff.innerText = `Current: ${currReturn.toFixed(2)}% (${(retDiff >= 0 ? '+' : '') + retDiff.toFixed(2)}% diff)`;
            kpiReturnDiff.style.color = retDiff >= 0 ? '#10b981' : '#ef4444';
        }
        if (kpiSharpeVal && kpiSharpeDiff) {
            kpiSharpeVal.innerText = targetData.sharpe.toFixed(2);
            
            const currSharpe = (cachedOptimizationResult.current_portfolio && typeof cachedOptimizationResult.current_portfolio.sharpe !== 'undefined') ? cachedOptimizationResult.current_portfolio.sharpe : 0.35;
            const sharpeDiff = targetData.sharpe - currSharpe;
            kpiSharpeDiff.innerText = `Current: ${currSharpe.toFixed(2)} (${(sharpeDiff >= 0 ? '+' : '') + sharpeDiff.toFixed(2)} diff)`;
            kpiSharpeDiff.style.color = sharpeDiff >= 0 ? '#10b981' : '#ef4444';
        }

        // 3. Populate Actionable Rebalancing tickets
        ticketsWrap.style.display = 'block';
        ticketsList.innerHTML = '';

        let hasTrades = false;
        allKeys.forEach(key => {
            const curW = currentWeights[key] || 0.0;
            const tarW = targetData.weights[key] || 0.0;
            const diff = tarW - curW;

            if (Math.abs(diff) < 1.0) return; // ignore minor offsets

            hasTrades = true;
            const isBuy = diff > 0;
            let actionText = isBuy ? 'Buy / Top-up' : 'Sell / Trim';
            let labelText = isBuy ? 'Allocate additional' : 'Liquidate approximately';
            if (key === 'CASH') {
                actionText = isBuy ? 'Hold in Cash' : 'Draw from Cash';
                labelText = isBuy ? 'Transfer additional' : 'Withdraw approximately';
            }
            const cls = isBuy ? 'buy' : 'sell';
            const diffPct = Math.abs(diff).toFixed(1);

            // Compute currency offset estimate
            const capitalOffset = (diff / 100.0) * totalValue;
            const capitalText = Math.abs(capitalOffset).toLocaleString('en-IN', { style: 'currency', currency: 'INR', maximumFractionDigits: 0 });

            ticketsList.innerHTML += `
                <div class="optimizer-ticket ${cls}" style="margin-bottom: 8px;">
                    <div class="optimizer-ticket-info">
                        <span style="font-weight: 700; font-size: 12px; color: var(--text-primary);">${key}</span>
                        <span style="color: var(--text-secondary); font-size: 10px;">
                            Current Weight: ${curW.toFixed(1)}% | Target Weight: ${tarW.toFixed(1)}%
                        </span>
                        <span style="font-weight: 600; font-size: 11px; margin-top: 2px;">
                            ${labelText} ${capitalText}
                        </span>
                    </div>
                    <span class="optimizer-ticket-action">${actionText} ${diffPct}%</span>
                </div>
            `;
        });

        if (!hasTrades) {
            ticketsList.innerHTML = `
                <div style="padding: 15px; text-align: center; color: var(--text-muted); font-size: 11px;">
                    Portfolio weights already align within a 1.0% threshold of optimized coordinates. No rebalancing actions required.
                </div>
            `;
        }

        if (aiWrap) {
            aiWrap.style.display = 'block';
            if (aiResult) {
                aiResult.innerHTML = `<p style="margin: 0; font-style: italic; color: var(--text-muted);">Click "Generate Report" to run institutional-grade LLM synthesis on your frontier portfolio shifts.</p>`;
            }
            if (runAiBtn) {
                runAiBtn.disabled = false;
                runAiBtn.innerHTML = `✨ Generate Report`;
            }
        }
    }

    function renderOptimizerChart(simulations, maxSharpe, minVol) {
        const ctx = document.getElementById('portfolio-frontier-chart').getContext('2d');
        if (optimizerChartInstance) {
            optimizerChartInstance.destroy();
        }

        const isLight = document.documentElement.getAttribute('data-mode') === 'light';
        const gridColor = isLight ? 'rgba(0,0,0,0.06)' : 'rgba(255,255,255,0.04)';
        const textColor = isLight ? '#475569' : '#9ca3af';

        const scatterData = simulations.map(p => ({
            x: p.x,
            y: p.y,
            sharpe: p.sharpe,
            weights_str: p.weights_str
        }));

        optimizerChartInstance = new Chart(ctx, {
            type: 'scatter',
            data: {
                datasets: [
                    {
                        label: 'Simulated Portfolios',
                        data: scatterData,
                        backgroundColor: 'rgba(0, 210, 255, 0.25)',
                        pointRadius: 2.5,
                        pointHoverRadius: 5,
                        showLine: false
                    },
                    {
                        label: 'Max Sharpe Portfolio',
                        data: [{ 
                            x: maxSharpe.volatility, 
                            y: maxSharpe.return, 
                            sharpe: maxSharpe.sharpe, 
                            weights_str: Object.entries(maxSharpe.weights).map(([k,v]) => `${k}: ${v}%`).join(" | ") 
                        }],
                        backgroundColor: '#eab308',
                        borderColor: '#ffffff',
                        borderWidth: 1.5,
                        pointRadius: 7,
                        pointHoverRadius: 9,
                        pointStyle: 'star',
                        showLine: false
                    },
                    {
                        label: 'Min Risk Portfolio',
                        data: [{ 
                            x: minVol.volatility, 
                            y: minVol.return, 
                            sharpe: minVol.sharpe, 
                            weights_str: Object.entries(minVol.weights).map(([k,v]) => `${k}: ${v}%`).join(" | ") 
                        }],
                        backgroundColor: '#10b981',
                        borderColor: '#ffffff',
                        borderWidth: 1.5,
                        pointRadius: 7,
                        pointHoverRadius: 9,
                        pointStyle: 'rectRot',
                        showLine: false
                    }
                ]
            },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                    legend: {
                        display: true,
                        labels: { color: textColor, font: { size: 9, family: 'Outfit' } }
                    },
                    tooltip: {
                        callbacks: {
                            label: function(context) {
                                const p = context.raw;
                                return [
                                    `${context.dataset.label}`,
                                    `Expected Return: ${p.y.toFixed(2)}%`,
                                    `Volatility (Risk): ${p.x.toFixed(2)}%`,
                                    `Sharpe Ratio: ${p.sharpe.toFixed(2)}`,
                                    `Allocations: ${p.weights_str || 'N/A'}`
                                ];
                            }
                        }
                    }
                },
                scales: {
                    x: {
                        grid: { color: gridColor },
                        title: { display: true, text: 'Volatility (Risk) %', color: textColor, font: { size: 9, family: 'Outfit' } },
                        ticks: { color: textColor, font: { size: 8 } }
                    },
                    y: {
                        grid: { color: gridColor },
                        title: { display: true, text: 'Expected Return %', color: textColor, font: { size: 9, family: 'Outfit' } },
                        ticks: { color: textColor, font: { size: 8 } }
                    }
                }
            }
        });
    }

    // Expose functions globally for tab navigations
    window.loadPortfolioOptimizerPanel = loadPortfolioOptimizerPanel;

    if (runBtn) {
        runBtn.addEventListener('click', runPortfolioOptimization);
    }

    if (runAiBtn) {
        runAiBtn.addEventListener('click', async () => {
            if (!cachedOptimizationResult) return;
            
            runAiBtn.disabled = true;
            runAiBtn.innerHTML = `<span>⏳ Synthesizing Report...</span>`;
            if (aiResult) {
                aiResult.innerHTML = `<p style="margin: 0; color: var(--text-secondary); font-style: italic;">🤖 Quantitative agent connecting to AI. Parsing covariance matrix and trade tickets...</p>`;
            }

            try {
                const targetData = activeOptimizationTarget === 'sharpe' ? cachedOptimizationResult.max_sharpe : cachedOptimizationResult.min_vol;
                const items = window.uniqueOptimizerAssets || [];
                const checkboxes = document.querySelectorAll('.optimizer-asset-checkbox');
                const checkedTickers = [];
                checkboxes.forEach(cb => {
                    if (cb.checked) checkedTickers.push(cb.getAttribute('data-symbol'));
                });

                const selectedHoldings = items.filter(item => checkedTickers.includes(item.symbol));
                const totalValue = selectedHoldings.reduce((sum, item) => sum + (parseFloat(item.current_value) || 0), 0);

                const currentWeights = {};
                selectedHoldings.forEach(item => {
                    const val = parseFloat(item.current_value) || 0;
                    currentWeights[item.symbol] = totalValue > 0 ? (val / totalValue) * 100.0 : 0.0;
                });

                const tickets = [];
                const allKeysSet = new Set([
                    ...Object.keys(targetData.weights),
                    ...Object.keys(currentWeights)
                ]);
                
                allKeysSet.forEach(key => {
                    const curW = currentWeights[key] || 0.0;
                    const tarW = targetData.weights[key] || 0.0;
                    const diff = tarW - curW;
                    if (Math.abs(diff) < 1.0) return; // ignore minor offsets
                    
                    const isBuy = diff > 0;
                    const actionText = isBuy ? (key === 'CASH' ? 'Hold in Cash' : 'Buy / Top-up') : (key === 'CASH' ? 'Draw from Cash' : 'Sell / Trim');
                    const capitalOffset = (diff / 100.0) * totalValue;
                    const capitalText = Math.abs(capitalOffset).toLocaleString('en-IN', { style: 'currency', currency: 'INR', maximumFractionDigits: 0 });
                    
                    tickets.push({
                        ticker: key,
                        action: actionText,
                        weight_diff: diff.toFixed(1),
                        value_str: capitalText
                    });
                });

                const currReturn = (cachedOptimizationResult.current_portfolio && typeof cachedOptimizationResult.current_portfolio.return !== 'undefined') ? cachedOptimizationResult.current_portfolio.return : 11.5;
                const currSharpe = (cachedOptimizationResult.current_portfolio && typeof cachedOptimizationResult.current_portfolio.sharpe !== 'undefined') ? cachedOptimizationResult.current_portfolio.sharpe : 0.35;

                const response = await fetch('/api/portfolio/optimizer-synthesis', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        target_type: activeOptimizationTarget,
                        current_return: currReturn,
                        current_sharpe: currSharpe,
                        target_return: targetData.return,
                        target_sharpe: targetData.sharpe,
                        target_weights: targetData.weights,
                        rebalance_tickets: tickets
                    })
                });

                if (!response.ok) throw new Error("Synthesis query returned error status.");
                const data = await response.json();
                
                if (data.synthesis) {
                    if (aiResult) {
                        aiResult.innerHTML = `<div style="line-height: 1.7; font-family: 'Inter', sans-serif; color: var(--text-secondary);">${data.synthesis}</div>`;
                    }
                } else {
                    throw new Error("Empty AI synthesis response.");
                }
            } catch (err) {
                console.error("AI Rebalancing Synthesis failed: ", err);
                showToast("Failed to generate AI Rebalancing Report.", "error");
                if (aiResult) {
                    aiResult.innerHTML = `<p style="margin: 0; color: #ef4444; font-style: italic;">⚠️ AI generation failed. Verify API connection or model availability.</p>`;
                }
            } finally {
                runAiBtn.disabled = false;
                runAiBtn.innerHTML = `✨ Regenerate`;
            }
        });
    }
})();

// Global scope helpers for AI news scraping and synthesis timeline
async function loadPortfolioNewsImpact(symbol, forceRefresh = false, runLLM = false) {
    const newsFeed = document.getElementById('news-feed-container');
    const newsSentimentWrapper = document.getElementById('news-sentiment-wrapper');
    const newsSentimentFill = document.getElementById('news-sentiment-thermometer-fill');
    const newsSentimentVal = document.getElementById('news-sentiment-index-val');
    const newsSentimentDesc = document.getElementById('news-sentiment-index-desc');
    const newsCacheStatus = document.getElementById('news-cache-status-badge');
    const newsDiagnostics = document.getElementById('news-diagnostics-badge');
    
    const countAll = document.getElementById('count-all');
    const countPositive = document.getElementById('count-positive');
    const countNegative = document.getElementById('count-negative');
    const countNeutral = document.getElementById('count-neutral');

    if (!newsFeed) return;

    // Show dynamic loaders
    const loaderMsg = runLLM ? "Scraping news via Jina Reader & correlating with AI..." : "Fetching live RSS catalog...";
    newsFeed.innerHTML = `
        <div style="padding:40px; text-align: center; width: 100%; color: var(--text-secondary); display: flex; flex-direction: column; align-items: center; gap: 12px;">
            <div class="loader-spinner" style="border: 2px solid rgba(255,255,255,0.1); border-top: 2px solid var(--color-primary); border-radius: 50%; width: 24px; height: 24px; animation: spin 1s linear infinite; box-sizing: border-box;"></div>
            <span style="font-size: 11px;">${loaderMsg}</span>
        </div>
    `;

    try {
        const url = `/api/portfolio/news-impact?symbol=${encodeURIComponent(symbol)}&refresh=${forceRefresh ? 'true' : 'false'}&run_llm=${runLLM ? 'true' : 'false'}`;
        const res = await fetch(url);
        if (!res.ok) throw new Error("Failed to fetch news impact API");
        const data = await res.json();

        if (!data.news_items || data.news_items.length === 0) {
            newsFeed.innerHTML = '<div style="padding:20px; text-align: center; width: 100%; color: var(--text-muted); font-size:11px;">No news catalysts identified for this ticker recently.</div>';
            if (countAll) countAll.innerText = '0';
            if (countPositive) countPositive.innerText = '0';
            if (countNegative) countNegative.innerText = '0';
            if (countNeutral) countNeutral.innerText = '0';
            if (newsSentimentFill) newsSentimentFill.style.width = '50%';
            if (newsSentimentVal) newsSentimentVal.innerText = '50% Neutral';
            return;
        }

        if (newsCacheStatus) {
            if (data.has_audit) {
                newsCacheStatus.innerText = data.cached ? "Cache: Active" : "Cache: Fresh Scrape";
                newsCacheStatus.style.color = data.cached ? "var(--text-muted)" : "var(--neon-green)";
            } else {
                newsCacheStatus.innerText = "Fast RSS Catalog";
                newsCacheStatus.style.color = "var(--text-muted)";
            }
        }
        if (newsDiagnostics) {
            if (data.has_audit) {
                const timeStr = data.updated_at ? data.updated_at.split(' ')[1] : "";
                newsDiagnostics.innerText = `Engine: " + (window.llmConfig ? window.llmConfig.fast_label : "AI") + " | Refreshed: ${timeStr || "Just Now"}`;
            } else {
                newsDiagnostics.innerText = "Engine: RSS | AI Audit Pending";
            }
        }

        const sentimentVal = data.sentiment_index;
        if (newsSentimentFill) {
            if (data.has_audit) {
                newsSentimentFill.style.width = `${sentimentVal}%`;
                newsSentimentFill.style.background = ''; // reset to default CSS linear-gradient
            } else {
                newsSentimentFill.style.width = '50%';
                newsSentimentFill.style.background = '#64748b'; // neutral grey
            }
        }
        if (newsSentimentVal) {
            if (data.has_audit) {
                if (sentimentVal >= 60) {
                    newsSentimentVal.innerText = `${sentimentVal.toFixed(1)}% Bullish`;
                    newsSentimentVal.style.color = 'var(--neon-green)';
                } else if (sentimentVal <= 40) {
                    newsSentimentVal.innerText = `${sentimentVal.toFixed(1)}% Bearish`;
                    newsSentimentVal.style.color = '#ef4444';
                } else {
                    newsSentimentVal.innerText = `${sentimentVal.toFixed(1)}% Neutral`;
                    newsSentimentVal.style.color = 'var(--color-amber)';
                }
            } else {
                newsSentimentVal.innerText = 'Consensus Pending';
                newsSentimentVal.style.color = 'var(--text-muted)';
            }
        }
        if (newsSentimentDesc) {
            if (data.has_audit) {
                let descText = "Balanced or mixed sentiment. Stock movements are primarily driven by macro index flows.";
                if (sentimentVal >= 60) {
                    descText = "Highly positive news sentiment. Press releases and filings signal strong expansion and operational performance.";
                } else if (sentimentVal <= 40) {
                    descText = "Precautionary market consensus. Watch for margin pressures, regulatory tariffs, or short-term sector headwinds.";
                }
                newsSentimentDesc.innerHTML = `Consensus: <strong>${descText}</strong>`;
            } else {
                newsSentimentDesc.innerHTML = `Consensus: <strong>AI Sentiment Audit is available for this ticker. Click 'Run AI Audit' below to analyze.</strong>`;
            }
        }

        newsFeed.innerHTML = '';
        newsFeed.dataset.hasAudit = data.has_audit ? 'true' : 'false';

        if (!data.has_audit) {
            const banner = document.createElement('div');
            banner.id = 'news-audit-cta-banner';
            banner.style.cssText = `
                background: linear-gradient(135deg, rgba(124, 58, 237, 0.1) 0%, rgba(79, 70, 229, 0.1) 100%);
                border: 1px solid rgba(124, 58, 237, 0.25);
                border-radius: 8px;
                padding: 12px 16px;
                margin-bottom: 16px;
                display: flex;
                align-items: center;
                justify-content: space-between;
                gap: 12px;
                backdrop-filter: blur(8px);
                box-shadow: 0 4px 12px rgba(124, 58, 237, 0.05);
            `;
            banner.innerHTML = `
                <div style="display: flex; align-items: center; gap: 12px; text-align: left;">
                    <span style="font-size: 20px;">🤖</span>
                    <div>
                        <strong style="display: block; font-size: 12.5px; color: var(--text-primary); font-family: 'Outfit', sans-serif;">AI Sentiment Audit Available</strong>
                        <span style="display: block; font-size: 10.5px; color: var(--text-muted); margin-top: 2px; line-height: 1.4;">Extract driver catalysts, sentiment scoring, and price anomaly correlation via AI & Jina Reader.</span>
                    </div>
                </div>
                <button id="run-groq-audit-btn" style="background: linear-gradient(135deg, #7c3aed, #4f46e5); color: #ffffff; border: none; padding: 7px 14px; font-size: 11px; font-weight: 700; border-radius: 50px; cursor: pointer; display: flex; align-items: center; gap: 6px; transition: all 0.2s ease; box-shadow: 0 2px 8px rgba(124, 58, 237, 0.3); white-space: nowrap; font-family: 'Outfit', sans-serif;"
                        onmouseover="this.style.transform='translateY(-1px)'; this.style.boxShadow='0 4px 12px rgba(124, 58, 237, 0.5)';"
                        onmouseout="this.style.transform='none'; this.style.boxShadow='0 2px 8px rgba(124, 58, 237, 0.3)';">
                    <span>✨</span> Run AI Audit
                </button>
            `;
            newsFeed.appendChild(banner);
            
            const auditBtn = banner.querySelector('#run-groq-audit-btn');
            if (auditBtn) {
                auditBtn.addEventListener('click', (e) => {
                    e.preventDefault();
                    e.stopPropagation();
                    loadPortfolioNewsImpact(symbol, true, true);
                });
            }
        }

        let posCount = 0;
        let negCount = 0;
        let neutCount = 0;

        data.news_items.forEach((item, index) => {
            const score = item.sentiment_score;
            let sentimentClass = 'neutral';
            let sentimentText = 'Neutral';
            if (data.has_audit) {
                if (score > 0.15) {
                    sentimentClass = 'positive';
                    sentimentText = `Bullish (+${score.toFixed(2)})`;
                    posCount++;
                } else if (score < -0.15) {
                    sentimentClass = 'negative';
                    sentimentText = `Bearish (${score.toFixed(2)})`;
                    negCount++;
                } else {
                    neutCount++;
                }
            } else {
                sentimentClass = 'unaudited';
                sentimentText = 'Unaudited';
            }

            const card = document.createElement('div');
            card.className = `timeline-card ${sentimentClass}`;
            card.dataset.sentiment = sentimentClass;
            
            let arHTML = "";
            if (item.abnormal_return && item.is_anomaly) {
                const arScore = item.abnormal_return;
                const arClass = arScore >= 0 ? 'up' : 'down';
                const arSign = arScore >= 0 ? '+' : '';
                arHTML = `<span class="badge-ar ${arClass}">${arSign}${arScore.toFixed(1)}% vs Nifty 50</span>`;
            }

            card.innerHTML = `
                <div class="news-card-header">
                    <div class="news-card-metadata">
                        <span>📰 ${item.publisher || 'Financial Feed'}</span>
                        <span>•</span>
                        <span>🕒 ${item.date || 'Today'}</span>
                    </div>
                    <div class="news-card-badges">
                        <button class="news-card-read-aloud-btn" style="background:transparent; border:none; color:var(--text-muted); cursor:pointer; font-size:10px; padding: 2px; display:inline-flex; align-items:center; opacity:0.75; transition: opacity 0.2s;" title="Read Headline Aloud">🔊 Listen</button>
                        <span class="badge-sentiment ${sentimentClass}">${sentimentText}</span>
                        <span class="badge-driver">${item.category || 'General'}</span>
                        ${arHTML}
                    </div>
                </div>
                <div class="news-card-body" style="margin-bottom: 0;">
                    <a href="${item.link || '#'}" target="_blank" style="text-decoration:none; color:inherit; font-size:12.5px; font-weight:700; line-height:1.45; color:var(--text-primary); display:block; cursor:pointer;">
                        ${item.title}
                    </a>
                </div>
            `;

            newsFeed.appendChild(card);

            const listenBtn = card.querySelector('.news-card-read-aloud-btn');
            if (listenBtn) {
                listenBtn.addEventListener('click', (e) => {
                    e.preventDefault();
                    e.stopPropagation();
                    const speechText = `${item.title}. Publisher: ${item.publisher || 'Financial Feed'}. Sentiment is ${sentimentText}.`;
                    toggleSpeechForMessage(speechText, listenBtn);
                });
            }
        });

        if (countAll) countAll.innerText = data.news_items.length;
        if (countPositive) countPositive.innerText = data.has_audit ? posCount : '-';
        if (countNegative) countNegative.innerText = data.has_audit ? negCount : '-';
        if (countNeutral) countNeutral.innerText = data.has_audit ? neutCount : '-';

        const chips = document.querySelectorAll('.news-filter-chip');
        chips.forEach(chip => {
            if (chip.dataset.filter === 'all') chip.classList.add('active');
            else chip.classList.remove('active');
        });

    } catch (err) {
        console.error("Error loading news impact:", err);
        newsFeed.innerHTML = `<div style="padding:20px; text-align: center; width: 100%; color: var(--color-crimson); font-size:11.5px;">Failed to scrape and correlate live catalysts: ${err.message}.</div>`;
    }
}

function setupNewsFilters() {
    const chips = document.querySelectorAll('.news-filter-chip');
    chips.forEach(chip => {
        const newChip = chip.cloneNode(true);
        chip.parentNode.replaceChild(newChip, chip);
        
        newChip.addEventListener('click', (e) => {
            e.preventDefault();
            e.stopPropagation();
            
            document.querySelectorAll('.news-filter-chip').forEach(c => c.classList.remove('active'));
            newChip.classList.add('active');
            
            const filterValue = newChip.dataset.filter;
            const cards = document.querySelectorAll('#news-feed-container .timeline-card');
            
            cards.forEach(card => {
                if (filterValue === 'all') {
                    card.style.display = 'block';
                } else if (card.dataset.sentiment === filterValue) {
                    card.style.display = 'block';
                } else {
                    card.style.display = 'none';
                }
            });
        });
    });
}

// --- GLOBAL MARKET NEWS TERMINAL ---
let globalMarketNewsData = null;
let currentMarketNewsSource = 'all';
let currentMarketNewsCategory = 'all';

function setupGlobalMarketNewsControls() {
    // 1. Search filter event
    const searchInput = document.getElementById('market-news-search');
    if (searchInput) {
        searchInput.addEventListener('input', () => {
            applyMarketNewsFilters();
        });
    }

    // 2. Source filter chips
    const sourceFiltersWrap = document.getElementById('market-news-source-filters');
    if (sourceFiltersWrap) {
        sourceFiltersWrap.addEventListener('click', (e) => {
            const chip = e.target.closest('.news-filter-chip');
            if (!chip) return;
            e.preventDefault();
            e.stopPropagation();

            sourceFiltersWrap.querySelectorAll('.news-filter-chip').forEach(c => c.classList.remove('active'));
            chip.classList.add('active');

            currentMarketNewsSource = chip.dataset.source;
            applyMarketNewsFilters();
        });
    }

    // 3. Category filter chips
    const categoryFiltersWrap = document.getElementById('market-news-category-filters');
    if (categoryFiltersWrap) {
        categoryFiltersWrap.addEventListener('click', (e) => {
            const chip = e.target.closest('.screener-filter-chip');
            if (!chip) return;
            e.preventDefault();
            e.stopPropagation();

            categoryFiltersWrap.querySelectorAll('.screener-filter-chip').forEach(c => c.classList.remove('active'));
            chip.classList.add('active');

            currentMarketNewsCategory = chip.dataset.category;
            applyMarketNewsFilters();
        });
    }

    // 4. AI Synthesis button
    const aiBtn = document.getElementById('market-news-ai-btn');
    if (aiBtn) {
        aiBtn.addEventListener('click', (e) => {
            e.preventDefault();
            e.stopPropagation();
            loadGlobalMarketNews(true, true);
        });
    }

    // AI read aloud button
    const newsReadAloudBtn = document.getElementById('market-news-ai-read-aloud-btn');
    if (newsReadAloudBtn) {
        newsReadAloudBtn.addEventListener('click', (e) => {
            e.preventDefault();
            e.stopPropagation();
            const synthesis = document.getElementById('market-news-ai-synthesis').innerText;
            const drivers = Array.from(document.querySelectorAll('#market-news-ai-drivers li'))
                                 .map(li => li.innerText).join('. ');
            const speechText = `Global Market News Summary: ${synthesis}. Key Drivers: ${drivers}`;
            window.SpeechPlayer.startSpeakingSection(speechText, "Market Intelligence", true);
        });
    }
}

async function loadGlobalMarketNews(forceRefresh = false, runLLM = false) {
    const newsFeed = document.getElementById('market-news-feed-container');
    const marquee = document.getElementById('market-news-marquee');
    const aiBriefingWrap = document.getElementById('market-news-ai-briefing-wrap');
    const aiTimeBadge = document.getElementById('market-news-ai-time-badge');
    const aiSynthesis = document.getElementById('market-news-ai-synthesis');
    const aiDrivers = document.getElementById('market-news-ai-drivers');
    const aiPlaceholder = document.getElementById('market-news-ai-placeholder');

    if (!newsFeed) return;

    // Show dynamic loader
    const loaderMsg = runLLM ? "Generating AI Market consensus briefing via AI..." : "Aggregating news from ET, LiveMint, Business Standard & Yahoo Finance...";
    newsFeed.innerHTML = `
        <div style="padding:40px; text-align: center; width: 100%; color: var(--text-secondary); display: flex; flex-direction: column; align-items: center; gap: 12px;">
            <div class="loader-spinner" style="border: 2px solid rgba(255,255,255,0.1); border-top: 2px solid var(--color-primary); border-radius: 50%; width: 24px; height: 24px; animation: spin 1s linear infinite; box-sizing: border-box;"></div>
            <span style="font-size: 11px;">${loaderMsg}</span>
        </div>
    `;

    try {
        const url = `/api/market-news?refresh=${forceRefresh ? 'true' : 'false'}&run_llm=${runLLM ? 'true' : 'false'}`;
        const res = await fetch(url);
        if (!res.ok) throw new Error("Failed to fetch market news from API");
        const data = await res.json();

        globalMarketNewsData = data;

        // 1. Populate Marquee Ticker
        if (marquee) {
            if (data.news_items && data.news_items.length > 0) {
                marquee.innerHTML = data.news_items.slice(0, 10).map(item => `
                    <span style="margin-right: 40px; display: inline-flex; align-items: center; gap: 6px;">
                        <span style="color: var(--color-primary);">[${item.source}]</span> ${item.title}
                    </span>
                `).join('');
            } else {
                marquee.innerText = "No bulletins available.";
            }
        }

        // 2. Populate AI Market Briefing
        if (data.has_ai_report && data.ai_report) {
            if (aiBriefingWrap) aiBriefingWrap.style.display = 'block';
            if (aiPlaceholder) aiPlaceholder.style.display = 'none';
            if (aiSynthesis) aiSynthesis.innerText = data.ai_report.synthesis_report;
            if (aiDrivers) {
                aiDrivers.innerHTML = (data.ai_report.top_drivers || []).map(driver => `
                    <li style="list-style-type: square; margin-left: 15px;">${driver}</li>
                `).join('');
            }
            if (aiTimeBadge) {
                const timePart = data.updated_at ? data.updated_at.split(' ')[1] : 'Just Now';
                aiTimeBadge.innerText = `Audited: ${timePart}`;
            }
        } else {
            if (aiBriefingWrap) aiBriefingWrap.style.display = 'none';
            if (aiPlaceholder) aiPlaceholder.style.display = 'flex';
        }

        // 3. Render news cards
        newsFeed.innerHTML = '';
        if (data.news_items && data.news_items.length > 0) {
            data.news_items.forEach(item => {
                const card = document.createElement('div');
                card.className = `timeline-card sentiment-${item.sentiment.toLowerCase()}`;
                card.dataset.sentiment = item.sentiment.toLowerCase();
                card.dataset.source = item.source;
                card.dataset.category = item.category;

                card.innerHTML = `
                    <div class="news-card-header">
                        <div class="news-card-metadata">
                            <span>📰 ${item.source}</span>
                            <span>•</span>
                            <span>🕒 ${item.date}</span>
                        </div>
                        <div class="news-card-badges">
                            <span class="badge-sentiment sentiment-${item.sentiment.toLowerCase()}">${item.sentiment}</span>
                            <span class="badge-driver">${item.category}</span>
                        </div>
                    </div>
                    <div class="news-card-body" style="margin-bottom: 0;">
                        <a href="${item.link || '#'}" target="_blank" style="text-decoration:none; color:inherit; font-size:12.5px; font-weight:700; line-height:1.45; color:var(--text-primary); display:block; cursor:pointer;">
                            ${item.title}
                        </a>
                    </div>
                `;
                newsFeed.appendChild(card);
            });
            applyMarketNewsFilters();
        } else {
            newsFeed.innerHTML = '<div style="padding:40px; text-align: center; width: 100%; color: var(--text-muted); font-size:12px;">No news catalysts identified in the last 30 days.</div>';
        }

    } catch (err) {
        console.error("Error loading global market news:", err);
        newsFeed.innerHTML = `<div style="padding:20px; text-align: center; width: 100%; color: var(--color-crimson); font-size:11.5px;">Failed to scrape and correlate live catalysts: ${err.message}.</div>`;
    }
}

function applyMarketNewsFilters() {
    const container = document.getElementById('market-news-feed-container');
    if (!container) return;

    const cards = container.querySelectorAll('.timeline-card');
    const query = (document.getElementById('market-news-search')?.value || '').toLowerCase().trim();

    let visibleCount = 0;
    cards.forEach(card => {
        const source = card.dataset.source;
        const category = card.dataset.category;
        const title = (card.querySelector('.news-card-body a')?.innerText || '').toLowerCase();

        const sourceMatch = (currentMarketNewsSource === 'all' || source === currentMarketNewsSource);
        const categoryMatch = (currentMarketNewsCategory === 'all' || category === currentMarketNewsCategory);
        const searchMatch = (!query || title.includes(query));

        if (sourceMatch && categoryMatch && searchMatch) {
            card.style.display = 'block';
            visibleCount++;
        } else {
            card.style.display = 'none';
        }
    });

    let noResultsMsg = document.getElementById('market-news-no-results');
    if (visibleCount === 0) {
        if (!noResultsMsg) {
            noResultsMsg = document.createElement('div');
            noResultsMsg.id = 'market-news-no-results';
            noResultsMsg.style.cssText = 'padding: 30px; text-align: center; color: var(--text-muted); font-size: 12px;';
            noResultsMsg.innerText = 'No news catalysts match the selected filters.';
            container.appendChild(noResultsMsg);
        } else {
            noResultsMsg.style.display = 'block';
        }
    } else {
        if (noResultsMsg) {
            noResultsMsg.style.display = 'none';
        }
    }
}

// Expose functions to global window context
window.loadGlobalMarketNews = loadGlobalMarketNews;
window.setupGlobalMarketNewsControls = setupGlobalMarketNewsControls;


