// ── AI Coach ──
function setupAcademyAICoach() {
    const input = document.getElementById('academy-ai-input');
    const sendBtn = document.getElementById('academy-ai-send-btn');
    if (!input || !sendBtn) return;

    const sendMessage = async () => {
        const question = input.value.trim();
        if (!question) return;

        const module = ACADEMY_CATALOG.find(m => m.id === academyActiveTopicId);
        const messagesEl = document.getElementById('academy-ai-messages');
        if (!messagesEl) return;

        // Add user message
        messagesEl.innerHTML += `<div class="academy-ai-msg user"><span>${question}</span></div>`;
        input.value = '';
        messagesEl.scrollTop = messagesEl.scrollHeight;

        // Add loading
        messagesEl.innerHTML += `<div class="academy-ai-msg assistant" id="academy-ai-loading"><span>🔄 Thinking...</span></div>`;
        messagesEl.scrollTop = messagesEl.scrollHeight;

        try {
            const activeSub = academyActiveSubPattern[academyActiveTopicId] || (module && ACADEMY_SUB_PATTERNS[academyActiveTopicId] ? ACADEMY_SUB_PATTERNS[academyActiveTopicId][0] : null);
            const sbVals = { ...academyActiveSliderValues, ...academyActiveSandboxValues };

            const res = await fetch('/api/learning/ask', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    question: question,
                    topic: module ? module.title : null,
                    category: module ? module.cat : null,
                    sandbox_values: sbVals,
                    sub_pattern: activeSub
                })
            });
            const data = await res.json();
            const loading = document.getElementById('academy-ai-loading');
            if (loading) loading.remove();

            const answer = data.answer || 'Sorry, I could not generate a response.';
            const answerId = `academy-coach-answer-${Date.now()}`;
            messagesEl.innerHTML += `
                <div class="academy-ai-msg assistant">
                    <span>
                        <button class="section-speak-btn" data-target="${answerId}" data-title="AI Coach Reply" style="background: none; border: none; cursor: pointer; padding: 2px; margin-right: 4px; display: inline-flex; align-items: center; justify-content: center; outline: none; vertical-align: middle;">🔊</button>
                        <span id="${answerId}">${answer.replace(/\n/g, '<br>')}</span>
                    </span>
                </div>
            `;
        } catch (err) {
            const loading = document.getElementById('academy-ai-loading');
            if (loading) loading.remove();
            messagesEl.innerHTML += `<div class="academy-ai-msg assistant"><span>⚠️ Error connecting to AI Coach. Please try again.</span></div>`;
        }
        messagesEl.scrollTop = messagesEl.scrollHeight;
    };

    sendBtn.addEventListener('click', sendMessage);
    input.addEventListener('keydown', (e) => { if (e.key === 'Enter') sendMessage(); });

    // Voice recognition setup
    const micBtn = document.getElementById('academy-ai-mic-btn');
    let academyRecognition = null;
    let isAcademyListening = false;

    if (micBtn) {
        const isAndroidSpeech = window.AndroidSpeech && typeof window.AndroidSpeech.startListening === 'function';
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;

        if (isAndroidSpeech) {
            micBtn.addEventListener('click', (e) => {
                e.stopPropagation();
                if (window.AndroidSpeechListening && window.activeSpeechRecognizerTarget === 'academy') {
                    window.AndroidSpeech.stopListening();
                } else {
                    window.activeSpeechRecognizerTarget = 'academy';
                    window.AndroidSpeech.startListening();
                }
            });
        } else if (!SpeechRecognition) {
            micBtn.style.display = 'none';
        } else {
            academyRecognition = new SpeechRecognition();
            academyRecognition.continuous = false;
            academyRecognition.interimResults = false;
            academyRecognition.lang = 'en-US';

            academyRecognition.onstart = () => {
                isAcademyListening = true;
                micBtn.innerHTML = '🔴';
                micBtn.classList.add('mic-listening');
            };

            academyRecognition.onend = () => {
                isAcademyListening = false;
                micBtn.innerHTML = '🎙️';
                micBtn.classList.remove('mic-listening');
            };

            academyRecognition.onresult = (event) => {
                const transcript = event.results[0][0].transcript;
                input.value = (input.value ? input.value + ' ' : '') + transcript;
            };

            academyRecognition.onerror = (event) => {
                console.error("Academy Speech recognition error:", event.error);
                if (event.error === 'no-speech') return;
                if (event.error === 'network') {
                    if (typeof showToast === 'function') {
                        showToast("Speech recognition network error. Please check your internet connection.", "warning");
                    }
                    return;
                }
                if (event.error === 'not-allowed') {
                    if (typeof showToast === 'function') {
                        showToast("Microphone access denied. Please enable mic permissions in browser settings.", "warning");
                    }
                    return;
                }
            };

            micBtn.addEventListener('click', (e) => {
                e.stopPropagation();
                if (isAcademyListening) {
                    academyRecognition.stop();
                } else {
                    try {
                        academyRecognition.start();
                    } catch (err) {
                        console.error("Failed to start speech recognition:", err);
                    }
                }
            });
        }
    }
}

let academyActiveSandboxValues = {};
